/// Errors that can occur when applying an action to the game.
#[derive(Debug, Error)]
pub enum RulesError {
    #[error("invalid action for current game phase: {0}")]
    InvalidAction(String),
    #[error("player {0} not found")]
    PlayerNotFound(String),
    #[error("coordinate out of bounds")]
    OutOfBounds,
    #[error("action not legal in current state")]
    NotLegal,
}

/// Context saved when a roll fails and a team reroll is available.
/// The engine pauses, offers the reroll, and resumes on `UseReRoll`.
#[derive(Debug, Clone)]
enum PendingReroll {
    /// A dodge roll failed; player has been moved to `dest` already.
    Dodge {
        player_id: String,
        home_moving: bool,
        origin_coord: FieldCoordinate,
        dest: FieldCoordinate,
        path_remaining: Vec<FieldCoordinate>,
        min_roll: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A go-for-it roll failed; player has been moved to `dest` already.
    GoForIt {
        player_id: String,
        home_moving: bool,
        origin_coord: FieldCoordinate,
        dest: FieldCoordinate,
        path_remaining: Vec<FieldCoordinate>,
        min_roll: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A ball-pickup roll failed; player is at `coord`, ball is in play.
    BallPickup {
        player_id: String,
        home_moving: bool,
        coord: FieldCoordinate,
        min_roll: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A pass roll was inaccurate/wildly-inaccurate; re-rolling would re-evaluate the pass.
    PassRoll {
        player_id: String,
        home_passing: bool,
        target_coord: FieldCoordinate,
        pass_stat: i32,
        target_nr: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A catch roll failed; re-rolling would retry the catch at the same square.
    CatchRoll {
        receiver_id: String,
        home_passing: bool,
        coord: FieldCoordinate,
        catch_min: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A Leap roll failed; player has been moved to `dest` already.
    Leap {
        player_id: String,
        home_moving: bool,
        origin_coord: FieldCoordinate,
        dest: FieldCoordinate,
        path_remaining: Vec<FieldCoordinate>,
        min_roll: i32,
        is_pro: bool,
        is_consummate_professional: bool,
    },
    /// A block roll produced Skull or BothDown-without-Block; can be rerolled.
    Block {
        attacker_id: String,
        home_attacking: bool,
        ctx: PendingBlockChoice,
        original_result: BlockResult,
        is_pro: bool,
    },
}

/// Context saved while waiting for the attacker to choose a push square.
#[derive(Debug, Clone)]
struct PendingPush {
    attacker_id: String,
    defender_id: String,
    home_attacking: bool,
    push_squares: Vec<FieldCoordinate>,
    do_armor: bool,
    attacker_coord: FieldCoordinate,
    def_has_stand_firm: bool,
    /// Fend: defender has Fend — attacker may not follow up.
    def_has_fend: bool,
}

/// Context saved while waiting for the attacker to declare follow-up.
#[derive(Debug, Clone)]
struct PendingFollowUp {
    attacker_id: String,
    attacker_from: FieldCoordinate,
    attacker_to: FieldCoordinate,   // defender's old position = where attacker can move
    defender_id: String,
    knocked_down: bool,             // true if the block result was a Pow (armor roll applied)
}

/// Context saved while waiting for the defender (with Taunt, BB2025) to decide whether to force attacker follow-up.
#[derive(Debug, Clone)]
struct PendingTaunt {
    defender_id: String,
    defender_is_home: bool,
    /// The follow-up state to set if Taunt is declined (normal choice given to attacker).
    follow_up: PendingFollowUp,
}

/// Context saved while waiting for the attacker to choose a block die result.
/// Only set when the attacker rolls 2+ dice (strength advantage).
#[derive(Debug, Clone)]
struct PendingBlockChoice {
    attacker_id: String,
    defender_id: String,
    home_attacking: bool,
    results: Vec<BlockResult>,
    att_has_block: bool,
    att_has_wrestle: bool,
    att_has_claws: bool,
    att_has_mb: bool,
    att_has_piling_on: bool,
    att_has_grab: bool,
    att_has_juggernaut: bool,
    att_has_strip_ball: bool,
    att_has_brawler: bool,
    att_has_hatred: bool,
    att_has_woodland_fury: bool,
    att_has_consummate_professional: bool,
    /// WorkingInTandem (BB2025): Lucien may reroll a single block die when Valen marks the defender.
    att_has_working_in_tandem_block: bool,
    is_blitz: bool,
    attacker_coord: FieldCoordinate,
    defender_coord: FieldCoordinate,
    def_has_sidestep: bool,
    def_has_wrestle: bool,
}

/// Context saved while waiting for attacker/defender to decide on Wrestle use (BothDown).
#[derive(Debug, Clone)]
struct PendingWrestle {
    ctx: PendingBlockChoice,
    asking_attacker: bool,
}

/// Context saved while waiting for a team to decide on apothecary use after an injury.
#[derive(Debug, Clone)]
struct PendingApothecary {
    player_id: String,
    player_is_home: bool,
    attacker_id: String,
    attacker_is_home: bool,
    ar1: i32, ar2: i32,
    inj1: i32, inj2: i32,
    was_ko: bool,
    was_cas: bool,
    si: Option<ffb_model::enums::SeriousInjuryKind>,
    is_dead: bool,
}

/// Context saved while waiting for the fouling team to decide on bribe use.
#[derive(Debug, Clone)]
struct PendingBribe {
    fouler_id: String,
    home_fouling: bool,
}

/// Context saved while waiting for the fouling team to decide on Argue the Call.
#[derive(Debug, Clone)]
struct PendingArgueTheCall {
    fouler_id: String,
    home_fouling: bool,
}

/// Context saved while offering Piling On after a Pow result.
#[derive(Debug, Clone)]
struct PendingPilingOn {
    attacker_id: String,
    defender_id: String,
    home_attacking: bool,
    defender_coord: FieldCoordinate,
    /// True if armor was already broken (re-roll injury instead of armor).
    armor_broken: bool,
}

/// Context for PutridRegurgitation (BB2020+): after a block knockdown, attacker may vomit on any adjacent opponent.
#[derive(Debug, Clone)]
struct PendingPutridRegurgitation {
    attacker_id: String,
    defender_id: String,
    home_attacking: bool,
}

/// Context for HitAndRun skill: after block, attacker may move one safe square.
#[derive(Debug, Clone)]
struct PendingHitAndRun {
    attacker_id: String,
    home_attacking: bool,
    valid_squares: Vec<FieldCoordinate>,
}

/// Context for Saboteur skill (BB2025): fallen player may roll 4+ to also knock down opponent.
#[derive(Debug, Clone)]
struct PendingSaboteur {
    /// The player offering Saboteur (the one who fell).
    player_id: String,
    /// The opponent who may be knocked down.
    target_id: String,
    /// True if the player offering Saboteur is on the home team.
    is_home: bool,
}

/// Context saved while waiting for the thrower to decide on BlastIt (BB2020+).
/// After the first HMP scatter direction is rolled, the player may reroll it.
#[derive(Debug, Clone)]
struct PendingBlastIt {
    thrower_id: String,
    home_throwing: bool,
    target_coord: FieldCoordinate,
    first_dir: i32,
    first_dest: FieldCoordinate,
}

/// Context saved while waiting for a PickMeUp (BB2020+) roll.
/// The non-active team's PickMeUp players can attempt to stand up prone teammates.
#[derive(Debug, Clone)]
struct PendingPickMeUp {
    /// True if the PickMeUp team is the home team.
    is_home: bool,
    /// Eligible prone teammates that may be stood up.
    eligible_players: Vec<String>,
}

/// Context saved while the active player (Zolcath) waits to select a target for auto-gaze.
/// ExcuseMeAreYouAZoat (BB2025): once per game, at activation, set one opponent within 3 squares to confused.
#[derive(Debug, Clone)]
struct PendingAutoGaze {
    /// The player using ExcuseMeAreYouAZoat.
    player_id: String,
    /// True if the using player is on the home team.
    is_home: bool,
}

/// BalefulHex (BB2020+): once per game, at activation, pick an opponent within 5 squares, roll 2+ to make confused+inactive.
#[derive(Debug, Clone)]
struct PendingBalefulHex {
    /// The player using BalefulHex.
    player_id: String,
    /// True if the using player is on the home team.
    is_home: bool,
}

/// LookIntoMyEyes (BB2020+): once per game, during Gaze action, roll 2+ to steal ball from defender.
#[derive(Debug, Clone)]
struct PendingLookIntoMyEyes {
    /// The player using LookIntoMyEyes.
    player_id: String,
    /// The target being gazed at.
    target_id: String,
    /// True if the using player is on the home team.
    is_home: bool,
}

/// ThenIStartedBlastin / BlastinSolvesEverything: wait for target selection, then roll D6.
#[derive(Debug, Clone)]
struct PendingBlastin {
    /// The player firing the keg.
    player_id: String,
    /// True if the blasting player is on the home team.
    is_home: bool,
    /// Which skill is being used.
    skill_id: SkillId,
}

/// WisdomOfTheWhiteDwarf: Grombrindal grants one skill to an adjacent teammate at their activation.
#[derive(Debug, Clone)]
struct PendingWisdomGrant {
    /// The player receiving the temporary skill (just activated).
    grantee_id: String,
    /// True if granter is on the home team.
    is_home: bool,
}

/// Context saved while waiting for the defender to choose a Trickster move square before block resolves.
#[derive(Debug, Clone)]
struct PendingTrickster {
    attacker_id: String,
    defender_id: String,
    home_attacking: bool,
    eligible_squares: Vec<FieldCoordinate>,
}

/// Context saved while waiting for the ball carrier to decide on DumpOff before a block resolves.
#[derive(Debug, Clone)]
struct PendingDumpOff {
    /// The attacker who declared the block
    attacker_id: String,
    /// The ball carrier (defender) who may DumpOff
    defender_id: String,
    /// True if the attacking side is home
    home_attacking: bool,
}

/// Context saved while opponents execute PassBlock/OnTheBall moves before interception.
#[derive(Debug, Clone)]
struct PendingPassBlock {
    /// Player making the pass.
    thrower_id: String,
    /// Target square of the pass.
    target_coord: FieldCoordinate,
    /// True if the passing team is home.
    home_passing: bool,
    /// Eligible players remaining to move (up to 3 squares each).
    eligible_players: Vec<String>,
    /// The pass result (Accurate/Inaccurate/WildlyInaccurate) — used after movement.
    pass_result_str: String,
    /// GiveAndGo: if true, thrower can still move after pass resolution.
    give_and_go: bool,
}

/// Kickoff reorganization (SolidDefence / Charge BB2025): one team moves up to D3+3 players.
#[derive(Debug, Clone)]
struct PendingSolidDefence {
    eligible: Vec<String>,
    remaining: i32,
    kicking_is_home: bool,
    /// True for Charge (receiving team moves forward), false for SolidDefence (kicking team moves back).
    is_charge: bool,
}

/// The headless game engine.
///
/// Owns the complete game state and a seeded RNG. Agents interact via
/// `current_prompt()` and `apply()`.
pub struct GameEngine {
    pub game: Game,
    rng: GameRng,
    pub seed: u64,
    cached_prompt: Option<AgentPrompt>,
    /// True once the active team has activated one player this turn (simplified parity flow).
    player_activated_this_turn: bool,
    /// How many players the receiving team has set up (for two-phase setup).
    setup_phase: u8,
    /// Waiting for the coin-flip winner to choose receive/kick before entering Setup.
    awaiting_receive_choice: bool,
    /// Pending reroll offer: set when a roll fails and a team reroll is available.
    pending_reroll: Option<PendingReroll>,
    /// Waiting for attacker to choose a push-back square.
    pending_push: Option<PendingPush>,
    /// Waiting for attacker to declare follow-up.
    pending_follow_up: Option<PendingFollowUp>,
    /// Waiting for attacker to choose which block die result to apply.
    pending_block_choice: Option<PendingBlockChoice>,
    /// Waiting for a team to decide on apothecary use after an injury.
    pending_apothecary: Option<PendingApothecary>,
    /// Waiting for a touchback: receiving team must pick who gets the ball.
    awaiting_touchback: bool,
    /// Waiting for fouling team to decide on bribe use.
    pending_bribe: Option<PendingBribe>,
    /// Waiting for attacker to decide on Piling On use after a Pow.
    pending_piling_on: Option<PendingPilingOn>,
    /// Vampire player who failed Blood Lust and must bite an adjacent teammate.
    pending_blood_lust: Option<String>,
    /// Waiting for attacker or defender to decide on Wrestle use (BothDown).
    pending_wrestle: Option<PendingWrestle>,
    /// Waiting for fouling team to decide on Argue the Call after ejection.
    pending_argue_the_call: Option<PendingArgueTheCall>,
    /// Waiting for opposing players with PassBlock/OnTheBall to move before interception.
    pending_pass_block: Option<PendingPassBlock>,
    /// Waiting for receiving team's OnTheBall players to position during kickoff scatter.
    pending_on_the_ball_kickoff: Option<Vec<String>>,
    /// Waiting for attacker to decide on StripBall use (BothDown vs ball-carrier).
    pending_strip_ball: Option<PendingBlockChoice>,
    /// Waiting for ball carrier (defender) to decide on DumpOff before the block resolves.
    pending_dump_off: Option<PendingDumpOff>,
    /// Waiting for defender (with Trickster) to choose a square to move to before block resolves.
    pending_trickster: Option<PendingTrickster>,
    /// Waiting for attacker to choose where to move (HitAndRun skill) after block completes.
    pending_hit_and_run: Option<PendingHitAndRun>,
    /// Waiting for attacker to decide on PutridRegurgitation (BB2020+) after a block knockdown.
    pending_putrid_regurgitation: Option<PendingPutridRegurgitation>,
    /// Waiting for defender (with Taunt, BB2025) to decide whether to force attacker follow-up.
    pending_taunt: Option<PendingTaunt>,
    /// Waiting for ThenIStartedBlastin / BlastinSolvesEverything target selection.
    pending_blastin: Option<PendingBlastin>,
    /// Waiting for a fallen player to decide on Saboteur (BB2025) use.
    pending_saboteur: Option<PendingSaboteur>,
    /// Waiting for the non-active team to decide which prone players to attempt to stand up (PickMeUp, BB2020+).
    pending_pick_me_up: Option<PendingPickMeUp>,
    /// Waiting for the active player (Zolcath) to select an auto-gaze target (ExcuseMeAreYouAZoat, BB2025).
    pending_auto_gaze: Option<PendingAutoGaze>,
    /// Waiting for the active player to select a BalefulHex target (BB2020+).
    pending_baleful_hex: Option<PendingBalefulHex>,
    /// Waiting to resolve LookIntoMyEyes roll (BB2020+).
    pending_look_into_my_eyes: Option<PendingLookIntoMyEyes>,
    /// Waiting for the active player to choose which skill to receive from WisdomOfTheWhiteDwarf.
    pending_wisdom_grant: Option<PendingWisdomGrant>,
    /// Waiting for thrower to decide on BlastIt (BB2020+) after first HMP scatter direction.
    pending_blast_it: Option<PendingBlastIt>,
    /// Waiting for receiving team to use KickoffReturn (BB2020+): one eligible player may move 3 squares.
    pending_kickoff_return: Option<Vec<String>>,
    /// HighKick kickoff (BB2020+): receiving team picks one eligible player to move to ball square.
    pending_high_kick: Option<Vec<String>>,
    /// Blitz kickoff event fired this drive: kicking team gets a free TurnMode::Blitz turn.
    blitz_kickoff_pending: bool,
    /// SolidDefence / Charge kickoff: one team may move D3+3 eligible players 2 squares.
    pending_solid_defence: Option<PendingSolidDefence>,
    /// True when BlastIt is active for the current HMP, granting catcher a -1 target modifier.
    blast_it_catch_bonus: bool,
    /// Card-applied temporary skills pending removal at turn/drive end: (player_id, skill_id, card_id).
    card_temporary_skills: Vec<(String, SkillId, String)>,
    /// Star player IDs purchased by home/away during the inducement phase.
    home_star_purchases: Vec<String>,
    away_star_purchases: Vec<String>,
}

/// Returns true if the race string matches one of the Blood Bowl undead team races.
fn is_undead_race(race: &str) -> bool {
    let lower = race.to_lowercase();
    lower.contains("undead") || lower.contains("khemri")
        || lower.contains("necromantic") || lower == "vampire"
}

impl GameEngine {
    /// Create a new game with two teams, using the given seed for all dice rolls.
    pub fn new(home: Team, away: Team, rules: Rules, seed: u64) -> Self {
        let mut game = Game::new(home, away, rules);
        // Initialize per-half rerolls from team purchase counts.
        game.turn_data_home.rerolls = game.team_home.rerolls;
        game.turn_data_away.rerolls = game.team_away.rerolls;
        let mut engine = GameEngine {
            game,
            rng: GameRng::new(seed),
            seed,
            cached_prompt: None,
            player_activated_this_turn: false,
            setup_phase: 0,
            awaiting_receive_choice: false,
            pending_reroll: None,
            pending_push: None,
            pending_follow_up: None,
            pending_block_choice: None,
            pending_apothecary: None,
            awaiting_touchback: false,
            pending_bribe: None,
            pending_piling_on: None,
            pending_blood_lust: None,
            pending_wrestle: None,
            pending_argue_the_call: None,
            pending_pass_block: None,
            pending_on_the_ball_kickoff: None,
            pending_strip_ball: None,
            pending_dump_off: None,
            pending_trickster: None,
            pending_hit_and_run: None,
            pending_putrid_regurgitation: None,
            pending_taunt: None,
            pending_blastin: None,
            pending_saboteur: None,
            pending_pick_me_up: None,
            pending_auto_gaze: None,
            pending_baleful_hex: None,
            pending_look_into_my_eyes: None,
            pending_wisdom_grant: None,
            pending_blast_it: None,
            pending_kickoff_return: None,
            pending_high_kick: None,
            blitz_kickoff_pending: false,
            pending_solid_defence: None,
            blast_it_catch_bonus: false,
            card_temporary_skills: Vec::new(),
            home_star_purchases: Vec::new(),
            away_star_purchases: Vec::new(),
        };
        engine.compute_next_prompt();
        engine
    }

    /// Current prompt that the active agent must respond to.
    pub fn current_prompt(&self) -> Option<&AgentPrompt> {
        self.cached_prompt.as_ref()
    }

    /// Which side is currently being asked to act.
    pub fn active_side(&self) -> TeamSide {
        if self.game.home_playing {
            TeamSide::Home
        } else {
            TeamSide::Away
        }
    }

    /// Whether the game has ended.
    pub fn is_finished(&self) -> bool {
        self.game.is_finished()
    }

    /// FNV-1a 64-bit state hash (matches Java's ParityRunner.stateHash()).
    pub fn state_hash_str(&self) -> String {
        state_hash(&self.game)
    }

    /// Apply an agent action and advance the game state.
    pub fn apply(&mut self, _side: TeamSide, action: Action) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        match action {
            Action::CoinChoice { heads } => {
                // Emit a GameOptions snapshot at game start (before the coin throw).
                let options_snapshot: std::collections::HashMap<String, String> = {
                    let mut m = std::collections::HashMap::new();
                    m.insert("rules".into(), format!("{:?}", self.game.rules));
                    m
                };
                events.push(GameEvent::GameOptions { options_snapshot });
                // Java StepSpectators: rolls d3 for each team's fan factor before coin.
                // team.fan_factor = team.dedicated_fans + d3_roll
                let fan_roll_home = self.rng.d3();
                self.game.team_home.fan_factor = self.game.team_home.dedicated_fans + fan_roll_home;
                let fan_roll_away = self.rng.d3();
                self.game.team_away.fan_factor = self.game.team_away.dedicated_fans + fan_roll_away;
                // Java StepWeather: rolls 2d6 for weather and sets it immediately.
                let weather_d1 = self.rng.d6();
                let weather_d2 = self.rng.d6();
                let weather = Weather::for_roll(weather_d1 + weather_d2);
                self.game.weather = weather;
                events.push(GameEvent::WeatherChange { weather });
                // Roll the actual coin with the game dice RNG (matches Java's throwCoin()).
                // Winner = whoever's guess (heads/tails) matches the physical coin result.
                let coin_is_heads = self.rng.bool();
                let home_won = heads == coin_is_heads;
                self.game.home_playing = home_won; // winner becomes "active" (chooser)
                self.awaiting_receive_choice = true;
                events.push(GameEvent::CoinThrow { home_won });
            }

            Action::ReceiveChoice { receive } => {
                // receive = true → the active (choosing) team wants to receive.
                let home_receives = if self.game.home_playing { receive } else { !receive };
                self.game.home_first_offense = home_receives;
                // The KICKER sets up first (Java sets homePlaying = !homeFirstOffense for setup).
                self.game.home_playing = !home_receives;
                self.awaiting_receive_choice = false;
                self.game.turn_mode = TurnMode::Setup;
                self.setup_phase = 0;
                let receive_team_id = if home_receives {
                    self.game.team_home.id.clone()
                } else {
                    self.game.team_away.id.clone()
                };
                events.push(GameEvent::ReceiveChoice { team_id: receive_team_id, receive: home_receives });
                events.push(GameEvent::StartHalf { half: self.game.half });
                // Emit PettyCash events at first-half start when TVs differ.
                if self.game.half == 1 {
                    let home_tv = self.game.team_home.team_value;
                    let away_tv = self.game.team_away.team_value;
                    if home_tv != away_tv {
                        let diff = (home_tv - away_tv).abs();
                        let lower_team_id = if home_tv < away_tv {
                            self.game.team_home.id.clone()
                        } else {
                            self.game.team_away.id.clone()
                        };
                        events.push(GameEvent::PettyCash { team_id: lower_team_id, amount: diff });
                    }
                }
                // Prayers to Nuffle: roll at start of first half
                if self.game.half == 1 {
                    let prayer_events = self.apply_prayers_to_nuffle_rolls();
                    events.extend(prayer_events);
                }
            }

            Action::ConfirmSetup => {
                self.place_team_canonical(self.game.home_playing);
                self.setup_phase += 1;
                if self.setup_phase >= 2 {
                    // Both teams set up — kicker kicks off
                    self.game.home_playing = !self.game.home_first_offense;
                    self.game.turn_mode = TurnMode::Kickoff;
                } else {
                    // Switch to the other team's setup
                    self.game.home_playing = !self.game.home_playing;
                }
            }

            Action::KickBall { coord } => {
                // Java sequence: KICKOFF_SCATTER_ROLL (D8+D6) runs BEFORE KICKOFF_RESULT_ROLL (2D6).
                let scatter_dir = self.rng.d8();
                let mut scatter_dist = self.rng.d6();

                let kickoff_roll = self.rng.d6_two();

                // Kick skill: any on-pitch player on kicking team halves scatter distance
                let kicking_home = !self.game.home_first_offense;
                let kicking_team = if kicking_home { &self.game.team_home } else { &self.game.team_away };
                let kicker_id = kicking_team.players.iter()
                    .find(|p| p.has_skill(SkillId::Kick)
                        && self.game.field_model.player_state(&p.id).map(|s| s.is_standing()).unwrap_or(false))
                    .map(|p| p.id.clone());
                if kicker_id.is_some() {
                    scatter_dist = (scatter_dist / 2).max(1);
                    if let Some(ref kid) = kicker_id {
                        events.push(GameEvent::SkillUse { player_id: kid.clone(), skill_id: SkillId::Kick as u16, used: true });
                    }
                }

                // Compute final ball landing square.
                // Java's StepKickoffScatterRoll uses lastValidCoordinate: walk the scatter path
                // step-by-step and use the last on-pitch square (not the original kick coord).
                use ffb_mechanics::mechanics::scatter_coordinate;
                use ffb_model::enums::Direction;
                let (final_coord, scatter_end_coord) = if let Some(dir) = Direction::for_roll(scatter_dir) {
                    let mut last_valid = coord;
                    let mut end_coord = coord;
                    for step in 1..=scatter_dist {
                        let (nx, ny) = scatter_coordinate(coord.x, coord.y, dir, step);
                        let nc = FieldCoordinate::new(nx, ny);
                        end_coord = nc;
                        if nc.is_on_pitch() {
                            last_valid = nc;
                        } else {
                            break;
                        }
                    }
                    (last_valid, end_coord)
                } else {
                    (coord, coord)
                };

                // Java touchback logic: uses ballCoordinateEnd (full scatter endpoint, may be off-pitch).
                // Touchback fires if ballCoordinateEnd is NOT in the receiving team's half.
                // Java FieldCoordinateBounds: HALF_HOME = x∈[0,12] ∩ y∈[0,14]; HALF_AWAY = x∈[13,25] ∩ y∈[0,14].
                // Off-pitch (any coord outside [0,25]×[0,14]) is never in either half → touchback.
                let receiving_home = self.game.home_first_offense;
                let y_ok = scatter_end_coord.y >= 0 && scatter_end_coord.y <= 14;
                let in_receiving_half = y_ok && if receiving_home {
                    scatter_end_coord.x >= 0 && scatter_end_coord.x < 13
                } else {
                    scatter_end_coord.x >= 13 && scatter_end_coord.x <= 25
                };
                let scatter_touchback = !in_receiving_half;

                // Place ball BEFORE apply_kickoff_event so WeatherChange NICE scatter can move it.
                self.game.field_model.ball_coordinate = Some(final_coord);
                self.game.field_model.ball_in_play = true;

                // Apply kickoff event (dice order: scatter d8+d6, then kickoff 2d6, then event dice).
                // WeatherChange NICE: rolls 3 extra d8 to scatter ball; may cause new touchback.
                let (kickoff_events, weather_touchback) = self.apply_kickoff_event(kickoff_roll, scatter_touchback);
                events.extend(kickoff_events);

                let touchback = scatter_touchback || weather_touchback;

                events.push(GameEvent::KickoffScatter {
                    start: coord,
                    direction: scatter_dir,
                    distance: scatter_dist,
                });
                self.mark_ball_moving();

                // Java's CSTI (CATCH_KICKOFF → CATCH_SCATTER loop):
                // First attempt uses CATCH_KICKOFF min_roll; after any bounce uses CATCH_SCATTER min_roll (+1).
                // Use current ball_coordinate (may have been moved by WeatherChange NICE scatter).
                if !touchback {
                    // CSTI (StepCatchScatterThrowIn BB2025):
                    // - CATCH_KICKOFF (first attempt at landing square): min_roll = max(2, agility + tz)
                    // - CATCH_SCATTER (after a bounce): min_roll = max(2, agility + tz + 1)
                    //   BB2025 CatchModifierCollection: "Inaccurate Pass or Scatter" adds +1 to min_roll
                    //   for CATCH_SCATTER and CATCH_BOMB modes.
                    // - If player at ball: roll d6. Success → done. Fail → bounceBall (d8).
                    // - If no player: bounceBall (d8) immediately (no catch die).
                    // - bounceBall: if new location has player → CATCH_SCATTER (try catch again).
                    //              if no player → null (done, ball rests).
                    let check_and_catch = |rng: &mut GameRng,
                                          coord: FieldCoordinate,
                                          receiving_home: bool,
                                          is_scatter: bool,
                                          game: &Game| -> Option<bool> {
                        let recv = if receiving_home { &game.team_home } else { &game.team_away };
                        let opp  = if receiving_home { &game.team_away  } else { &game.team_home  };
                        let catcher = recv.players.iter().find(|p| {
                            game.field_model.player_coordinate(&p.id) == Some(coord)
                                && game.field_model.player_state(&p.id).map(|s| s.is_standing()).unwrap_or(false)
                        });
                        if let Some(c) = catcher {
                            let tz: i32 = opp.players.iter().filter(|p| {
                                game.field_model.player_state(&p.id).map(|s| s.has_tacklezones()).unwrap_or(false)
                                    && game.field_model.player_coordinate(&p.id).map(|oc| oc.is_adjacent(coord)).unwrap_or(false)
                            }).count() as i32;
                            // Disturbing Presence: opposing players within 3 squares that are
                            // not prone or stunned (BB2020+: "unless your player is prone/stunned").
                            // Java CatchModifierCollection adds +1 per adjacent DP-skilled player.
                            let dp: i32 = opp.players.iter().filter(|p| {
                                p.has_skill(SkillId::DisturbingPresence)
                                    && game.field_model.player_state(&p.id)
                                        .map(|s| !s.is_prone_or_stunned())
                                        .unwrap_or(false)
                                    && game.field_model.player_coordinate(&p.id)
                                        .map(|oc| {
                                            let dx = (oc.x - coord.x).abs();
                                            let dy = (oc.y - coord.y).abs();
                                            dx <= 3 && dy <= 3
                                        })
                                        .unwrap_or(false)
                            }).count() as i32;
                            // BB2025: CATCH_SCATTER has +1 to min_roll (Inaccurate Pass or Scatter modifier)
                            let scatter_mod: i32 = if is_scatter { 1 } else { 0 };
                            let min_roll = (c.agility + tz + dp + scatter_mod).max(2).min(6);
                            let roll = rng.d6();
                            let caught = roll >= min_roll;
                            // Auto-reroll on failed CATCH: Catch and MonstrousMouth only.
                            // SureHands is for PICKUP (moving to ball), not CATCH (receiving a
                            // kicked ball). Java StepApplyKickoffResult calls DiceRoller.rollSkill()
                            // automatically for Catch/MonstrousMouth here — no dialog is shown.
                            let caught = if !caught && c.has_skill(SkillId::Catch) {
                                rng.d6() >= min_roll
                            } else if !caught && c.has_skill(SkillId::MonstrousMouth) {
                                rng.d6() >= min_roll
                            } else {
                                caught
                            };
                            Some(caught)
                        } else {
                            None // no player
                        }
                    };
                    let mut current = self.game.field_model.ball_coordinate.unwrap_or(final_coord);
                    let mut is_scatter = false;
                    loop {
                        match check_and_catch(&mut self.rng, current, receiving_home, is_scatter, &self.game) {
                            Some(true) => { break; }
                            Some(false) | None => {
                                // failed catch OR no player → bounceBall
                                let bounce_roll = self.rng.d8();
                                if let Some(dir) = Direction::for_roll(bounce_roll) {
                                    let (bx, by) = scatter_coordinate(current.x, current.y, dir, 1);
                                    let new_coord = FieldCoordinate::new(bx, by);
                                    self.game.field_model.ball_coordinate = Some(new_coord);
                                    // Java StepCatchScatterThrowIn: during kickoff, fScatterBounds =
                                    // HALF_AWAY (x∈[13,25]) or HALF_HOME (x∈[0,12]). If bounce lands
                                    // outside the receiving half → touchback (not throw-in).
                                    let in_receiving_half = if receiving_home {
                                        new_coord.x >= 0 && new_coord.x <= 12
                                            && new_coord.y >= 0 && new_coord.y <= 14
                                    } else {
                                        new_coord.x >= 13 && new_coord.x <= 25
                                            && new_coord.y >= 0 && new_coord.y <= 14
                                    };
                                    if !in_receiving_half {
                                        // Ball left receiving half during kickoff CSTI → touchback
                                        self.awaiting_touchback = true;
                                        break;
                                    }
                                    // Check if player at new location (CATCH_SCATTER vs null)
                                    let has_player = {
                                        let recv = if receiving_home { &self.game.team_home } else { &self.game.team_away };
                                        recv.players.iter().any(|p| {
                                            self.game.field_model.player_coordinate(&p.id) == Some(new_coord)
                                                && self.game.field_model.player_state(&p.id).map(|s| s.is_standing()).unwrap_or(false)
                                        })
                                    };
                                    if has_player {
                                        current = new_coord; // loop to try catch at new location
                                        is_scatter = true; // subsequent catches are CATCH_SCATTER
                                    } else {
                                        break; // ball rests here (bounceBall returns null)
                                    }
                                } else {
                                    break;
                                }
                            }
                        }
                    }
                }

                // RiotousRookies: if either team purchased riotous rookies, roll 2D6+1 per count
                // and emit the event (temporary linemen join the team's reserves for this drive).
                for is_home in [true, false] {
                    let (team_id, count) = {
                        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                        (team.id.clone(), team.riotous_rookies)
                    };
                    if count > 0 {
                        let roll = self.rng.d6() + self.rng.d6() + 1; // 2D6+1 per inducement (simplified: roll once)
                        let total = roll * count;
                        events.push(GameEvent::RiotousRookies { team_id, player_count: total });
                    }
                }

                // Swarming (BB2016/BB2020): if either team has Swarming-skilled reserve players,
                // roll D6 to determine how many may be placed on the pitch.
                for is_home in [true, false] {
                    let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                    let has_swarming_reserves = team.players.iter().any(|p| {
                        p.has_skill(SkillId::Swarming)
                            && self.game.field_model.player_state(&p.id)
                                .map(|s| s.base() == PS_RESERVE)
                                .unwrap_or(false)
                    });
                    if has_swarming_reserves {
                        let swarming_roll = self.rng.d6();
                        let team_id = team.id.clone();
                        events.push(GameEvent::SwarmingPlayersRoll { team_id, roll: swarming_roll });
                    }
                }

                // If ball is out of bounds or in wrong half, offer a touchback
                if touchback {
                    self.awaiting_touchback = true;
                }

                // OnTheBall: receiving team players may move up to 3 squares before ball lands
                let receiving_home = self.game.home_first_offense;
                let receiving_team = if receiving_home { &self.game.team_home } else { &self.game.team_away };
                let otb_eligible: Vec<String> = receiving_team.players.iter()
                    .filter(|p| p.has_skill(SkillId::OnTheBall)
                        && self.game.field_model.player_state(&p.id).map(|s| s.is_standing()).unwrap_or(false))
                    .map(|p| p.id.clone())
                    .collect();
                if !otb_eligible.is_empty() && !touchback {
                    events.push(GameEvent::PassBlockEligible {
                        player_ids: otb_eligible.clone(),
                        home_defending: receiving_home,
                    });
                    self.pending_on_the_ball_kickoff = Some(otb_eligible);
                }

                // KickoffReturn (BB2020+): after ball lands, one eligible receiving-team player
                // with KickoffReturn skill may move up to 3 squares (if not on LOS and not
                // adjacent to standing opponents).
                let receiving_home_kr = self.game.home_first_offense;
                let kicking_team_is_home_kr = !receiving_home_kr;
                if self.game.rules != Rules::Bb2016 && !touchback {
                    let opp_team_players: Vec<(String, FieldCoordinate)> = {
                        let opp = if kicking_team_is_home_kr { &self.game.team_home } else { &self.game.team_away };
                        opp.players.iter().filter_map(|p| {
                            let coord = self.game.field_model.player_coordinate(&p.id)?;
                            let state = self.game.field_model.player_state(&p.id)?;
                            if state.is_standing() { Some((p.id.clone(), coord)) } else { None }
                        }).collect()
                    };
                    let receiving_team_kr = if receiving_home_kr { &self.game.team_home } else { &self.game.team_away };
                    let los_x = if receiving_home_kr { 12 } else { 13 };
                    let kr_eligible: Vec<String> = receiving_team_kr.players.iter().filter_map(|p| {
                        if !p.has_skill(SkillId::KickOffReturn) { return None; }
                        let coord = self.game.field_model.player_coordinate(&p.id)?;
                        let state = self.game.field_model.player_state(&p.id)?;
                        if !state.is_standing() { return None; }
                        // Exclude LOS players
                        if coord.x == los_x { return None; }
                        // Exclude players adjacent to standing opponents
                        let has_adj_opp = opp_team_players.iter().any(|(_, oc)| {
                            (coord.x - oc.x).abs() <= 1 && (coord.y - oc.y).abs() <= 1 && coord != *oc
                        });
                        if has_adj_opp { return None; }
                        Some(p.id.clone())
                    }).collect();
                    if !kr_eligible.is_empty() {
                        self.pending_kickoff_return = Some(kr_eligible);
                    }
                }

                if self.blitz_kickoff_pending {
                    // Blitz kickoff: kicking team gets a free turn in TurnMode::Blitz.
                    // pending_on_the_ball_kickoff / pending_kickoff_return (if set) are resolved
                    // first via the prompt system, then this Blitz turn begins.
                    self.game.home_playing = !self.game.home_first_offense; // kicking team
                    self.game.turn_mode = TurnMode::Blitz;
                    self.player_activated_this_turn = false;
                } else {
                    // Normal transition to Regular play for the receiving team.
                    self.game.home_playing = self.game.home_first_offense;
                    // Java only increments the ACTIVE team's turn_nr when their turn starts.
                    // The other team's turn_nr stays at 0 until their first turn begins.
                    // Only set to 1 if still 0 — kickoff events like TimeOut may have already
                    // advanced the counter to a higher value.
                    if self.game.home_first_offense {
                        if self.game.turn_data_home.turn_nr == 0 {
                            self.game.turn_data_home.turn_nr = 1;
                        }
                    } else if self.game.turn_data_away.turn_nr == 0 {
                        self.game.turn_data_away.turn_nr = 1;
                    }
                    self.game.turn_mode = TurnMode::Regular;
                    self.player_activated_this_turn = false;
                }
            }

            Action::ActivatePlayer { player_id, player_action } => {
                let team_is_home = self.game.home_playing;
                let has_player = if team_is_home {
                    self.game.team_home.has_player(&player_id)
                } else {
                    self.game.team_away.has_player(&player_id)
                };
                if !has_player {
                    return Err(RulesError::PlayerNotFound(player_id.clone()));
                }
                // Translate the player action choice to a PlayerAction enum
                let pa = match player_action {
                    crate::action::PlayerActionChoice::Move => PlayerAction::Move,
                    crate::action::PlayerActionChoice::Blitz => PlayerAction::Blitz,
                    crate::action::PlayerActionChoice::Block => PlayerAction::Block,
                    crate::action::PlayerActionChoice::Stab => PlayerAction::Stab,
                    crate::action::PlayerActionChoice::Pass => PlayerAction::Pass,
                    crate::action::PlayerActionChoice::Foul => PlayerAction::Foul,
                    crate::action::PlayerActionChoice::HandOff => PlayerAction::HandOver,
                    crate::action::PlayerActionChoice::StandUp => PlayerAction::StandUp,
                    crate::action::PlayerActionChoice::StandUpBlitz => PlayerAction::StandUpBlitz,
                    crate::action::PlayerActionChoice::BreatheFire => PlayerAction::BreatheFire,
                    crate::action::PlayerActionChoice::ProjectileVomit => PlayerAction::ProjectileVomit,
                    crate::action::PlayerActionChoice::ThrowBomb => PlayerAction::ThrowBomb,
                    crate::action::PlayerActionChoice::SecureTheBall => PlayerAction::SecureTheBall,
                    crate::action::PlayerActionChoice::ThrowTeamMate => PlayerAction::ThrowTeamMate,
                    crate::action::PlayerActionChoice::KickTeamMate => PlayerAction::KickTeamMate,
                    crate::action::PlayerActionChoice::Punt => PlayerAction::Punt,
                    crate::action::PlayerActionChoice::Swoop => PlayerAction::Swoop,
                    crate::action::PlayerActionChoice::HypnoticGaze => PlayerAction::Move,
                };
                let current_state = self.game.field_model.player_state(&player_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                let active_state = current_state.change_active(true);
                self.game.field_model.set_player_state(&player_id, active_state);
                events.push(GameEvent::PlayerAction { player_id: player_id.clone(), action: pa });
                self.game.acting_player.set_player(player_id, pa);
                self.player_activated_this_turn = true;

                // Mark blitz/pass/foul/hand-over as used when activation is declared
                let turn_data = if team_is_home {
                    &mut self.game.turn_data_home
                } else {
                    &mut self.game.turn_data_away
                };
                match pa {
                    PlayerAction::Blitz | PlayerAction::StandUpBlitz | PlayerAction::Block => {
                        turn_data.blitz_used = true;
                    }
                    PlayerAction::Pass | PlayerAction::PassMove | PlayerAction::ThrowBomb => {
                        turn_data.pass_used = true;
                    }
                    PlayerAction::HandOver | PlayerAction::HandOverMove => {
                        turn_data.hand_over_used = true;
                    }
                    PlayerAction::Foul | PlayerAction::FoulMove => {
                        turn_data.foul_used = true;
                    }
                    PlayerAction::SecureTheBall => {
                        turn_data.secure_the_ball_used = true;
                    }
                    PlayerAction::ThrowTeamMate | PlayerAction::ThrowTeamMateMove => {
                        turn_data.ttm_used = true;
                    }
                    PlayerAction::KickTeamMate | PlayerAction::KickTeamMateMove => {
                        turn_data.ktm_used = true;
                    }
                    _ => {}
                }

                // Capture prompt state before activation checks so SecureTheBall can detect new prompts.
                let had_prompt_before_activation = self.cached_prompt.is_some();

                // Negatrait checks: BoneHead / ReallyStupid / WildAnimal
                // Must run after action resources are marked so a failed roll still consumes them.
                if self.game.turn_mode.check_negatraits() {
                    let acting_id = self.game.acting_player.player_id.clone();
                    if let Some(pid) = acting_id {
                        let negatrait_events = self.check_negatrait(&pid, pa);
                        events.extend(negatrait_events);
                    }
                }

                // WisdomOfTheWhiteDwarf (BB2020+): when an adjacent teammate activates, Grombrindal
                // can grant Break Tackle, Dauntless, Mighty Blow, or Sure Feet until end of activation.
                // Clear activation-granted temporary skills, but preserve card-applied skills
                // (which are cleared at turn/drive end instead).
                {
                    let card_pairs: std::collections::HashSet<(String, SkillId)> = self.card_temporary_skills.iter()
                        .map(|(pid, sid, _)| (pid.clone(), *sid))
                        .collect();
                    let active_team = if team_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                    for p in active_team.players.iter_mut() {
                        let pid = p.id.clone();
                        p.temporary_skills.retain(|sw| card_pairs.contains(&(pid.clone(), sw.skill_id)));
                    }
                }
                if self.pending_wisdom_grant.is_none() {
                    let acting_id = self.game.acting_player.player_id.clone();
                    if let Some(ref pid) = acting_id {
                        let grantee_coord = self.game.field_model.player_coordinate(pid);
                        if let Some(gc) = grantee_coord {
                            let same_team = if team_is_home { &self.game.team_home } else { &self.game.team_away };
                            let granter = same_team.players.iter().find(|p| {
                                p.id != *pid
                                    && p.has_skill(SkillId::WisdomOfTheWhiteDwarf)
                                    && !p.used_skills.contains(&SkillId::WisdomOfTheWhiteDwarf)
                                    && self.game.field_model.player_coordinate(&p.id)
                                        .map(|c| c.distance_in_steps(gc) <= 1).unwrap_or(false)
                                    && self.game.field_model.player_state(&p.id)
                                        .map(|s| s.has_tacklezones()).unwrap_or(false)
                            }).map(|p| p.id.clone());
                            if let Some(granter_id) = granter {
                                // Mark WisdomOfTheWhiteDwarf as used and offer skill choice
                                {
                                    let team = if team_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                                    if let Some(p) = team.player_mut(&granter_id) {
                                        p.used_skills.insert(SkillId::WisdomOfTheWhiteDwarf);
                                    }
                                }
                                events.push(GameEvent::SkillUse {
                                    player_id: granter_id.clone(),
                                    skill_id: SkillId::WisdomOfTheWhiteDwarf as u16,
                                    used: true,
                                });
                                use ffb_model::enums::SkillCategory;
                                self.cached_prompt = Some(AgentPrompt::SelectSkill {
                                    player_id: pid.clone(),
                                    available: vec![(SkillCategory::Strength, vec![
                                        SkillId::BreakTackle as u16,
                                        SkillId::Dauntless as u16,
                                        SkillId::MightyBlow as u16,
                                        SkillId::SureFeet as u16,
                                    ])],
                                });
                                self.pending_wisdom_grant = Some(PendingWisdomGrant {
                                    grantee_id: pid.clone(),
                                    is_home: team_is_home,
                                });
                            }
                        }
                    }
                }

                // ExcuseMeAreYouAZoat (BB2025): once per game, at activation, auto-gaze an opponent within 3 squares.
                if self.game.rules == Rules::Bb2025 {
                    let acting_id = self.game.acting_player.player_id.clone();
                    if let Some(ref pid) = acting_id {
                        let (has_skill, used) = if team_is_home {
                            let p = self.game.team_home.player(pid);
                            (p.map(|p| p.has_skill(SkillId::ExcuseMeAreYouAZoat)).unwrap_or(false),
                             p.map(|p| p.used_skills.contains(&SkillId::ExcuseMeAreYouAZoat)).unwrap_or(true))
                        } else {
                            let p = self.game.team_away.player(pid);
                            (p.map(|p| p.has_skill(SkillId::ExcuseMeAreYouAZoat)).unwrap_or(false),
                             p.map(|p| p.used_skills.contains(&SkillId::ExcuseMeAreYouAZoat)).unwrap_or(true))
                        };
                        if has_skill && !used {
                            let my_coord = self.game.field_model.player_coordinate(pid).unwrap_or(FieldCoordinate::new(13, 7));
                            let opp_team = if team_is_home { &self.game.team_away } else { &self.game.team_home };
                            let eligible: Vec<String> = opp_team.players.iter()
                                .filter_map(|p| {
                                    let state = self.game.field_model.player_state(&p.id)?;
                                    if !state.has_tacklezones() { return None; }
                                    let coord = self.game.field_model.player_coordinate(&p.id)?;
                                    if coord.distance_in_steps(my_coord) <= 3 {
                                        Some(p.id.clone())
                                    } else {
                                        None
                                    }
                                })
                                .collect();
                            if !eligible.is_empty() {
                                events.push(GameEvent::SkillUse {
                                    player_id: pid.clone(),
                                    skill_id: SkillId::ExcuseMeAreYouAZoat as u16,
                                    used: true,
                                });
                                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                                    eligible_players: eligible,
                                    reason: "autoGazeZoat".into(),
                                });
                                self.pending_auto_gaze = Some(PendingAutoGaze {
                                    player_id: pid.clone(),
                                    is_home: team_is_home,
                                });
                            }
                        }
                    }
                }

                // BalefulHex (BB2020+): once per game, at activation, pick an opponent within 5 squares,
                // roll D6: 2+ = target becomes confused and inactive for the turn.
                if self.game.rules != Rules::Bb2016 && self.pending_baleful_hex.is_none() && self.pending_auto_gaze.is_none() {
                    let acting_id = self.game.acting_player.player_id.clone();
                    if let Some(ref pid) = acting_id {
                        let (has_skill, used) = if team_is_home {
                            let p = self.game.team_home.player(pid);
                            (p.map(|p| p.has_skill(SkillId::BalefulHex)).unwrap_or(false),
                             p.map(|p| p.used_skills.contains(&SkillId::BalefulHex)).unwrap_or(true))
                        } else {
                            let p = self.game.team_away.player(pid);
                            (p.map(|p| p.has_skill(SkillId::BalefulHex)).unwrap_or(false),
                             p.map(|p| p.used_skills.contains(&SkillId::BalefulHex)).unwrap_or(true))
                        };
                        if has_skill && !used {
                            let my_coord = self.game.field_model.player_coordinate(pid).unwrap_or(FieldCoordinate::new(13, 7));
                            let opp_team = if team_is_home { &self.game.team_away } else { &self.game.team_home };
                            let eligible: Vec<String> = opp_team.players.iter()
                                .filter_map(|p| {
                                    let state = self.game.field_model.player_state(&p.id)?;
                                    if !state.has_tacklezones() { return None; }
                                    let coord = self.game.field_model.player_coordinate(&p.id)?;
                                    if coord.distance_in_steps(my_coord) <= 5 {
                                        Some(p.id.clone())
                                    } else {
                                        None
                                    }
                                })
                                .collect();
                            if !eligible.is_empty() {
                                events.push(GameEvent::SkillUse {
                                    player_id: pid.clone(),
                                    skill_id: SkillId::BalefulHex as u16,
                                    used: true,
                                });
                                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                                    eligible_players: eligible,
                                    reason: "balefulHex".into(),
                                });
                                self.pending_baleful_hex = Some(PendingBalefulHex {
                                    player_id: pid.clone(),
                                    is_home: team_is_home,
                                });
                            }
                        }
                    }
                }

                // ThenIStartedBlastin (BB2020) / BlastinSolvesEverything (BB2025):
                // once per turn, at activation, choose any opponent on the field, roll D6:
                // 3+ = target takes armor+injury; 1 = acting player takes armor+injury (backfire).
                if self.pending_blastin.is_none() && self.pending_baleful_hex.is_none() && self.pending_auto_gaze.is_none() {
                    let acting_id = self.game.acting_player.player_id.clone();
                    if let Some(ref pid) = acting_id {
                        let blastin_skill = match self.game.rules {
                            Rules::Bb2016 => None,
                            Rules::Bb2020 => {
                                let p = self.game.team_home.player(pid).or_else(|| self.game.team_away.player(pid));
                                if p.map(|p| p.has_skill(SkillId::ThenIStartedBlastin) && !p.used_skills.contains(&SkillId::ThenIStartedBlastin)).unwrap_or(false) {
                                    Some(SkillId::ThenIStartedBlastin)
                                } else { None }
                            }
                            _ => {
                                let p = self.game.team_home.player(pid).or_else(|| self.game.team_away.player(pid));
                                if p.map(|p| p.has_skill(SkillId::BlastinSolvesEverything) && !p.used_skills.contains(&SkillId::BlastinSolvesEverything)).unwrap_or(false) {
                                    Some(SkillId::BlastinSolvesEverything)
                                } else { None }
                            }
                        };
                        if let Some(skill) = blastin_skill {
                            let opp_team = if team_is_home { &self.game.team_away } else { &self.game.team_home };
                            let eligible: Vec<String> = opp_team.players.iter()
                                .filter_map(|p| {
                                    // Must be on pitch (has a coordinate) and not dead/casualty
                                    self.game.field_model.player_coordinate(&p.id)?;
                                    let state = self.game.field_model.player_state(&p.id)?;
                                    if state.is_casualty() || state.is_killed() { return None; }
                                    Some(p.id.clone())
                                })
                                .collect();
                            if !eligible.is_empty() {
                                events.push(GameEvent::ThenIStartedBlastin { player_id: pid.clone() });
                                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                                    eligible_players: eligible,
                                    reason: "blastin".into(),
                                });
                                self.pending_blastin = Some(PendingBlastin {
                                    player_id: pid.clone(),
                                    is_home: team_is_home,
                                    skill_id: skill,
                                });
                            }
                        }
                    }
                }

                // SecureTheBall (BB2025): immediately attempt 2+ pickup — no separate Move needed.
                // Only skip if a NEW prompt was set during this activation (e.g. negatrait, WisdomGrant).
                let activation_set_new_prompt = !had_prompt_before_activation && self.cached_prompt.is_some();
                if pa == PlayerAction::SecureTheBall && !activation_set_new_prompt {
                    if let Some(ref pid) = self.game.acting_player.player_id.clone() {
                        if let Some(player_coord) = self.game.field_model.player_coordinate(pid) {
                            if self.game.field_model.ball_coordinate == Some(player_coord)
                                && self.game.field_model.ball_in_play
                            {
                                let rain_mod = if self.game.weather == Weather::PouringRain { 1 } else { 0 };
                                let dp_mod = self.count_disturbing_presence(player_coord, team_is_home);
                                let pickup_min = (2 + rain_mod + dp_mod).max(2);
                                let roll = self.rng.d6();
                                let success = is_skill_roll_successful(roll, pickup_min);
                                if success {
                                    events.push(GameEvent::BallPickedUp { player_id: pid.clone(), coord: player_coord });
                                    self.mark_ball_not_moving();
                                } else {
                                    let scatter_dir = self.rng.d8();
                                    events.push(GameEvent::BallScattered { player_id: pid.clone(), coord: player_coord, direction: scatter_dir });
                                    self.mark_ball_moving();
                                }
                            }
                        }
                    }
                }
            }

            Action::EndTurn => {
                // Blitz kickoff mini-turn: kicking team ends their free turn.
                if self.game.turn_mode == TurnMode::Blitz {
                    let kicking_team_id = if self.game.home_playing {
                        self.game.team_home.id.clone()
                    } else {
                        self.game.team_away.id.clone()
                    };
                    self.game.acting_player.clear();
                    self.reset_player_states_end_of_turn(self.game.home_playing);
                    {
                        let td = if self.game.home_playing {
                            &mut self.game.turn_data_home
                        } else {
                            &mut self.game.turn_data_away
                        };
                        td.reset_for_turn();
                    }
                    events.push(GameEvent::TurnEnd { team_id: kicking_team_id, turn_nr: 0 });
                    self.blitz_kickoff_pending = false;
                    // Transition to receiving team's regular play.
                    self.game.home_playing = self.game.home_first_offense;
                    // Java only increments the ACTIVE team's turn_nr when their turn starts.
                    // Only set to 1 if still 0 — TimeOut may have already advanced the counter.
                    if self.game.home_first_offense {
                        if self.game.turn_data_home.turn_nr == 0 {
                            self.game.turn_data_home.turn_nr = 1;
                        }
                    } else if self.game.turn_data_away.turn_nr == 0 {
                        self.game.turn_data_away.turn_nr = 1;
                    }
                    self.game.turn_mode = TurnMode::Regular;
                    self.player_activated_this_turn = false;
                    // Clear card-applied temporary skills at end of this mini-turn.
                    let deactivation_events = self.clear_card_temporary_skills();
                    events.extend(deactivation_events);
                    // Skip normal EndTurn processing.
                } else {

                let ending_team_id = if self.game.home_playing {
                    self.game.team_home.id.clone()
                } else {
                    self.game.team_away.id.clone()
                };

                // Clear acting player
                self.game.acting_player.clear();

                // Reset PS_MOVING back to PS_STANDING for all active-team players
                // and wake up stunned players (PS_STUNNED → PS_PRONE)
                self.reset_player_states_end_of_turn(self.game.home_playing);

                // Reset per-turn flags for the active team and capture completed turn_nr.
                // Java semantics: turn_nr is incremented at the START of each team's turn
                // (set at kickoff for T1, then incremented by the OTHER team's EndTurn for T2+).
                // So at EndTurn we reset the active team's flags but do NOT touch their turn_nr.
                let turn_nr = if self.game.home_playing {
                    let td = &mut self.game.turn_data_home;
                    let nr = td.turn_nr;
                    td.reset_for_turn();
                    nr
                } else {
                    let td = &mut self.game.turn_data_away;
                    let nr = td.turn_nr;
                    td.reset_for_turn();
                    nr
                };

                events.push(GameEvent::TurnEnd { team_id: ending_team_id, turn_nr });

                // Clear card-applied temporary skills at end of this turn.
                let deactivation_events = self.clear_card_temporary_skills();
                events.extend(deactivation_events);

                // Increment the NEXT team's turn_nr to prepare for their upcoming turn.
                // Java semantics: turn_nr is incremented at the START of each INIT_SELECTING;
                // we simulate this by incrementing the next team's turn_nr at EndTurn.
                // CRITICAL: do NOT persist the increment if it would end the half — the
                // game_end state must still show both teams at turn_nr=8, matching Java's
                // state where T9 INIT_SELECTING is never entered and turn_nr is never >8.
                let half_done = if self.game.home_playing {
                    let next = self.game.turn_data_away.turn_nr + 1;
                    let done = next > 8;
                    if !done { self.game.turn_data_away.turn_nr = next; }
                    done
                } else {
                    let next = self.game.turn_data_home.turn_nr + 1;
                    let done = next > 8;
                    if !done { self.game.turn_data_home.turn_nr = next; }
                    done
                };

                if half_done {
                    if self.game.half == 1 {
                        // Half time: swap offense/defense, reset turn data
                        self.game.half = 2;
                        self.game.home_first_offense = !self.game.home_first_offense;
                        self.game.turn_data_home = TurnData::new();
                        self.game.turn_data_away = TurnData::new();
                        // Restore per-half rerolls from team purchase count.
                        self.game.turn_data_home.rerolls = self.game.team_home.rerolls;
                        self.game.turn_data_away.rerolls = self.game.team_away.rerolls;
                        // MasterChef: each chef rolls 3D6; each 4+ steals one opponent reroll
                        let chef_events = self.apply_master_chef_rolls();
                        events.extend(chef_events);
                        // Prayers to Nuffle: each team with prayers rolls D16
                        let prayer_events = self.apply_prayers_to_nuffle_rolls();
                        events.extend(prayer_events);
                        // Sweltering Heat: exhaust random players, matching Java StepEndTurn.getFaintingCount().
                        // Dice consumed: d3 (fainting count) + d(on_pitch_size) × fainting_count per team.
                        if self.game.weather == Weather::SwelteringHeat {
                            let fainting_count = self.rng.d3() as usize;
                            for is_home in [true, false] {
                                let player_ids: Vec<String> = {
                                    let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                                    team.players.iter().map(|p| p.id.clone()).collect()
                                };
                                let mut on_pitch: Vec<String> = player_ids.into_iter()
                                    .filter(|id| {
                                        self.game.field_model.player_coordinate(id)
                                            .map(|c| c.is_on_pitch())
                                            .unwrap_or(false)
                                    })
                                    .collect();
                                for _ in 0..fainting_count {
                                    if on_pitch.is_empty() { break; }
                                    let idx = self.rng.range(on_pitch.len());
                                    let pid = on_pitch.remove(idx);
                                    let state = self.game.field_model.player_state(&pid)
                                        .unwrap_or(PlayerState::new(PS_STANDING));
                                    self.game.field_model.set_player_state(&pid, state.change_base(PS_EXHAUSTED));
                                    self.game.field_model.player_coordinates.remove(pid.as_str());
                                    events.push(GameEvent::HeatExhaustion { player_id: pid });
                                }
                            }
                        }
                        // Java only rolls spectators and weather at game start (H1), not at halftime.
                        // Matching Java: do NOT re-roll fans or weather at H2 transition.
                        // Re-run setup for second half kickoff
                        events.push(GameEvent::StartHalf { half: 2 });
                        self.game.home_playing = self.game.home_first_offense;
                        self.game.turn_mode = TurnMode::Setup;
                        self.setup_phase = 0;
                        // Eject BEFORE place_all_in_reserve so ejected players end up
                        // PS_BADLY_HURT (not overwritten to PS_RESERVE by place_all).
                        let sw_events = self.eject_secret_weapon_players();
                        events.extend(sw_events);
                        self.place_all_in_reserve();
                    } else {
                        // Game over — eject before reserve so state is consistent.
                        let sw_events = self.eject_secret_weapon_players();
                        events.extend(sw_events);
                        self.place_all_in_reserve();
                        self.game.turn_mode = TurnMode::EndGame;
                        self.game.status = ffb_model::enums::GameStatus::Finished;
                        // Emit WinningsRoll for each team: base = fan_factor * 10k, roll = D6
                        for is_home in [true, false] {
                            let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                            let base = team.fan_factor * 10_000;
                            let roll = self.rng.d6();
                            let total = base + roll * 10_000;
                            let team_id = team.id.clone();
                            events.push(GameEvent::WinningsRoll { team_id, base, roll, total });
                        }
                        // MVP awarding: randomly select one eligible player per team and award MVP SPPs.
                        // Eligible: not dead (PS_RIP) and not permanently removed.
                        use ffb_mechanics::mechanics::spp_table;
                        for is_home in [true, false] {
                            let mvp_spp = spp_table(self.game.rules).mvp;
                            let eligible: Vec<String> = {
                                let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                                team.players.iter().filter_map(|p| {
                                    let state = self.game.field_model.player_state(&p.id)
                                        .unwrap_or(PlayerState::new(PS_RESERVE));
                                    if state.base() == PS_RIP { None } else { Some(p.id.clone()) }
                                }).collect()
                            };
                            if !eligible.is_empty() {
                                let idx = self.rng.range(eligible.len());
                                let mvp_id = eligible[idx].clone();
                                let team_id = (if is_home { &self.game.team_home } else { &self.game.team_away }).id.clone();
                                self.award_spp(&mvp_id, is_home, mvp_spp);
                                events.push(GameEvent::MvpRoll { team_id, player_id: mvp_id, spp: mvp_spp });
                            }
                        }
                    }
                } else {
                    // Switch to other team's turn
                    self.game.home_playing = !self.game.home_playing;
                    self.game.turn_mode = TurnMode::Regular;
                    self.player_activated_this_turn = false;
                    // Refresh Leader and LordOfChaos reroll for the new active team.
                    let new_home = self.game.home_playing;
                    if let Some(leader_evt) = self.refresh_leader_state(new_home) {
                        events.push(leader_evt);
                    }
                    if let Some(loc_evt) = self.refresh_lord_of_chaos_state(new_home) {
                        events.push(loc_evt);
                    }
                }
                } // end else (non-Blitz EndTurn)
            }

            Action::UseReRoll { use_reroll } => {
                if let Some(pending) = self.pending_reroll.take() {
                    let reroll_events = self.resolve_pending_reroll(pending, use_reroll)?;
                    events.extend(reroll_events);
                }
            }

            Action::Block { defender_id } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let block_events = self.apply_block(&pid, &defender_id)?;
                    events.extend(block_events);
                }
            }

            Action::Stab { defender_id } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let stab_events = self.apply_stab(&pid, &defender_id)?;
                    events.extend(stab_events);
                }
            }

            Action::MultiBlock { defender1_id, defender2_id } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let mb_events = self.apply_multi_block(&pid, &defender1_id, &defender2_id)?;
                    events.extend(mb_events);
                }
            }

            Action::BlockChoice { die_index } => {
                if let Some(choice) = self.pending_block_choice.take() {
                    let choice_events = self.resolve_block_choice(choice, die_index)?;
                    events.extend(choice_events);
                }
            }

            Action::PushTo { coord } => {
                if let Some(push) = self.pending_push.take() {
                    let push_events = self.resolve_push(push, coord)?;
                    events.extend(push_events);
                }
            }

            Action::FollowUp { follow_up } => {
                if let Some(fu) = self.pending_follow_up.take() {
                    let attacker_id = fu.attacker_id.clone();
                    let defender_id = fu.defender_id.clone();
                    let knocked_down = fu.knocked_down;
                    let home_attacking = self.game.team_home.has_player(&attacker_id);
                    if follow_up {
                        self.game.field_model.set_player_coordinate(&attacker_id, fu.attacker_to);
                        events.push(GameEvent::PlayerMoved {
                            player_id: attacker_id.clone(),
                            coord: fu.attacker_to,
                        });
                    }
                    // After follow-up resolves, check HitAndRun
                    if let Some(har) = self.build_hit_and_run(&attacker_id, home_attacking) {
                        self.cached_prompt = Some(AgentPrompt::HitAndRun {
                            player_id: attacker_id.clone(),
                            squares: har.valid_squares.clone(),
                        });
                        self.pending_hit_and_run = Some(har);
                        // Store PutridRegurgitation to offer after HitAndRun resolves
                        if knocked_down {
                            if let Some(pr) = self.build_putrid_regurgitation(&attacker_id, &defender_id, home_attacking) {
                                self.pending_putrid_regurgitation = Some(pr);
                            }
                        }
                    } else if knocked_down {
                        // No HitAndRun — offer PutridRegurgitation directly if applicable
                        if let Some(pr) = self.build_putrid_regurgitation(&attacker_id, &defender_id, home_attacking) {
                            self.cached_prompt = Some(AgentPrompt::SkillUse {
                                player_id: attacker_id.clone(),
                                skill_id: SkillId::PutridRegurgitation as u16,
                                skill_name: "Putrid Regurgitation".into(),
                            });
                            self.pending_putrid_regurgitation = Some(pr);
                        }
                    }
                }
            }

            Action::HitAndRun { coord } => {
                if let Some(har) = self.pending_hit_and_run.take() {
                    if let Some(c) = coord {
                        if har.valid_squares.contains(&c) {
                            self.game.field_model.set_player_coordinate(&har.attacker_id, c);
                            events.push(GameEvent::SkillUse {
                                player_id: har.attacker_id.clone(),
                                skill_id: SkillId::HitAndRun as u16,
                                used: true,
                            });
                            events.push(GameEvent::PlayerMoved {
                                player_id: har.attacker_id,
                                coord: c,
                            });
                        }
                    }
                    // After HitAndRun resolves, offer PutridRegurgitation if pending
                    if let Some(pr) = self.pending_putrid_regurgitation.take() {
                        self.cached_prompt = Some(AgentPrompt::SkillUse {
                            player_id: pr.attacker_id.clone(),
                            skill_id: SkillId::PutridRegurgitation as u16,
                            skill_name: "Putrid Regurgitation".into(),
                        });
                        self.pending_putrid_regurgitation = Some(pr);
                    }
                }
            }

            Action::TricksterMove { coord } => {
                if let Some(trick) = self.pending_trickster.take() {
                    if trick.eligible_squares.contains(&coord) {
                        let old_coord = self.game.field_model.player_coordinate(&trick.defender_id);
                        self.game.field_model.set_player_coordinate(&trick.defender_id, coord);
                        events.push(GameEvent::PlayerMoved {
                            player_id: trick.defender_id.clone(),
                            coord,
                        });
                        // Ball follows defender if they were carrying it
                        if let Some(oc) = old_coord {
                            if self.game.field_model.ball_coordinate == Some(oc)
                                && self.game.field_model.ball_in_play
                            {
                                self.game.field_model.ball_coordinate = Some(coord);
                            }
                        }
                    }
                    // Resume block from new defender position
                    let att_id = trick.attacker_id.clone();
                    let def_id = trick.defender_id.clone();
                    self.game.home_playing = trick.home_attacking;
                    let block_events = self.apply_block(&att_id, &def_id)?;
                    events.extend(block_events);
                }
            }

            Action::Foul { target_id } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let foul_events = self.apply_foul(&pid, &target_id)?;
                    events.extend(foul_events);
                    // Mark foul as used for this turn
                    if self.game.home_playing {
                        self.game.turn_data_home.foul_used = true;
                    } else {
                        self.game.turn_data_away.foul_used = true;
                    }
                }
            }

            Action::Move { path } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let move_events = self.apply_move(&pid, &path)?;
                    events.extend(move_events);
                }
            }

            Action::Pass { coord } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let pass_events = self.apply_pass(&pid, coord)?;
                    events.extend(pass_events);
                }
            }

            Action::HandOff { receiver_id } => {
                if let Some(pid) = self.game.acting_player.player_id.clone() {
                    let ho_events = self.apply_hand_off(&pid, &receiver_id)?;
                    events.extend(ho_events);
                }
            }

            Action::Acknowledge => {}

            // ── Group 2: PlacePlayer during setup ─────────────────────────────
            Action::PlacePlayer { player_id, coord } => {
                if self.game.turn_mode == TurnMode::Setup {
                    let home_setting_up = self.game.home_playing;
                    let owns_player = if home_setting_up {
                        self.game.team_home.has_player(&player_id)
                    } else {
                        self.game.team_away.has_player(&player_id)
                    };
                    if owns_player {
                        // Away team coordinates are transformed (x mirrored at 25)
                        let actual_coord = if home_setting_up {
                            coord
                        } else {
                            FieldCoordinate::new(25 - coord.x, coord.y)
                        };
                        if actual_coord.is_on_pitch() {
                            self.game.field_model.set_player_coordinate(&player_id, actual_coord);
                            self.game.field_model.set_player_state(&player_id, PlayerState::new(PS_STANDING));
                            events.push(GameEvent::PlayerMoved { player_id, coord: actual_coord });
                        } else {
                            // Off-pitch coord = move to reserves
                            self.game.field_model.set_player_state(&player_id, PlayerState::new(PS_RESERVE));
                            self.game.field_model.player_coordinates.remove(&player_id);
                        }
                    }
                }
            }

            // ── Group 3a: Touchback ───────────────────────────────────────────
            Action::Touchback { player_id } => {
                if self.awaiting_touchback {
                    self.awaiting_touchback = false;
                    let coord = self.game.field_model.player_coordinate(&player_id)
                        .unwrap_or(FieldCoordinate::new(13, 7));
                    self.game.field_model.ball_coordinate = Some(coord);
                    events.push(GameEvent::BallPickedUp { player_id, coord });
                    self.mark_ball_not_moving();
                }
            }

            // ── Group 4a: Apothecary ──────────────────────────────────────────
            Action::UseApothecary { player_id, use_apothecary } => {
                if let Some(apo) = self.pending_apothecary.take() {
                    let apo_events = self.resolve_apothecary(apo, use_apothecary, &player_id)?;
                    events.extend(apo_events);
                }
            }

            // ── Group 5: Bribe ────────────────────────────────────────────────
            Action::UseBribe { use_bribe } => {
                if let Some(bribe) = self.pending_bribe.take() {
                    let bribe_events = self.resolve_bribe(bribe, use_bribe)?;
                    events.extend(bribe_events);
                }
            }

            Action::ArgueTheCall { argue } => {
                if let Some(atc) = self.pending_argue_the_call.take() {
                    let atc_events = self.resolve_argue_the_call(atc, argue)?;
                    events.extend(atc_events);
                }
            }

            // ── Group 10a: HypnoticGaze ───────────────────────────────────────
            Action::HypnoticGaze { target_id } => {
                let rules = self.game.rules;
                let home = self.game.home_playing;
                let gazer_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let gazer_ag = if home {
                    self.game.team_home.player(&gazer_id).map(|p| p.agility).unwrap_or(3)
                } else {
                    self.game.team_away.player(&gazer_id).map(|p| p.agility).unwrap_or(3)
                };
                // BlackInk: once per game, auto-succeed HypnoticGaze without rolling
                let black_ink_avail = {
                    let team = if home { &self.game.team_home } else { &self.game.team_away };
                    team.player(&gazer_id).map(|p| {
                        p.has_skill(SkillId::BlackInk) && !p.used_skills.contains(&SkillId::BlackInk)
                    }).unwrap_or(false)
                };
                if black_ink_avail {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&gazer_id) { p.used_skills.insert(SkillId::BlackInk); }
                    events.push(GameEvent::SkillUse { player_id: gazer_id.clone(), skill_id: SkillId::BlackInk as u16, used: true });
                    if let Some(state) = self.game.field_model.player_state(&target_id) {
                        self.game.field_model.set_player_state(&target_id, state.change_confused(true));
                    }
                    self.game.acting_player.has_acted = true;
                    return Ok(events);
                }
                let min_roll = match rules {
                    Rules::Bb2016 => (7 - gazer_ag.min(6)).max(2),
                    _ => gazer_ag.max(2),
                };
                let roll = self.rng.d6();
                let mut success = roll >= min_roll;
                events.push(GameEvent::HypnoticGazeRoll {
                    player_id: gazer_id.clone(),
                    target_id: target_id.clone(),
                    roll,
                    success,
                });
                // MesmerisingDance / MesmerizingDance: once per game, auto-reroll failed Gaze
                // Both spellings exist (BB2025 uses -ising, BB2020 uses -izing).
                if !success {
                    let dance_skill = if home {
                        let p = self.game.team_home.player(&gazer_id);
                        if p.map(|p| p.has_skill(SkillId::MesmerisingDance)).unwrap_or(false) {
                            Some(SkillId::MesmerisingDance)
                        } else if p.map(|p| p.has_skill(SkillId::MesmerizingDance)).unwrap_or(false) {
                            Some(SkillId::MesmerizingDance)
                        } else { None }
                    } else {
                        let p = self.game.team_away.player(&gazer_id);
                        if p.map(|p| p.has_skill(SkillId::MesmerisingDance)).unwrap_or(false) {
                            Some(SkillId::MesmerisingDance)
                        } else if p.map(|p| p.has_skill(SkillId::MesmerizingDance)).unwrap_or(false) {
                            Some(SkillId::MesmerizingDance)
                        } else { None }
                    };
                    let used_dance = if let Some(sk) = dance_skill {
                        let p = if home { self.game.team_home.player(&gazer_id) }
                                else { self.game.team_away.player(&gazer_id) };
                        p.map(|p| p.used_skills.contains(&sk)).unwrap_or(false)
                    } else { false };
                    if let Some(sk) = dance_skill {
                        if !used_dance {
                            let reroll = self.rng.d6();
                            success = reroll >= min_roll;
                            events.push(GameEvent::SkillUse {
                                player_id: gazer_id.clone(),
                                skill_id: sk as u16,
                                used: true,
                            });
                            events.push(GameEvent::HypnoticGazeRoll {
                                player_id: gazer_id.clone(),
                                target_id: target_id.clone(),
                                roll: reroll,
                                success,
                            });
                            let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&gazer_id) {
                                p.used_skills.insert(sk);
                            }
                        }
                    }
                }
                if success {
                    if let Some(state) = self.game.field_model.player_state(&target_id) {
                        self.game.field_model.set_player_state(&target_id, state.change_confused(true));
                    }
                    // LookIntoMyEyes (BB2020+): if gazer has the skill and the target holds the ball, roll 2+ to steal it.
                    if rules != Rules::Bb2016 {
                        let has_eyes = if home {
                            self.game.team_home.player(&gazer_id).map(|p| p.has_skill(SkillId::LookIntoMyEyes)).unwrap_or(false)
                        } else {
                            self.game.team_away.player(&gazer_id).map(|p| p.has_skill(SkillId::LookIntoMyEyes)).unwrap_or(false)
                        };
                        let used_eyes = if home {
                            self.game.team_home.player(&gazer_id).map(|p| p.used_skills.contains(&SkillId::LookIntoMyEyes)).unwrap_or(false)
                        } else {
                            self.game.team_away.player(&gazer_id).map(|p| p.used_skills.contains(&SkillId::LookIntoMyEyes)).unwrap_or(false)
                        };
                        let target_has_ball = self.game.field_model.ball_coordinate
                            .and_then(|bc| self.game.field_model.player_coordinate(&target_id))
                            .map(|tc| self.game.field_model.ball_coordinate == Some(tc))
                            .unwrap_or(false);
                        if has_eyes && !used_eyes && target_has_ball {
                            let eye_roll = self.rng.d6();
                            let eye_success = eye_roll >= 2;
                            events.push(GameEvent::SkillUse {
                                player_id: gazer_id.clone(),
                                skill_id: SkillId::LookIntoMyEyes as u16,
                                used: true,
                            });
                            events.push(GameEvent::LookIntoMyEyesRoll {
                                player_id: gazer_id.clone(),
                                roll: eye_roll,
                                success: eye_success,
                                rerolled: false,
                            });
                            if eye_success {
                                if let Some(gazer_coord) = self.game.field_model.player_coordinate(&gazer_id) {
                                    self.game.field_model.ball_coordinate = Some(gazer_coord);
                                    events.push(GameEvent::BallPickedUp { player_id: gazer_id.clone(), coord: gazer_coord });
                                    self.mark_ball_not_moving();
                                }
                            }
                            let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&gazer_id) {
                                p.used_skills.insert(SkillId::LookIntoMyEyes);
                            }
                        }
                    }
                }
                self.game.acting_player.has_acted = true;
            }

            // ── Group 10b: ThrowBomb (Bombardier) ────────────────────────────
            Action::ThrowBomb { coord } => {
                let rules = self.game.rules;
                let home = self.game.home_playing;
                let bomber_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let bomber_ag = if home {
                    self.game.team_home.player(&bomber_id).map(|p| p.agility).unwrap_or(3)
                } else {
                    self.game.team_away.player(&bomber_id).map(|p| p.agility).unwrap_or(3)
                };
                let bomber_coord = self.game.field_model.player_coordinate(&bomber_id)
                    .unwrap_or(FieldCoordinate::new(12, 7));
                // Kaboom: once per game, force the bomb to explode at the thrower's position
                let kaboom_avail = {
                    let team = if home { &self.game.team_home } else { &self.game.team_away };
                    team.player(&bomber_id).map(|p| {
                        p.has_skill(SkillId::Kaboom) && !p.used_skills.contains(&SkillId::Kaboom)
                    }).unwrap_or(false)
                };
                let dist = ffb_model::util::passing::passing_distance(bomber_coord, coord)
                    .unwrap_or(ffb_model::enums::PassingDistance::LongBomb);
                use ffb_mechanics::mechanics::evaluate_pass;
                let roll = self.rng.d6();
                let pass_result = evaluate_pass(rules, bomber_ag, roll, dist, &[], false);
                use ffb_mechanics::mechanics::{is_armour_broken};
                // If fumble, bomb explodes at thrower's square; Kaboom also forces explosion at thrower's square
                let land_coord = if kaboom_avail {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&bomber_id) { p.used_skills.insert(SkillId::Kaboom); }
                    events.push(GameEvent::SkillUse { player_id: bomber_id.clone(), skill_id: SkillId::Kaboom as u16, used: true });
                    bomber_coord
                } else if matches!(pass_result, ffb_mechanics::mechanics::PassResult::Fumble | ffb_mechanics::mechanics::PassResult::SavedFumble) {
                    bomber_coord
                } else {
                    coord
                };
                events.push(GameEvent::PassRoll {
                    player_id: bomber_id.clone(),
                    target: bomber_ag.max(2),
                    distance: dist,
                    roll,
                    result: ffb_model::enums::PassResult::Complete,
                    rerolled: false,
                });
                // Scatter bomb one square from landing in a random direction
                let scatter_dir = self.rng.d8();
                use ffb_mechanics::mechanics::scatter_coordinate;
                use ffb_model::enums::Direction;
                let (blast_coord, bomb_out_of_bounds) = if let Some(d) = Direction::for_roll(scatter_dir) {
                    let (nx, ny) = scatter_coordinate(land_coord.x, land_coord.y, d, 1);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { (nc, false) } else { (land_coord, true) }
                } else { (land_coord, false) };
                if bomb_out_of_bounds {
                    events.push(GameEvent::BombOutOfBounds { coord: blast_coord });
                }
                // Hit all players adjacent to blast square (including the square itself) with armor roll
                // If a standing player is exactly at blast_coord, emit BombExplodesAfterCatch
                let bomb_catcher: Option<String> = {
                    let all: Vec<_> = self.game.team_home.players.iter().chain(self.game.team_away.players.iter()).collect();
                    all.into_iter().find(|p| {
                        self.game.field_model.player_coordinate(&p.id) == Some(blast_coord)
                            && self.game.field_model.player_state(&p.id).map(|s| s.is_standing()).unwrap_or(false)
                    }).map(|p| p.id.clone())
                };
                if let Some(ref catcher_id) = bomb_catcher {
                    events.push(GameEvent::BombExplodesAfterCatch {
                        player_id: catcher_id.clone(),
                        coord: blast_coord,
                    });
                }
                let all_player_ids: Vec<(String, bool)> = self.game.team_home.players.iter()
                    .map(|p| (p.id.clone(), true))
                    .chain(self.game.team_away.players.iter().map(|p| (p.id.clone(), false)))
                    .collect();
                for (pid, is_home_player) in all_player_ids {
                    if let Some(pcoord) = self.game.field_model.player_coordinate(&pid) {
                        if pcoord == blast_coord || pcoord.is_adjacent(blast_coord) {
                            let av = if is_home_player {
                                self.game.team_home.player(&pid).map(|p| p.armour).unwrap_or(8)
                            } else {
                                self.game.team_away.player(&pid).map(|p| p.armour).unwrap_or(8)
                            };
                            let ar1 = self.rng.d6();
                            let ar2 = self.rng.d6();
                            if is_armour_broken(av, ar1 + ar2, rules) {
                                let inj1 = self.rng.d6();
                                let inj2 = self.rng.d6();
                                let total = inj1 + inj2;
                                let was_cas = total >= 10;
                                let was_ko = total >= 8 && !was_cas;
                                let new_state = if was_cas || was_ko {
                                    PlayerState::new(PS_KNOCKED_OUT)
                                } else {
                                    PlayerState::new(PS_PRONE)
                                };
                                self.game.field_model.set_player_state(&pid, new_state);
                                events.push(GameEvent::Injury {
                                    player_id: pid.clone(),
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: Some([inj1, inj2]),
                                    serious_injury: None,
                                    was_ko,
                                    was_cas,
                                });
                            } else {
                                events.push(GameEvent::Injury {
                                    player_id: pid.clone(),
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: None,
                                    serious_injury: None,
                                    was_ko: false,
                                    was_cas: false,
                                });
                            }
                        }
                    }
                }
                // AllYouCanEat: once per game, allow a second ThrowBomb in the same activation
                let all_you_can_eat = {
                    let team = if home { &self.game.team_home } else { &self.game.team_away };
                    team.player(&bomber_id).map(|p| {
                        p.has_skill(SkillId::AllYouCanEat) && !p.used_skills.contains(&SkillId::AllYouCanEat)
                    }).unwrap_or(false)
                };
                if all_you_can_eat {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&bomber_id) { p.used_skills.insert(SkillId::AllYouCanEat); }
                    events.push(GameEvent::SkillUse { player_id: bomber_id.clone(), skill_id: SkillId::AllYouCanEat as u16, used: true });
                    // Don't mark has_acted — allow another ThrowBomb this activation
                } else {
                    self.game.acting_player.has_acted = true;
                }
            }

            // ── Group 10c: ThrowTeamMate / KickTeamMate ───────────────────────
            Action::ThrowTeamMate { player_id: thrown_id, coord } => {
                let home = self.game.home_playing;
                let rules = self.game.rules;
                let thrower_id = self.game.acting_player.player_id.clone().unwrap_or_default();

                // Always Hungry check: thrower with this skill must roll 2+ or they eat the teammate
                let has_always_hungry = if home {
                    self.game.team_home.player(&thrower_id)
                } else {
                    self.game.team_away.player(&thrower_id)
                }.map(|p| p.has_skill(SkillId::AlwaysHungry)).unwrap_or(false);

                if has_always_hungry {
                    let ah_roll = self.rng.d6();
                    let ah_success = ah_roll >= 2;
                    events.push(GameEvent::AlwaysHungry {
                        player_id: thrower_id.clone(),
                        roll: ah_roll,
                        success: ah_success,
                    });
                    if !ah_success {
                        // Thrower tries to eat teammate — thrown player attempts escape (2+)
                        let escape_roll = self.rng.d6();
                        let escaped = escape_roll >= 2;
                        events.push(GameEvent::EscapeRoll {
                            player_id: thrown_id.clone(),
                            roll: escape_roll,
                            success: escaped,
                        });
                        if !escaped {
                            // Player is eaten: casualty
                            self.game.field_model.set_player_state(&thrown_id, PlayerState::new(PS_BADLY_HURT));
                            self.game.field_model.player_coordinates.remove(&thrown_id);
                            events.push(GameEvent::Injury {
                                player_id: thrown_id,
                                armor_roll: None,
                                injury_roll: None,
                                serious_injury: None,
                                was_ko: false,
                                was_cas: true,
                            });
                        }
                        // Either way (escaped or eaten), TTM fails this turn
                        self.game.acting_player.has_acted = true;
                        self.compute_next_prompt();
                        return Ok(events);
                    }
                }

                let thrower_ag = if home {
                    self.game.team_home.player(&thrower_id).map(|p| p.agility).unwrap_or(3)
                } else {
                    self.game.team_away.player(&thrower_id).map(|p| p.agility).unwrap_or(3)
                };
                let thrower_coord = self.game.field_model.player_coordinate(&thrower_id)
                    .unwrap_or(FieldCoordinate::new(12, 7));
                let dist = ffb_model::util::passing::passing_distance(thrower_coord, coord)
                    .unwrap_or(ffb_model::enums::PassingDistance::LongBomb);
                use ffb_mechanics::mechanics::evaluate_pass;
                let roll = self.rng.d6();
                let pass_result = evaluate_pass(rules, thrower_ag, roll, dist, &[], false);
                let ttm_pass_result = match pass_result {
                    ffb_mechanics::mechanics::PassResult::Accurate => ffb_model::enums::PassResult::Complete,
                    ffb_mechanics::mechanics::PassResult::Fumble |
                    ffb_mechanics::mechanics::PassResult::SavedFumble => ffb_model::enums::PassResult::Fumble,
                    _ => ffb_model::enums::PassResult::Inaccurate,
                };
                events.push(GameEvent::ThrowTeamMateRoll {
                    thrower_id: thrower_id.clone(),
                    thrown_id: thrown_id.clone(),
                    roll,
                    result: ttm_pass_result,
                });
                let has_swoop = if home {
                    self.game.team_home.player(&thrown_id).map(|p| p.has_skill(SkillId::Swoop)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&thrown_id).map(|p| p.has_skill(SkillId::Swoop)).unwrap_or(false)
                };
                let has_bullseye = if home {
                    self.game.team_home.player(&thrower_id).map(|p| p.has_skill(SkillId::Bullseye)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&thrower_id).map(|p| p.has_skill(SkillId::Bullseye)).unwrap_or(false)
                };
                let is_superb = matches!(pass_result, ffb_mechanics::mechanics::PassResult::Accurate);
                // In BB2016 accurate = land at target; in BB2020+ both accurate and inaccurate scatter.
                // Bullseye (BB2025): skip scatter on superb (accurate) throw.
                let land_coord = if is_superb && (has_bullseye || rules == Rules::Bb2016) {
                    coord // Bullseye or BB2016 superb: no scatter
                } else {
                    let dir = self.rng.d8();
                    use ffb_mechanics::mechanics::scatter_coordinate;
                    use ffb_model::enums::Direction;
                    if let Some(d) = Direction::for_roll(dir) {
                        let (nx, ny) = scatter_coordinate(coord.x, coord.y, d, 1);
                        let nc = FieldCoordinate::new(nx, ny);
                        if nc.is_on_pitch() { nc } else { coord }
                    } else { coord }
                };
                // Swoop: player glides to landing position and emits SwoopPlayer event
                if has_swoop {
                    events.push(GameEvent::SwoopPlayer { player_id: thrown_id.clone(), coord: land_coord });
                }
                // Check for Right Stuff roll (landing roll)
                // Check for collision: another player already in the landing square
                let collision_id = self.game.field_model.player_at(land_coord)
                    .filter(|id| *id != &thrown_id)
                    .map(|id| id.to_owned());
                let has_lethal_flight = if home {
                    self.game.team_home.player(&thrown_id).map(|p| p.has_skill(SkillId::LethalFlight)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&thrown_id).map(|p| p.has_skill(SkillId::LethalFlight)).unwrap_or(false)
                };
                let mut collision_happened = false;
                if let Some(ref hit_id) = collision_id {
                    // Is it an opponent?
                    let is_opponent = if home {
                        self.game.team_away.has_player(hit_id)
                    } else {
                        self.game.team_home.has_player(hit_id)
                    };
                    if is_opponent {
                        collision_happened = true;
                        let hit_is_home = !home;
                        events.push(GameEvent::PlayerFellDown { player_id: hit_id.clone(), coord: land_coord });
                        self.game.field_model.set_player_state(hit_id, PlayerState::new(PS_PRONE));
                        // LethalFlight: +1 to armor or injury roll (reuse arm_bar_mod semantic)
                        let lf_mod = if has_lethal_flight { 1 } else { 0 };
                        let inj_events = self.apply_fall_injury(hit_id, hit_is_home, lf_mod);
                        events.extend(inj_events);
                    }
                }
                // Thrown player falls on collision
                let right_stuff_roll = self.rng.d6();
                // Reliable: if thrower fumbles, thrown player lands safely regardless of roll
                let thrower_has_reliable = if home {
                    self.game.team_home.player(&thrower_id)
                } else {
                    self.game.team_away.player(&thrower_id)
                }.map(|p| p.has_skill(SkillId::Reliable)).unwrap_or(false);
                let fumble_lands_safely = thrower_has_reliable && matches!(ttm_pass_result, ffb_model::enums::PassResult::Fumble);
                let landed_safely = !collision_happened && (right_stuff_roll >= 4 || fumble_lands_safely);
                events.push(GameEvent::RightStuffRoll {
                    player_id: thrown_id.clone(),
                    roll: right_stuff_roll,
                    success: landed_safely,
                });
                self.game.field_model.set_player_coordinate(&thrown_id, land_coord);
                if landed_safely {
                    self.game.field_model.set_player_state(&thrown_id, PlayerState::new(PS_STANDING));
                    events.push(GameEvent::PlayerMoved { player_id: thrown_id.clone(), coord: land_coord });
                    // Check touchdown
                    if self.is_opponent_endzone(land_coord, home) {
                        let has_ball = self.game.field_model.ball_coordinate == Some(land_coord);
                        if has_ball {
                            if home { self.game.game_result.home.score += 1; } else { self.game.game_result.away.score += 1; }
                            events.push(GameEvent::Touchdown { player_id: thrown_id, coord: land_coord });
                            self.game.field_model.ball_in_play = false;
                            self.mark_ball_not_moving();
                            self.game.acting_player.clear();
                            self.player_activated_this_turn = false;
                            self.game.home_playing = !home;
                            self.game.turn_mode = TurnMode::Setup;
                            self.setup_phase = 0;
                            self.place_all_in_reserve();
                        }
                    }
                } else {
                    self.game.field_model.set_player_state(&thrown_id, PlayerState::new(PS_PRONE));
                    events.push(GameEvent::PlayerFellDown { player_id: thrown_id.clone(), coord: land_coord });
                    // Failed landing → armor roll for thrown player
                    let thrown_is_home = self.game.team_home.has_player(&thrown_id);
                    let fall_events = self.apply_fall_injury(&thrown_id, thrown_is_home, 0);
                    events.extend(fall_events);
                }
                self.game.acting_player.has_acted = true;
            }

            Action::KickTeamMate { player_id: kicked_id, coord } => {
                // Simplified: kick always scatters like a wildly inaccurate throw
                let home = self.game.home_playing;
                use ffb_mechanics::mechanics::scatter_coordinate;
                use ffb_model::enums::Direction;
                let dir = self.rng.d8();
                let land_coord = if let Some(d) = Direction::for_roll(dir) {
                    let (nx, ny) = scatter_coordinate(coord.x, coord.y, d, 1);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { nc } else { coord }
                } else { coord };
                // Landing roll
                let roll = self.rng.d6();
                let landed = roll >= 4;
                events.push(GameEvent::RightStuffRoll { player_id: kicked_id.clone(), roll, success: landed });
                self.game.field_model.set_player_coordinate(&kicked_id, land_coord);
                if landed {
                    self.game.field_model.set_player_state(&kicked_id, PlayerState::new(PS_STANDING));
                    events.push(GameEvent::PlayerMoved { player_id: kicked_id, coord: land_coord });
                } else {
                    self.game.field_model.set_player_state(&kicked_id, PlayerState::new(PS_PRONE));
                    events.push(GameEvent::PlayerFellDown { player_id: kicked_id, coord: land_coord });
                }
                let _ = home;
                self.game.acting_player.has_acted = true;
            }

            // ── Group 10e: Punt (BB2025) ──────────────────────────────────────
            // Punt skill: acting player kicks the ball as a half-action during their turn.
            // Ball scatters 3D6 in a chosen direction (no kickoff events, no half field restriction).
            Action::Punt { coord } => {
                let punter_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let has_punt = if self.game.home_playing {
                    self.game.team_home.player(&punter_id).map(|p| p.has_skill(SkillId::Punt)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&punter_id).map(|p| p.has_skill(SkillId::Punt)).unwrap_or(false)
                };
                if !has_punt {
                    return Err(RulesError::NotLegal);
                }
                let scatter_dir = self.rng.d8();
                let d1 = self.rng.d6();
                let d2 = self.rng.d6();
                let d3 = self.rng.d6();
                let scatter_dist = d1 + d2 + d3;
                use ffb_mechanics::mechanics::scatter_coordinate;
                use ffb_model::enums::Direction;
                let final_coord = if let Some(dir) = Direction::for_roll(scatter_dir) {
                    let (nx, ny) = scatter_coordinate(coord.x, coord.y, dir, scatter_dist);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { nc } else { coord }
                } else {
                    coord
                };
                self.game.field_model.ball_coordinate = Some(final_coord);
                self.game.field_model.ball_in_play = true;
                events.push(GameEvent::KickoffScatter {
                    start: coord,
                    direction: scatter_dir,
                    distance: scatter_dist,
                });
                self.mark_ball_moving();
                // Mark punt as used for this drive
                if self.game.home_playing {
                    self.game.turn_data_home.punt_used = true;
                } else {
                    self.game.turn_data_away.punt_used = true;
                }
                // Punt is a half-action: acting_player remains active for second action
            }

            // ── Group 10f: BreatheFire ────────────────────────────────────────
            Action::BreatheFire { target_id } => {
                let home = self.game.home_playing;
                let attacker_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let bf_events = self.apply_breathe_fire(&attacker_id, home, &target_id)?;
                events.extend(bf_events);
                self.game.acting_player.has_acted = true;
            }

            // ── Group 10g: ProjectileVomit ───────────────────────────────────
            Action::ProjectileVomit { target_id } => {
                let home = self.game.home_playing;
                let attacker_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let pv_events = self.apply_projectile_vomit(&attacker_id, home, &target_id)?;
                events.extend(pv_events);
                self.game.acting_player.has_acted = true;
            }

            // ── Group 10d: WizardSpell ────────────────────────────────────────
            Action::WizardSpell { spell, coord } => {
                let rules = self.game.rules;
                let wizard_team_id = if _side == TeamSide::Home {
                    self.game.team_home.id.clone()
                } else {
                    self.game.team_away.id.clone()
                };
                let spell_name = format!("{spell:?}");
                events.push(GameEvent::WizardUse {
                    team_id: wizard_team_id,
                    spell: spell_name,
                    coord: Some(coord),
                });
                match spell {
                    crate::action::WizardSpellChoice::Fireball => {
                        // 3×3 blast centered on coord; +1 to injury roll for fireball
                        let all_player_ids: Vec<(String, i32, bool)> = self.game.team_home.players.iter()
                            .map(|p| (p.id.clone(), p.armour, true))
                            .chain(self.game.team_away.players.iter().map(|p| (p.id.clone(), p.armour, false)))
                            .collect();
                        for (pid, av, is_home_target) in all_player_ids {
                            if let Some(pc) = self.game.field_model.player_coordinate(&pid) {
                                if (pc.x - coord.x).abs() <= 1 && (pc.y - coord.y).abs() <= 1 {
                                    let ar1 = self.rng.d6();
                                    let ar2 = self.rng.d6();
                                    if is_armour_broken(av, ar1 + ar2, rules) {
                                        let inj1 = self.rng.d6();
                                        let inj2 = self.rng.d6();
                                        let niggling_mod = self.niggling_injury_mod(&pid, is_home_target);
                                        let total = inj1 + inj2 + niggling_mod + 1; // +1 fireball injury modifier
                                        let mut was_cas = total >= 10;
                                        let mut was_ko = total >= 8 && !was_cas;
                                        // ThickSkull: on KO result, roll D6; on 4+ downgrade to Stunned
                                        if was_ko && self.check_thick_skull(&pid, is_home_target, &mut events) {
                                            was_ko = false;
                                        }
                                        // Decay: BH/Stunned on a Decay player becomes CAS
                                        let has_decay = if is_home_target {
                                            self.game.team_home.player(&pid)
                                        } else {
                                            self.game.team_away.player(&pid)
                                        }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                                        if has_decay && !was_cas && !was_ko {
                                            was_cas = true;
                                        }
                                        let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                                        let regen = if was_cas {
                                            self.try_regeneration(&pid, is_home_target, &mut events)
                                        } else { false };
                                        let was_cas = was_cas && !regen;
                                        let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                                            else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                                            else if !regen { PlayerState::new(PS_PRONE) }
                                            else { PlayerState::new(PS_RESERVE) };
                                        if !regen { self.game.field_model.set_player_state(&pid, new_state); }
                                        if was_cas {
                                            if let Some(si_kind) = si {
                                                self.apply_casualty_to_player(&pid, is_home_target, si_kind);
                                            }
                                        }
                                        events.push(GameEvent::Injury {
                                            player_id: pid,
                                            armor_roll: Some([ar1, ar2]),
                                            injury_roll: Some([inj1, inj2]),
                                            serious_injury: si,
                                            was_ko,
                                            was_cas,
                                        });
                                    } else {
                                        events.push(GameEvent::Injury {
                                            player_id: pid,
                                            armor_roll: Some([ar1, ar2]),
                                            injury_roll: None,
                                            serious_injury: None,
                                            was_ko: false,
                                            was_cas: false,
                                        });
                                    }
                                }
                            }
                        }
                    }
                    crate::action::WizardSpellChoice::Lightning => {
                        // Single player at coord; +1 to armor and injury roll for lightning
                        let target = self.game.team_home.players.iter()
                            .map(|p| (p.id.clone(), p.armour, true))
                            .chain(self.game.team_away.players.iter().map(|p| (p.id.clone(), p.armour, false)))
                            .find(|(pid, _, _)| self.game.field_model.player_coordinate(pid) == Some(coord));
                        if let Some((pid, av, is_home_target)) = target {
                            let ar1 = self.rng.d6();
                            let ar2 = self.rng.d6();
                            if is_armour_broken(av, ar1 + ar2 + 1, rules) {
                                let inj1 = self.rng.d6();
                                let inj2 = self.rng.d6();
                                let niggling_mod = self.niggling_injury_mod(&pid, is_home_target);
                                let total = inj1 + inj2 + niggling_mod + 1; // +1 lightning injury modifier
                                let mut was_cas = total >= 10;
                                let mut was_ko = total >= 8 && !was_cas;
                                // ThickSkull: downgrade KO to Stunned on 4+
                                if was_ko && self.check_thick_skull(&pid, is_home_target, &mut events) {
                                    was_ko = false;
                                }
                                // Decay: BH/Stunned becomes CAS
                                let has_decay = if is_home_target {
                                    self.game.team_home.player(&pid)
                                } else {
                                    self.game.team_away.player(&pid)
                                }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                                if has_decay && !was_cas && !was_ko {
                                    was_cas = true;
                                }
                                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                                let regen = if was_cas {
                                    self.try_regeneration(&pid, is_home_target, &mut events)
                                } else { false };
                                let was_cas = was_cas && !regen;
                                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                                    else if !regen { PlayerState::new(PS_PRONE) }
                                    else { PlayerState::new(PS_RESERVE) };
                                if !regen { self.game.field_model.set_player_state(&pid, new_state); }
                                if was_cas {
                                    if let Some(si_kind) = si {
                                        self.apply_casualty_to_player(&pid, is_home_target, si_kind);
                                    }
                                }
                                events.push(GameEvent::Injury {
                                    player_id: pid,
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: Some([inj1, inj2]),
                                    serious_injury: si,
                                    was_ko,
                                    was_cas,
                                });
                            } else {
                                events.push(GameEvent::Injury {
                                    player_id: pid,
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: None,
                                    serious_injury: None,
                                    was_ko: false,
                                    was_cas: false,
                                });
                            }
                        }
                    }
                }
                events.push(GameEvent::SpellEffectRoll { roll: self.rng.d6() });
            }

            // ── Group 4c: SelectSkill (level-up or WisdomOfTheWhiteDwarf grant) ──
            Action::SelectSkill { skill_id } => {
                if let Some(grant) = self.pending_wisdom_grant.take() {
                    // WisdomOfTheWhiteDwarf: add skill temporarily to grantee for this turn
                    let player = if grant.is_home {
                        self.game.team_home.player_mut(&grant.grantee_id)
                    } else {
                        self.game.team_away.player_mut(&grant.grantee_id)
                    };
                    if let Some(p) = player {
                        use ffb_model::model::skill_def::SkillWithValue;
                        p.temporary_skills.push(SkillWithValue::new(skill_id));
                    }
                    events.push(GameEvent::SkillUse {
                        player_id: grant.grantee_id,
                        skill_id: skill_id as u16,
                        used: true,
                    });
                } else {
                    // Apply the selected skill to the acting player's extra_skills (level-up).
                    if let Some(pid) = self.game.acting_player.player_id.clone() {
                        let is_home = self.player_is_home(&pid).unwrap_or(self.game.home_playing);
                        let player = if is_home {
                            self.game.team_home.player_mut(&pid)
                        } else {
                            self.game.team_away.player_mut(&pid)
                        };
                        if let Some(p) = player {
                            use ffb_model::model::skill_def::SkillWithValue;
                            p.extra_skills.push(SkillWithValue::new(skill_id));
                            // Stat-increase skills also directly increment the relevant stat.
                            match skill_id {
                                SkillId::MovementIncrease => p.movement += 1,
                                SkillId::StrengthIncrease => p.strength += 1,
                                SkillId::AgilityIncrease => p.agility -= 1, // AG target improves by lowering
                                SkillId::ArmourIncrease => p.armour += 1,
                                SkillId::PassingIncrease => p.passing -= 1, // PA target improves by lowering
                                _ => {}
                            }
                        }
                        events.push(GameEvent::SkillUse {
                            player_id: pid,
                            skill_id: skill_id as u16,
                            used: true,
                        });
                    }
                }
            }

            // ── Group 11a: BuyInducements (pre-game) ──────────────────────────
            Action::BuyInducements { purchases } => {
                let team_is_home = self.game.home_playing;
                for p in &purchases {
                    let count = p.count as i32;
                    let team = if team_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                    match p.id.as_str() {
                        "bloodweiserBabes" => team.bloodweiser_kegs += count,
                        "bribes" => team.bribes += count,
                        "prayers" => team.prayers_to_nuffle += count,
                        "halflingMasterChef" => team.master_chefs += count,
                        "wanderingApothecaries" | "plagueDoctors" => team.apothecaries += count,
                        "riotousRookies" => team.riotous_rookies += count,
                        "extraTeamTraining" => {
                            // Extra rerolls for this game (add to starting reroll pool)
                            if team_is_home { self.game.turn_data_home.rerolls += count; }
                            else { self.game.turn_data_away.rerolls += count; }
                        }
                        "wizard" => {
                            // Mark wizard as available (stored as flag on team or reroll slot)
                            // For now, we increment a per-team wizard count as a proxy.
                            // In parity, wizards are used via Action::WizardSpell.
                        }
                        _ => {
                            // Star players: track purchase and detect double-hire.
                            if p.id.starts_with("starPlayer_") {
                                let other_stars = if team_is_home { &self.away_star_purchases } else { &self.home_star_purchases };
                                if other_stars.contains(&p.id) {
                                    events.push(GameEvent::DoubleHiredStarPlayer);
                                }
                                let this_stars = if team_is_home { &mut self.home_star_purchases } else { &mut self.away_star_purchases };
                                this_stars.push(p.id.clone());
                            }
                        }
                    }
                    events.push(GameEvent::BuyInducement {
                        team_id: (if team_is_home { &self.game.team_home } else { &self.game.team_away }).id.clone(),
                        inducement_id: p.id.clone(),
                        count: p.count,
                    });
                }
            }

            // ── Group 11b: PlayCard ───────────────────────────────────────────
            Action::PlayCard { card_id: ref card_id_val, ref target_player_id } => {
                let card_id = card_id_val.clone();
                let target_player_id = target_player_id.clone();
                let is_home = self.game.home_playing;
                let team_id = if is_home {
                    self.game.team_home.id.clone()
                } else {
                    self.game.team_away.id.clone()
                };
                events.push(GameEvent::PlayCard { team_id, card_id: card_id.clone() });

                // Apply card effect based on known card_ids (CardEffect mapping).
                // Temporary skills are added to the target player's temporary_skills list.
                let effect = match card_id.as_str() {
                    // DISTRACTED: target gains BoneHead until end of this turn
                    "distract" | "Distract" | "distracted" => Some((SkillId::BoneHead, false)),
                    // SEDATIVE: target gains ReallyStupid until end of this turn
                    "sedative" | "Sedative" | "witch_s_brew" | "witchsBrew" => Some((SkillId::ReallyStupid, false)),
                    // MAD_CAP_MUSHROOM_POTION: target gains JumpUp + NoHands
                    "mad_cap_mushroom_potion" | "madCapMushroomPotion" => Some((SkillId::NoHands, true)),
                    _ => None,
                };

                if let (Some((skill, also_jump_up)), Some(ref target_id)) = (effect, &target_player_id) {
                    let target_is_home = self.game.team_home.has_player(target_id);
                    let team = if target_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(target_id) {
                        p.temporary_skills.push(ffb_model::model::skill_def::SkillWithValue::new(skill));
                        if also_jump_up {
                            p.temporary_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::JumpUp));
                        }
                    }
                    // Track card-applied skills for removal at turn/drive end.
                    self.card_temporary_skills.push((target_id.clone(), skill, card_id.clone()));
                    if also_jump_up {
                        self.card_temporary_skills.push((target_id.clone(), SkillId::JumpUp, card_id.clone()));
                    }
                    events.push(GameEvent::CardEffectRoll { card_id: card_id.clone(), roll: 0, effect: format!("{:?}", skill) });
                }

                // ILLEGALLY_SUBSTITUTED: send target player to reserve (remove from pitch)
                if card_id.contains("illegal") || card_id.contains("Illegal") || card_id == "illegalSubstitution" {
                    if let Some(ref target_id) = target_player_id {
                        let target_is_home = self.game.team_home.has_player(target_id);
                        let new_state = PlayerState::new(PS_RESERVE);
                        self.game.field_model.remove_player(target_id);
                        if target_is_home {
                            if let Some(p) = self.game.team_home.player_mut(target_id) {
                                let _ = p; // player stays on roster but off pitch
                            }
                        }
                        self.game.field_model.set_player_state(target_id, new_state);
                        events.push(GameEvent::CardDeactivated { card_id: card_id.clone() });
                    }
                }

                // POISONED: target takes an armor roll (no injury modifier)
                if card_id.contains("poison") || card_id.contains("Poison") {
                    if let Some(ref target_id) = target_player_id {
                        let target_is_home = self.game.team_home.has_player(target_id);
                        let fall_evs = self.apply_fall_injury(target_id, target_is_home, 0);
                        events.extend(fall_evs);
                    }
                }
            }

            // ── Intercept (decline — engine auto-resolves interceptions) ─────
            Action::Intercept { attempt: _ } => {
                // Interceptions are currently resolved automatically in apply_pass.
                // Explicit intercept actions are accepted but have no additional effect.
            }

            // ── SelectPlayer (used for touchback and HighKick) ────────────────
            Action::SelectPlayer { player_id } => {
                if let Some(_biter_id) = self.pending_blood_lust.take() {
                    // Vampire bites adjacent teammate: direct injury roll (no armor check).
                    use ffb_mechanics::mechanics::{InjuryOutcome, injury_result};
                    let target_rules = self.game.rules;
                    let inj1 = self.rng.d6();
                    let inj2 = self.rng.d6();
                    let outcome = injury_result([inj1, inj2], &[]);
                    let (was_ko, was_cas, serious_injury) = match outcome {
                        InjuryOutcome::Stunned | InjuryOutcome::BadlyHurt => (false, false, None),
                        InjuryOutcome::KnockedOut => (true, false, None),
                        InjuryOutcome::Casualty => {
                            let si1 = self.rng.d6();
                            let si2 = self.rng.d6();
                            let si = match target_rules {
                                Rules::Bb2016 => serious_injury_bb2016(si1, si2),
                                Rules::Bb2020 | Rules::Common => serious_injury_bb2020(si1),
                                Rules::Bb2025 => serious_injury_bb2025(si1),
                            };
                            (false, true, si)
                        }
                    };
                    let new_state = if was_ko { PS_KNOCKED_OUT }
                        else if was_cas { PS_BADLY_HURT }
                        else { PS_PRONE };
                    self.game.field_model.set_player_state(&player_id, PlayerState::new(new_state));
                    events.push(GameEvent::Injury {
                        player_id: player_id.clone(),
                        armor_roll: None,
                        injury_roll: Some([inj1, inj2]),
                        serious_injury,
                        was_ko,
                        was_cas,
                    });
                } else if self.pending_on_the_ball_kickoff.is_some() {
                    // OnTheBall during kickoff: receiving player can move up to 3 squares to position.
                    if player_id.is_empty() {
                        // Decline — clear and continue
                        self.pending_on_the_ball_kickoff = None;
                    } else {
                        let ball_coord = self.game.field_model.ball_coordinate.unwrap_or(FieldCoordinate::new(13, 7));
                        let from = self.game.field_model.player_coordinate(&player_id)
                            .unwrap_or(FieldCoordinate::new(12, 7));
                        let dx = (ball_coord.x - from.x).signum();
                        let dy = (ball_coord.y - from.y).signum();
                        let dest = FieldCoordinate::new(from.x + dx, from.y + dy);
                        if dest.is_on_pitch() && self.game.field_model.player_at(dest).is_none() {
                            self.game.field_model.player_coordinates.insert(player_id.clone(), dest);
                        }
                        events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: dest });
                        if let Some(ref mut otb) = self.pending_on_the_ball_kickoff {
                            otb.retain(|id| id != &player_id);
                            if otb.is_empty() {
                                self.pending_on_the_ball_kickoff = None;
                            }
                        }
                    }
                } else if self.pending_kickoff_return.is_some() {
                    // KickoffReturn: receiving player moves up to 3 squares after ball lands.
                    if player_id.is_empty() {
                        // Decline — clear and continue
                        self.pending_kickoff_return = None;
                    } else {
                        // Move the chosen player up to 3 squares toward the ball.
                        let ball_coord = self.game.field_model.ball_coordinate.unwrap_or(FieldCoordinate::new(13, 7));
                        let from = self.game.field_model.player_coordinate(&player_id)
                            .unwrap_or(ball_coord);
                        let max_steps = 3i32;
                        let mut cur = from;
                        for _ in 0..max_steps {
                            let dx = (ball_coord.x - cur.x).signum();
                            let dy = (ball_coord.y - cur.y).signum();
                            if dx == 0 && dy == 0 { break; }
                            let next = FieldCoordinate::new(cur.x + dx, cur.y + dy);
                            if next.is_on_pitch() && self.game.field_model.player_at(next).is_none() {
                                cur = next;
                            } else {
                                break;
                            }
                        }
                        if cur != from {
                            self.game.field_model.player_coordinates.insert(player_id.clone(), cur);
                        }
                        events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: cur });
                        self.pending_kickoff_return = None;
                    }
                } else if self.pending_high_kick.is_some() {
                    // HighKick: agent picks one receiving-team player to teleport to ball square.
                    self.pending_high_kick = None;
                    if !player_id.is_empty() {
                        if let Some(ball_coord) = self.game.field_model.ball_coordinate {
                            // Only move if ball square is unoccupied
                            if self.game.field_model.player_at(ball_coord).is_none() {
                                self.game.field_model.player_coordinates.insert(player_id.clone(), ball_coord);
                            }
                            events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: ball_coord });
                        }
                    }
                } else if self.pending_solid_defence.is_some() {
                    // SolidDefence / Charge: move selected player 2 squares toward own end zone.
                    if player_id.is_empty() {
                        // Agent declines further selection.
                        self.pending_solid_defence = None;
                    } else {
                        let (is_charge, kicking_is_home) = self.pending_solid_defence.as_ref()
                            .map(|sd| (sd.is_charge, sd.kicking_is_home))
                            .unwrap_or((false, false));
                        // Determine direction: kicking team moves backward, receiving team moves forward.
                        // Home end zone is x=0, away end zone is x=25.
                        let move_dx = if is_charge {
                            // Charge: receiving team moves toward opponent end zone.
                            // Receiving home team → toward x=25 (away endzone): dx=+1
                            // Receiving away team → toward x=0 (home endzone): dx=-1
                            if !kicking_is_home { 1i32 } else { -1i32 }
                        } else {
                            // SolidDefence: kicking team moves backward (toward own end zone)
                            // Kicking home team: moves toward x=0, dx = -1
                            // Kicking away team: moves toward x=25, dx = +1
                            if kicking_is_home { -1i32 } else { 1i32 }
                        };
                        if let Some(from) = self.game.field_model.player_coordinate(&player_id) {
                            // Move 2 squares in direction, stopping at pitch boundary
                            let mut dest = from;
                            for _ in 0..2 {
                                let nx = dest.x + move_dx;
                                let nc = FieldCoordinate::new(nx, dest.y);
                                if nc.is_on_pitch() && self.game.field_model.player_at(nc).is_none() {
                                    dest = nc;
                                } else {
                                    break;
                                }
                            }
                            if dest != from {
                                self.game.field_model.player_coordinates.insert(player_id.clone(), dest);
                                events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: dest });
                            }
                        }
                        // Decrement remaining and remove player from eligible.
                        if let Some(ref mut sd) = self.pending_solid_defence {
                            sd.remaining -= 1;
                            sd.eligible.retain(|id| id != &player_id);
                            if sd.remaining <= 0 || sd.eligible.is_empty() {
                                self.pending_solid_defence = None;
                            }
                        }
                    }
                } else if self.pending_pass_block.is_some() {
                    // PassBlock/OnTheBall move: the defender moves 1 square toward the pass lane.
                    // After this, remove the player from eligible list; if list is empty, resolve pass.
                    let (thrower_id, target_coord, home_passing, pr_str, give_and_go_flag) = {
                        let pb = self.pending_pass_block.as_ref().unwrap();
                        (pb.thrower_id.clone(), pb.target_coord, pb.home_passing, pb.pass_result_str.clone(), pb.give_and_go)
                    };
                    if player_id.is_empty() {
                        // Agent declined to move — emit PassBlock with no player, clear and resolve pass
                        events.push(GameEvent::PassBlock { player_id: None });
                        self.pending_pass_block = None;
                        let continue_events = self.resolve_pass_after_pass_block(&thrower_id, target_coord, home_passing, &pr_str, give_and_go_flag)?;
                        events.extend(continue_events);
                    } else {
                        // Emit PassBlock with chosen player
                        events.push(GameEvent::PassBlock { player_id: Some(player_id.clone()) });
                        // Move the chosen player one square toward target_coord
                        let from = self.game.field_model.player_coordinate(&player_id)
                            .unwrap_or(FieldCoordinate::new(12, 7));
                        let dx = (target_coord.x - from.x).signum();
                        let dy = (target_coord.y - from.y).signum();
                        let dest = FieldCoordinate::new(from.x + dx, from.y + dy);
                        if dest.is_on_pitch() && self.game.field_model.player_at(dest).is_none() {
                            self.game.field_model.player_coordinates.insert(player_id.clone(), dest);
                        }
                        events.push(GameEvent::PlayerMoved {
                            player_id: player_id.clone(),
                            coord: dest,
                        });
                        // Remove this player from eligible list; if empty, resolve pass
                        if let Some(ref mut pb) = self.pending_pass_block {
                            pb.eligible_players.retain(|id| id != &player_id);
                            if pb.eligible_players.is_empty() {
                                let thrower_id2 = pb.thrower_id.clone();
                                let tc2 = pb.target_coord;
                                let hp2 = pb.home_passing;
                                let pr2 = pb.pass_result_str.clone();
                                let gg2 = pb.give_and_go;
                                self.pending_pass_block = None;
                                let continue_events = self.resolve_pass_after_pass_block(&thrower_id2, tc2, hp2, &pr2, gg2)?;
                                events.extend(continue_events);
                            }
                        }
                    }
                } else if self.pending_pick_me_up.is_some() {
                    // PickMeUp: non-active team selects which prone teammate to try to stand up.
                    if player_id.is_empty() {
                        // Decline remaining — clear and done
                        self.pending_pick_me_up = None;
                        self.cached_prompt = None;
                    } else {
                        let roll = self.rng.d6();
                        let success = roll >= 5;
                        if success {
                            if let Some(state) = self.game.field_model.player_state(&player_id) {
                                self.game.field_model.set_player_state(&player_id, state.change_base(PS_STANDING));
                            }
                        }
                        events.push(GameEvent::PickMeUpRoll { player_id: player_id.clone(), roll, success });
                        // Remove this player from the eligible list
                        if let Some(ref mut pmu) = self.pending_pick_me_up {
                            pmu.eligible_players.retain(|id| id != &player_id);
                            if pmu.eligible_players.is_empty() {
                                self.pending_pick_me_up = None;
                                self.cached_prompt = None;
                            } else {
                                // Re-offer with remaining eligible players
                                let remaining = pmu.eligible_players.clone();
                                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                                    eligible_players: remaining,
                                    reason: "pickMeUp".into(),
                                });
                            }
                        }
                    }
                } else if self.pending_auto_gaze.is_some() {
                    // ExcuseMeAreYouAZoat: active player selects which opponent to gaze (or declines).
                    let gaze = self.pending_auto_gaze.take().unwrap();
                    if !player_id.is_empty() {
                        // Mark skill used
                        let team = if gaze.is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = team.player_mut(&gaze.player_id) {
                            p.used_skills.insert(SkillId::ExcuseMeAreYouAZoat);
                        }
                        // Set target to confused (loses tackle zones)
                        if let Some(state) = self.game.field_model.player_state(&player_id) {
                            self.game.field_model.set_player_state(&player_id, state.change_confused(true));
                        }
                    } else {
                        // Declined — skill is not marked used (once-per-game is on use, not on offer)
                    }
                    self.cached_prompt = None;
                } else if self.pending_baleful_hex.is_some() {
                    // BalefulHex: active player selected an opponent to hex (or declined with empty id).
                    let hex = self.pending_baleful_hex.take().unwrap();
                    if !player_id.is_empty() {
                        // Mark skill used on the caster
                        let caster_team = if hex.is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = caster_team.player_mut(&hex.player_id) {
                            p.used_skills.insert(SkillId::BalefulHex);
                        }
                        let roll = self.rng.d6();
                        let success = roll >= 2;
                        events.push(GameEvent::BalefulHexRoll {
                            attacker_id: hex.player_id.clone(),
                            target_id: player_id.clone(),
                            roll,
                            success,
                            rerolled: false,
                        });
                        if success {
                            if let Some(state) = self.game.field_model.player_state(&player_id) {
                                self.game.field_model.set_player_state(
                                    &player_id,
                                    state.change_confused(true).change_active(false),
                                );
                            }
                        }
                    }
                    self.cached_prompt = None;
                } else if self.pending_blastin.is_some() {
                    // ThenIStartedBlastin / BlastinSolvesEverything: player selected a blast target.
                    let blastin = self.pending_blastin.take().unwrap();
                    // Mark skill used
                    let blasting_team = if blastin.is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = blasting_team.player_mut(&blastin.player_id) {
                        p.used_skills.insert(blastin.skill_id);
                    }
                    let roll = self.rng.d6();
                    let success = roll >= 3;
                    let backfire = roll == 1;
                    events.push(GameEvent::SpellEffectRoll { roll });
                    let rules = self.game.rules;
                    let hit_target_id = if backfire {
                        blastin.player_id.clone() // hits self
                    } else if success {
                        player_id.clone()
                    } else {
                        String::new() // no hit on 2 (no reroll in simplified version)
                    };
                    if !hit_target_id.is_empty() {
                        let target_is_home = if backfire { blastin.is_home } else { !blastin.is_home };
                        let target_av = if target_is_home {
                            self.game.team_home.player(&hit_target_id).map(|p| p.armour).unwrap_or(8)
                        } else {
                            self.game.team_away.player(&hit_target_id).map(|p| p.armour).unwrap_or(8)
                        };
                        let ar1 = self.rng.d6();
                        let ar2 = self.rng.d6();
                        let armor_broken = is_armour_broken(target_av, ar1 + ar2, rules);
                        if armor_broken {
                            let ir1 = self.rng.d6();
                            let ir2 = self.rng.d6();
                            let total = ir1 + ir2;
                            let was_cas = total >= 10;
                            let was_ko = total >= 8 && !was_cas;
                            let (si, _) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                            let new_state = if was_cas { PlayerState::new(PS_BADLY_HURT) }
                                else if was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                                else { PlayerState::new(PS_PRONE) };
                            self.game.field_model.set_player_state(&hit_target_id, new_state);
                            events.push(GameEvent::Injury {
                                player_id: hit_target_id.clone(),
                                armor_roll: Some([ar1, ar2]),
                                injury_roll: Some([ir1, ir2]),
                                serious_injury: si,
                                was_ko,
                                was_cas,
                            });
                        } else {
                            events.push(GameEvent::Injury {
                                player_id: hit_target_id.clone(),
                                armor_roll: Some([ar1, ar2]),
                                injury_roll: None,
                                serious_injury: None,
                                was_ko: false,
                                was_cas: false,
                            });
                        }
                    }
                    self.cached_prompt = None;
                } else if self.awaiting_touchback {
                    self.awaiting_touchback = false;
                    let coord = self.game.field_model.player_coordinate(&player_id)
                        .unwrap_or(FieldCoordinate::new(13, 7));
                    self.game.field_model.ball_coordinate = Some(coord);
                    events.push(GameEvent::BallPickedUp { player_id, coord });
                    self.mark_ball_not_moving();
                }
            }

            // ── SelectWeather ─────────────────────────────────────────────────
            Action::SelectWeather { weather } => {
                self.game.weather = weather;
                events.push(GameEvent::WeatherChange { weather });
            }

            // ── UseSkill: declared skill use (engine-generated prompts) ───────
            Action::UseSkill { skill_id, use_skill } => {
                // Piling On: attacker decides whether to go prone and re-roll armor/injury.
                if skill_id == SkillId::PilingOn {
                    if let Some(po) = self.pending_piling_on.take() {
                        let po_events = self.resolve_piling_on(po, use_skill)?;
                        events.extend(po_events);
                    }
                } else if skill_id == SkillId::Wrestle {
                    if let Some(pw) = self.pending_wrestle.take() {
                        let wrestle_events = self.resolve_wrestle(pw, use_skill)?;
                        events.extend(wrestle_events);
                    }
                } else if skill_id == SkillId::StripBall {
                    if let Some(sb_ctx) = self.pending_strip_ball.take() {
                        let strip_events = self.resolve_strip_ball(sb_ctx, use_skill)?;
                        events.extend(strip_events);
                    }
                } else if skill_id == SkillId::DumpOff {
                    if let Some(dump) = self.pending_dump_off.take() {
                        let dump_events = self.resolve_dump_off(dump, use_skill)?;
                        events.extend(dump_events);
                    }
                } else if skill_id == SkillId::Trickster {
                    if let Some(trick) = self.pending_trickster.take() {
                        events.push(GameEvent::SkillUse {
                            player_id: trick.defender_id.clone(),
                            skill_id: SkillId::Trickster as u16,
                            used: use_skill,
                        });
                        if use_skill {
                            // Mark Trickster as used; offer coordinate selection
                            let def_is_home = !trick.home_attacking;
                            let team = if def_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&trick.defender_id) {
                                p.used_skills.insert(SkillId::Trickster);
                            }
                            self.cached_prompt = Some(AgentPrompt::TricksterMove {
                                player_id: trick.defender_id.clone(),
                                squares: trick.eligible_squares.clone(),
                            });
                            self.pending_trickster = Some(trick);
                        } else {
                            // Declined: mark as used (prevents re-offer) and resume block normally
                            let def_is_home = !trick.home_attacking;
                            let team = if def_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&trick.defender_id) {
                                p.used_skills.insert(SkillId::Trickster);
                            }
                            let att_id = trick.attacker_id.clone();
                            let def_id = trick.defender_id.clone();
                            self.game.home_playing = trick.home_attacking;
                            let block_events = self.apply_block(&att_id, &def_id)?;
                            events.extend(block_events);
                        }
                    }
                } else if skill_id == SkillId::SlashingNails {
                    events.push(GameEvent::SkillUse {
                        player_id: self.game.acting_player.player_id.clone().unwrap_or_default(),
                        skill_id: skill_id as u16,
                        used: use_skill,
                    });
                    if use_skill {
                        self.game.acting_player.temporary_claws = true;
                    }
                } else if skill_id == SkillId::FrenziedRush {
                    events.push(GameEvent::SkillUse {
                        player_id: self.game.acting_player.player_id.clone().unwrap_or_default(),
                        skill_id: skill_id as u16,
                        used: use_skill,
                    });
                    if use_skill {
                        self.game.acting_player.temporary_frenzy = true;
                    }
                } else if skill_id == SkillId::Incorporeal {
                    events.push(GameEvent::SkillUse {
                        player_id: self.game.acting_player.player_id.clone().unwrap_or_default(),
                        skill_id: skill_id as u16,
                        used: use_skill,
                    });
                    if use_skill {
                        self.game.acting_player.ignore_tackle_zones = true;
                        let pid = self.game.acting_player.player_id.clone().unwrap_or_default();
                        let team = if self.game.home_playing { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = team.player_mut(&pid) { p.used_skills.insert(SkillId::Incorporeal); }
                    }
                } else if skill_id == SkillId::Saboteur {
                    if let Some(sab) = self.pending_saboteur.take() {
                        let sab_events = self.resolve_saboteur(sab, use_skill)?;
                        events.extend(sab_events);
                    }
                } else if skill_id == SkillId::Fumblerooskie || skill_id == SkillId::Fumblerooski {
                    // Intentional ball drop: player declares they are leaving the ball at their
                    // current square before moving. Ball coordinate stays put; player moves normally.
                    events.push(GameEvent::SkillUse {
                        player_id: self.game.acting_player.player_id.clone().unwrap_or_default(),
                        skill_id: skill_id as u16,
                        used: use_skill,
                    });
                } else if skill_id == SkillId::Taunt {
                    if let Some(taunt) = self.pending_taunt.take() {
                        if use_skill {
                            // Defender forces attacker to follow up: move attacker automatically.
                            events.push(GameEvent::SkillUse {
                                player_id: taunt.defender_id.clone(),
                                skill_id: SkillId::Taunt as u16,
                                used: true,
                            });
                            let fu = taunt.follow_up;
                            self.game.field_model.set_player_coordinate(&fu.attacker_id, fu.attacker_to);
                            events.push(GameEvent::PlayerMoved { player_id: fu.attacker_id, coord: fu.attacker_to });
                        } else {
                            // Declined: offer normal follow-up choice to attacker.
                            events.push(GameEvent::SkillUse {
                                player_id: taunt.defender_id.clone(),
                                skill_id: SkillId::Taunt as u16,
                                used: false,
                            });
                            let fu = taunt.follow_up;
                            self.cached_prompt = Some(AgentPrompt::FollowUp {
                                attacker_id: fu.attacker_id.clone(),
                                target_coord: fu.attacker_to,
                            });
                            self.pending_follow_up = Some(fu);
                        }
                    }
                } else if skill_id == SkillId::BlastIt {
                    if let Some(bi) = self.pending_blast_it.take() {
                        let blast_events = self.resolve_blast_it(bi, use_skill)?;
                        events.extend(blast_events);
                    }
                } else if skill_id == SkillId::PutridRegurgitation {
                    if let Some(pr) = self.pending_putrid_regurgitation.take() {
                        events.push(GameEvent::SkillUse {
                            player_id: pr.attacker_id.clone(),
                            skill_id: SkillId::PutridRegurgitation as u16,
                            used: use_skill,
                        });
                        if use_skill {
                            // Mark skill as used this game
                            let team = if pr.home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&pr.attacker_id) {
                                p.used_skills.insert(SkillId::PutridRegurgitation);
                            }
                            let vomit_events = self.apply_projectile_vomit(&pr.attacker_id.clone(), pr.home_attacking, &pr.defender_id.clone())?;
                            events.extend(vomit_events);
                        }
                    }
                } else if skill_id == SkillId::RaidingParty && use_skill {
                    // RaidingParty: once per drive, move an adjacent open teammate 1 square toward the ball
                    let home = self.game.home_playing;
                    let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                    let rp_avail = if home {
                        self.game.team_home.player(&att_id)
                    } else {
                        self.game.team_away.player(&att_id)
                    }.map(|p| p.has_skill(SkillId::RaidingParty) && !p.used_skills.contains(&SkillId::RaidingParty)).unwrap_or(false);
                    if rp_avail {
                        let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(SkillId::RaidingParty); }
                        events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: SkillId::RaidingParty as u16, used: true });
                        // Find adjacent open (no tackle zones from opponents) teammate and move 1 square toward ball
                        let att_coord = self.game.field_model.player_coordinate(&att_id);
                        let ball_coord = self.game.field_model.ball_coordinate;
                        if let (Some(ac), Some(bc)) = (att_coord, ball_coord) {
                            let opp_team = if home { &self.game.team_away } else { &self.game.team_home };
                            let my_team = if home { &self.game.team_home } else { &self.game.team_away };
                            let target_tm: Option<String> = my_team.players.iter()
                                .filter(|p| p.id != att_id)
                                .find(|p| {
                                    let tc = self.game.field_model.player_coordinate(&p.id);
                                    let ts = self.game.field_model.player_state(&p.id);
                                    let adj = tc.map(|c| c.is_adjacent(ac)).unwrap_or(false);
                                    let standing = ts.map(|s| s.is_standing()).unwrap_or(false);
                                    let no_tz_adj = if let Some(tc) = tc {
                                        !opp_team.players.iter().any(|op| {
                                            self.game.field_model.player_coordinate(&op.id)
                                                .map(|oc| oc.is_adjacent(tc))
                                                .unwrap_or(false)
                                            && self.game.field_model.player_state(&op.id)
                                                .map(|s| s.has_tacklezones()).unwrap_or(false)
                                        })
                                    } else { false };
                                    adj && standing && no_tz_adj
                                })
                                .map(|p| p.id.clone());
                            if let Some(tm_id) = target_tm {
                                if let Some(tc) = self.game.field_model.player_coordinate(&tm_id) {
                                    let dx = (bc.x - tc.x).signum();
                                    let dy = (bc.y - tc.y).signum();
                                    let dest = FieldCoordinate::new(tc.x + dx, tc.y + dy);
                                    if dest.is_on_pitch() && self.game.field_model.player_at(dest).is_none() {
                                        self.game.field_model.set_player_coordinate(&tm_id, dest);
                                        events.push(GameEvent::PlayerMoved { player_id: tm_id, coord: dest });
                                    }
                                }
                            }
                        }
                    }
                } else {
                    let _ = (skill_id, use_skill);
                }
            }

            // ── Star-player special attacks ───────────────────────────────────
            // PrimalSavagery: attacker rolls D6+ST vs defender D6+AV; on success defender is injured
            Action::LashOut { target_id } => {
                let home = self.game.home_playing;
                let rules = self.game.rules;
                let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let (att_str, has_skill) = if home {
                    let p = self.game.team_home.player(&att_id);
                    (p.map(|p| p.strength).unwrap_or(3),
                     p.map(|p| p.has_skill(SkillId::PrimalSavagery) && !p.used_skills.contains(&SkillId::PrimalSavagery)).unwrap_or(false))
                } else {
                    let p = self.game.team_away.player(&att_id);
                    (p.map(|p| p.strength).unwrap_or(3),
                     p.map(|p| p.has_skill(SkillId::PrimalSavagery) && !p.used_skills.contains(&SkillId::PrimalSavagery)).unwrap_or(false))
                };
                if has_skill {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(SkillId::PrimalSavagery); }
                    events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: SkillId::PrimalSavagery as u16, used: true });
                    let def_av = if home {
                        self.game.team_away.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    } else {
                        self.game.team_home.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    };
                    let att_roll = self.rng.d6();
                    let def_roll = self.rng.d6();
                    let success = att_roll + att_str > def_roll + def_av;
                    if success {
                        let inj1 = self.rng.d6();
                        let inj2 = self.rng.d6();
                        let total = inj1 + inj2;
                        let was_cas = total >= 10;
                        let was_ko = total >= 8 && !was_cas;
                        let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                        self.game.field_model.set_player_state(&target_id, PlayerState::new(new_state));
                        events.push(GameEvent::Injury {
                            player_id: target_id.clone(),
                            armor_roll: None,
                            injury_roll: Some([inj1, inj2]),
                            serious_injury: None,
                            was_ko,
                            was_cas,
                        });
                    }
                }
                self.game.acting_player.has_acted = true;
            }

            // TastyMorsel: bite adjacent opponent (like Stab with +1 injury modifier)
            Action::Bite { target_id } => {
                let home = self.game.home_playing;
                let rules = self.game.rules;
                let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let has_skill = if home {
                    self.game.team_home.player(&att_id)
                } else {
                    self.game.team_away.player(&att_id)
                }.map(|p| p.has_skill(SkillId::TastyMorsel) && !p.used_skills.contains(&SkillId::TastyMorsel)).unwrap_or(false);
                if has_skill {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(SkillId::TastyMorsel); }
                    events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: SkillId::TastyMorsel as u16, used: true });
                    let def_is_home = !home;
                    let def_av = if def_is_home {
                        self.game.team_home.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    } else {
                        self.game.team_away.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    };
                    let ar1 = self.rng.d6();
                    let ar2 = self.rng.d6();
                    let armor_broken = is_armour_broken(def_av, ar1 + ar2, rules);
                    events.push(GameEvent::Injury {
                        player_id: target_id.clone(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: None,
                        serious_injury: None,
                        was_ko: false,
                        was_cas: false,
                    });
                    if armor_broken {
                        let inj1 = self.rng.d6();
                        let inj2 = self.rng.d6();
                        let total = inj1 + inj2 + 1; // +1 bite modifier
                        let was_cas = total >= 10;
                        let was_ko = total >= 8 && !was_cas;
                        let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                        self.game.field_model.set_player_state(&target_id, PlayerState::new(new_state));
                        events.push(GameEvent::Injury {
                            player_id: target_id.clone(),
                            armor_roll: None,
                            injury_roll: Some([inj1, inj2]),
                            serious_injury: None,
                            was_ko,
                            was_cas,
                        });
                    }
                }
                self.game.acting_player.has_acted = true;
            }

            // FuriousOutburst / TheFlashingBlade: armor roll against adjacent opponent instead of block
            Action::ArmourRollAttack { target_id } => {
                let home = self.game.home_playing;
                let rules = self.game.rules;
                let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let (has_furious, has_flashing) = if home {
                    let p = self.game.team_home.player(&att_id);
                    (p.map(|p| p.has_skill(SkillId::FuriousOutburst) && !p.used_skills.contains(&SkillId::FuriousOutburst)).unwrap_or(false),
                     p.map(|p| p.has_skill(SkillId::TheFlashingBlade) && !p.used_skills.contains(&SkillId::TheFlashingBlade)).unwrap_or(false))
                } else {
                    let p = self.game.team_away.player(&att_id);
                    (p.map(|p| p.has_skill(SkillId::FuriousOutburst) && !p.used_skills.contains(&SkillId::FuriousOutburst)).unwrap_or(false),
                     p.map(|p| p.has_skill(SkillId::TheFlashingBlade) && !p.used_skills.contains(&SkillId::TheFlashingBlade)).unwrap_or(false))
                };
                let skill_id = if has_furious { Some(SkillId::FuriousOutburst) } else if has_flashing { Some(SkillId::TheFlashingBlade) } else { None };
                if let Some(sk) = skill_id {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(sk); }
                    events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: sk as u16, used: true });
                    let def_is_home = !home;
                    let def_av = if def_is_home {
                        self.game.team_home.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    } else {
                        self.game.team_away.player(&target_id).map(|p| p.armour).unwrap_or(8)
                    };
                    let ar1 = self.rng.d6();
                    let ar2 = self.rng.d6();
                    let armor_broken = is_armour_broken(def_av, ar1 + ar2, rules);
                    events.push(GameEvent::Injury {
                        player_id: target_id.clone(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: None,
                        serious_injury: None,
                        was_ko: false,
                        was_cas: false,
                    });
                    if armor_broken {
                        let inj1 = self.rng.d6();
                        let inj2 = self.rng.d6();
                        let total = inj1 + inj2;
                        let was_cas = total >= 10;
                        let was_ko = total >= 8 && !was_cas;
                        let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                        self.game.field_model.set_player_state(&target_id, PlayerState::new(new_state));
                        events.push(GameEvent::Injury {
                            player_id: target_id.clone(),
                            armor_roll: None,
                            injury_roll: Some([inj1, inj2]),
                            serious_injury: None,
                            was_ko,
                            was_cas,
                        });
                    }
                }
                self.game.acting_player.has_acted = true;
            }

            // BeerBarrelBash: throw keg (once per drive) — similar to ThrowBomb with fixed blast
            Action::ThrowKeg { coord } => {
                let home = self.game.home_playing;
                let rules = self.game.rules;
                let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let has_skill = if home {
                    self.game.team_home.player(&att_id)
                } else {
                    self.game.team_away.player(&att_id)
                }.map(|p| p.has_skill(SkillId::BeerBarrelBash) && !p.used_skills.contains(&SkillId::BeerBarrelBash)).unwrap_or(false);
                if has_skill {
                    let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(SkillId::BeerBarrelBash); }
                    events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: SkillId::BeerBarrelBash as u16, used: true });
                    // Keg hits all players in target square and adjacent (armor roll, no injury modifier)
                    let all_player_ids: Vec<(String, bool)> = self.game.team_home.players.iter()
                        .map(|p| (p.id.clone(), true))
                        .chain(self.game.team_away.players.iter().map(|p| (p.id.clone(), false)))
                        .collect();
                    for (pid, is_home_player) in all_player_ids {
                        if let Some(pcoord) = self.game.field_model.player_coordinate(&pid) {
                            if pcoord == coord || pcoord.is_adjacent(coord) {
                                let av = if is_home_player {
                                    self.game.team_home.player(&pid).map(|p| p.armour).unwrap_or(8)
                                } else {
                                    self.game.team_away.player(&pid).map(|p| p.armour).unwrap_or(8)
                                };
                                let ar1 = self.rng.d6();
                                let ar2 = self.rng.d6();
                                if is_armour_broken(av, ar1 + ar2, rules) {
                                    let inj1 = self.rng.d6();
                                    let inj2 = self.rng.d6();
                                    let total = inj1 + inj2;
                                    let was_cas = total >= 10;
                                    let was_ko = total >= 8 && !was_cas;
                                    let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                                    self.game.field_model.set_player_state(&pid, PlayerState::new(new_state));
                                    events.push(GameEvent::Injury {
                                        player_id: pid.clone(),
                                        armor_roll: Some([ar1, ar2]),
                                        injury_roll: Some([inj1, inj2]),
                                        serious_injury: None,
                                        was_ko,
                                        was_cas,
                                    });
                                } else {
                                    events.push(GameEvent::Injury {
                                        player_id: pid.clone(),
                                        armor_roll: Some([ar1, ar2]),
                                        injury_roll: None,
                                        serious_injury: None,
                                        was_ko: false,
                                        was_cas: false,
                                    });
                                }
                            }
                        }
                    }
                }
                self.game.acting_player.has_acted = true;
            }

            // CatchOfTheDay: at activation, D6 >= 3 picks up ball within 3 squares
            Action::CatchOfTheDay => {
                let home = self.game.home_playing;
                let att_id = self.game.acting_player.player_id.clone().unwrap_or_default();
                let has_skill = if home {
                    self.game.team_home.player(&att_id)
                } else {
                    self.game.team_away.player(&att_id)
                }.map(|p| p.has_skill(SkillId::CatchOfTheDay) && !p.used_skills.contains(&SkillId::CatchOfTheDay)).unwrap_or(false);
                if has_skill {
                    if let (Some(ball_coord), Some(att_coord)) = (
                        self.game.field_model.ball_coordinate,
                        self.game.field_model.player_coordinate(&att_id),
                    ) {
                        let ball_grounded = self.game.field_model.player_at(ball_coord).is_none()
                            || self.game.field_model.player_at(ball_coord).map(|pid| pid.as_str() != att_id.as_str()).unwrap_or(false);
                        if ball_coord.distance_in_steps(att_coord) <= 3 && ball_grounded {
                            let team = if home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&att_id) { p.used_skills.insert(SkillId::CatchOfTheDay); }
                            let roll = self.rng.d6();
                            events.push(GameEvent::SkillUse { player_id: att_id.clone(), skill_id: SkillId::CatchOfTheDay as u16, used: true });
                            if roll >= 3 {
                                self.game.field_model.ball_coordinate = Some(att_coord);
                                events.push(GameEvent::BallPickedUp { player_id: att_id.clone(), coord: att_coord });
                            }
                        }
                    }
                }
                // CatchOfTheDay does not consume the player's activation
            }

            _ => {
                // Unknown actions silently pass through
            }
        }

        self.compute_next_prompt();
        Ok(events)
    }

    /// Roll a single d6 using the engine's RNG.
    pub fn d6(&mut self) -> i32 {
        self.rng.d6()
    }

    /// Roll two d6 using the engine's RNG.
    pub fn d6_two(&mut self) -> i32 {
        self.rng.d6_two()
    }

    // ── Private helpers ───────────────────────────────────────────────────────

    fn compute_next_prompt(&mut self) {
        // If the engine is already waiting for a specific response, don't overwrite it.
        if self.pending_reroll.is_some()
            || self.pending_push.is_some()
            || self.pending_follow_up.is_some()
            || self.pending_block_choice.is_some()
            || self.pending_bribe.is_some()
            || self.pending_piling_on.is_some()
            || self.pending_blood_lust.is_some()
            || self.pending_wrestle.is_some()
            || self.pending_argue_the_call.is_some()
            || self.pending_strip_ball.is_some()
            || self.pending_dump_off.is_some()
            || self.pending_trickster.is_some()
            || self.pending_hit_and_run.is_some()
            || self.pending_putrid_regurgitation.is_some()
            || self.pending_taunt.is_some()
            || self.pending_saboteur.is_some()
            || self.pending_pick_me_up.is_some()
            || self.pending_auto_gaze.is_some()
            || self.pending_baleful_hex.is_some()
            || self.pending_look_into_my_eyes.is_some()
            || self.pending_blastin.is_some()
            || self.pending_wisdom_grant.is_some()
            || self.pending_blast_it.is_some()
        {
            return;
        }

        // PassBlock/OnTheBall: offer defending player movement before interception.
        if let Some(ref pb) = self.pending_pass_block {
            let players = pb.eligible_players.clone();
            self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                eligible_players: players,
                reason: "passBlock".into(),
            });
            return;
        }

        // OnTheBall during kickoff: receiving team positions players before ball lands.
        if let Some(ref otb) = self.pending_on_the_ball_kickoff {
            let players = otb.clone();
            self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                eligible_players: players,
                reason: "onTheBallKickoff".into(),
            });
            return;
        }

        // KickoffReturn (BB2020+): receiving team may move one eligible player up to 3 squares.
        if let Some(ref kr) = self.pending_kickoff_return {
            let players = kr.clone();
            self.cached_prompt = Some(AgentPrompt::KickoffReturn {
                eligible_players: players,
            });
            return;
        }

        // HighKick (BB2020+): receiving team selects one player to move to the ball square.
        if let Some(ref hk) = self.pending_high_kick {
            let players = hk.clone();
            self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                eligible_players: players,
                reason: "highKick".into(),
            });
            return;
        }

        // SolidDefence / Charge (BB2020+): one team selects eligible players to reposition.
        if let Some(ref sd) = self.pending_solid_defence {
            if sd.remaining > 0 && !sd.eligible.is_empty() {
                let players = sd.eligible.clone();
                let reason = if sd.is_charge { "charge" } else { "solidDefence" };
                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                    eligible_players: players,
                    reason: reason.into(),
                });
                return;
            }
        }

        // Apothecary offer takes priority over normal game flow.
        if let Some(ref apo) = self.pending_apothecary {
            let team_id = if apo.player_is_home {
                self.game.team_home.id.clone()
            } else {
                self.game.team_away.id.clone()
            };
            let _ = team_id;
            self.cached_prompt = Some(AgentPrompt::UseApothecary {
                player_id: apo.player_id.clone(),
                apothecary_type: "standard".into(),
            });
            return;
        }

        // Touchback: receiving team picks who gets the ball.
        if self.awaiting_touchback {
            let receiving_home = self.game.home_first_offense;
            let team = if receiving_home { &self.game.team_home } else { &self.game.team_away };
            let eligible: Vec<(String, FieldCoordinate)> = team.players.iter()
                .filter(|p| {
                    self.game.field_model.player_state(&p.id)
                        .map(|s| s.base() <= PS_STUNNED && s.base() >= PS_STANDING)
                        .unwrap_or(false)
                })
                .filter_map(|p| {
                    self.game.field_model.player_coordinate(&p.id)
                        .map(|c| (p.id.clone(), c))
                })
                .collect();
            self.cached_prompt = Some(AgentPrompt::Touchback { eligible_players: eligible });
            return;
        }

        // Intercept: coin flip winner must choose receive/kick before setup.
        if self.awaiting_receive_choice {
            let choosing_team_id = if self.game.home_playing {
                self.game.team_home.id.clone()
            } else {
                self.game.team_away.id.clone()
            };
            self.cached_prompt = Some(AgentPrompt::ReceiveChoice {
                team_id: choosing_team_id,
            });
            return;
        }

        self.cached_prompt = match self.game.turn_mode {
            TurnMode::StartGame => Some(AgentPrompt::CoinChoice {
                is_home: true,
            }),

            TurnMode::Setup => {
                let team_id = if self.game.home_playing {
                    self.game.team_home.id.clone()
                } else {
                    self.game.team_away.id.clone()
                };
                let players: Vec<String> = if self.game.home_playing {
                    self.game.team_home.players.iter().map(|p| p.id.clone()).collect()
                } else {
                    self.game.team_away.players.iter().map(|p| p.id.clone()).collect()
                };
                Some(AgentPrompt::TeamSetup { team_id, players })
            }

            TurnMode::Kickoff => Some(AgentPrompt::KickBall),

            TurnMode::Regular | TurnMode::Blitz => {
                if self.game.is_finished() {
                    None
                } else if self.player_activated_this_turn {
                    // Check if this is a Blitz turn where the block step is still available
                    let is_blitz_pending = self.game.acting_player.is_active()
                        && matches!(
                            self.game.acting_player.player_action,
                            Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)
                        )
                        && !self.game.acting_player.blitz_blocked;

                    if is_blitz_pending {
                        // Blitz block step: re-offer the active player with [Block] only
                        let pid = self.game.acting_player.player_id.clone().unwrap_or_default();
                        let home = self.game.home_playing;
                        let coord = self.game.field_model.player_coordinate(&pid);
                        let opponent = if home { &self.game.team_away } else { &self.game.team_home };
                        let has_adjacent_opponent = if let Some(c) = coord {
                            opponent.players.iter().any(|op| {
                                let oc = self.game.field_model.player_coordinate(&op.id);
                                let os = self.game.field_model.player_state(&op.id);
                                match (oc, os) {
                                    (Some(oc), Some(os)) => oc.is_adjacent(c) && os.has_tacklezones(),
                                    _ => false,
                                }
                            })
                        } else {
                            false
                        };

                        if has_adjacent_opponent {
                            Some(AgentPrompt::ActivatePlayer {
                                eligible_players: vec![(pid, vec![PlayerAction::Block])],
                            })
                        } else {
                            // No adjacent opponents — blitz block not possible, must end turn
                            Some(AgentPrompt::ActivatePlayer { eligible_players: vec![] })
                        }
                    } else {
                        // Active team has already fully activated — agent must end turn
                        Some(AgentPrompt::ActivatePlayer {
                            eligible_players: vec![],
                        })
                    }
                } else {
                    // Offer all Standing/Prone players as eligible to activate
                    let players = self.eligible_players_for_activation();
                    Some(AgentPrompt::ActivatePlayer {
                        eligible_players: players,
                    })
                }
            }

            TurnMode::EndGame => None,

            _ => None,
        };
    }

    fn eligible_players_for_activation(&self) -> Vec<(String, Vec<ffb_model::enums::PlayerAction>)> {
        use ffb_model::enums::PlayerAction;

        let home = self.game.home_playing;
        let team = if home { &self.game.team_home } else { &self.game.team_away };
        let opponent = if home { &self.game.team_away } else { &self.game.team_home };
        let turn_data = if home { &self.game.turn_data_home } else { &self.game.turn_data_away };

        let ball_coord = self.game.field_model.ball_coordinate;

        team.players.iter().filter_map(|p| {
            let state = self.game.field_model.player_state(&p.id)?;
            let base = state.base();
            // Only standing or prone players can be activated; stunned/KO/off-pitch cannot
            let is_standing = state.is_standing();
            let is_prone = base == PS_PRONE;
            if !is_standing && !is_prone {
                return None;
            }
            let coord = self.game.field_model.player_coordinate(&p.id)?;

            if is_prone {
                // Prone players can stand up (and optionally blitz after)
                let mut actions = vec![PlayerAction::StandUp];
                if !turn_data.blitz_used {
                    let adjacent_to_opponent = opponent.players.iter().any(|op| {
                        if let (Some(oc), Some(os)) = (
                            self.game.field_model.player_coordinate(&op.id),
                            self.game.field_model.player_state(&op.id),
                        ) {
                            oc.is_adjacent(coord) && os.has_tacklezones()
                        } else {
                            false
                        }
                    });
                    if adjacent_to_opponent {
                        actions.push(PlayerAction::StandUpBlitz);
                    }
                }
                return Some((p.id.clone(), actions));
            }

            // Standing player
            let mut actions = vec![PlayerAction::Move];

            // Block: adjacent to a standing opponent and no blitz used yet
            // ViciousVines (once per half): can block over distance 2 instead of adjacent
            // KickEmWhileTheyReDown: chainsaw can target prone/KO'd opponents (no tackle zones)
            if !turn_data.blitz_used {
                let has_vicious_vines = p.has_skill(SkillId::ViciousVines)
                    && !p.used_skills.contains(&SkillId::ViciousVines);
                let has_kick_em = p.has_skill(SkillId::KickEmWhileTheyReDown);
                let has_chainsaw = p.has_skill(SkillId::Chainsaw);
                let block_range = if has_vicious_vines { 2 } else { 1 };
                let adjacent_to_opponent = opponent.players.iter().any(|op| {
                    if let (Some(oc), Some(os)) = (
                        self.game.field_model.player_coordinate(&op.id),
                        self.game.field_model.player_state(&op.id),
                    ) {
                        let in_range = oc.distance_in_steps(coord) <= block_range;
                        let valid_target = os.has_tacklezones()
                            || (has_chainsaw && has_kick_em && (os.base() == PS_PRONE || os.base() == PS_STUNNED || os.base() == PS_KNOCKED_OUT));
                        in_range && valid_target
                    } else {
                        false
                    }
                });
                if adjacent_to_opponent {
                    actions.push(PlayerAction::Block);
                    actions.push(PlayerAction::Blitz);
                }
            }

            // Pass: player carries the ball and pass not yet used this turn
            if !turn_data.pass_used && ball_coord == Some(coord) {
                actions.push(PlayerAction::Pass);
            }

            // Hand-off: player carries the ball, hand-over not yet used, friendly teammate adjacent
            if !turn_data.hand_over_used && ball_coord == Some(coord) {
                let teammate_adjacent = team.players.iter().any(|tp| {
                    tp.id != p.id && self.game.field_model.player_coordinate(&tp.id)
                        .map(|tc| tc.is_adjacent(coord))
                        .unwrap_or(false)
                });
                if teammate_adjacent {
                    actions.push(PlayerAction::HandOver);
                }
            }

            // Foul: adjacent to a prone/stunned opponent and foul not yet used
            // SneakiestOfTheLot: player may foul even when foul_used is already true
            let can_foul = !turn_data.foul_used || p.has_skill(SkillId::SneakiestOfTheLot);
            if can_foul {
                let foul_target_exists = opponent.players.iter().any(|op| {
                    if let (Some(oc), Some(os)) = (
                        self.game.field_model.player_coordinate(&op.id),
                        self.game.field_model.player_state(&op.id),
                    ) {
                        oc.is_adjacent(coord) && !os.has_tacklezones()
                            && (os.base() == PS_PRONE || os.base() == PS_STUNNED)
                    } else {
                        false
                    }
                });
                if foul_target_exists {
                    actions.push(PlayerAction::Foul);
                }
            }

            Some((p.id.clone(), actions))
        }).collect()
    }

    /// Place all players of `home` (true) or away (false) team in a canonical formation.
    /// Matches Java ParityRunner.placeReserves() exactly (canonical squares + transform for away).
    fn place_team_canonical(&mut self, home: bool) {
        // Sort players by jersey number (nr), cap at 11 — matches Java.
        // Only place players who are in PS_RESERVE (healthy, available for setup).
        // Players in PS_BADLY_HURT / PS_SERIOUS_INJURY / PS_RIP / PS_KNOCKED_OUT
        // stay in their respective dugout boxes and are NOT placed on the pitch.
        let mut players: Vec<(String, i32)> = if home {
            self.game.team_home.players.iter().map(|p| (p.id.clone(), p.nr)).collect()
        } else {
            self.game.team_away.players.iter().map(|p| (p.id.clone(), p.nr)).collect()
        };
        players.sort_by_key(|&(_, nr)| nr);
        players.truncate(11);
        // Canonical home-perspective squares (mirror of Java's placeReserves)
        // LOS: first 3 players on line of scrimmage (x=12)
        // Overflow: remaining players
        let los: &[(i32, i32)] = &[(12,7),(12,6),(12,8),(12,5),(12,9),(12,4),(12,10)];
        let overflow: &[(i32, i32)] = &[(5,5),(5,7),(5,9),(6,6),(6,8),(4,6),(4,8),(3,6),(3,8),(2,5),(2,9),(1,7)];

        // Compact placement: available players fill canonical slots from slot 0 upward,
        // skipping ejected/injured/KO'd players (they are not placed). This matches Java's
        // placeReserves() which iterates Reserve players in jersey order and places them
        // at consecutive LOS/overflow squares.
        let available: Vec<&(String, i32)> = players.iter().filter(|(pid, _)| {
            match self.game.field_model.player_state(pid) {
                None => true,  // No state = available (game start before first H1 setup)
                Some(s) => s.base() == PS_RESERVE,
            }
        }).collect();

        let n_avail = available.len();
        let los_needed = if n_avail >= 3 { 3 } else { n_avail };

        for (placed, (pid, _)) in available.iter().enumerate() {
            let (ox, oy) = if placed < los_needed {
                los[placed]
            } else {
                let ovf_idx = placed - los_needed;
                if ovf_idx < overflow.len() { overflow[ovf_idx] } else { continue }
            };

            // For away team, transform: x_away = 25 - ox, y = oy
            let coord = if home {
                FieldCoordinate::new(ox, oy)
            } else {
                FieldCoordinate::new(25 - ox, oy)
            };

            self.game.field_model.set_player_coordinate(pid, coord);
            self.game.field_model.set_player_state(pid, PlayerState::new(PS_STANDING));
        }
    }

    /// At end of turn: reset PS_MOVING → PS_STANDING; wake PS_STUNNED → PS_PRONE;
    /// clear active/confused/hypnotized flags; clear per-turn used_skills for all players of the given side.
    fn reset_player_states_end_of_turn(&mut self, home_side: bool) {
        let ids: Vec<String> = if home_side {
            self.game.team_home.players.iter().map(|p| p.id.clone()).collect()
        } else {
            self.game.team_away.players.iter().map(|p| p.id.clone()).collect()
        };
        for pid in &ids {
            if let Some(state) = self.game.field_model.player_state(pid) {
                let base = state.base();
                let new_state = match base {
                    PS_MOVING => state.change_active(false).change_base(PS_STANDING),
                    PS_STUNNED => state.change_active(false).change_base(PS_PRONE),
                    _ => state.change_active(false).recover_tacklezones(),
                };
                self.game.field_model.set_player_state(pid, new_state);
            }
            // Clear per-turn skill usage, preserving once-per-game/half/drive skills
            let team = if home_side { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(pid) {
                p.used_skills.retain(|skill_id| {
                    use ffb_mechanics::skills::skill_def;
                    use ffb_model::enums::SkillUsageType;
                    matches!(skill_def(*skill_id).map(|d| d.usage_type).unwrap_or(SkillUsageType::Regular),
                        SkillUsageType::OncePerGame | SkillUsageType::OncePerHalf | SkillUsageType::OncePerDrive)
                });
            }
        }
    }

    /// Returns true if any standing opponent adjacent to `coord` has the given skill.
    fn any_adjacent_opponent_has_skill(&self, coord: FieldCoordinate, home_moving: bool, skill: SkillId) -> bool {
        let opponent_team = if home_moving { &self.game.team_away } else { &self.game.team_home };
        opponent_team.players.iter().any(|p| {
            let opp_coord = self.game.field_model.player_coordinate(&p.id);
            let opp_state = self.game.field_model.player_state(&p.id);
            match (opp_coord, opp_state) {
                (Some(oc), Some(os)) => oc.is_adjacent(coord) && os.has_tacklezones() && p.has_skill(skill),
                _ => false,
            }
        })
    }

    /// Count block assists for the given side adjacent to `target_coord`.
    ///
    /// Mirrors Java `ServerUtilPlayer.findBlockStrength()`:
    /// - Teammate adjacent to target with tackle zones = potential assist
    /// - Guard: always counts regardless of counter-assists
    /// - Normal assist: only counts if opponent has no other players with tackle zones
    ///   adjacent to the assisting player (i.e., no counter-assist cancels it)
    ///
    /// `home_assisting` = the team providing assists (not necessarily the attacking team).
    /// `target_coord` = where the opponent being blocked is.
    /// `blocker_id` = exclude this player from the assisting-candidate list.
    /// `counter_blocker_id` = the main opponent player (excluded from counter-assist count).
    fn count_block_assists(
        &self,
        home_assisting: bool,
        target_coord: FieldCoordinate,
        blocker_id: &str,
        counter_blocker_id: &str,
    ) -> i32 {
        let assisting_team = if home_assisting { &self.game.team_home } else { &self.game.team_away };
        let opposing_team = if home_assisting { &self.game.team_away } else { &self.game.team_home };

        // Defensive: if the main defender has Defensive, players adjacent to the defender can't assist
        let main_defender_has_defensive = opposing_team.players.iter()
            .find(|p| p.id == counter_blocker_id)
            .map(|p| p.has_skill(SkillId::Defensive))
            .unwrap_or(false);
        let defender_coord = self.game.field_model.player_coordinate(counter_blocker_id);

        assisting_team.players.iter().filter(|candidate| {
            candidate.id != blocker_id
        }).filter(|candidate| {
            let coord = self.game.field_model.player_coordinate(&candidate.id);
            let state = self.game.field_model.player_state(&candidate.id);
            match (coord, state) {
                (Some(c), Some(s)) => c.is_adjacent(target_coord) && s.has_tacklezones(),
                _ => false,
            }
        }).filter(|candidate| {
            // Defensive: candidate cannot assist if they are in the defender's tackle zones
            if main_defender_has_defensive && !candidate.has_skill(SkillId::Guard) {
                if let (Some(dc), Some(cc)) = (defender_coord, self.game.field_model.player_coordinate(&candidate.id)) {
                    if dc.is_adjacent(cc) {
                        return false;
                    }
                }
            }
            // Guard: always assists regardless of counter-assists
            if candidate.has_skill(SkillId::Guard) {
                return true;
            }
            // Normal assist: no opponent (other than the main defender) has tackle zones adjacent to candidate
            let candidate_coord = self.game.field_model.player_coordinate(&candidate.id);
            if let Some(cand_c) = candidate_coord {
                let counter_assists = opposing_team.players.iter().filter(|opp| {
                    opp.id != counter_blocker_id
                }).filter(|opp| {
                    let oc = self.game.field_model.player_coordinate(&opp.id);
                    let os = self.game.field_model.player_state(&opp.id);
                    match (oc, os) {
                        (Some(oc), Some(os)) => oc.is_adjacent(cand_c) && os.has_tacklezones(),
                        _ => false,
                    }
                }).count();
                counter_assists == 0
            } else {
                false
            }
        }).count() as i32
    }

    /// Count standing opposing players that exert tackle zones on `coord`.
    ///
    /// A player exerts tackle zones when `PlayerState::has_tacklezones()` is true.
    fn count_tackle_zones_at(&self, coord: FieldCoordinate, home_moving: bool) -> i32 {
        let opponent_team = if home_moving {
            &self.game.team_away
        } else {
            &self.game.team_home
        };
        opponent_team.players.iter().filter(|p| {
            // Titchy players don't exert a -1 TZ modifier when opponents dodge INTO their square
            if p.has_skill(SkillId::Titchy) { return false; }
            let opp_coord = self.game.field_model.player_coordinate(&p.id);
            let opp_state = self.game.field_model.player_state(&p.id);
            match (opp_coord, opp_state) {
                (Some(oc), Some(os)) => oc.is_adjacent(coord) && os.has_tacklezones(),
                _ => false,
            }
        }).count() as i32
    }

    /// Count opposing players with DisturbingPresence within 3 squares of `coord` that have tackle zones.
    fn count_disturbing_presence(&self, coord: FieldCoordinate, is_home_acting: bool) -> i32 {
        let opposing_team = if is_home_acting { &self.game.team_away } else { &self.game.team_home };
        opposing_team.players.iter()
            .filter(|p| {
                if !p.has_skill(SkillId::DisturbingPresence) { return false; }
                if !self.game.field_model.player_state(&p.id)
                    .map(|s| s.has_tacklezones()).unwrap_or(false) { return false; }
                self.game.field_model.player_coordinate(&p.id)
                    .map(|c| (c.x - coord.x).abs() <= 3 && (c.y - coord.y).abs() <= 3)
                    .unwrap_or(false)
            })
            .count() as i32
    }

    /// Count on-pitch players with FanFavourite skill for the given side (BB2016).
    fn count_fan_favourites_on_pitch(&self, is_home: bool) -> i32 {
        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        team.players.iter()
            .filter(|p| p.has_skill(SkillId::FanFavourite))
            .filter(|p| self.game.field_model.player_coordinate(&p.id).is_some())
            .count() as i32
    }

    /// Whether a given coordinate is the opponent's end zone (for the moving side).
    fn is_opponent_endzone(&self, coord: FieldCoordinate, home_moving: bool) -> bool {
        if home_moving {
            coord.x == 25  // away endzone
        } else {
            coord.x == 0   // home endzone
        }
    }

    /// BallAndChain: auto-resolve random-direction movement for up to MA squares.
    ///
    /// Each step rolls a D8 direction (WhirlingDervish grants one reroll).
    /// - Off-pitch destination: crowd-surf the BallAndChain player and end.
    /// - Occupied by standing opponent: knock them down and resolve injury (like a block),
    ///   then the BallAndChain player falls prone (the flail injures them too on a BothDown).
    /// - Otherwise: move there normally.
    fn apply_ball_and_chain_move(&mut self, player_id: &str) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let home_moving = self.game.home_playing;
        let rules = self.game.rules;

        let (ma, has_whirling_dervish, av) = {
            let team = if home_moving { &self.game.team_home } else { &self.game.team_away };
            let p = team.player(player_id);
            (
                p.map(|p| p.movement).unwrap_or(6),
                p.map(|p| p.has_skill(SkillId::WhirlingDervish)).unwrap_or(false),
                p.map(|p| p.armour).unwrap_or(8),
            )
        };

        let mut whirling_used = false;

        'outer: for step in 0..ma {
            let _ = step;
            let current_coord = match self.game.field_model.player_coordinate(player_id) {
                Some(c) => c,
                None => break,
            };

            let dir_roll = self.rng.d8();
            // WhirlingDervish: reroll direction once per activation if the first would be suboptimal.
            // Simplified: always use the first roll (agent has no choice in direction).
            let final_dir_roll = if has_whirling_dervish && !whirling_used {
                // Reroll and take the higher (less likely to go off-pitch or into opponent).
                // For AI purposes, always reroll when WhirlingDervish is available.
                whirling_used = true;
                events.push(GameEvent::SkillUse {
                    player_id: player_id.to_owned(),
                    skill_id: SkillId::WhirlingDervish as u16,
                    used: true,
                });
                let reroll = self.rng.d8();
                reroll // take the reroll
            } else {
                dir_roll
            };

            use ffb_model::enums::Direction;
            use ffb_mechanics::mechanics::scatter_coordinate;
            let new_coord = match Direction::for_roll(final_dir_roll) {
                Some(dir) => {
                    let (nx, ny) = scatter_coordinate(current_coord.x, current_coord.y, dir, 1);
                    FieldCoordinate::new(nx, ny)
                }
                None => current_coord,
            };

            if !new_coord.is_on_pitch() {
                // BallAndChain player is crowd-surfed
                self.game.field_model.player_coordinates.remove(player_id);
                events.push(GameEvent::ScatterPlayer {
                    player_id: player_id.to_owned(),
                    coords: vec![new_coord],
                });
                let ar1 = self.rng.d6();
                let ar2 = self.rng.d6();
                use ffb_mechanics::mechanics::is_armour_broken;
                let armor_broken = is_armour_broken(av, ar1 + ar2, rules);
                if armor_broken {
                    let ir1 = self.rng.d6();
                    let ir2 = self.rng.d6();
                    let total = ir1 + ir2;
                    let was_cas = total >= 10;
                    let was_ko = total >= 8 && !was_cas;
                    let new_state = if was_cas || was_ko { PlayerState::new(PS_BADLY_HURT) }
                        else { PlayerState::new(PS_PRONE) };
                    self.game.field_model.set_player_state(player_id, new_state);
                    events.push(GameEvent::Injury {
                        player_id: player_id.to_owned(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: Some([ir1, ir2]),
                        serious_injury: None,
                        was_ko,
                        was_cas,
                    });
                } else {
                    self.game.field_model.set_player_state(player_id, PlayerState::new(PS_KNOCKED_OUT));
                    events.push(GameEvent::Injury {
                        player_id: player_id.to_owned(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: None,
                        serious_injury: None,
                        was_ko: false,
                        was_cas: false,
                    });
                }
                self.game.acting_player.has_acted = true;
                return Ok(events);
            }

            // Check for player in destination square
            let occupant = self.game.field_model.player_at(new_coord).map(|s| s.to_owned());
            if let Some(occ_id) = occupant {
                let occ_is_home = self.game.team_home.player(&occ_id).is_some();
                let occ_av = if occ_is_home {
                    self.game.team_home.player(&occ_id).map(|p| p.armour).unwrap_or(8)
                } else {
                    self.game.team_away.player(&occ_id).map(|p| p.armour).unwrap_or(8)
                };
                let occ_standing = self.game.field_model.player_state(&occ_id)
                    .map(|s| s.is_standing()).unwrap_or(false);
                if occ_standing {
                    // Knock the occupant down (flail hit — no block dice, just armor roll)
                    let ar1 = self.rng.d6();
                    let ar2 = self.rng.d6();
                    use ffb_mechanics::mechanics::is_armour_broken;
                    let armor_broken = is_armour_broken(occ_av, ar1 + ar2, rules);
                    if armor_broken {
                        let ir1 = self.rng.d6();
                        let ir2 = self.rng.d6();
                        let total = ir1 + ir2;
                        let was_cas = total >= 10;
                        let was_ko = total >= 8 && !was_cas;
                        let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                        let regen = if was_cas { self.try_regeneration(&occ_id, occ_is_home, &mut events) } else { false };
                        let was_cas_f = was_cas && !regen;
                        let new_state = if !regen && (is_dead || was_cas_f) { PlayerState::new(PS_BADLY_HURT) }
                            else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                            else if !regen { PlayerState::new(PS_PRONE) }
                            else { PlayerState::new(PS_RESERVE) };
                        if !regen { self.game.field_model.set_player_state(&occ_id, new_state); }
                        if was_cas_f {
                            use ffb_mechanics::mechanics::casualty_spp;
                            let cas_spp = casualty_spp(rules, false);
                            self.award_spp(player_id, home_moving, cas_spp);
                            if let Some(si_kind) = si {
                                self.apply_casualty_to_player(&occ_id, occ_is_home, si_kind);
                            }
                        }
                        events.push(GameEvent::Injury {
                            player_id: occ_id.clone(),
                            armor_roll: Some([ar1, ar2]),
                            injury_roll: Some([ir1, ir2]),
                            serious_injury: si,
                            was_ko,
                            was_cas: was_cas_f,
                        });
                    } else {
                        // Armor held: occupant knocked prone
                        let cur_state = self.game.field_model.player_state(&occ_id).unwrap_or(PlayerState::new(PS_STANDING));
                        self.game.field_model.set_player_state(&occ_id, cur_state.change_base(PS_PRONE).change_active(false));
                        events.push(GameEvent::Injury {
                            player_id: occ_id.clone(),
                            armor_roll: Some([ar1, ar2]),
                            injury_roll: None,
                            serious_injury: None,
                            was_ko: false,
                            was_cas: false,
                        });
                    }
                    // BallAndChain player is also knocked prone (they fall too)
                    let bac_state = self.game.field_model.player_state(player_id).unwrap_or(PlayerState::new(PS_STANDING));
                    self.game.field_model.set_player_state(player_id, bac_state.change_base(PS_PRONE).change_active(false));
                    events.push(GameEvent::PlayerFellDown {
                        player_id: player_id.to_owned(),
                        coord: current_coord,
                    });
                    self.game.acting_player.has_acted = true;
                    break 'outer;
                }
            }

            // Clear square: move there
            self.game.field_model.set_player_coordinate(player_id, new_coord);
            events.push(GameEvent::PlayerMoved {
                player_id: player_id.to_owned(),
                coord: new_coord,
            });
        }

        self.game.acting_player.has_acted = true;
        Ok(events)
    }

    /// Resolve a Block action against `defender_id`.
    ///
    /// Simplified auto-resolution: roll dice, choose best result for attacker,
    /// handle armor/injury chain. No multi-step prompting (BlockChoice/PushTo/FollowUp).
    /// Stab: attacker with the Stab skill directly rolls armor against an adjacent opponent
    /// (no block dice). On armor break → full injury roll. Attacker uses their action.
    fn apply_stab(
        &mut self,
        attacker_id: &str,
        defender_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let rules = self.game.rules;
        let home_attacking = self.game.home_playing;

        // Attacker must have Stab skill; Treacherous allows stabbing a teammate
        let (att_has_stab, att_has_treacherous, att_has_master_assassin, att_has_toxin, att_has_sneaky_pair) = if home_attacking {
            let p = self.game.team_home.player(attacker_id);
            (p.map(|p| p.has_skill(SkillId::Stab)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Treacherous) && !p.used_skills.contains(&SkillId::Treacherous)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::MasterAssassin)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ToxinConnoisseur)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ASneakyPair)).unwrap_or(false))
        } else {
            let p = self.game.team_away.player(attacker_id);
            (p.map(|p| p.has_skill(SkillId::Stab)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Treacherous) && !p.used_skills.contains(&SkillId::Treacherous)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::MasterAssassin)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ToxinConnoisseur)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ASneakyPair)).unwrap_or(false))
        };
        // Treacherous: can stab a ball-carrying teammate to steal the ball (no turnover)
        let defender_is_teammate = if home_attacking {
            self.game.team_home.player(defender_id).is_some()
        } else {
            self.game.team_away.player(defender_id).is_some()
        };
        if defender_is_teammate && att_has_treacherous {
            // Mark Treacherous used and emit SkillUse
            let team = if home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(attacker_id) { p.used_skills.insert(SkillId::Treacherous); }
            events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::Treacherous as u16, used: true });
            let teammate_av = if home_attacking {
                self.game.team_home.player(defender_id).map(|p| p.armour).unwrap_or(8)
            } else {
                self.game.team_away.player(defender_id).map(|p| p.armour).unwrap_or(8)
            };
            let ar1 = self.rng.d6(); let ar2 = self.rng.d6();
            let armor_broken = is_armour_broken(teammate_av, ar1 + ar2, rules);
            events.push(GameEvent::Injury { player_id: defender_id.to_owned(), armor_roll: Some([ar1, ar2]), injury_roll: None, serious_injury: None, was_ko: false, was_cas: false });
            if armor_broken {
                let inj1 = self.rng.d6(); let inj2 = self.rng.d6();
                let total = inj1 + inj2;
                let was_cas = total >= 10; let was_ko = total >= 8 && !was_cas;
                let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                self.game.field_model.set_player_state(defender_id, PlayerState::new(new_state));
                events.push(GameEvent::Injury { player_id: defender_id.to_owned(), armor_roll: None, injury_roll: Some([inj1, inj2]), serious_injury: None, was_ko, was_cas });
                // Take the ball if teammate had it
                if self.game.field_model.ball_coordinate == self.game.field_model.player_coordinate(defender_id) {
                    if let Some(att_coord) = self.game.field_model.player_coordinate(attacker_id) {
                        self.game.field_model.ball_coordinate = Some(att_coord);
                        events.push(GameEvent::BallPickedUp { player_id: attacker_id.to_owned(), coord: att_coord });
                    }
                }
            }
            self.game.acting_player.has_acted = true;
            return Ok(events);
        }
        if !att_has_stab {
            return Ok(events);
        }
        // ASneakyPair: +1 armor and +1 injury when stabbing if the partner is adjacent to target.
        let stab_sneaky_pair_mod = if att_has_sneaky_pair && rules != Rules::Bb2016 {
            let target_coord = self.game.field_model.player_coordinate(defender_id).unwrap_or(FieldCoordinate::new(13, 7));
            let att_team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
            let partner_adj = att_team.players.iter()
                .filter(|p| p.id != attacker_id && p.has_skill(SkillId::ASneakyPair))
                .any(|p| {
                    let state = self.game.field_model.player_state(&p.id).unwrap_or(PlayerState::new(PS_PRONE));
                    if !state.has_tacklezones() { return false; }
                    let coord = match self.game.field_model.player_coordinate(&p.id) { Some(c) => c, None => return false };
                    coord.distance_in_steps(target_coord) <= 1
                });
            if partner_adj { 1 } else { 0 }
        } else { 0 };

        let def_is_home = !home_attacking;
        let def_av = if home_attacking {
            self.game.team_away.player(defender_id).map(|p| p.armour).unwrap_or(8)
        } else {
            self.game.team_home.player(defender_id).map(|p| p.armour).unwrap_or(8)
        };

        // Stakes (BB2016): +1 armor roll when stabbing an undead-roster player
        let stakes_mod = if rules == Rules::Bb2016 {
            let att_has_stakes = if home_attacking {
                self.game.team_home.player(attacker_id)
            } else {
                self.game.team_away.player(attacker_id)
            }.map(|p| p.has_skill(SkillId::Stakes)).unwrap_or(false);
            if att_has_stakes {
                let def_team = if home_attacking { &self.game.team_away } else { &self.game.team_home };
                let is_undead = is_undead_race(&def_team.race)
                    || def_team.player(defender_id).and_then(|p| p.race.as_deref()).map(is_undead_race).unwrap_or(false);
                if is_undead { 1 } else { 0 }
            } else { 0 }
        } else { 0 };

        // Stab: roll 2d6 against defender's armor (no MightyBlow bonus)
        let ar1 = self.rng.d6();
        let ar2 = self.rng.d6();
        let armor_broken = is_armour_broken(def_av, ar1 + ar2 + stab_sneaky_pair_mod + stakes_mod, rules);

        if armor_broken {
            let ir1 = self.rng.d6();
            let ir2 = self.rng.d6();
            let niggling_mod = self.niggling_injury_mod(defender_id, def_is_home);
            // ToxinConnoisseur: +1 to injury roll when result is not yet CAS
            let toxin_mod = if att_has_toxin { 1 } else { 0 };
            let initial_total = ir1 + ir2 + niggling_mod + toxin_mod + stab_sneaky_pair_mod;
            // MasterAssassin: re-roll injury die once if result is not CAS (once per game implicit via Stab context)
            let (final_ir1, final_ir2, total) = if att_has_master_assassin && initial_total < 10 {
                events.push(GameEvent::SkillUse {
                    player_id: attacker_id.to_owned(),
                    skill_id: SkillId::MasterAssassin as u16,
                    used: true,
                });
                let r1 = self.rng.d6();
                let r2 = self.rng.d6();
                (r1, r2, r1 + r2 + niggling_mod)
            } else {
                (ir1, ir2, initial_total)
            };
            let mut was_cas = total >= 10;
            let mut was_ko = total >= 8 && !was_cas;
            // ThickSkull: on KO, roll D6; on 4+ downgrade to Stunned
            if was_ko && self.check_thick_skull(defender_id, def_is_home, &mut events) {
                was_ko = false;
            }
            // Decay: BH/Stunned result becomes CAS
            let def_has_decay_stab = if home_attacking {
                self.game.team_away.player(defender_id)
            } else {
                self.game.team_home.player(defender_id)
            }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
            if def_has_decay_stab && !was_cas && !was_ko {
                was_cas = true;
            }
            let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
            let regen = if was_cas {
                self.try_regeneration(defender_id, def_is_home, &mut events)
            } else { false };
            let was_cas = was_cas && !regen;
            let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                else if !regen { let st = self.game.field_model.player_state(defender_id).unwrap_or(PlayerState::new(PS_STANDING)); st.change_base(PS_PRONE).change_active(false) }
                else { PlayerState::new(PS_RESERVE) };
            if !regen { self.game.field_model.set_player_state(defender_id, new_state); }
            if was_cas {
                use ffb_mechanics::mechanics::casualty_spp;
                let cas_spp = casualty_spp(rules, false);
                // BB2025: special-action CAS only grants SPP with ViolentInnovator
                let grants_spp = rules != Rules::Bb2025 || {
                    let att_team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
                    att_team.player(attacker_id).map(|p| p.has_skill(SkillId::ViolentInnovator)).unwrap_or(false)
                };
                if grants_spp { self.award_spp(attacker_id, home_attacking, cas_spp); }
                if let Some(si_kind) = si {
                    self.apply_casualty_to_player(defender_id, def_is_home, si_kind);
                }
            }
            events.push(GameEvent::Injury {
                player_id: defender_id.to_owned(),
                armor_roll: Some([ar1, ar2]),
                injury_roll: Some([final_ir1, final_ir2]),
                serious_injury: si,
                was_ko,
                was_cas,
            });
        } else {
            events.push(GameEvent::Injury {
                player_id: defender_id.to_owned(),
                armor_roll: Some([ar1, ar2]),
                injury_roll: None,
                serious_injury: None,
                was_ko: false,
                was_cas: false,
            });
        }

        self.game.acting_player.has_acted = true;
        Ok(events)
    }

    /// BreatheFire (BB2020+): roll 1D6 against an adjacent opponent.
    /// - 6: KNOCK_DOWN — defender takes armor+injury roll (full casualty path)
    /// - 1 or effective 1: FAILURE — attacker takes armor+injury roll (turnover)
    /// - effective < 4: NO_EFFECT
    /// - effective 4-5: PRONE — defender goes prone, no armor roll
    /// "Effective" roll is roll-1 when defender ST > 4.
    fn apply_breathe_fire(
        &mut self,
        attacker_id: &str,
        home_attacking: bool,
        defender_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        let def_st = if home_attacking {
            self.game.team_away.player(defender_id).map(|p| p.strength).unwrap_or(3)
        } else {
            self.game.team_home.player(defender_id).map(|p| p.strength).unwrap_or(3)
        };

        let strong_opponent = def_st > 4;
        let roll = self.rng.d6();
        let effective_roll = if strong_opponent { roll - 1 } else { roll };

        let knock_down = roll == 6;
        let failure = !knock_down && (roll == 1 || effective_roll == 1);
        let prone = !knock_down && !failure && effective_roll >= 4;

        events.push(GameEvent::BreatheFireRoll {
            attacker_id: attacker_id.to_owned(),
            defender_id: defender_id.to_owned(),
            roll,
            knock_down,
            prone,
            failure,
            rerolled: false,
        });

        if knock_down {
            // Defender knocked down — armor+injury roll (no armor modifier)
            let def_is_home = !home_attacking;
            let def_av = if def_is_home {
                self.game.team_home.player(defender_id).map(|p| p.armour).unwrap_or(8)
            } else {
                self.game.team_away.player(defender_id).map(|p| p.armour).unwrap_or(8)
            };
            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            let niggling = self.niggling_injury_mod(defender_id, def_is_home);
            if is_armour_broken(def_av, ar1 + ar2, self.game.rules) {
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2 + niggling;
                let mut was_cas = total >= 10;
                let mut was_ko = total >= 8 && !was_cas;
                if was_ko && self.check_thick_skull(defender_id, def_is_home, &mut events) {
                    was_ko = false;
                }
                let has_decay = if def_is_home {
                    self.game.team_home.player(defender_id)
                } else {
                    self.game.team_away.player(defender_id)
                }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                if has_decay && !was_cas && !was_ko { was_cas = true; }
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let regen = if was_cas { self.try_regeneration(defender_id, def_is_home, &mut events) } else { false };
                let was_cas = was_cas && !regen;
                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) };
                if !regen { self.game.field_model.set_player_state(defender_id, new_state); }
                if was_cas {
                    if let Some(si_kind) = si { self.apply_casualty_to_player(defender_id, def_is_home, si_kind); }
                    use ffb_mechanics::mechanics::casualty_spp;
                    let cas_spp = casualty_spp(self.game.rules, false);
                    // BB2025: BreatheFire CAS only grants SPP with ViolentInnovator
                    let bf_grants_spp = self.game.rules != Rules::Bb2025 || {
                        let att_team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
                        att_team.player(attacker_id).map(|p| p.has_skill(SkillId::ViolentInnovator)).unwrap_or(false)
                    };
                    if bf_grants_spp { self.award_spp(attacker_id, home_attacking, cas_spp); }
                }
                events.push(GameEvent::Injury {
                    player_id: defender_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                // Armor held — defender just goes prone
                self.game.field_model.set_player_state(defender_id, PlayerState::new(PS_PRONE));
                events.push(GameEvent::Injury {
                    player_id: defender_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
            }
        } else if prone {
            // Defender placed prone (no armor roll)
            self.game.field_model.set_player_state(defender_id, PlayerState::new(PS_PRONE));
            events.push(GameEvent::PlayerFellDown {
                player_id: defender_id.to_owned(),
                coord: self.game.field_model.player_coordinate(defender_id).unwrap_or(FieldCoordinate::new(0, 0)),
            });
        } else if failure {
            // Attacker burns themselves — they take armor+injury roll (turnover)
            let att_is_home = home_attacking;
            let att_av = if att_is_home {
                self.game.team_home.player(attacker_id).map(|p| p.armour).unwrap_or(8)
            } else {
                self.game.team_away.player(attacker_id).map(|p| p.armour).unwrap_or(8)
            };
            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            if is_armour_broken(att_av, ar1 + ar2, self.game.rules) {
                let niggling = self.niggling_injury_mod(attacker_id, att_is_home);
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2 + niggling;
                let mut was_cas = total >= 10;
                let mut was_ko = total >= 8 && !was_cas;
                if was_ko && self.check_thick_skull(attacker_id, att_is_home, &mut events) { was_ko = false; }
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let regen = if was_cas { self.try_regeneration(attacker_id, att_is_home, &mut events) } else { false };
                let was_cas = was_cas && !regen;
                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) };
                if !regen { self.game.field_model.set_player_state(attacker_id, new_state); }
                if was_cas {
                    if let Some(si_kind) = si { self.apply_casualty_to_player(attacker_id, att_is_home, si_kind); }
                }
                events.push(GameEvent::Injury {
                    player_id: attacker_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                self.game.field_model.set_player_state(attacker_id, PlayerState::new(PS_PRONE));
                events.push(GameEvent::Injury {
                    player_id: attacker_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
            }
            // Turnover
            self.game.acting_player.clear();
        }

        Ok(events)
    }

    /// ProjectileVomit (BB2020+, PutridRegurgitation): roll 1D6 against an adjacent opponent.
    /// - Roll 2+: success — defender takes full armor+injury roll
    /// - Roll 1: failure — attacker takes armor+injury roll (turnover)
    fn apply_projectile_vomit(
        &mut self,
        attacker_id: &str,
        home_attacking: bool,
        defender_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        let roll = self.rng.d6();
        let success = roll >= 2;

        events.push(GameEvent::ProjectileVomitRoll {
            attacker_id: attacker_id.to_owned(),
            defender_id: defender_id.to_owned(),
            roll,
            success,
            rerolled: false,
        });

        if success {
            let def_is_home = !home_attacking;
            let def_av = if def_is_home {
                self.game.team_home.player(defender_id).map(|p| p.armour).unwrap_or(8)
            } else {
                self.game.team_away.player(defender_id).map(|p| p.armour).unwrap_or(8)
            };
            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            let niggling = self.niggling_injury_mod(defender_id, def_is_home);
            if is_armour_broken(def_av, ar1 + ar2, self.game.rules) {
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2 + niggling;
                let mut was_cas = total >= 10;
                let mut was_ko = total >= 8 && !was_cas;
                if was_ko && self.check_thick_skull(defender_id, def_is_home, &mut events) { was_ko = false; }
                let has_decay = if def_is_home {
                    self.game.team_home.player(defender_id)
                } else {
                    self.game.team_away.player(defender_id)
                }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                if has_decay && !was_cas && !was_ko { was_cas = true; }
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let regen = if was_cas { self.try_regeneration(defender_id, def_is_home, &mut events) } else { false };
                let was_cas = was_cas && !regen;
                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) };
                if !regen { self.game.field_model.set_player_state(defender_id, new_state); }
                if was_cas {
                    if let Some(si_kind) = si { self.apply_casualty_to_player(defender_id, def_is_home, si_kind); }
                    use ffb_mechanics::mechanics::casualty_spp;
                    let cas_spp = casualty_spp(self.game.rules, false);
                    self.award_spp(attacker_id, home_attacking, cas_spp);
                }
                events.push(GameEvent::Injury {
                    player_id: defender_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                self.game.field_model.set_player_state(defender_id, PlayerState::new(PS_PRONE));
                events.push(GameEvent::Injury {
                    player_id: defender_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
            }
        } else {
            // Failure — attacker takes armor+injury roll (turnover)
            let att_av = if home_attacking {
                self.game.team_home.player(attacker_id).map(|p| p.armour).unwrap_or(8)
            } else {
                self.game.team_away.player(attacker_id).map(|p| p.armour).unwrap_or(8)
            };
            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            if is_armour_broken(att_av, ar1 + ar2, self.game.rules) {
                let niggling = self.niggling_injury_mod(attacker_id, home_attacking);
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2 + niggling;
                let mut was_cas = total >= 10;
                let mut was_ko = total >= 8 && !was_cas;
                if was_ko && self.check_thick_skull(attacker_id, home_attacking, &mut events) { was_ko = false; }
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let regen = if was_cas { self.try_regeneration(attacker_id, home_attacking, &mut events) } else { false };
                let was_cas = was_cas && !regen;
                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) };
                if !regen { self.game.field_model.set_player_state(attacker_id, new_state); }
                if was_cas {
                    if let Some(si_kind) = si { self.apply_casualty_to_player(attacker_id, home_attacking, si_kind); }
                }
                events.push(GameEvent::Injury {
                    player_id: attacker_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                self.game.field_model.set_player_state(attacker_id, PlayerState::new(PS_PRONE));
                events.push(GameEvent::Injury {
                    player_id: attacker_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
            }
            self.game.acting_player.clear();
        }

        Ok(events)
    }

    fn apply_block(
        &mut self,
        attacker_id: &str,
        defender_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let home_attacking = self.game.home_playing;
        let rules = self.game.rules;

        // Attacker stats + skills
        let tmp_claws = self.game.acting_player.temporary_claws;
        let (att_str_base, att_has_block, att_has_horns, att_has_dauntless,
             att_has_claws, att_has_mb, att_has_piling_on, att_has_grab, att_has_wrestle,
             att_has_juggernaut, att_has_strip_ball, att_has_brawler, att_has_hatred, att_has_woodland_fury,
             att_has_consummate_professional) = if home_attacking {
            let p = self.game.team_home.player(attacker_id);
            (p.map(|p| p.strength).unwrap_or(3),
             p.map(|p| p.has_skill(SkillId::Block)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Horns)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Dauntless)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Claw)).unwrap_or(false) || tmp_claws,
             p.map(|p| p.has_skill(SkillId::MightyBlow)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::PilingOn)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Grab)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Juggernaut)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::StripBall)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Brawler)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Hatred)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::WoodlandFury)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ConsummateProfessional) && !p.used_skills.contains(&SkillId::ConsummateProfessional)).unwrap_or(false))
        } else {
            let p = self.game.team_away.player(attacker_id);
            (p.map(|p| p.strength).unwrap_or(3),
             p.map(|p| p.has_skill(SkillId::Block)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Horns)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Dauntless)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Claw)).unwrap_or(false) || tmp_claws,
             p.map(|p| p.has_skill(SkillId::MightyBlow)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::PilingOn)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Grab)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Juggernaut)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::StripBall)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Brawler)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Hatred)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::WoodlandFury)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::ConsummateProfessional) && !p.used_skills.contains(&SkillId::ConsummateProfessional)).unwrap_or(false))
        };

        // Defender stats + skills
        let (def_str, _def_av, def_sidestep_raw, def_has_wrestle) = if home_attacking {
            let p = self.game.team_away.player(defender_id);
            (p.map(|p| p.strength).unwrap_or(3),
             p.map(|p| p.armour).unwrap_or(8),
             p.map(|p| p.has_skill(SkillId::SideStep) || p.has_skill(SkillId::Sidestep)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false))
        } else {
            let p = self.game.team_home.player(defender_id);
            (p.map(|p| p.strength).unwrap_or(3),
             p.map(|p| p.armour).unwrap_or(8),
             p.map(|p| p.has_skill(SkillId::SideStep) || p.has_skill(SkillId::Sidestep)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false))
        };
        // Grab cancels Sidestep (BB2020 rule: Grab > Sidestep)
        let def_has_sidestep = def_sidestep_raw && !att_has_grab;

        // ViciousVines: once per half, can block over distance 2; mark as used when distance > 1
        {
            let att_coord = self.game.field_model.player_coordinate(attacker_id);
            let def_coord = self.game.field_model.player_coordinate(defender_id);
            if let (Some(ac), Some(dc)) = (att_coord, def_coord) {
                if ac.distance_in_steps(dc) > 1 {
                    let vv_avail = if home_attacking {
                        self.game.team_home.player(attacker_id)
                    } else {
                        self.game.team_away.player(attacker_id)
                    }.map(|p| p.has_skill(SkillId::ViciousVines) && !p.used_skills.contains(&SkillId::ViciousVines)).unwrap_or(false);
                    if vv_avail {
                        let team = if home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = team.player_mut(attacker_id) { p.used_skills.insert(SkillId::ViciousVines); }
                        events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::ViciousVines as u16, used: true });
                    }
                }
            }
        }

        // WorkingInTandem (BB2025): Lucien (value="block") can reroll a single die when Valen (value="pass")
        // is adjacent to the defender AND Lucien hasn't used it this game.
        let att_has_working_in_tandem_block = if self.game.rules == Rules::Bb2025 {
            let attacker_has_lucien_variant = if home_attacking {
                self.game.team_home.player(attacker_id)
            } else {
                self.game.team_away.player(attacker_id)
            }.map(|p| {
                p.has_skill(SkillId::WorkingInTandem)
                    && !p.used_skills.contains(&SkillId::WorkingInTandem)
                    && p.starting_skills.iter().chain(p.extra_skills.iter())
                        .any(|sw| sw.skill_id == SkillId::WorkingInTandem
                            && sw.value.as_deref() == Some("block"))
            }).unwrap_or(false);
            if attacker_has_lucien_variant {
                let def_coord_opt = self.game.field_model.player_coordinate(defender_id);
                if let Some(def_coord) = def_coord_opt {
                    let partner_team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
                    partner_team.players.iter().any(|p| {
                        p.id != attacker_id
                            && p.has_skill(SkillId::WorkingInTandem)
                            && self.game.field_model.player_state(&p.id)
                                .map(|s| s.has_tacklezones()).unwrap_or(false)
                            && self.game.field_model.player_coordinate(&p.id)
                                .map(|c| c.distance_in_steps(def_coord) <= 1).unwrap_or(false)
                    })
                } else { false }
            } else { false }
        } else { false };

        // Foul Appearance: attacker must roll 2+ or the block action is lost.
        let def_has_foul_appearance = if home_attacking {
            self.game.team_away.player(defender_id)
        } else {
            self.game.team_home.player(defender_id)
        }.map(|p| p.has_skill(SkillId::FoulAppearance)).unwrap_or(false);
        if def_has_foul_appearance {
            let fa_roll = self.rng.d6();
            let fa_ok = fa_roll >= 2;
            events.push(GameEvent::FoulAppearanceRoll {
                player_id: defender_id.to_owned(),
                roll: fa_roll,
                failed: !fa_ok,
            });
            if !fa_ok {
                // Block is cancelled
                self.game.acting_player.has_acted = true;
                if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                    self.game.acting_player.blitz_blocked = true;
                }
                return Ok(events);
            }
        }

        // DumpOff: if defender has ball + DumpOff skill + pass not yet used, offer it
        {
            let def_has_ball = self.game.field_model.ball_coordinate
                == self.game.field_model.player_coordinate(defender_id)
                && self.game.field_model.ball_in_play;
            let def_is_home = !home_attacking;
            let (def_has_dump_off, pass_used) = if def_is_home {
                let p = self.game.team_home.player(defender_id);
                let td = &self.game.turn_data_home;
                (p.map(|p| p.has_skill(SkillId::DumpOff)).unwrap_or(false), td.pass_used)
            } else {
                let p = self.game.team_away.player(defender_id);
                let td = &self.game.turn_data_away;
                (p.map(|p| p.has_skill(SkillId::DumpOff)).unwrap_or(false), td.pass_used)
            };
            if def_has_ball && def_has_dump_off && !pass_used {
                self.pending_dump_off = Some(PendingDumpOff {
                    attacker_id: attacker_id.to_owned(),
                    defender_id: defender_id.to_owned(),
                    home_attacking,
                });
                self.cached_prompt = Some(AgentPrompt::SkillUse {
                    player_id: defender_id.to_owned(),
                    skill_id: SkillId::DumpOff as u16,
                    skill_name: "DumpOff".into(),
                });
                return Ok(events);
            }
        }

        // Trickster: defender may move one square before the block resolves (once per game).
        if self.pending_trickster.is_none() {
            let def_is_home = !home_attacking;
            let (def_has_trickster, def_trickster_used, def_has_ball_and_chain) = if def_is_home {
                let p = self.game.team_home.player(defender_id);
                (p.map(|p| p.has_skill(SkillId::Trickster)).unwrap_or(false),
                 p.map(|p| p.used_skills.contains(&SkillId::Trickster)).unwrap_or(false),
                 p.map(|p| p.has_skill(SkillId::BallAndChain)).unwrap_or(false))
            } else {
                let p = self.game.team_away.player(defender_id);
                (p.map(|p| p.has_skill(SkillId::Trickster)).unwrap_or(false),
                 p.map(|p| p.used_skills.contains(&SkillId::Trickster)).unwrap_or(false),
                 p.map(|p| p.has_skill(SkillId::BallAndChain)).unwrap_or(false))
            };
            let def_standing = self.game.field_model.player_state(defender_id)
                .map(|s| s.is_standing()).unwrap_or(false);
            if def_has_trickster && !def_trickster_used && !def_has_ball_and_chain && def_standing {
                let def_coord = self.game.field_model.player_coordinate(defender_id);
                if let Some(dc) = def_coord {
                    let eligible: Vec<FieldCoordinate> = dc.neighbours().into_iter()
                        .filter(|c| c.is_on_pitch() && self.game.field_model.player_at(*c).is_none())
                        .collect();
                    if !eligible.is_empty() {
                        self.pending_trickster = Some(PendingTrickster {
                            attacker_id: attacker_id.to_owned(),
                            defender_id: defender_id.to_owned(),
                            home_attacking,
                            eligible_squares: eligible,
                        });
                        self.cached_prompt = Some(AgentPrompt::SkillUse {
                            player_id: defender_id.to_owned(),
                            skill_id: SkillId::Trickster as u16,
                            skill_name: "Trickster".into(),
                        });
                        return Ok(events);
                    }
                }
            }
        }

        // Chainsaw: instead of normal block dice, roll D6.
        // On 1: kickback — the wielder is hit (armor roll +3). On 2+: defender is hit (armor roll +3).
        let att_has_chainsaw = if home_attacking {
            self.game.team_home.player(attacker_id)
        } else {
            self.game.team_away.player(attacker_id)
        }.map(|p| p.has_skill(SkillId::Chainsaw)).unwrap_or(false);

        // GhostlyFlames / Chainsaw block action type check
        let is_blitz_action = matches!(
            self.game.acting_player.player_action,
            Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)
        );

        if att_has_chainsaw {
            let saw_roll = self.rng.d6();
            events.push(GameEvent::ChainsawRoll { player_id: attacker_id.to_owned(), roll: saw_roll });
            if saw_roll == 1 {
                // Kickback — attacker is hit (injury roll directly, no armor roll)
                let att_coord = self.game.field_model.player_coordinate(attacker_id)
                    .unwrap_or(FieldCoordinate::new(12, 7));
                let att_state = self.game.field_model.player_state(attacker_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                self.game.field_model.set_player_state(attacker_id, att_state.change_base(PS_PRONE));
                events.push(GameEvent::PlayerFellDown { player_id: attacker_id.to_owned(), coord: att_coord });
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2;
                let was_cas = total >= 10;
                let was_ko = total >= 8 && !was_cas;
                let (si, _) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let new_state = if was_cas { PlayerState::new(PS_BADLY_HURT) }
                    else if was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else { PlayerState::new(PS_PRONE) };
                self.game.field_model.set_player_state(attacker_id, new_state);
                events.push(GameEvent::Injury {
                    player_id: attacker_id.to_owned(),
                    armor_roll: None,
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                // Hit — defender falls; armor roll with +3 modifier (or +4 with GhostlyFlames)
                let def_coord = self.game.field_model.player_coordinate(defender_id)
                    .unwrap_or(FieldCoordinate::new(13, 7));
                let def_is_home = !home_attacking;
                let def_av = if def_is_home {
                    self.game.team_home.player(defender_id).map(|p| p.armour).unwrap_or(8)
                } else {
                    self.game.team_away.player(defender_id).map(|p| p.armour).unwrap_or(8)
                };
                // GhostlyFlames (BB2020+): once per half, +4 instead of +3 when blitzing
                let has_ghostly_flames = if rules != Rules::Bb2016 && is_blitz_action {
                    if home_attacking {
                        self.game.team_home.player(attacker_id)
                    } else {
                        self.game.team_away.player(attacker_id)
                    }.map(|p| {
                        p.has_skill(SkillId::GhostlyFlames)
                            && !p.used_skills.contains(&SkillId::GhostlyFlames)
                    }).unwrap_or(false)
                } else {
                    false
                };
                let chainsaw_mod = if has_ghostly_flames { 4 } else { 3 };
                if has_ghostly_flames {
                    let team = if home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(attacker_id) { p.used_skills.insert(SkillId::GhostlyFlames); }
                    events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::GhostlyFlames as u16, used: true });
                }
                let def_state = self.game.field_model.player_state(defender_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                self.game.field_model.set_player_state(defender_id, def_state.change_base(PS_PRONE));
                events.push(GameEvent::PlayerFellDown { player_id: defender_id.to_owned(), coord: def_coord });
                let ar1 = self.rng.d6();
                let ar2 = self.rng.d6();
                let armor_broken = is_armour_broken(def_av, ar1 + ar2 + chainsaw_mod, rules);
                events.push(GameEvent::Injury {
                    player_id: defender_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
                if armor_broken {
                    let inj1 = self.rng.d6();
                    let inj2 = self.rng.d6();
                    let total = inj1 + inj2;
                    let was_cas = total >= 10;
                    let was_ko = total >= 8 && !was_cas;
                    let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                    let regen = if was_cas { self.try_regeneration(defender_id, !home_attacking, &mut events) } else { false };
                    let was_cas_f = was_cas && !regen;
                    let new_state = if !regen && (is_dead || was_cas_f) { PlayerState::new(PS_BADLY_HURT) }
                        else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                        else if !regen { PlayerState::new(PS_PRONE) }
                        else { PlayerState::new(PS_RESERVE) };
                    self.game.field_model.set_player_state(defender_id, new_state);
                    if was_cas_f {
                        if let Some(si_kind) = si { self.apply_casualty_to_player(defender_id, !home_attacking, si_kind); }
                        use ffb_mechanics::mechanics::casualty_spp;
                        let cas_spp = casualty_spp(rules, false);
                        // BB2025: Chainsaw CAS only grants SPP with ViolentInnovator
                        let chain_grants_spp = rules != Rules::Bb2025 || {
                            let att_team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
                            att_team.player(attacker_id).map(|p| p.has_skill(SkillId::ViolentInnovator)).unwrap_or(false)
                        };
                        if chain_grants_spp { self.award_spp(attacker_id, home_attacking, cas_spp); }
                    }
                    events.push(GameEvent::Injury {
                        player_id: defender_id.to_owned(),
                        armor_roll: None,
                        injury_roll: Some([inj1, inj2]),
                        serious_injury: si,
                        was_ko,
                        was_cas: was_cas_f,
                    });
                }
            }
            // MaximumCarnage: once per game, allow a second chainsaw attack in the same activation (on hit, saw_roll >= 2)
            let max_carnage_avail = {
                let team = if home_attacking { &self.game.team_home } else { &self.game.team_away };
                team.player(attacker_id).map(|p| {
                    p.has_skill(SkillId::MaximumCarnage) && !p.used_skills.contains(&SkillId::MaximumCarnage)
                }).unwrap_or(false)
            };
            if max_carnage_avail {
                let team = if home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
                if let Some(p) = team.player_mut(attacker_id) { p.used_skills.insert(SkillId::MaximumCarnage); }
                events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::MaximumCarnage as u16, used: true });
                // Don't set has_acted — allow another Block/chainsaw action this turn
            } else {
                self.game.acting_player.has_acted = true;
                if is_blitz_action {
                    self.game.acting_player.blitz_blocked = true;
                }
            }
            return Ok(events);
        }

        // Compute assists using coordinates
        let defender_coord = self.game.field_model.player_coordinate(defender_id)
            .unwrap_or(FieldCoordinate::new(13, 7));
        let attacker_coord = self.game.field_model.player_coordinate(attacker_id)
            .unwrap_or(FieldCoordinate::new(12, 7));

        let att_assists = self.count_block_assists(home_attacking, defender_coord, attacker_id, defender_id);
        let def_assists = self.count_block_assists(!home_attacking, attacker_coord, defender_id, attacker_id);

        // Horns: +1 ST when blitzing
        let is_blitz = matches!(
            self.game.acting_player.player_action,
            Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)
        );
        let horns_bonus = if att_has_horns && is_blitz { 1 } else { 0 };

        // Dauntless: roll D6 to match defender's ST if attacker ST is lower
        let att_str = att_str_base + horns_bonus;
        let att_str = if att_has_dauntless && att_str < def_str {
            let daunt_roll = self.rng.d6();
            let daunt_min = minimum_roll_dauntless(att_str, def_str);
            let mut daunt_success = daunt_roll >= daunt_min;
            events.push(GameEvent::DauntlessRoll {
                player_id: attacker_id.to_owned(),
                roll: daunt_roll,
                success: daunt_success,
            });
            // BlindRage: free reroll on failed Dauntless roll
            if !daunt_success {
                let blind_rage_avail = if home_attacking {
                    self.game.team_home.player(attacker_id)
                } else {
                    self.game.team_away.player(attacker_id)
                }.map(|p| p.has_skill(SkillId::BlindRage) && !p.used_skills.contains(&SkillId::BlindRage)).unwrap_or(false);
                if blind_rage_avail {
                    if home_attacking { if let Some(p) = self.game.team_home.player_mut(attacker_id) { p.used_skills.insert(SkillId::BlindRage); } }
                    else if let Some(p) = self.game.team_away.player_mut(attacker_id) { p.used_skills.insert(SkillId::BlindRage); }
                    events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::BlindRage as u16, used: true });
                    let rr = self.rng.d6();
                    daunt_success = rr >= daunt_min;
                    events.push(GameEvent::DauntlessRoll { player_id: attacker_id.to_owned(), roll: rr, success: daunt_success });
                }
            }
            // Indomitable: once per game, after successful Dauntless, double attacker ST
            let indomitable_bonus = if daunt_success {
                let avail = if home_attacking {
                    self.game.team_home.player(attacker_id)
                } else {
                    self.game.team_away.player(attacker_id)
                }.map(|p| p.has_skill(SkillId::Indomitable) && !p.used_skills.contains(&SkillId::Indomitable)).unwrap_or(false);
                if avail {
                    if home_attacking { if let Some(p) = self.game.team_home.player_mut(attacker_id) { p.used_skills.insert(SkillId::Indomitable); } }
                    else if let Some(p) = self.game.team_away.player_mut(attacker_id) { p.used_skills.insert(SkillId::Indomitable); }
                    events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::Indomitable as u16, used: true });
                    def_str // add def_str more → total = def_str * 2
                } else { 0 }
            } else { 0 };
            if daunt_success { def_str + indomitable_bonus } else { att_str }
        } else {
            att_str
        };

        let eff_att_str = att_str + att_assists;
        let eff_def_str = def_str + def_assists;

        let mut n_dice = block_dice_count(eff_att_str, eff_def_str);
        // GoredByTheBull: once per game, +1 block die when blitzing (attacker picks)
        if is_blitz {
            let gtb_avail = if home_attacking {
                self.game.team_home.player(attacker_id)
            } else {
                self.game.team_away.player(attacker_id)
            }.map(|p| p.has_skill(SkillId::GoredByTheBull) && !p.used_skills.contains(&SkillId::GoredByTheBull)).unwrap_or(false);
            if gtb_avail {
                if home_attacking { if let Some(p) = self.game.team_home.player_mut(attacker_id) { p.used_skills.insert(SkillId::GoredByTheBull); } }
                else if let Some(p) = self.game.team_away.player_mut(attacker_id) { p.used_skills.insert(SkillId::GoredByTheBull); }
                events.push(GameEvent::SkillUse { player_id: attacker_id.to_owned(), skill_id: SkillId::GoredByTheBull as u16, used: true });
                n_dice += 1; // +1 from attacker's perspective (negative → less disadvantage, positive → more dice)
            }
        }
        let n_rolls = n_dice.unsigned_abs() as usize;
        let attacker_picks = n_dice >= 0;

        // Roll all dice
        let dice: Vec<i32> = (0..n_rolls.max(1)).map(|_| self.rng.d6()).collect();
        let results: Vec<BlockResult> = dice.iter().map(|&d| block_result_for_roll(d)).collect();

        // When the attacker picks and has 2+ dice, pause for an agent die choice.
        // When the defender picks (n_dice < 0) or there's only 1 die, auto-select.
        let auto_chosen = if !attacker_picks || n_dice <= 1 {
            Some(Self::pick_best_block_result(&results, attacker_picks))
        } else {
            None
        };

        let selected_index = auto_chosen
            .map(|chosen| results.iter().position(|&r| r == chosen).unwrap_or(0) as i32)
            .unwrap_or(0);

        events.push(GameEvent::BlockRoll {
            attacker_id: attacker_id.to_owned(),
            defender_id: defender_id.to_owned(),
            nr_of_dice: n_dice,
            dice: dice.clone(),
            selected_index,
            own_choice: attacker_picks,
            rerolled: false,
        });

        // Juggernaut when blitzing: treat as having Block for BothDown; defender Wrestle/Sidestep ignored
        let juggernaut_active = att_has_juggernaut && is_blitz;
        let eff_att_has_block = att_has_block || juggernaut_active;
        let eff_def_has_sidestep = def_has_sidestep && !juggernaut_active;
        let eff_def_has_wrestle = def_has_wrestle && !juggernaut_active;

        let context = PendingBlockChoice {
            attacker_id: attacker_id.to_owned(),
            defender_id: defender_id.to_owned(),
            home_attacking,
            results: results.clone(),
            att_has_block: eff_att_has_block,
            att_has_wrestle,
            att_has_claws,
            att_has_mb,
            att_has_piling_on,
            att_has_grab,
            att_has_juggernaut: juggernaut_active,
            att_has_strip_ball,
            att_has_brawler,
            att_has_hatred,
            att_has_woodland_fury,
            att_has_consummate_professional,
            att_has_working_in_tandem_block,
            is_blitz,
            attacker_coord,
            defender_coord,
            def_has_sidestep: eff_def_has_sidestep,
            def_has_wrestle: eff_def_has_wrestle,
        };

        if let Some(chosen) = auto_chosen {
            // Immediate resolution (single die or defender picks)
            let resolve_events = self.resolve_block_result(chosen, context)?;
            events.extend(resolve_events);
        } else {
            // Pause: attacker must choose which die to apply
            self.pending_block_choice = Some(context);
            self.cached_prompt = Some(AgentPrompt::BlockChoice {
                attacker_id: attacker_id.to_owned(),
                defender_id: defender_id.to_owned(),
                dice,
                own_choice: true,
                nr_of_dice: n_dice,
            });
        }

        Ok(events)
    }

    /// Multiple Block (BB2020+): two simultaneous 1-die blocks, each defender gets +2 effective ST.
    fn apply_multi_block(
        &mut self,
        attacker_id: &str,
        defender1_id: &str,
        defender2_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let home_attacking = self.game.home_playing;

        // Verify attacker has MultipleBlock skill
        let has_mb = if home_attacking {
            self.game.team_home.player(attacker_id)
                .map(|p| p.has_skill(SkillId::MultipleBlock)).unwrap_or(false)
        } else {
            self.game.team_away.player(attacker_id)
                .map(|p| p.has_skill(SkillId::MultipleBlock)).unwrap_or(false)
        };
        if !has_mb {
            return Ok(events);
        }

        let att_str = if home_attacking {
            self.game.team_home.player(attacker_id).map(|p| p.strength).unwrap_or(3)
        } else {
            self.game.team_away.player(attacker_id).map(|p| p.strength).unwrap_or(3)
        };

        events.push(GameEvent::SkillUse {
            player_id: attacker_id.to_owned(),
            skill_id: SkillId::MultipleBlock as u16,
            used: true,
        });

        for def_id in &[defender1_id, defender2_id] {
            let def_str = if home_attacking {
                self.game.team_away.player(def_id).map(|p| p.strength).unwrap_or(3)
            } else {
                self.game.team_home.player(def_id).map(|p| p.strength).unwrap_or(3)
            };

            let attacker_coord = self.game.field_model.player_coordinate(attacker_id)
                .unwrap_or(FieldCoordinate::new(12, 7));
            let defender_coord = self.game.field_model.player_coordinate(def_id)
                .unwrap_or(FieldCoordinate::new(13, 7));

            let att_assists = self.count_block_assists(home_attacking, defender_coord, attacker_id, def_id);
            let def_assists = self.count_block_assists(!home_attacking, attacker_coord, def_id, attacker_id);

            // +2 to each defender's effective strength (Multiple Block penalty)
            let eff_att = att_str + att_assists;
            let eff_def = def_str + def_assists + 2;

            let n_dice = block_dice_count(eff_att, eff_def);
            let attacker_picks = n_dice >= 0;
            let n_rolls = n_dice.unsigned_abs().max(1) as usize;

            let dice: Vec<i32> = (0..n_rolls).map(|_| self.rng.d6()).collect();
            let results: Vec<BlockResult> = dice.iter().map(|&d| block_result_for_roll(d)).collect();
            let chosen = Self::pick_best_block_result(&results, attacker_picks);
            let selected_index = results.iter().position(|&r| r == chosen).unwrap_or(0) as i32;

            events.push(GameEvent::BlockRoll {
                attacker_id: attacker_id.to_owned(),
                defender_id: def_id.to_string(),
                nr_of_dice: n_dice,
                dice: dice.clone(),
                selected_index,
                own_choice: attacker_picks,
                rerolled: false,
            });

            let att_has_block = if home_attacking {
                self.game.team_home.player(attacker_id).map(|p| p.has_skill(SkillId::Block)).unwrap_or(false)
            } else {
                self.game.team_away.player(attacker_id).map(|p| p.has_skill(SkillId::Block)).unwrap_or(false)
            };
            let def_has_sidestep = if home_attacking {
                self.game.team_away.player(def_id)
                    .map(|p| p.has_skill(SkillId::SideStep) || p.has_skill(SkillId::Sidestep)).unwrap_or(false)
            } else {
                self.game.team_home.player(def_id)
                    .map(|p| p.has_skill(SkillId::SideStep) || p.has_skill(SkillId::Sidestep)).unwrap_or(false)
            };
            let def_has_wrestle = if home_attacking {
                self.game.team_away.player(def_id).map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false)
            } else {
                self.game.team_home.player(def_id).map(|p| p.has_skill(SkillId::Wrestle)).unwrap_or(false)
            };

            let ctx = PendingBlockChoice {
                attacker_id: attacker_id.to_owned(),
                defender_id: def_id.to_string(),
                home_attacking,
                results,
                att_has_block,
                att_has_wrestle: false,
                att_has_claws: false,
                att_has_mb: false,
                att_has_piling_on: false,
                att_has_grab: false,
                att_has_juggernaut: false,
                att_has_strip_ball: false,
                att_has_brawler: false,
                att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
                is_blitz: false,
                attacker_coord,
                defender_coord,
                def_has_sidestep,
                def_has_wrestle,
            };
            let resolve_events = self.resolve_block_result(chosen, ctx)?;
            events.extend(resolve_events);
        }

        // No follow-up after Multiple Block
        self.game.acting_player.has_acted = true;
        Ok(events)
    }

    /// Resolve the block after the agent has chosen a die index.
    fn resolve_block_choice(
        &mut self,
        context: PendingBlockChoice,
        die_index: usize,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let idx = die_index.min(context.results.len().saturating_sub(1));
        let chosen = context.results[idx];
        self.resolve_block_result(chosen, context)
    }

    /// Apply a concrete block result (Skull/BothDown/Pushback/Pow/PowPushback).
    ///
    /// Called both from immediate auto-resolution and from the BlockChoice handler.
    fn resolve_block_result(
        &mut self,
        chosen: BlockResult,
        ctx: PendingBlockChoice,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        // Before resolving bad results, check if attacker can reroll (team reroll available)
        let bad_for_attacker = matches!(chosen, BlockResult::Skull)
            || (matches!(chosen, BlockResult::BothDown) && !ctx.att_has_block);
        if bad_for_attacker {
            // Brawler (BB2020): free re-roll of a single BothDown die, not available on blitzes
            if matches!(chosen, BlockResult::BothDown) && ctx.att_has_brawler && !ctx.is_blitz {
                let brawler_used = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::Brawler)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::Brawler)).unwrap_or(false)
                };
                if !brawler_used {
                    // Mark Brawler as used and offer the reroll
                    if ctx.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) {
                            p.used_skills.insert(SkillId::Brawler);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) {
                        p.used_skills.insert(SkillId::Brawler);
                    }
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(),
                        home_attacking: ctx.home_attacking,
                        original_result: chosen,
                        ctx: ctx.clone(),
                        is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // WoodlandFury (BB2025): once per game, re-roll a single die when would be knocked down
            if matches!(chosen, BlockResult::Skull) && ctx.att_has_woodland_fury {
                let wf_used = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::WoodlandFury)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::WoodlandFury)).unwrap_or(false)
                };
                if !wf_used {
                    if ctx.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) {
                            p.used_skills.insert(SkillId::WoodlandFury);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) {
                        p.used_skills.insert(SkillId::WoodlandFury);
                    }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::WoodlandFury as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(),
                        home_attacking: ctx.home_attacking,
                        original_result: chosen,
                        ctx: ctx.clone(),
                        is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // Hatred (BB2025): free re-roll of a single Skull die (simplified: no race check)
            if matches!(chosen, BlockResult::Skull) && ctx.att_has_hatred {
                let hatred_used = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::Hatred)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::Hatred)).unwrap_or(false)
                };
                if !hatred_used {
                    if ctx.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) {
                            p.used_skills.insert(SkillId::Hatred);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) {
                        p.used_skills.insert(SkillId::Hatred);
                    }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::Hatred as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(),
                        home_attacking: ctx.home_attacking,
                        original_result: chosen,
                        ctx: ctx.clone(),
                        is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // ConsummateProfessional (BB2020+): once per game, free reroll on any bad block result
            if ctx.att_has_consummate_professional {
                let cp_used = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::ConsummateProfessional)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::ConsummateProfessional)).unwrap_or(false)
                };
                if !cp_used {
                    if ctx.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) {
                            p.used_skills.insert(SkillId::ConsummateProfessional);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) {
                        p.used_skills.insert(SkillId::ConsummateProfessional);
                    }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::ConsummateProfessional as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(),
                        home_attacking: ctx.home_attacking,
                        original_result: chosen,
                        ctx: ctx.clone(),
                        is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // WorkingInTandem (BB2025): Lucien may reroll a single block die when Valen marks the defender
            if ctx.att_has_working_in_tandem_block {
                let wit_used = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::WorkingInTandem)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                        .map(|p| p.used_skills.contains(&SkillId::WorkingInTandem)).unwrap_or(false)
                };
                if !wit_used {
                    if ctx.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) {
                            p.used_skills.insert(SkillId::WorkingInTandem);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) {
                        p.used_skills.insert(SkillId::WorkingInTandem);
                    }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::WorkingInTandem as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(),
                        home_attacking: ctx.home_attacking,
                        original_result: chosen,
                        ctx: ctx.clone(),
                        is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // UnstoppableMomentum: free reroll of a single Skull die during blitz (Regular — resets per turn)
            if matches!(chosen, BlockResult::Skull) && ctx.is_blitz {
                let um_avail = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                }.map(|p| p.has_skill(SkillId::UnstoppableMomentum) && !p.used_skills.contains(&SkillId::UnstoppableMomentum)).unwrap_or(false);
                if um_avail {
                    if ctx.home_attacking { if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) { p.used_skills.insert(SkillId::UnstoppableMomentum); } }
                    else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) { p.used_skills.insert(SkillId::UnstoppableMomentum); }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::UnstoppableMomentum as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(), home_attacking: ctx.home_attacking,
                        original_result: chosen, ctx: ctx.clone(), is_pro: false,
                    });
                    return Ok(events);
                }
            }
            // SavageBlow: once per game, reroll any bad block result
            {
                let sb_avail = if ctx.home_attacking {
                    self.game.team_home.player(&ctx.attacker_id)
                } else {
                    self.game.team_away.player(&ctx.attacker_id)
                }.map(|p| p.has_skill(SkillId::SavageBlow) && !p.used_skills.contains(&SkillId::SavageBlow)).unwrap_or(false);
                if sb_avail {
                    if ctx.home_attacking { if let Some(p) = self.game.team_home.player_mut(&ctx.attacker_id) { p.used_skills.insert(SkillId::SavageBlow); } }
                    else if let Some(p) = self.game.team_away.player_mut(&ctx.attacker_id) { p.used_skills.insert(SkillId::SavageBlow); }
                    events.push(GameEvent::SkillUse { player_id: ctx.attacker_id.clone(), skill_id: SkillId::SavageBlow as u16, used: true });
                    self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                        attacker_id: ctx.attacker_id.clone(), home_attacking: ctx.home_attacking,
                        original_result: chosen, ctx: ctx.clone(), is_pro: false,
                    });
                    return Ok(events);
                }
            }
            let pro_available = self.pro_reroll_available(&ctx.attacker_id, ctx.home_attacking);
            if self.team_reroll_available(ctx.home_attacking) || pro_available {
                let is_pro = !self.team_reroll_available(ctx.home_attacking) && pro_available;
                self.offer_reroll(ctx.home_attacking, "block", PendingReroll::Block {
                    attacker_id: ctx.attacker_id.clone(),
                    home_attacking: ctx.home_attacking,
                    original_result: chosen,
                    ctx: ctx.clone(),
                    is_pro,
                });
                return Ok(events);
            }
        }

        match chosen {
            BlockResult::Skull => {
                // Attacker trips — prone at current position, no armor roll
                let att_state = self.game.field_model.player_state(&ctx.attacker_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                self.game.field_model.set_player_state(
                    &ctx.attacker_id,
                    att_state.change_active(false).change_base(PS_PRONE),
                );
                let att_coord = self.game.field_model.player_coordinate(&ctx.attacker_id)
                    .unwrap_or(FieldCoordinate::new(0, 0));
                events.push(GameEvent::PlayerFellDown {
                    player_id: ctx.attacker_id.clone(),
                    coord: att_coord,
                });
                // Scatter ball if attacker was carrying it
                if self.game.field_model.ball_coordinate == Some(att_coord)
                    && self.game.field_model.ball_in_play
                {
                    let att_is_home = ctx.home_attacking;
                    let has_sph = if att_is_home {
                        self.game.team_home.player(&ctx.attacker_id)
                    } else {
                        self.game.team_away.player(&ctx.attacker_id)
                    }.map(|p| p.has_skill(SkillId::SafePairOfHands)).unwrap_or(false);
                    if !has_sph {
                        let dir = self.rng.d8();
                        events.push(GameEvent::BallScattered { player_id: ctx.attacker_id.clone(), coord: att_coord, direction: dir });
                        self.mark_ball_moving();
                    }
                }
                // Saboteur (BB2025): fallen attacker may roll 4+ to knock down defender.
                if self.game.rules == Rules::Bb2025 {
                    let att_has_saboteur = if ctx.home_attacking {
                        self.game.team_home.player(&ctx.attacker_id)
                    } else {
                        self.game.team_away.player(&ctx.attacker_id)
                    }.map(|p| p.has_skill(SkillId::Saboteur)).unwrap_or(false);
                    if att_has_saboteur {
                        let sab = PendingSaboteur {
                            player_id: ctx.attacker_id.clone(),
                            target_id: ctx.defender_id.clone(),
                            is_home: ctx.home_attacking,
                        };
                        self.cached_prompt = Some(AgentPrompt::SkillUse {
                            player_id: ctx.attacker_id.clone(),
                            skill_id: SkillId::Saboteur as u16,
                            skill_name: "Saboteur".into(),
                        });
                        self.pending_saboteur = Some(sab);
                        return Ok(events);
                    }
                }
            }
            BlockResult::BothDown => {
                // StripBall: if attacker has StripBall and defender has ball, offer to treat BothDown as Pushed.
                // MonstrousMouth cancels StripBall against the carrier.
                let def_has_ball = self.game.field_model.ball_coordinate == Some(ctx.defender_coord)
                    && self.game.field_model.ball_in_play;
                let defender_is_home = !ctx.home_attacking;
                let def_has_monstrous_mouth = if defender_is_home {
                    self.game.team_home.player(&ctx.defender_id)
                } else {
                    self.game.team_away.player(&ctx.defender_id)
                }.map(|p| p.has_skill(SkillId::MonstrousMouth)).unwrap_or(false);
                if ctx.att_has_strip_ball && def_has_ball && !def_has_monstrous_mouth {
                    let att_id = ctx.attacker_id.clone();
                    self.pending_strip_ball = Some(ctx.clone());
                    self.cached_prompt = Some(AgentPrompt::SkillUse {
                        player_id: att_id,
                        skill_id: SkillId::StripBall as u16,
                        skill_name: "Strip Ball".into(),
                    });
                    return Ok(events);
                }

                // Attacker stays standing if they have Block (unless Wrestle overrides).
                let attacker_falls_base = !ctx.att_has_block;

                // Wrestle: either player can choose to make both fall.
                // Attacker with Wrestle: useful when defender has Block (BB2020) or as a tactic.
                // Defender with Wrestle: useful when attacker has Block and would stay standing.
                let att_can_wrestle = ctx.att_has_wrestle;
                // Defender can use Wrestle unless attacker is blitzing with Juggernaut (simplified: always allowed)
                let def_can_wrestle = ctx.def_has_wrestle;

                if att_can_wrestle {
                    // Ask attacker first
                    let att_id = ctx.attacker_id.clone();
                    self.pending_wrestle = Some(PendingWrestle { ctx, asking_attacker: true });
                    self.cached_prompt = Some(AgentPrompt::SkillUse {
                        player_id: att_id,
                        skill_id: SkillId::Wrestle as u16,
                        skill_name: "Wrestle".into(),
                    });
                    return Ok(events);
                } else if def_can_wrestle && !attacker_falls_base {
                    // Defender offered Wrestle only when attacker would stay standing (has Block)
                    let def_id = ctx.defender_id.clone();
                    self.pending_wrestle = Some(PendingWrestle { ctx, asking_attacker: false });
                    self.cached_prompt = Some(AgentPrompt::SkillUse {
                        player_id: def_id,
                        skill_id: SkillId::Wrestle as u16,
                        skill_name: "Wrestle".into(),
                    });
                    return Ok(events);
                } else {
                    // Auto-resolve: attacker falls if no Block, defender always falls
                    // WatchOut: first time per half being blocked, defender counts as having Dodge (doesn't fall on BothDown)
                    let defender_is_home_bd = !ctx.home_attacking;
                    let watch_out_avail = if defender_is_home_bd {
                        self.game.team_home.player(&ctx.defender_id)
                    } else {
                        self.game.team_away.player(&ctx.defender_id)
                    }.map(|p| p.has_skill(SkillId::WatchOut) && !p.used_skills.contains(&SkillId::WatchOut)).unwrap_or(false);
                    if watch_out_avail {
                        if defender_is_home_bd { if let Some(p) = self.game.team_home.player_mut(&ctx.defender_id) { p.used_skills.insert(SkillId::WatchOut); } }
                        else if let Some(p) = self.game.team_away.player_mut(&ctx.defender_id) { p.used_skills.insert(SkillId::WatchOut); }
                        events.push(GameEvent::SkillUse { player_id: ctx.defender_id.clone(), skill_id: SkillId::WatchOut as u16, used: true });
                    }
                    let both_fall = attacker_falls_base;
                    let ids: Vec<String> = if both_fall && watch_out_avail {
                        // WatchOut defender doesn't fall; only attacker falls
                        vec![ctx.attacker_id.clone()]
                    } else if both_fall {
                        vec![ctx.attacker_id.clone(), ctx.defender_id.clone()]
                    } else if watch_out_avail {
                        // Neither falls — BothDown with attacker having Block + defender having WatchOut
                        vec![]
                    } else {
                        vec![ctx.defender_id.clone()]
                    };
                    if !ids.is_empty() {
                        Self::apply_both_down_falls(
                            &mut self.game.field_model,
                            &mut self.rng,
                            &self.game.team_home,
                            &self.game.team_away,
                            &ids,
                            &mut events,
                        );
                    }
                    self.game.acting_player.has_acted = true;
                    if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                        self.game.acting_player.blitz_blocked = true;
                    }
                    return Ok(events);
                }
            }
            BlockResult::Pushback | BlockResult::PowPushback | BlockResult::Pow => {
                let do_armor = matches!(chosen, BlockResult::PowPushback | BlockResult::Pow);

                // Compute push squares.
                // Grab: attacker chooses any empty adjacent square (cancels Sidestep).
                // Sidestep: defender may choose any adjacent square except the attacker's.
                // Normal: 3-square push cone facing away from the attacker.
                let push_dx = ctx.defender_coord.x - ctx.attacker_coord.x;
                let push_dy = ctx.defender_coord.y - ctx.attacker_coord.y;
                let cone_squares: Vec<FieldCoordinate> = if ctx.att_has_grab {
                    // Grab: any empty adjacent square (excludes attacker's own square)
                    ctx.defender_coord.neighbours()
                        .iter()
                        .copied()
                        .filter(|&s| {
                            s != ctx.attacker_coord
                                && self.game.field_model.player_at(s).is_none()
                        })
                        .collect()
                } else if ctx.def_has_sidestep {
                    ctx.defender_coord.neighbours()
                        .iter()
                        .copied()
                        .filter(|&s| s != ctx.attacker_coord)
                        .collect()
                } else {
                    ctx.defender_coord.neighbours()
                        .iter()
                        .copied()
                        .filter(|&s| {
                            if s == ctx.attacker_coord { return false; }
                            let sdx = s.x - ctx.defender_coord.x;
                            let sdy = s.y - ctx.defender_coord.y;
                            sdx * push_dx + sdy * push_dy > 0
                        })
                        .collect()
                };

                let on_pitch_squares: Vec<FieldCoordinate> = cone_squares.iter().copied()
                    .filter(|c| c.is_on_pitch())
                    .collect();

                // Crowd surf: all push-cone squares are off-pitch
                if on_pitch_squares.is_empty() {
                    // Crowd surf: player is pushed off the pitch.
                    // The crowd rolls 2D6; if it exceeds the player's AV, injury is rolled.
                    // No follow-up is possible, and no Mighty Blow modifiers apply.
                    let rules = self.game.rules;
                    let defender_is_home = !ctx.home_attacking;
                    let (def_av, def_stunty_cs) = if ctx.home_attacking {
                        let p = self.game.team_away.player(&ctx.defender_id);
                        (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false))
                    } else {
                        let p = self.game.team_home.player(&ctx.defender_id);
                        (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false))
                    };
                    let stunty_cs_mod = if def_stunty_cs { -1 } else { 0 };
                    let crowd_coord = self.game.field_model.player_coordinate(&ctx.defender_id)
                        .unwrap_or(FieldCoordinate::new(12, 7));
                    self.game.field_model.player_coordinates.remove(&ctx.defender_id);
                    events.push(GameEvent::ScatterPlayer {
                        player_id: ctx.defender_id.clone(),
                        coords: vec![crowd_coord],
                    });
                    let ar1 = self.rng.d6();
                    let ar2 = self.rng.d6();
                    let armor_broken = is_armour_broken(def_av, ar1 + ar2 + stunty_cs_mod, rules);
                    if armor_broken {
                        let inj1 = self.rng.d6();
                        let inj2 = self.rng.d6();
                        let niggling_mod = self.niggling_injury_mod(&ctx.defender_id, defender_is_home);
                        let total = inj1 + inj2 + niggling_mod;
                        let mut was_cas = total >= 10;
                        let mut was_ko = total >= 8 && !was_cas;
                        // ThickSkull: on KO result, roll D6; on 4+ downgrade to Stunned
                        if was_ko && self.check_thick_skull(&ctx.defender_id, defender_is_home, &mut events) {
                            was_ko = false;
                        }
                        // Decay: BH/stunned result on a Decay player becomes CAS.
                        let def_has_decay_crowd = if ctx.home_attacking {
                            self.game.team_away.player(&ctx.defender_id)
                        } else {
                            self.game.team_home.player(&ctx.defender_id)
                        }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                        if def_has_decay_crowd && !was_cas && !was_ko {
                            was_cas = true;
                        }
                        let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                        let regen = if was_cas {
                            self.try_regeneration(&ctx.defender_id, defender_is_home, &mut events)
                        } else { false };
                        let was_cas = was_cas && !regen;
                        let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                            else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                            else if !regen { PlayerState::new(PS_PRONE) }
                            else { PlayerState::new(PS_RESERVE) };
                        if !regen { self.game.field_model.set_player_state(&ctx.defender_id, new_state); }
                        if was_cas {
                            use ffb_mechanics::mechanics::casualty_spp;
                            let cas_spp = casualty_spp(rules, false);
                            self.award_spp(&ctx.attacker_id, ctx.home_attacking, cas_spp);
                            if let Some(si_kind) = si {
                                self.apply_casualty_to_player(&ctx.defender_id, defender_is_home, si_kind);
                            }
                        }
                        events.push(GameEvent::Injury {
                            player_id: ctx.defender_id.clone(),
                            armor_roll: Some([ar1, ar2]),
                            injury_roll: Some([inj1, inj2]),
                            serious_injury: si,
                            was_ko,
                            was_cas,
                        });
                    } else {
                        self.game.field_model.set_player_state(&ctx.defender_id, PlayerState::new(PS_KNOCKED_OUT));
                        events.push(GameEvent::Injury {
                            player_id: ctx.defender_id.clone(),
                            armor_roll: Some([ar1, ar2]),
                            injury_roll: None,
                            serious_injury: None,
                            was_ko: true,
                            was_cas: false,
                        });
                    }
                    self.game.acting_player.has_acted = true;
                    if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                        self.game.acting_player.blitz_blocked = true;
                    }
                    return Ok(events);
                }

                // Normal push: use on-pitch cone squares
                let push_squares = on_pitch_squares.clone();

                events.push(GameEvent::Pushback {
                    attacker_id: ctx.attacker_id.clone(),
                    defender_id: ctx.defender_id.clone(),
                    squares: push_squares.clone(),
                });

                let def_is_home = !ctx.home_attacking;
                let def_has_stand_firm = if def_is_home {
                    self.game.team_home.player(&ctx.defender_id)
                } else {
                    self.game.team_away.player(&ctx.defender_id)
                }.map(|p| p.has_skill(SkillId::StandFirm)).unwrap_or(false);
                let def_has_fend = if def_is_home {
                    self.game.team_home.player(&ctx.defender_id)
                } else {
                    self.game.team_away.player(&ctx.defender_id)
                }.map(|p| p.has_skill(SkillId::Fend)).unwrap_or(false);
                self.pending_push = Some(PendingPush {
                    attacker_id: ctx.attacker_id.clone(),
                    defender_id: ctx.defender_id.clone(),
                    home_attacking: ctx.home_attacking,
                    push_squares: push_squares.clone(),
                    do_armor,
                    attacker_coord: ctx.attacker_coord,
                    def_has_stand_firm,
                    def_has_fend,
                });
                self.cached_prompt = Some(AgentPrompt::Pushback {
                    attacker_id: ctx.attacker_id.clone(),
                    defender_id: ctx.defender_id.clone(),
                    squares: push_squares,
                });
                // Don't mark has_acted yet — resolve_push does it after the push is resolved
                return Ok(events);
            }
        }

        self.game.acting_player.has_acted = true;
        if matches!(
            self.game.acting_player.player_action,
            Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)
        ) {
            self.game.acting_player.blitz_blocked = true;
        }
        Ok(events)
    }

    /// Place each player in `ids` prone and scatter the ball if they carry it.
    fn apply_both_down_falls(
        field: &mut ffb_model::model::field_model::FieldModel,
        rng: &mut GameRng,
        team_home: &ffb_model::model::team::Team,
        team_away: &ffb_model::model::team::Team,
        ids: &[String],
        events: &mut Vec<GameEvent>,
    ) {
        for pid in ids {
            let state = field.player_state(pid).unwrap_or(PlayerState::new(PS_STANDING));
            field.set_player_state(pid, state.change_active(false).change_base(PS_PRONE));
            let coord = field.player_coordinate(pid).unwrap_or(FieldCoordinate::new(0, 0));
            events.push(GameEvent::PlayerFellDown { player_id: pid.clone(), coord });
            if field.ball_coordinate == Some(coord) && field.ball_in_play {
                let pid_is_home = team_home.has_player(pid);
                let has_sph = if pid_is_home {
                    team_home.player(pid)
                } else {
                    team_away.player(pid)
                }.map(|p| p.has_skill(SkillId::SafePairOfHands)).unwrap_or(false);
                if !has_sph {
                    let dir = rng.d8();
                    events.push(GameEvent::BallScattered { player_id: pid.clone(), coord, direction: dir });
                    field.ball_moving = true;
                }
            }
        }
    }

    /// Resolve Wrestle skill decision after an agent responds to a BothDown prompt.
    fn resolve_wrestle(
        &mut self,
        pw: PendingWrestle,
        use_wrestle: bool,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let ctx = pw.ctx;

        if use_wrestle {
            // Wrestle used: both players go prone regardless of Block
            events.push(GameEvent::SkillUse {
                player_id: if pw.asking_attacker { ctx.attacker_id.clone() } else { ctx.defender_id.clone() },
                skill_id: SkillId::Wrestle as u16,
                used: true,
            });
            let ids = vec![ctx.attacker_id.clone(), ctx.defender_id.clone()];
            Self::apply_both_down_falls(
                &mut self.game.field_model,
                &mut self.rng,
                &self.game.team_home,
                &self.game.team_away,
                &ids,
                &mut events,
            );
            self.game.acting_player.has_acted = true;
            if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                self.game.acting_player.blitz_blocked = true;
            }
        } else if pw.asking_attacker && ctx.def_has_wrestle {
            // Attacker declined; now offer defender Wrestle
            let def_id = ctx.defender_id.clone();
            self.pending_wrestle = Some(PendingWrestle { ctx, asking_attacker: false });
            self.cached_prompt = Some(AgentPrompt::SkillUse {
                player_id: def_id,
                skill_id: SkillId::Wrestle as u16,
                skill_name: "Wrestle".into(),
            });
        } else {
            // No Wrestle used; resolve with Block/no-Block logic
            let attacker_falls = !ctx.att_has_block;
            let ids: Vec<String> = if attacker_falls {
                vec![ctx.attacker_id.clone(), ctx.defender_id.clone()]
            } else {
                vec![ctx.defender_id.clone()]
            };
            Self::apply_both_down_falls(
                &mut self.game.field_model,
                &mut self.rng,
                &self.game.team_home,
                &self.game.team_away,
                &ids,
                &mut events,
            );
            self.game.acting_player.has_acted = true;
            if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                self.game.acting_player.blitz_blocked = true;
            }
        }
        Ok(events)
    }

    /// Resolve StripBall decision: attacker may treat BothDown as Pushed when defender has ball.
    /// DumpOff: defender chose whether to pass before the block resolves.
    /// If used: emit SkillUse, enter a "DumpOff pass" mode (simplified: let the engine continue
    /// with a normal pass action from the defending team's perspective). The block continues
    /// after the pass is resolved.
    fn resolve_dump_off(&mut self, dump: PendingDumpOff, use_dump_off: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        events.push(GameEvent::SkillUse {
            player_id: dump.defender_id.clone(),
            skill_id: SkillId::DumpOff as u16,
            used: use_dump_off,
        });
        if use_dump_off {
            // Mark the defending team's pass as used
            if !dump.home_attacking {
                self.game.turn_data_home.pass_used = true;
            } else {
                self.game.turn_data_away.pass_used = true;
            }
            // Store the block context so we can resume after the DumpOff pass.
            // For now, simplified: offer the defending team's agent a pass action prompt.
            // The block will automatically resume (the DumpOff pass is a separate agent action).
            // We change turn_mode to DumpOff so the engine knows we're in a dump-off.
            self.game.turn_mode = TurnMode::DumpOff;
            // Store the pending attacker/defender so the block resumes
            self.game.acting_player.set_player(dump.attacker_id.clone(), PlayerAction::Block);
            // After DumpOff pass is resolved (or declined), resume the block
            // The cached_prompt will be set by compute_next_prompt to let the defender pass.
        } else {
            // Defender declined DumpOff; proceed with block normally.
            // Mark pass as used to prevent DumpOff from triggering again in apply_block.
            if !dump.home_attacking {
                self.game.turn_data_home.pass_used = true;
            } else {
                self.game.turn_data_away.pass_used = true;
            }
            let att_id = dump.attacker_id.clone();
            let def_id = dump.defender_id.clone();
            self.game.home_playing = dump.home_attacking;
            let block_events = self.apply_block(&att_id, &def_id)?;
            // Reset pass_used so the defending team can still pass on their own turn
            if !dump.home_attacking {
                self.game.turn_data_home.pass_used = false;
            } else {
                self.game.turn_data_away.pass_used = false;
            }
            events.extend(block_events);
        }
        Ok(events)
    }

    fn resolve_strip_ball(&mut self, ctx: PendingBlockChoice, use_strip_ball: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        if use_strip_ball {
            events.push(GameEvent::SkillUse {
                player_id: ctx.attacker_id.clone(),
                skill_id: SkillId::StripBall as u16,
                used: true,
            });
            // Treat as Pushed: just push the defender, no armor roll, attacker stays standing.
            let push_dx = ctx.defender_coord.x - ctx.attacker_coord.x;
            let push_dy = ctx.defender_coord.y - ctx.attacker_coord.y;
            let push_squares: Vec<FieldCoordinate> = ctx.defender_coord.neighbours()
                .iter()
                .copied()
                .filter(|&s| {
                    if s == ctx.attacker_coord { return false; }
                    let sdx = s.x - ctx.defender_coord.x;
                    let sdy = s.y - ctx.defender_coord.y;
                    sdx * push_dx + sdy * push_dy > 0
                })
                .filter(|c| c.is_on_pitch())
                .collect();
            let push_squares = if push_squares.is_empty() { vec![ctx.defender_coord] } else { push_squares };
            events.push(GameEvent::Pushback {
                attacker_id: ctx.attacker_id.clone(),
                defender_id: ctx.defender_id.clone(),
                squares: push_squares.clone(),
            });
            let def_has_fend = if ctx.home_attacking {
                self.game.team_away.player(&ctx.defender_id)
            } else {
                self.game.team_home.player(&ctx.defender_id)
            }.map(|p| p.has_skill(SkillId::Fend)).unwrap_or(false);
            let def_has_stand_firm = if ctx.home_attacking {
                self.game.team_away.player(&ctx.defender_id)
            } else {
                self.game.team_home.player(&ctx.defender_id)
            }.map(|p| p.has_skill(SkillId::StandFirm)).unwrap_or(false);
            self.pending_push = Some(PendingPush {
                attacker_id: ctx.attacker_id.clone(),
                defender_id: ctx.defender_id.clone(),
                home_attacking: ctx.home_attacking,
                push_squares: push_squares.clone(),
                do_armor: false,
                attacker_coord: ctx.attacker_coord,
                def_has_stand_firm,
                def_has_fend,
            });
            self.cached_prompt = Some(AgentPrompt::Pushback {
                attacker_id: ctx.attacker_id.clone(),
                defender_id: ctx.defender_id.clone(),
                squares: push_squares,
            });
            self.game.acting_player.has_acted = true;
        } else {
            // Declined: continue with normal BothDown resolution
            let attacker_falls = !ctx.att_has_block;
            let ids: Vec<String> = if attacker_falls {
                vec![ctx.attacker_id.clone(), ctx.defender_id.clone()]
            } else {
                vec![ctx.defender_id.clone()]
            };
            Self::apply_both_down_falls(
                &mut self.game.field_model,
                &mut self.rng,
                &self.game.team_home,
                &self.game.team_away,
                &ids,
                &mut events,
            );
            self.game.acting_player.has_acted = true;
            if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                self.game.acting_player.blitz_blocked = true;
            }
        }
        Ok(events)
    }

    /// Resolve a push-to action: move the defender, run armor/injury if needed, then prompt for follow-up.
    fn resolve_push(&mut self, push: PendingPush, coord: FieldCoordinate) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        // Move defender to the chosen square (clamp to valid options)
        let dest = if push.push_squares.contains(&coord) { coord } else {
            push.push_squares.first().copied().unwrap_or(coord)
        };
        let defender_old_coord = self.game.field_model.player_coordinate(&push.defender_id)
            .unwrap_or(dest);
        // Stand Firm: defender may choose not to be pushed (stays in place)
        if !push.def_has_stand_firm {
            // Chain push: if dest is occupied, cascade the push to the occupant first
            if let Some(occupant_id) = self.game.field_model.player_at(dest).cloned() {
                if occupant_id != push.defender_id && occupant_id != push.attacker_id {
                    // Find a free on-pitch adjacent square away from attacker to chain-push occupant
                    let push_dir_x = dest.x - push.attacker_coord.x;
                    let push_dir_y = dest.y - push.attacker_coord.y;
                    let adj_on_pitch = self.game.field_model.adjacent_on_pitch(dest);
                    let chain_dest_opt: Option<FieldCoordinate> = adj_on_pitch.iter().copied()
                        .filter(|&c| {
                            let dx = c.x - dest.x;
                            let dy = c.y - dest.y;
                            dx * push_dir_x.signum() + dy * push_dir_y.signum() >= 0
                        })
                        .find(|&c| self.game.field_model.player_at(c).is_none());
                    if let Some(chain_dest) = chain_dest_opt {
                        self.game.field_model.set_player_coordinate(&occupant_id, chain_dest);
                        events.push(GameEvent::PlayerMoved {
                            player_id: occupant_id,
                            coord: chain_dest,
                        });
                    } else {
                        // No free square: crowd surf the occupant
                        self.game.field_model.player_coordinates.remove(&occupant_id);
                        events.push(GameEvent::ScatterPlayer {
                            player_id: occupant_id.clone(),
                            coords: vec![dest],
                        });
                        let occ_is_home = self.game.team_home.has_player(&occupant_id);
                        let occ_av = if occ_is_home {
                            self.game.team_home.player(&occupant_id).map(|p| p.armour).unwrap_or(8)
                        } else {
                            self.game.team_away.player(&occupant_id).map(|p| p.armour).unwrap_or(8)
                        };
                        let rules = self.game.rules;
                        let ar1 = self.rng.d6();
                        let ar2 = self.rng.d6();
                        if is_armour_broken(occ_av, ar1 + ar2, rules) {
                            let inj1 = self.rng.d6();
                            let inj2 = self.rng.d6();
                            let niggling_mod = self.niggling_injury_mod(&occupant_id, occ_is_home);
                            let total = inj1 + inj2 + niggling_mod;
                            let was_cas = total >= 10;
                            let was_ko = total >= 8 && !was_cas;
                            let new_state = if was_cas { PlayerState::new(PS_BADLY_HURT) }
                                else if was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                                else { PlayerState::new(PS_PRONE) };
                            self.game.field_model.set_player_state(&occupant_id, new_state);
                            events.push(GameEvent::Injury {
                                player_id: occupant_id,
                                armor_roll: Some([ar1, ar2]),
                                injury_roll: Some([inj1, inj2]),
                                serious_injury: None,
                                was_ko,
                                was_cas,
                            });
                        } else {
                            self.game.field_model.set_player_state(&occupant_id, PlayerState::new(PS_PRONE));
                            events.push(GameEvent::Injury {
                                player_id: occupant_id,
                                armor_roll: Some([ar1, ar2]),
                                injury_roll: None,
                                serious_injury: None,
                                was_ko: false,
                                was_cas: false,
                            });
                        }
                    }
                }
            }
            self.game.field_model.set_player_coordinate(&push.defender_id, dest);
            events.push(GameEvent::PlayerMoved {
                player_id: push.defender_id.clone(),
                coord: dest,
            });

            // TrapDoorFall / TrapDoorFallForSpp: pushed defender lands on a trap door → D6 roll
            if self.game.field_model.has_trap_door(dest) {
                let roll = self.rng.d6();
                let escaped = roll != 1;
                events.push(GameEvent::TrapDoor {
                    player_id: push.defender_id.clone(),
                    roll,
                    escaped,
                });
                if !escaped {
                    // Ball scatters if defender was carrying it
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(&push.defender_id, dest, !push.home_attacking) {
                        events.push(scatter_ev);
                    }
                    let def_is_home = !push.home_attacking;
                    let fall_evs = self.apply_fall_injury(&push.defender_id, def_is_home, 0);
                    // TrapDoorFallForSpp: award SPP to attacker if the fall results in a CAS
                    let was_cas = fall_evs.iter().any(|e| matches!(e, GameEvent::Injury { was_cas: true, .. }));
                    events.extend(fall_evs);
                    if was_cas {
                        use ffb_mechanics::mechanics::casualty_spp;
                        let cas_spp = casualty_spp(self.game.rules, false);
                        self.award_spp(&push.attacker_id, push.home_attacking, cas_spp);
                    }
                    self.game.field_model.remove_player(&push.defender_id);
                    return Ok(events);
                }
            }
        } else {
            events.push(GameEvent::SkillUse {
                player_id: push.defender_id.clone(),
                skill_id: SkillId::StandFirm as u16,
                used: true,
            });
        }

        // EyeGouge: attacker with EyeGouge removes pushed player's tackle zones until next activation
        let att_has_eye_gouge = if push.home_attacking {
            self.game.team_home.player(&push.attacker_id)
                .map(|p| p.has_skill(SkillId::EyeGouge)).unwrap_or(false)
        } else {
            self.game.team_away.player(&push.attacker_id)
                .map(|p| p.has_skill(SkillId::EyeGouge)).unwrap_or(false)
        };
        if att_has_eye_gouge {
            if let Some(def_state) = self.game.field_model.player_state(&push.defender_id) {
                self.game.field_model.set_player_state(
                    &push.defender_id,
                    def_state.change_eye_gouged(true),
                );
                events.push(GameEvent::SkillUse {
                    player_id: push.attacker_id.clone(),
                    skill_id: SkillId::EyeGouge as u16,
                    used: true,
                });
            }
        }

        // Lookup attacker skills needed for Pow/armor processing
        let (att_has_mb, att_has_claws_push, att_has_piling_on_push, att_has_brutal_block, att_has_dwarfen_scourge, att_has_krump, att_has_slayer) = if push.home_attacking {
            let p = self.game.team_home.player(&push.attacker_id);
            (p.map(|p| p.has_skill(SkillId::MightyBlow)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Claw)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::PilingOn)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::BrutalBlock)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::DwarfenScourge) || p.has_skill(SkillId::DwarvenScourge)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::KrumpAndSmash)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Slayer)).unwrap_or(false))
        } else {
            let p = self.game.team_away.player(&push.attacker_id);
            (p.map(|p| p.has_skill(SkillId::MightyBlow)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Claw)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::PilingOn)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::BrutalBlock)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::DwarfenScourge) || p.has_skill(SkillId::DwarvenScourge)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::KrumpAndSmash)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::Slayer)).unwrap_or(false))
        };
        // Slayer: +1 armor and +1 injury when defender has ST >= 5 (only in block, not foul)
        let def_str_for_slayer = if push.home_attacking {
            self.game.team_away.player(&push.defender_id).map(|p| p.strength).unwrap_or(0)
        } else {
            self.game.team_home.player(&push.defender_id).map(|p| p.strength).unwrap_or(0)
        };
        let slayer_active = att_has_slayer && def_str_for_slayer >= 5;

        let mut last_armor_broken = false;
        if push.do_armor {
            let rules = self.game.rules;
            // Knock down defender
            let def_state = self.game.field_model.player_state(&push.defender_id)
                .unwrap_or(PlayerState::new(PS_STANDING));
            self.game.field_model.set_player_state(
                &push.defender_id,
                def_state.change_base(PS_PRONE),
            );
            events.push(GameEvent::PlayerFellDown {
                player_id: push.defender_id.clone(),
                coord: dest,
            });

            // Ball scatter when defender falls (unless Safe Pair of Hands)
            if self.game.field_model.ball_coordinate == Some(dest)
                && self.game.field_model.ball_in_play
            {
                let defender_is_home = !push.home_attacking;
                let has_safe_hands = if defender_is_home {
                    self.game.team_home.player(&push.defender_id)
                } else {
                    self.game.team_away.player(&push.defender_id)
                }.map(|p| p.has_skill(SkillId::SafePairOfHands)).unwrap_or(false);
                if !has_safe_hands {
                    let scatter_dir = self.rng.d8();
                    events.push(GameEvent::BallScattered {
                        player_id: push.defender_id.clone(),
                        coord: dest,
                        direction: scatter_dir,
                    });
                    self.mark_ball_moving();
                }
            }

            let (def_av, def_has_stunty_blk, def_has_iron_hard_skin) = if push.home_attacking {
                let p = self.game.team_away.player(&push.defender_id);
                (p.map(|p| p.armour).unwrap_or(8),
                 p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
                 p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
            } else {
                let p = self.game.team_home.player(&push.defender_id);
                (p.map(|p| p.armour).unwrap_or(8),
                 p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
                 p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
            };
            // IronHardSkin: ignores armor modifiers from skills (Stunty, Claws, MightyBlow, etc.)
            let stunty_mod = if def_has_stunty_blk && !def_has_iron_hard_skin { -1 } else { 0 };

            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            // Claws and MightyBlow are mutually exclusive; pick the better option.
            // Claws: armor roll 8+ auto-breaks regardless of AV.
            // MightyBlow: +1 to armor roll.
            // Slayer: once per game, +1 to armor roll vs ST 5+ defenders
            let slayer_already_used = if slayer_active && !def_has_iron_hard_skin {
                if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.used_skills.contains(&SkillId::Slayer)).unwrap_or(true)
            } else { true };
            let slayer_armor_mod = if slayer_active && !slayer_already_used && !def_has_iron_hard_skin { 1 } else { 0 };
            // IronHardSkin: attacker's Claws and MightyBlow don't apply
            let eff_att_has_claws = att_has_claws_push && !def_has_iron_hard_skin;
            let eff_att_has_mb = att_has_mb && !def_has_iron_hard_skin;
            let claws_breaks = eff_att_has_claws && (ar1 + ar2 + stunty_mod + slayer_armor_mod >= 8);
            let mb_bonus = if eff_att_has_mb && !claws_breaks { 1 } else { 0 };
            // DwarfenScourge: once per game, +1 to armor roll (adds to break chance) — blocked by IronHardSkin
            let ds_armor_mod = if att_has_dwarfen_scourge && !def_has_iron_hard_skin && !claws_breaks && mb_bonus == 0 {
                let already_used = if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.used_skills.contains(&SkillId::DwarfenScourge) || p.used_skills.contains(&SkillId::DwarvenScourge)).unwrap_or(true);
                if !already_used { 1 } else { 0 }
            } else { 0 };
            let mut armor_broken = claws_breaks || is_armour_broken(def_av, ar1 + ar2 + mb_bonus + stunty_mod + ds_armor_mod + slayer_armor_mod, rules);
            // Mark Slayer as used if it was applied
            if slayer_armor_mod > 0 {
                if push.home_attacking {
                    if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) {
                        p.used_skills.insert(SkillId::Slayer);
                    }
                } else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) {
                    p.used_skills.insert(SkillId::Slayer);
                }
                events.push(GameEvent::SkillUse {
                    player_id: push.attacker_id.clone(),
                    skill_id: SkillId::Slayer as u16,
                    used: true,
                });
            }
            // Mark DwarfenScourge as used if it was applied
            if ds_armor_mod > 0 {
                if push.home_attacking {
                    if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) {
                        p.used_skills.insert(SkillId::DwarfenScourge);
                    }
                } else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) {
                    p.used_skills.insert(SkillId::DwarfenScourge);
                }
                events.push(GameEvent::SkillUse {
                    player_id: push.attacker_id.clone(),
                    skill_id: SkillId::DwarfenScourge as u16,
                    used: true,
                });
            }
            // KrumpAndSmash: once per game, re-roll armor when it fails to break
            if att_has_krump && !armor_broken {
                let already_used = if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.used_skills.contains(&SkillId::KrumpAndSmash)).unwrap_or(true);
                if !already_used {
                    if push.home_attacking {
                        if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) {
                            p.used_skills.insert(SkillId::KrumpAndSmash);
                        }
                    } else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) {
                        p.used_skills.insert(SkillId::KrumpAndSmash);
                    }
                    events.push(GameEvent::SkillUse {
                        player_id: push.attacker_id.clone(),
                        skill_id: SkillId::KrumpAndSmash as u16,
                        used: true,
                    });
                    let kar1 = self.rng.d6();
                    let kar2 = self.rng.d6();
                    armor_broken = claws_breaks || is_armour_broken(def_av, kar1 + kar2 + mb_bonus + stunty_mod, rules);
                }
            }
            let defender_is_home = !push.home_attacking;
            // OldPro: once per game, defender rerolls own armor when it doesn't break
            if !armor_broken {
                let old_pro_avail = if defender_is_home {
                    self.game.team_home.player(&push.defender_id)
                } else {
                    self.game.team_away.player(&push.defender_id)
                }.map(|p| p.has_skill(SkillId::OldPro) && !p.used_skills.contains(&SkillId::OldPro)).unwrap_or(false);
                if old_pro_avail {
                    if defender_is_home { if let Some(p) = self.game.team_home.player_mut(&push.defender_id) { p.used_skills.insert(SkillId::OldPro); } }
                    else if let Some(p) = self.game.team_away.player_mut(&push.defender_id) { p.used_skills.insert(SkillId::OldPro); }
                    events.push(GameEvent::SkillUse { player_id: push.defender_id.clone(), skill_id: SkillId::OldPro as u16, used: true });
                    let rar1 = self.rng.d6();
                    let rar2 = self.rng.d6();
                    armor_broken = is_armour_broken(def_av, rar1 + rar2 + mb_bonus + stunty_mod, rules);
                }
            }
            // CrushingBlow: once per game, attacker applies +1 to armor roll (auto-apply if armor not broken)
            if !armor_broken {
                let crushing_avail = if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.has_skill(SkillId::CrushingBlow) && !p.used_skills.contains(&SkillId::CrushingBlow) && !def_has_iron_hard_skin).unwrap_or(false);
                if crushing_avail {
                    if push.home_attacking { if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::CrushingBlow); } }
                    else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::CrushingBlow); }
                    events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::CrushingBlow as u16, used: true });
                    armor_broken = claws_breaks || is_armour_broken(def_av, ar1 + ar2 + mb_bonus + stunty_mod + ds_armor_mod + slayer_armor_mod + 1, rules);
                }
            }
            // Ram: once per game, attacker applies +1 to armor OR injury roll (prefer armor if not broken)
            let ram_armor_applied;
            {
                let ram_avail = if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.has_skill(SkillId::Ram) && !p.used_skills.contains(&SkillId::Ram) && !def_has_iron_hard_skin).unwrap_or(false);
                if ram_avail && !armor_broken {
                    if push.home_attacking { if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::Ram); } }
                    else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::Ram); }
                    events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::Ram as u16, used: true });
                    armor_broken = claws_breaks || is_armour_broken(def_av, ar1 + ar2 + mb_bonus + stunty_mod + ds_armor_mod + slayer_armor_mod + 1, rules);
                    ram_armor_applied = armor_broken; // applied to armor; if broke, don't also apply to injury
                } else { ram_armor_applied = false; }
            }
            last_armor_broken = armor_broken;
            if armor_broken {
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let niggling_mod = self.niggling_injury_mod(&push.defender_id, defender_is_home);
                // BrutalBlock: once per game, +1 to block injury roll (auto-apply if unused)
                let brutal_block_mod = if att_has_brutal_block {
                    let already_used = if push.home_attacking {
                        self.game.team_home.player(&push.attacker_id)
                    } else {
                        self.game.team_away.player(&push.attacker_id)
                    }.map(|p| p.used_skills.contains(&SkillId::BrutalBlock)).unwrap_or(true);
                    if !already_used {
                        if push.home_attacking {
                            if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) {
                                p.used_skills.insert(SkillId::BrutalBlock);
                            }
                        } else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) {
                            p.used_skills.insert(SkillId::BrutalBlock);
                        }
                        events.push(GameEvent::SkillUse {
                            player_id: push.attacker_id.clone(),
                            skill_id: SkillId::BrutalBlock as u16,
                            used: true,
                        });
                        1
                    } else { 0 }
                } else { 0 };
                // MightyBlow: +1 to injury roll (same +1 as armor roll)
                let mb_inj_mod = if att_has_mb { 1 } else { 0 };
                // Slayer: +1 to injury roll vs ST 5+ defenders (only if armor mod was applied)
                let slayer_inj_mod = if slayer_armor_mod > 0 { 1 } else { 0 };
                // Ram: +1 to injury roll if not applied to armor roll
                let ram_inj_mod = if !ram_armor_applied {
                    let ram_avail = if push.home_attacking {
                        self.game.team_home.player(&push.attacker_id)
                    } else {
                        self.game.team_away.player(&push.attacker_id)
                    }.map(|p| p.has_skill(SkillId::Ram) && !p.used_skills.contains(&SkillId::Ram) && !def_has_iron_hard_skin).unwrap_or(false);
                    if ram_avail {
                        if push.home_attacking { if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::Ram); } }
                        else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::Ram); }
                        events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::Ram as u16, used: true });
                        1
                    } else { 0 }
                } else { 0 };
                // SavageMauling: once per game, attacker rerolls injury roll
                let mut inj_total_base = inj1 + inj2 + niggling_mod + brutal_block_mod + mb_inj_mod + slayer_inj_mod + ram_inj_mod;
                let sm_avail = if push.home_attacking {
                    self.game.team_home.player(&push.attacker_id)
                } else {
                    self.game.team_away.player(&push.attacker_id)
                }.map(|p| p.has_skill(SkillId::SavageMauling) && !p.used_skills.contains(&SkillId::SavageMauling)).unwrap_or(false);
                if sm_avail {
                    if push.home_attacking { if let Some(p) = self.game.team_home.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::SavageMauling); } }
                    else if let Some(p) = self.game.team_away.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::SavageMauling); }
                    events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::SavageMauling as u16, used: true });
                    let ri1 = self.rng.d6(); let ri2 = self.rng.d6();
                    let reroll_total = ri1 + ri2 + niggling_mod + brutal_block_mod + mb_inj_mod + slayer_inj_mod + ram_inj_mod;
                    if reroll_total > inj_total_base { inj_total_base = reroll_total; }
                }
                let total = inj_total_base;
                let mut was_cas = total >= 10;
                let mut was_ko = total >= 8 && !was_cas;
                // ThickSkull: on KO, roll D6; on 4+, only Stunned
                if was_ko && self.check_thick_skull(&push.defender_id, defender_is_home, &mut events) {
                    was_ko = false;
                }
                // Decay: any BH/Stunned result on a player with Decay becomes CAS instead.
                let defender_has_decay = if push.home_attacking {
                    self.game.team_away.player(&push.defender_id)
                } else {
                    self.game.team_home.player(&push.defender_id)
                }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
                if defender_has_decay && !was_cas && !was_ko {
                    was_cas = true;
                }
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };

                // Regeneration: CAS'd player with Regeneration rolls D6; on 4+ recovers to reserve
                let regen = if was_cas {
                    self.try_regeneration(&push.defender_id, defender_is_home, &mut events)
                } else { false };
                let was_cas = was_cas && !regen;

                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) }; // regen: already set by try_regeneration
                if !regen {
                    self.game.field_model.set_player_state(&push.defender_id, new_state);
                }
                if was_cas {
                    use ffb_mechanics::mechanics::casualty_spp;
                    let cas_spp = casualty_spp(rules, false);
                    self.award_spp(&push.attacker_id, push.home_attacking, cas_spp);
                    // PumpUpTheCrowd: once per drive, attacker causes block CAS → grant team reroll
                    let (has_putc, used_putc) = {
                        let team = if push.home_attacking { &self.game.team_home } else { &self.game.team_away };
                        let p = team.player(&push.attacker_id);
                        (p.map(|p| p.has_skill(SkillId::PumpUpTheCrowd)).unwrap_or(false),
                         if push.home_attacking { self.game.turn_data_home.rerolls_pump_up_the_crowd_one_drive > 0 }
                         else { self.game.turn_data_away.rerolls_pump_up_the_crowd_one_drive > 0 })
                    };
                    if has_putc && !used_putc {
                        events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::PumpUpTheCrowd as u16, used: true });
                        let td = if push.home_attacking { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
                        td.rerolls_pump_up_the_crowd_one_drive += 1;
                        td.rerolls += 1;
                    }
                }
                // Offer apothecary if available (not for KO or regen)
                let offered = if !regen {
                    self.try_offer_apothecary(
                        &push.defender_id.clone(), defender_is_home,
                        &push.attacker_id.clone(), push.home_attacking,
                        ar1, ar2, inj1, inj2, was_ko, was_cas, si, is_dead,
                    )
                } else { false };
                if offered {
                    // Engine will pause for apothecary response — set up follow-up pending first
                    self.pending_follow_up = Some(PendingFollowUp {
                        attacker_id: push.attacker_id.clone(),
                        attacker_from: push.attacker_coord,
                        attacker_to: defender_old_coord,
                        defender_id: push.defender_id.clone(),
                        knocked_down: push.do_armor,
                    });
                    self.game.acting_player.has_acted = true;
                    if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                        self.game.acting_player.blitz_blocked = true;
                    }
                    return Ok(events);
                }
                if was_cas {
                    if let Some(si_kind) = si {
                        self.apply_casualty_to_player(&push.defender_id, !push.home_attacking, si_kind);
                    }
                }
                events.push(GameEvent::Injury {
                    player_id: push.defender_id.clone(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                events.push(GameEvent::Injury {
                    player_id: push.defender_id.clone(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: None,
                    serious_injury: None,
                    was_ko: false,
                    was_cas: false,
                });
            }
        }

        // Piling On (BB2016): after a Pow/PowPushback, if defender is not a casualty,
        // offer attacker the option to go prone and re-roll armor (+2) or injury (+2).
        if push.do_armor && att_has_piling_on_push {
            let used_piling_on = if push.home_attacking {
                self.game.team_home.player(&push.attacker_id)
            } else {
                self.game.team_away.player(&push.attacker_id)
            }.map(|p| p.used_skills.contains(&SkillId::PilingOn)).unwrap_or(false);
            let defender_is_cas = {
                let state = self.game.field_model.player_state(&push.defender_id)
                    .unwrap_or(PlayerState::new(PS_PRONE));
                state.base() == PS_BADLY_HURT || state.base() == PS_KNOCKED_OUT
            };
            let attacker_is_falling = {
                let state = self.game.field_model.player_state(&push.attacker_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                state.base() == PS_PRONE
            };
            if !used_piling_on && !defender_is_cas && !attacker_is_falling {
                self.pending_piling_on = Some(PendingPilingOn {
                    attacker_id: push.attacker_id.clone(),
                    defender_id: push.defender_id.clone(),
                    home_attacking: push.home_attacking,
                    defender_coord: dest,
                    armor_broken: last_armor_broken,
                });
                self.cached_prompt = Some(AgentPrompt::PilingOn {
                    player_id: push.attacker_id.clone(),
                    target_id: push.defender_id.clone(),
                });
                events.push(GameEvent::PilingOn {
                    player_id: push.attacker_id.clone(),
                    target_id: push.defender_id.clone(),
                    rerolled: false,
                });
                self.game.acting_player.has_acted = true;
                if matches!(self.game.acting_player.player_action, Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)) {
                    self.game.acting_player.blitz_blocked = true;
                }
                return Ok(events);
            }
        }

        // PileDriver: after a block that knocked the defender down, attacker can foul
        if push.do_armor {
            let att_has_pile_driver = if push.home_attacking {
                self.game.team_home.player(&push.attacker_id)
            } else {
                self.game.team_away.player(&push.attacker_id)
            }.map(|p| p.has_skill(SkillId::PileDriver)).unwrap_or(false);
            let foul_used = if push.home_attacking {
                self.game.turn_data_home.foul_used
            } else {
                self.game.turn_data_away.foul_used
            };
            let defender_is_prone = self.game.field_model.player_state(&push.defender_id)
                .map(|s| s.base() == PS_PRONE || s.base() == PS_STUNNED)
                .unwrap_or(false);
            if att_has_pile_driver && !foul_used && defender_is_prone {
                // Auto-apply foul using existing foul mechanics
                if push.home_attacking { self.game.turn_data_home.foul_used = true; } else { self.game.turn_data_away.foul_used = true; }
                let foul_events = self.apply_foul(&push.attacker_id, &push.defender_id)?;
                events.extend(foul_events);
            }
        }

        // Mark block step done on the acting player
        self.game.acting_player.has_acted = true;
        if matches!(
            self.game.acting_player.player_action,
            Some(PlayerAction::Blitz) | Some(PlayerAction::StandUpBlitz)
        ) {
            self.game.acting_player.blitz_blocked = true;
        }

        // Check for Frenzy: if the attacker has Frenzy and this was a pushback (not a Pow-only),
        // the attacker must follow up and make a second block if the defender is still standing.
        let tmp_frenzy = self.game.acting_player.player_id.as_deref() == Some(push.attacker_id.as_str())
            && self.game.acting_player.temporary_frenzy;
        let att_has_frenzy = if push.home_attacking {
            self.game.team_home.player(&push.attacker_id)
        } else {
            self.game.team_away.player(&push.attacker_id)
        }.map(|p| p.has_skill(SkillId::Frenzy)).unwrap_or(false) || tmp_frenzy;

        if att_has_frenzy {
            // Forced follow-up: attacker moves to defender's old square automatically
            self.game.field_model.set_player_coordinate(&push.attacker_id, defender_old_coord);
            events.push(GameEvent::PlayerMoved {
                player_id: push.attacker_id.clone(),
                coord: defender_old_coord,
            });

            // Second block: only if defender is still on-pitch and standing
            let defender_state = self.game.field_model.player_state(&push.defender_id);
            let defender_coord = self.game.field_model.player_coordinate(&push.defender_id);
            if let (Some(ds), Some(dc)) = (defender_state, defender_coord) {
                let defender_standing = ds.base() == PS_STANDING;
                let adjacent = defender_old_coord.is_adjacent(dc);
                if defender_standing && adjacent {
                    let att_id = push.attacker_id.clone();
                    let def_id = push.defender_id.clone();
                    let frenzy_events = self.apply_block(&att_id, &def_id)?;
                    events.extend(frenzy_events);
                    return Ok(events);
                }
            }
            // FuryOfTheBloodGod: when Frenzy second block can't fire (defender not standing/adjacent),
            // grant 2 extra block actions
            let fotbg_avail = if push.home_attacking {
                self.game.team_home.player(&push.attacker_id)
            } else {
                self.game.team_away.player(&push.attacker_id)
            }.map(|p| {
                p.has_skill(SkillId::FuryOfTheBloodGod) && !p.used_skills.contains(&SkillId::FuryOfTheBloodGod)
            }).unwrap_or(false);
            if fotbg_avail {
                let team = if push.home_attacking { &mut self.game.team_home } else { &mut self.game.team_away };
                if let Some(p) = team.player_mut(&push.attacker_id) { p.used_skills.insert(SkillId::FuryOfTheBloodGod); }
                events.push(GameEvent::SkillUse { player_id: push.attacker_id.clone(), skill_id: SkillId::FuryOfTheBloodGod as u16, used: true });
                self.game.acting_player.fury_of_blood_god_blocks = 2;
                self.game.acting_player.blitz_blocked = false; // allow extra blocks
            }
            return Ok(events);
        }

        // Stand Firm: defender stayed put — no follow-up square available; check HitAndRun
        if push.def_has_stand_firm {
            if let Some(har) = self.build_hit_and_run(&push.attacker_id, push.home_attacking) {
                self.cached_prompt = Some(AgentPrompt::HitAndRun {
                    player_id: push.attacker_id.clone(),
                    squares: har.valid_squares.clone(),
                });
                self.pending_hit_and_run = Some(har);
            }
            return Ok(events);
        }

        // Fend: defender has Fend — attacker may not follow up after a push; check HitAndRun
        if push.def_has_fend {
            events.push(GameEvent::SkillUse {
                player_id: push.defender_id.clone(),
                skill_id: SkillId::Fend as u16,
                used: true,
            });
            self.game.acting_player.has_acted = true;
            if let Some(har) = self.build_hit_and_run(&push.attacker_id, push.home_attacking) {
                self.cached_prompt = Some(AgentPrompt::HitAndRun {
                    player_id: push.attacker_id.clone(),
                    squares: har.valid_squares.clone(),
                });
                self.pending_hit_and_run = Some(har);
            }
            return Ok(events);
        }

        // Saboteur (BB2025): after defender falls on a Pow, they may roll 4+ to knock down attacker.
        if push.do_armor && self.game.rules == Rules::Bb2025 {
            let defender_is_home = !push.home_attacking;
            let def_has_saboteur = if defender_is_home {
                self.game.team_home.player(&push.defender_id)
            } else {
                self.game.team_away.player(&push.defender_id)
            }.map(|p| p.has_skill(SkillId::Saboteur)).unwrap_or(false);
            let attacker_is_standing = self.game.field_model.player_state(&push.attacker_id)
                .map(|s| s.is_standing()).unwrap_or(false);
            if def_has_saboteur && attacker_is_standing {
                self.cached_prompt = Some(AgentPrompt::SkillUse {
                    player_id: push.defender_id.clone(),
                    skill_id: SkillId::Saboteur as u16,
                    skill_name: "Saboteur".into(),
                });
                self.pending_saboteur = Some(PendingSaboteur {
                    player_id: push.defender_id.clone(),
                    target_id: push.attacker_id.clone(),
                    is_home: defender_is_home,
                });
                // Suspend follow-up until Saboteur resolves; store pending for after
                self.pending_follow_up = Some(PendingFollowUp {
                    attacker_id: push.attacker_id.clone(),
                    attacker_from: push.attacker_coord,
                    attacker_to: defender_old_coord,
                    defender_id: push.defender_id.clone(),
                    knocked_down: push.do_armor,
                });
                return Ok(events);
            }
        }

        // Taunt (BB2025): on a Pushback (not Pow), defender with Taunt may force attacker to follow up.
        if self.game.rules == Rules::Bb2025 && !push.do_armor {
            let defender_is_home = !push.home_attacking;
            let def_has_taunt = if defender_is_home {
                self.game.team_home.player(&push.defender_id)
            } else {
                self.game.team_away.player(&push.defender_id)
            }.map(|p| p.has_skill(SkillId::Taunt)).unwrap_or(false);
            if def_has_taunt {
                let follow_up = PendingFollowUp {
                    attacker_id: push.attacker_id.clone(),
                    attacker_from: push.attacker_coord,
                    attacker_to: defender_old_coord,
                    defender_id: push.defender_id.clone(),
                    knocked_down: false, // Taunt only triggers on Pushback, not Pow
                };
                self.cached_prompt = Some(AgentPrompt::SkillUse {
                    player_id: push.defender_id.clone(),
                    skill_id: SkillId::Taunt as u16,
                    skill_name: "Taunt".into(),
                });
                self.pending_taunt = Some(PendingTaunt {
                    defender_id: push.defender_id.clone(),
                    defender_is_home,
                    follow_up,
                });
                return Ok(events);
            }
        }

        // Offer follow-up
        self.pending_follow_up = Some(PendingFollowUp {
            attacker_id: push.attacker_id.clone(),
            attacker_from: push.attacker_coord,
            attacker_to: defender_old_coord,
            defender_id: push.defender_id.clone(),
            knocked_down: push.do_armor,
        });
        self.cached_prompt = Some(AgentPrompt::FollowUp {
            attacker_id: push.attacker_id.clone(),
            target_coord: defender_old_coord,
        });

        Ok(events)
    }

    /// Choose the best block result for the picking player.
    ///
    /// Priority for attacker: Pow > PowPushback > Pushback > BothDown > Skull
    /// Priority for defender: Skull > BothDown > Pushback > PowPushback > Pow
    fn pick_best_block_result(results: &[BlockResult], attacker_picks: bool) -> BlockResult {
        if results.is_empty() {
            return BlockResult::Pushback;
        }
        let priority: &[BlockResult] = if attacker_picks {
            &[BlockResult::Pow, BlockResult::PowPushback, BlockResult::Pushback,
              BlockResult::BothDown, BlockResult::Skull]
        } else {
            &[BlockResult::Skull, BlockResult::BothDown, BlockResult::Pushback,
              BlockResult::PowPushback, BlockResult::Pow]
        };
        for &desired in priority {
            if results.contains(&desired) {
                return desired;
            }
        }
        results[0]
    }

    /// Apply a Move action: walk the given path, rolling for GFI/dodge at each step.
    ///
    /// On a failed roll the player goes prone and movement stops.
    /// On a touchdown the score is updated and the drive ends.
    fn apply_move(
        &mut self,
        player_id: &str,
        path: &[FieldCoordinate],
    ) -> Result<Vec<GameEvent>, RulesError> {
        // TakeRoot: if player is rooted, they cannot move
        if self.game.field_model.player_state(player_id).map(|s| s.is_rooted()).unwrap_or(false) {
            return Ok(vec![]);
        }

        // BallAndChain: ignore provided path; auto-resolve random direction movement
        let has_ball_and_chain = {
            let home_moving = self.game.home_playing;
            if home_moving {
                self.game.team_home.player(player_id)
            } else {
                self.game.team_away.player(player_id)
            }.map(|p| p.has_skill(SkillId::BallAndChain)).unwrap_or(false)
        };
        if has_ball_and_chain {
            return self.apply_ball_and_chain_move(player_id);
        }

        let mut events = Vec::new();
        let home_moving = self.game.home_playing;
        let rules = self.game.rules;

        // Get player stats (stable over the move)
        let player = if home_moving {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        };
        let quick_snap = if home_moving { self.game.turn_data_home.quick_snap_bonus } else { self.game.turn_data_away.quick_snap_bonus };
        let ma = player.map(|p| p.movement).unwrap_or(6) + quick_snap;
        let ag = player.map(|p| p.agility).unwrap_or(3);
        let st = player.map(|p| p.strength).unwrap_or(3);
        let has_sure_hands = player.map(|p| p.has_skill(SkillId::SureHands)).unwrap_or(false);
        let has_big_hand = player.map(|p| p.has_skill(SkillId::BigHand)).unwrap_or(false);
        let has_no_hands = player.map(|p| p.has_skill(SkillId::NoHands)).unwrap_or(false);
        let has_sure_feet = player.map(|p| p.has_skill(SkillId::SureFeet)).unwrap_or(false);
        let has_dodge_reroll = player.map(|p|
            p.has_skill(SkillId::SureFeet) || p.has_skill(SkillId::Dodge)
        ).unwrap_or(false);
        let has_two_heads = player.map(|p| p.has_skill(SkillId::TwoHeads)).unwrap_or(false);
        let has_break_tackle = player.map(|p| p.has_skill(SkillId::BreakTackle)).unwrap_or(false);
        let has_sprint = player.map(|p| p.has_skill(SkillId::Sprint)).unwrap_or(false);
        let has_burst_of_speed = player.map(|p| p.has_skill(SkillId::BurstOfSpeed)).unwrap_or(false);
        let used_burst_of_speed = player.map(|p| p.used_skills.contains(&SkillId::BurstOfSpeed)).unwrap_or(false);
        let has_drunkard = player.map(|p| p.has_skill(SkillId::Drunkard)).unwrap_or(false);
        let has_leap = player.map(|p| p.has_skill(SkillId::Leap) || p.has_skill(SkillId::PogoStick) || p.has_skill(SkillId::Pogo)).unwrap_or(false);
        let has_jump_up = player.map(|p| p.has_skill(SkillId::JumpUp)).unwrap_or(false);
        let has_very_long_legs = player.map(|p| p.has_skill(SkillId::VeryLongLegs)).unwrap_or(false);
        // Maximum GFI steps: normally 2; Sprint allows 3; BurstOfSpeed allows 3 once per game.
        let max_gfi: i32 = if has_sprint { 3 } else if has_burst_of_speed && !used_burst_of_speed { 3 } else { 2 };
        // Drop immutable borrow before the loop (used_skills checked fresh each step)

        // Current move count is tracked in acting_player
        let mut current_move = self.game.acting_player.current_move;

        // Stand-up from prone (only on first activation, current_move == 0)
        if current_move == 0 {
            let player_state = self.game.field_model.player_state(player_id)
                .unwrap_or(PlayerState::new(PS_STANDING));
            if player_state.base() == PS_PRONE {
                if has_jump_up {
                    // JumpUp: free stand-up with a roll (target 2+ in BB2016; 7-ag in BB2020+).
                    let jump_up_target = match rules {
                        Rules::Bb2016 => 2,
                        _ => ((7 - ag).max(2)).min(6),
                    };
                    let roll = self.rng.d6();
                    let success = roll >= jump_up_target;
                    events.push(GameEvent::JumpUpRoll {
                        player_id: player_id.to_owned(),
                        target: jump_up_target,
                        roll,
                        success,
                    });
                    if !success {
                        // Failed JumpUp — stays prone, can't act further
                        self.game.acting_player.current_move = current_move;
                        return Ok(events);
                    }
                    // Succeeded: stand up for free (no movement cost)
                } else if must_roll_to_stand_up(ma) {
                    // MA ≤ 3: need 4+ to stand up
                    // Timmmber: adjacent standing teammates not in tackle zones add +1 each
                    let timmmber_bonus = if player.map(|p| p.has_skill(SkillId::Timmmber)).unwrap_or(false) {
                        let prone_coord = self.game.field_model.player_coordinate(player_id)
                            .unwrap_or(FieldCoordinate::new(13, 7));
                        let own_team = if home_moving { &self.game.team_home } else { &self.game.team_away };
                        let opp_team = if home_moving { &self.game.team_away } else { &self.game.team_home };
                        own_team.players.iter().filter(|m| m.id != player_id).filter(|m| {
                            let mc = self.game.field_model.player_coordinate(&m.id);
                            let ms = self.game.field_model.player_state(&m.id);
                            match (mc, ms) {
                                (Some(mc), Some(ms)) => mc.is_adjacent(prone_coord) && ms.is_standing(),
                                _ => false,
                            }
                        }).filter(|m| {
                            // Not in any enemy tackle zone
                            let mc = self.game.field_model.player_coordinate(&m.id).unwrap();
                            !opp_team.players.iter().any(|op| {
                                let oc = self.game.field_model.player_coordinate(&op.id);
                                let os = self.game.field_model.player_state(&op.id);
                                match (oc, os) {
                                    (Some(oc), Some(os)) => oc.is_adjacent(mc) && os.has_tacklezones(),
                                    _ => false,
                                }
                            })
                        }).count() as i32
                    } else { 0 };
                    let roll = self.rng.d6();
                    // Always a failure on a 1; otherwise 4+ (Timmmber bonus adds +1 per assisting teammate)
                    let success = roll > 1 && (roll + timmmber_bonus >= 4);
                    events.push(GameEvent::StandUpRoll {
                        player_id: player_id.to_owned(),
                        target: 4,
                        roll,
                        success,
                    });
                    if !success {
                        // Failed stand-up — stays prone, turn over
                        events.push(GameEvent::PlayerFellDown {
                            player_id: player_id.to_owned(),
                            coord: self.game.field_model.player_coordinate(player_id)
                                .unwrap_or(FieldCoordinate::new(13, 7)),
                        });
                        self.game.acting_player.current_move = current_move;
                        return Ok(events);
                    }
                }
                // Stand up: pay STAND_UP_COST squares (JumpUp skips this cost)
                if !has_jump_up {
                    current_move += STAND_UP_COST;
                }
                self.game.field_model.set_player_state(
                    player_id,
                    player_state.change_base(PS_STANDING),
                );
            }
        }

        for (step_idx, &dest) in path.iter().enumerate() {
            if !dest.is_on_pitch() {
                return Err(RulesError::OutOfBounds);
            }

            // Capture source coordinate before any movement this step.
            let source_coord = self.game.field_model.player_coordinate(player_id)
                .unwrap_or(dest);

            // ── Tentacles check ───────────────────────────────────────────────
            // Any adjacent opponent with Tentacles and TZ can attempt to hold the mover.
            // Formula: 2d6 ≥ (6 + tentacles_ST - mover_ST). On failure: player stays.
            {
                let tentacle_opponents: Vec<(String, i32)> = {
                    let adj = self.game.field_model.adjacent_on_pitch(source_coord);
                    adj.into_iter()
                        .filter_map(|ac| self.game.field_model.player_at(ac).cloned().map(|id| (id, ac)))
                        .filter(|(tid, _ac)| {
                            // Must be an opposing player with TZ
                            let is_opp = if home_moving {
                                self.game.team_away.has_player(tid)
                            } else {
                                self.game.team_home.has_player(tid)
                            };
                            if !is_opp { return false; }
                            let opp_state = self.game.field_model.player_state(tid)
                                .unwrap_or(PlayerState::new(PS_STANDING));
                            opp_state.has_tacklezones()
                        })
                        .filter_map(|(tid, _ac)| {
                            let opp = if home_moving {
                                self.game.team_away.player(&tid)
                            } else {
                                self.game.team_home.player(&tid)
                            };
                            let has_tentacles = opp.map(|p| p.has_skill(SkillId::Tentacles)).unwrap_or(false);
                            if has_tentacles {
                                Some((tid.clone(), opp.map(|p| p.strength).unwrap_or(3)))
                            } else {
                                None
                            }
                        })
                        .collect()
                };
                let mut held_by_tentacles = false;
                for (tent_id, tent_st) in &tentacle_opponents {
                    let min_escape = (6 + tent_st - st).max(2);
                    let r1 = self.rng.d6();
                    let r2 = self.rng.d6();
                    let escaped = r1 + r2 >= min_escape;
                    events.push(GameEvent::EscapeRoll {
                        player_id: player_id.to_owned(),
                        roll: r1 + r2,
                        success: escaped,
                    });
                    if !escaped {
                        // Player is held — movement ends at source.
                        held_by_tentacles = true;
                        let _ = tent_id;
                        break;
                    }
                }
                if held_by_tentacles {
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
            }

            // Check for GFI (Sprint: allows up to 3 GFI steps instead of 2)
            let gfi = current_move >= ma;
            if gfi && (current_move - ma) >= max_gfi {
                // Exceeded maximum GFI steps — illegal move; fall prone without rolling
                self.game.field_model.set_player_coordinate(player_id, dest);
                let cur_state = self.game.field_model.player_state(player_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                self.game.field_model.set_player_state(player_id, cur_state.change_active(false).change_base(PS_PRONE));
                events.push(GameEvent::PlayerFellDown { player_id: player_id.to_owned(), coord: dest });
                if let Some(scatter_ev) = self.scatter_ball_if_carried(player_id, source_coord, home_moving) {
                    events.push(scatter_ev);
                }
                self.game.acting_player.current_move = current_move + 1;
                return Ok(events);
            }
            if gfi {
                // BurstOfSpeed: mark used when taking the third GFI (gfi_index=2 → current_move-ma == 2)
                if has_burst_of_speed && !used_burst_of_speed && (current_move - ma) == 2 {
                    let team = if home_moving { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(player_id) {
                        p.used_skills.insert(SkillId::BurstOfSpeed);
                    }
                    events.push(GameEvent::SkillUse {
                        player_id: player_id.to_owned(),
                        skill_id: SkillId::BurstOfSpeed as u16,
                        used: true,
                    });
                }
                let gfi_mod = (if rules == Rules::Bb2025 && self.game.weather == Weather::Blizzard { 1 } else { 0 })
                    + if has_drunkard { 1 } else { 0 };
                let min_roll = minimum_roll_going_for_it(gfi_mod);
                let roll = self.rng.d6();
                let gfi_success = is_skill_roll_successful(roll, min_roll);
                events.push(GameEvent::GoForItRoll {
                    player_id: player_id.to_owned(),
                    target: min_roll,
                    roll,
                    success: gfi_success,
                    rerolled: false,
                });
                if !gfi_success {
                    // Failed GFI — move player to dest first (they tried to go there)
                    let cur_coord = self.game.field_model.player_coordinate(player_id)
                        .unwrap_or(dest);
                    self.game.field_model.set_player_coordinate(player_id, dest);
                    self.game.acting_player.current_move = current_move + 1;

                    // SureFeet: free GFI reroll, once per turn
                    let sf_used = {
                        let team = if home_moving { &self.game.team_home } else { &self.game.team_away };
                        team.player(player_id).map(|p| p.used_skills.contains(&SkillId::SureFeet)).unwrap_or(true)
                    };
                    if has_sure_feet && !sf_used {
                        let reroll = self.rng.d6();
                        let sf_success = is_skill_roll_successful(reroll, min_roll);
                        {
                            let team = if home_moving { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::SureFeet); }
                        }
                        events.push(GameEvent::GoForItRoll {
                            player_id: player_id.to_owned(),
                            target: min_roll,
                            roll: reroll,
                            success: sf_success,
                            rerolled: true,
                        });
                        if sf_success {
                            // Continue the move after a successful SureFeet reroll
                            current_move += 1;
                            let new_path = path[step_idx + 1..].to_vec();
                            if !new_path.is_empty() {
                                let cont = self.apply_move(player_id, &new_path)?;
                                events.extend(cont);
                            }
                            return Ok(events);
                        }
                        // Fell down even after SureFeet — fall through to prone
                    }

                    // ConsummateProfessional: free once-per-game reroll (checked before team reroll)
                    if self.cp_reroll_available(&player_id, home_moving) {
                        let path_remaining = path[step_idx + 1..].to_vec();
                        let pending = PendingReroll::GoForIt {
                            player_id: player_id.to_owned(),
                            home_moving,
                            origin_coord: source_coord,
                            dest,
                            path_remaining,
                            min_roll,
                            is_pro: false,
                            is_consummate_professional: true,
                        };
                        self.offer_cp_reroll(&player_id, home_moving, "goForIt", pending, &mut events);
                        return Ok(events);
                    }
                    // SwiftAsTheBreeze: once per game, pass GFI on 2+ (ignore modifiers)
                    {
                        let swift_avail = if home_moving {
                            self.game.team_home.player(&player_id)
                        } else {
                            self.game.team_away.player(&player_id)
                        }.map(|p| p.has_skill(SkillId::SwiftAsTheBreeze) && !p.used_skills.contains(&SkillId::SwiftAsTheBreeze)).unwrap_or(false);
                        if swift_avail {
                            if home_moving { if let Some(p) = self.game.team_home.player_mut(&player_id) { p.used_skills.insert(SkillId::SwiftAsTheBreeze); } }
                            else if let Some(p) = self.game.team_away.player_mut(&player_id) { p.used_skills.insert(SkillId::SwiftAsTheBreeze); }
                            events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::SwiftAsTheBreeze as u16, used: true });
                            // Auto-succeed at 2+
                            let path_remaining = path[step_idx + 1..].to_vec();
                            self.offer_reroll(home_moving, "goForIt", PendingReroll::GoForIt {
                                player_id: player_id.to_owned(), home_moving,
                                origin_coord: source_coord, dest, path_remaining,
                                min_roll: 2, // ignore modifiers
                                is_pro: false,
                                is_consummate_professional: true, // free, already consumed
                            });
                            return Ok(events);
                        }
                    }
                    // HalflingLuck / ThinkingMansTroll: once-per-game/half personal free reroll for GFI
                    {
                        let path_remaining = path[step_idx + 1..].to_vec();
                        let (hl, tmt) = if home_moving {
                            let p = self.game.team_home.player(&player_id);
                            (p.map(|p| p.has_skill(SkillId::HalflingLuck) && !p.used_skills.contains(&SkillId::HalflingLuck)).unwrap_or(false),
                             p.map(|p| p.has_skill(SkillId::ThinkingMansTroll) && !p.used_skills.contains(&SkillId::ThinkingMansTroll)).unwrap_or(false))
                        } else {
                            let p = self.game.team_away.player(&player_id);
                            (p.map(|p| p.has_skill(SkillId::HalflingLuck) && !p.used_skills.contains(&SkillId::HalflingLuck)).unwrap_or(false),
                             p.map(|p| p.has_skill(SkillId::ThinkingMansTroll) && !p.used_skills.contains(&SkillId::ThinkingMansTroll)).unwrap_or(false))
                        };
                        if hl || tmt {
                            let skill_used = if hl { SkillId::HalflingLuck } else { SkillId::ThinkingMansTroll };
                            if home_moving { if let Some(p) = self.game.team_home.player_mut(&player_id) { p.used_skills.insert(skill_used); } }
                            else if let Some(p) = self.game.team_away.player_mut(&player_id) { p.used_skills.insert(skill_used); }
                            events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: skill_used as u16, used: true });
                            self.offer_reroll(home_moving, "goForIt", PendingReroll::GoForIt {
                                player_id: player_id.to_owned(), home_moving,
                                origin_coord: source_coord, dest, path_remaining, min_roll,
                                is_pro: false,
                                is_consummate_professional: true, // free reroll, skill already consumed
                            });
                            return Ok(events);
                        }
                    }
                    // Offer team reroll (or Pro) if available
                    let pro_available = self.pro_reroll_available(&player_id, home_moving);
                    if self.team_reroll_available(home_moving) || pro_available {
                        let is_pro = !self.team_reroll_available(home_moving) && pro_available;
                        let path_remaining = path[step_idx + 1..].to_vec();
                        self.offer_reroll(home_moving, "goForIt", PendingReroll::GoForIt {
                            player_id: player_id.to_owned(),
                            home_moving,
                            origin_coord: source_coord,
                            dest,
                            path_remaining,
                            min_roll,
                            is_pro,
                            is_consummate_professional: false,
                        });
                        return Ok(events);
                    }

                    // SteadyFooting (BB2025): on 6, player doesn't fall; can continue moving
                    if self.try_steady_footing(player_id, home_moving, &mut events) {
                        current_move += 1;
                        self.game.acting_player.current_move = current_move;
                        let new_path = path[step_idx + 1..].to_vec();
                        if !new_path.is_empty() {
                            let cont = self.apply_move(player_id, &new_path)?;
                            events.extend(cont);
                        }
                        return Ok(events);
                    }

                    // No reroll → fall prone at dest with armor/injury roll
                    events.push(GameEvent::PlayerFellDown {
                        player_id: player_id.to_owned(),
                        coord: cur_coord,
                    });
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(player_id, cur_coord, home_moving) {
                        events.push(scatter_ev);
                    }
                    let fall_evs = self.apply_fall_injury(player_id, home_moving, 0);
                    events.extend(fall_evs);
                    return Ok(events);
                }
            }

            // Leap: if dest is occupied by any standing/moving player AND the mover has Leap,
            // perform an AG roll instead of a dodge. On fail the mover falls prone at dest.
            let dest_occupied = self.game.field_model.player_at(dest).is_some();
            if dest_occupied {
                if has_leap {
                    // Leap roll: target 2+ in BB2016; (7-ag) capped at [2,6] in BB2020+.
                    // VeryLongLegs: -1 modifier to leap/jump target (easier to succeed).
                    let vll_leap_mod = if has_very_long_legs { -1 } else { 0 };
                    // BoundingLeap: once per game, ignore modifiers and treat leap target as 2+
                    let bounding_leap_avail = if home_moving {
                        self.game.team_home.player(&player_id)
                    } else {
                        self.game.team_away.player(&player_id)
                    }.map(|p| p.has_skill(SkillId::BoundingLeap) && !p.used_skills.contains(&SkillId::BoundingLeap)).unwrap_or(false);
                    let min_roll = if bounding_leap_avail {
                        if home_moving { if let Some(p) = self.game.team_home.player_mut(&player_id) { p.used_skills.insert(SkillId::BoundingLeap); } }
                        else if let Some(p) = self.game.team_away.player_mut(&player_id) { p.used_skills.insert(SkillId::BoundingLeap); }
                        // Note: SkillUse emitted below after the roll to keep event ordering clean
                        2
                    } else {
                        match rules {
                            Rules::Bb2016 => 2,
                            _ => ((7 - ag + vll_leap_mod).max(2)).min(6),
                        }
                    };
                    let roll = self.rng.d6();
                    let leap_success = roll >= min_roll;
                    events.push(GameEvent::JumpRoll {
                        player_id: player_id.to_owned(),
                        target: min_roll,
                        roll,
                        success: leap_success,
                    });
                    if bounding_leap_avail {
                        events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::BoundingLeap as u16, used: true });
                    }
                    if !leap_success {
                        self.game.field_model.set_player_coordinate(player_id, dest);
                        self.game.acting_player.current_move = current_move + 1;

                        if self.cp_reroll_available(&player_id, home_moving) {
                            let path_remaining = path[step_idx + 1..].to_vec();
                            let pending = PendingReroll::Leap {
                                player_id: player_id.to_owned(),
                                home_moving,
                                origin_coord: source_coord,
                                dest,
                                path_remaining,
                                min_roll,
                                is_pro: false,
                                is_consummate_professional: true,
                            };
                            self.offer_cp_reroll(&player_id, home_moving, "leap", pending, &mut events);
                            return Ok(events);
                        }
                        let pro_available = self.pro_reroll_available(&player_id, home_moving);
                        if self.team_reroll_available(home_moving) || pro_available {
                            let is_pro = !self.team_reroll_available(home_moving) && pro_available;
                            let path_remaining = path[step_idx + 1..].to_vec();
                            self.offer_reroll(home_moving, "leap", PendingReroll::Leap {
                                player_id: player_id.to_owned(),
                                home_moving,
                                origin_coord: source_coord,
                                dest,
                                path_remaining,
                                min_roll,
                                is_pro,
                                is_consummate_professional: false,
                            });
                            return Ok(events);
                        }

                        // ArmBar applies on failed leap (jump) from source_coord
                        let arm_bar = self.arm_bar_mod_at(source_coord, home_moving);
                        events.push(GameEvent::PlayerFellDown {
                            player_id: player_id.to_owned(),
                            coord: dest,
                        });
                        if let Some(scatter_ev) = self.scatter_ball_if_carried(player_id, source_coord, home_moving) {
                            events.push(scatter_ev);
                        }
                        let fall_evs = self.apply_fall_injury(player_id, home_moving, arm_bar);
                        events.extend(fall_evs);
                        current_move += 1;
                        self.game.acting_player.current_move = current_move;
                        return Ok(events);
                    }
                } else {
                    // No Leap: cannot enter occupied square — stop movement here.
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
            }

            // Check for tackle zones at destination (requires dodge roll)
            let tzs = self.count_tackle_zones_at(dest, home_moving);
            // Two Heads: never penalised by more than 1 tackle zone
            let effective_tzs = if has_two_heads { tzs.min(1) } else { tzs };
            // ── Diving Tackle: any adjacent opponent at SOURCE with unused DivingTackle adds +2
            // ── Prehensile Tail: any adjacent opponent at SOURCE with PrehensileTail adds +1
            let (diving_tackle_mod, prehensile_tail_mod): (i32, i32) = {
                let adj = self.game.field_model.adjacent_on_pitch(source_coord);
                let mut any_dt = false;
                let mut any_pt = false;
                for ac in adj {
                    if let Some(tid) = self.game.field_model.player_at(ac).cloned() {
                        let is_opp = if home_moving {
                            self.game.team_away.has_player(&tid)
                        } else {
                            self.game.team_home.has_player(&tid)
                        };
                        if !is_opp { continue; }
                        let opp = if home_moving {
                            self.game.team_away.player(&tid)
                        } else {
                            self.game.team_home.player(&tid)
                        };
                        if opp.map(|p| p.has_skill(SkillId::DivingTackle) && !p.used_skills.contains(&SkillId::DivingTackle)).unwrap_or(false) {
                            any_dt = true;
                        }
                        if opp.map(|p| p.has_skill(SkillId::PrehensileTail)).unwrap_or(false) {
                            any_pt = true;
                        }
                    }
                }
                let dt = if any_dt && effective_tzs > 0 { 2 } else { 0 };
                let pt = if any_pt { 1 } else { 0 };
                (dt, pt)
            };
            if (effective_tzs > 0 || diving_tackle_mod > 0 || prehensile_tail_mod > 0)
                && !self.game.acting_player.ignore_tackle_zones
            {
                // Break Tackle: once per turn, player may use ST instead of AG for dodge
                let used_break_tackle = if home_moving {
                    self.game.team_home.player(player_id)
                } else {
                    self.game.team_away.player(player_id)
                }.map(|p| p.used_skills.contains(&SkillId::BreakTackle)).unwrap_or(false);
                // Compute target with AG, then with ST; use the lower one if Break Tackle available
                let dp_mod = self.count_disturbing_presence(dest, home_moving);
                let total_mod = effective_tzs + diving_tackle_mod + prehensile_tail_mod + dp_mod;
                let ag_target = match rules {
                    Rules::Bb2016 => minimum_roll_dodge_bb2016(ag, total_mod),
                    _ => (ag + total_mod).max(2),
                };
                let bt_target = match rules {
                    Rules::Bb2016 => minimum_roll_dodge_bb2016(st, total_mod),
                    _ => ((7 - st) + total_mod).max(2),
                };
                let using_break_tackle = has_break_tackle && !used_break_tackle && bt_target < ag_target;
                let min_roll = if using_break_tackle { bt_target } else { ag_target };
                // Mark DivingTackle as used and make DT players prone
                if diving_tackle_mod > 0 {
                    let dt_ids: Vec<String> = {
                        let adj = self.game.field_model.adjacent_on_pitch(source_coord);
                        adj.into_iter()
                            .filter_map(|ac| self.game.field_model.player_at(ac).cloned())
                            .filter(|tid| {
                                let is_opp = if home_moving {
                                    self.game.team_away.has_player(tid)
                                } else {
                                    self.game.team_home.has_player(tid)
                                };
                                if !is_opp { return false; }
                                let opp = if home_moving {
                                    self.game.team_away.player(tid)
                                } else {
                                    self.game.team_home.player(tid)
                                };
                                opp.map(|p| p.has_skill(SkillId::DivingTackle) && !p.used_skills.contains(&SkillId::DivingTackle)).unwrap_or(false)
                            })
                            .collect()
                    };
                    for dt_id in &dt_ids {
                        if let Some(p) = if home_moving {
                            self.game.team_away.player_mut(dt_id)
                        } else {
                            self.game.team_home.player_mut(dt_id)
                        } {
                            p.used_skills.insert(SkillId::DivingTackle);
                        }
                        let dt_coord = self.game.field_model.player_coordinate(dt_id)
                            .unwrap_or(source_coord);
                        let dt_state = self.game.field_model.player_state(dt_id)
                            .unwrap_or(PlayerState::new(PS_STANDING));
                        self.game.field_model.set_player_state(dt_id, dt_state.change_base(PS_PRONE));
                        events.push(GameEvent::SkillUse {
                            player_id: dt_id.to_string(),
                            skill_id: SkillId::DivingTackle as u16,
                            used: true,
                        });
                        events.push(GameEvent::PlayerFellDown {
                            player_id: dt_id.to_owned(),
                            coord: dt_coord,
                        });
                    }
                }
                if using_break_tackle {
                    if let Some(p) = if home_moving {
                        self.game.team_home.player_mut(player_id)
                    } else {
                        self.game.team_away.player_mut(player_id)
                    } {
                        p.used_skills.insert(SkillId::BreakTackle);
                    }
                }
                let roll = self.rng.d6();
                let mut dodge_success = is_skill_roll_successful(roll, min_roll);
                let mut dodge_rerolled = false;

                // Tackle skill on any adjacent opponent negates Dodge/SureFeet reroll
                let opponent_has_tackle = self.any_adjacent_opponent_has_skill(dest, home_moving, SkillId::Tackle);

                // Dodge/SureFeet reroll on first failure (blocked by Tackle)
                let used_dodge_reroll = if home_moving {
                    self.game.team_home.player(player_id)
                } else {
                    self.game.team_away.player(player_id)
                }.map(|p| p.used_skills.contains(&SkillId::SureFeet) || p.used_skills.contains(&SkillId::Dodge)).unwrap_or(false);
                if !dodge_success && has_dodge_reroll && !used_dodge_reroll && !opponent_has_tackle {
                    let reroll = self.rng.d6();
                    dodge_success = is_skill_roll_successful(reroll, min_roll);
                    dodge_rerolled = true;
                    // Mark reroll skill as used
                    let skill_used = if rules == Rules::Bb2020 { SkillId::SureFeet } else { SkillId::Dodge };
                    if let Some(p) = if home_moving {
                        self.game.team_home.player_mut(player_id)
                    } else {
                        self.game.team_away.player_mut(player_id)
                    } {
                        p.used_skills.insert(skill_used);
                    }
                }

                events.push(GameEvent::DodgeRoll {
                    player_id: player_id.to_owned(),
                    target: min_roll,
                    roll,
                    success: dodge_success,
                    rerolled: dodge_rerolled,
                });

                if !dodge_success {
                    // Failed dodge — move player to destination (they reached it, then fell)
                    self.game.field_model.set_player_coordinate(player_id, dest);
                    self.game.acting_player.current_move = current_move + 1;

                    // ConsummateProfessional: free once-per-game reroll (checked before team reroll)
                    if self.cp_reroll_available(&player_id, home_moving) {
                        let path_remaining = path[step_idx + 1..].to_vec();
                        let pending = PendingReroll::Dodge {
                            player_id: player_id.to_owned(),
                            home_moving,
                            origin_coord: source_coord,
                            dest,
                            path_remaining,
                            min_roll,
                            is_pro: false,
                            is_consummate_professional: true,
                        };
                        self.offer_cp_reroll(&player_id, home_moving, "dodge", pending, &mut events);
                        return Ok(events);
                    }
                    // Offer team reroll (or Pro) if available (skill reroll already consumed above)
                    let pro_available = self.pro_reroll_available(&player_id, home_moving);
                    if self.team_reroll_available(home_moving) || pro_available {
                        let is_pro = !self.team_reroll_available(home_moving) && pro_available;
                        let path_remaining = path[step_idx + 1..].to_vec();
                        self.offer_reroll(home_moving, "dodge", PendingReroll::Dodge {
                            player_id: player_id.to_owned(),
                            home_moving,
                            origin_coord: source_coord,
                            dest,
                            path_remaining,
                            min_roll,
                            is_pro,
                            is_consummate_professional: false,
                        });
                        return Ok(events);
                    }

                    // SteadyFooting (BB2025): on 6, player doesn't fall; can continue moving
                    if self.try_steady_footing(player_id, home_moving, &mut events) {
                        current_move += 1;
                        self.game.acting_player.current_move = current_move;
                        let new_path = path[step_idx + 1..].to_vec();
                        if !new_path.is_empty() {
                            let cont = self.apply_move(player_id, &new_path)?;
                            events.extend(cont);
                        }
                        return Ok(events);
                    }

                    // No reroll → fall prone at dest with armor/injury roll
                    // ArmBar: opponents adjacent to source_coord (where dodge started) may apply
                    let arm_bar = self.arm_bar_mod_at(source_coord, home_moving);
                    events.push(GameEvent::PlayerFellDown {
                        player_id: player_id.to_owned(),
                        coord: dest,
                    });
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(player_id, source_coord, home_moving) {
                        events.push(scatter_ev);
                    }
                    let fall_evs = self.apply_fall_injury(player_id, home_moving, arm_bar);
                    events.extend(fall_evs);
                    current_move += 1;
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
            }

            // Track if player is carrying the ball before moving
            let was_carrying = self.game.field_model.ball_coordinate == Some(source_coord)
                && self.game.field_model.ball_in_play;

            // Move the player
            self.game.field_model.set_player_coordinate(player_id, dest);
            // Ball moves with carrier
            if was_carrying {
                self.game.field_model.ball_coordinate = Some(dest);
            }
            let cur_state = self.game.field_model.player_state(player_id)
                .unwrap_or(PlayerState::new(PS_STANDING));
            self.game.field_model.set_player_state(
                player_id,
                cur_state.change_base(PS_MOVING),
            );
            events.push(GameEvent::PlayerMoved {
                player_id: player_id.to_owned(),
                coord: dest,
            });
            current_move += 1;

            // ── Trap door check ───────────────────────────────────────────────
            // If the player lands on a trap door, roll D6: 1 = fall through (injury + removal).
            if self.game.field_model.has_trap_door(dest) {
                let roll = self.rng.d6();
                let escaped = roll != 1;
                events.push(GameEvent::TrapDoor {
                    player_id: player_id.to_owned(),
                    roll,
                    escaped,
                });
                if !escaped {
                    // Player falls through: scatter ball if carried, apply injury, remove from pitch.
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(player_id, dest, home_moving) {
                        events.push(scatter_ev);
                    }
                    let fall_evs = self.apply_fall_injury(player_id, home_moving, 0);
                    events.extend(fall_evs);
                    self.game.field_model.remove_player(player_id);
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
            }

            // ── Shadowing check ───────────────────────────────────────────────
            // After a successful step, any adjacent opponent at source with Shadowing
            // may attempt to follow. Formula: 2d6 ≥ (8 + shadowing_MA - mover_MA).
            // On success: player is pulled back to source (movement ends).
            {
                let shadowers: Vec<(String, i32)> = {
                    let adj = self.game.field_model.adjacent_on_pitch(source_coord);
                    adj.into_iter()
                        .filter_map(|ac| self.game.field_model.player_at(ac).cloned().map(|id| (id, ac)))
                        .filter(|(tid, _ac)| {
                            let is_opp = if home_moving {
                                self.game.team_away.has_player(tid)
                            } else {
                                self.game.team_home.has_player(tid)
                            };
                            if !is_opp { return false; }
                            let opp_state = self.game.field_model.player_state(tid)
                                .unwrap_or(PlayerState::new(PS_STANDING));
                            opp_state.has_tacklezones()
                        })
                        .filter_map(|(tid, _ac)| {
                            let opp = if home_moving {
                                self.game.team_away.player(&tid)
                            } else {
                                self.game.team_home.player(&tid)
                            };
                            let has_shadowing = opp.map(|p| p.has_skill(SkillId::Shadowing) && !p.used_skills.contains(&SkillId::Shadowing)).unwrap_or(false);
                            if has_shadowing {
                                Some((tid.clone(), opp.map(|p| p.movement).unwrap_or(6)))
                            } else {
                                None
                            }
                        })
                        .collect()
                };
                let mut pulled_back = false;
                for (shadow_id, shadow_ma) in &shadowers {
                    let min_escape = (8 + shadow_ma - ma).max(2);
                    let r1 = self.rng.d6();
                    let r2 = self.rng.d6();
                    let escaped = r1 + r2 >= min_escape;
                    events.push(GameEvent::EscapeRoll {
                        player_id: player_id.to_owned(),
                        roll: r1 + r2,
                        success: escaped,
                    });
                    if !escaped {
                        // Shadowing succeeds: move player back to source.
                        self.game.field_model.set_player_coordinate(player_id, source_coord);
                        let cur_st = self.game.field_model.player_state(player_id)
                            .unwrap_or(PlayerState::new(PS_STANDING));
                        self.game.field_model.set_player_state(
                            player_id, cur_st.change_base(PS_STANDING).change_active(false)
                        );
                        // Mark the shadowing player's skill as used
                        if let Some(p) = if home_moving {
                            self.game.team_away.player_mut(shadow_id)
                        } else {
                            self.game.team_home.player_mut(shadow_id)
                        } {
                            p.used_skills.insert(SkillId::Shadowing);
                        }
                        events.push(GameEvent::PlayerMoved {
                            player_id: player_id.to_owned(),
                            coord: source_coord,
                        });
                        pulled_back = true;
                        break;
                    }
                }
                if pulled_back {
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
            }

            // Check for ball pickup (skip if player was already carrying the ball)
            if !was_carrying && self.game.field_model.ball_coordinate == Some(dest) && self.game.field_model.ball_in_play {
                // NoHands / NoBall: player can never pick up the ball; ball scatters immediately
                let has_no_ball_pickup = has_no_hands || {
                    if home_moving { &self.game.team_home } else { &self.game.team_away }
                        .player(player_id).map(|p| p.has_skill(SkillId::NoBall)).unwrap_or(false)
                };
                if has_no_ball_pickup {
                    let scatter_dir = self.rng.d8();
                    events.push(GameEvent::BallScattered {
                        player_id: player_id.to_owned(),
                        coord: dest,
                        direction: scatter_dir,
                    });
                    self.mark_ball_moving();
                    self.game.acting_player.current_move = current_move;
                    return Ok(events);
                }
                let pickup_roll = self.rng.d6();
                let rain_mod = if self.game.weather == Weather::PouringRain { 1 } else { 0 };
                let dp_raw = self.count_disturbing_presence(dest, home_moving);
                let dp_mod = if has_big_hand { 0 } else { dp_raw };
                // SecureTheBall (BB2025): 2+ base instead of agility-based pickup
                let is_secure_the_ball = self.game.acting_player.player_action == Some(PlayerAction::SecureTheBall);
                let pickup_min = if is_secure_the_ball {
                    (2 + rain_mod + dp_mod).max(2)
                } else {
                    match rules {
                        Rules::Bb2016 => (6 - ag.min(6) + 1 + rain_mod + dp_mod).max(2),
                        _ => (ag + rain_mod + dp_mod).max(2),
                    }
                };
                let mut pickup_success = is_skill_roll_successful(pickup_roll, pickup_min);

                // SureHands reroll on first failure (not allowed for SecureTheBall)
                let used_sure_hands = if home_moving {
                    self.game.team_home.player(player_id)
                } else {
                    self.game.team_away.player(player_id)
                }.map(|p| p.used_skills.contains(&SkillId::SureHands)).unwrap_or(false);
                if !pickup_success && has_sure_hands && !used_sure_hands && !is_secure_the_ball {
                    let reroll = self.rng.d6();
                    pickup_success = is_skill_roll_successful(reroll, pickup_min);
                    if let Some(p) = if home_moving {
                        self.game.team_home.player_mut(player_id)
                    } else {
                        self.game.team_away.player_mut(player_id)
                    } {
                        p.used_skills.insert(SkillId::SureHands);
                    }
                }

                if pickup_success {
                    events.push(GameEvent::BallPickedUp {
                        player_id: player_id.to_owned(),
                        coord: dest,
                    });
                    self.mark_ball_not_moving();
                } else {
                    // SecureTheBall: no rerolls allowed; scatter immediately on failure
                    if !is_secure_the_ball {
                        // ConsummateProfessional: free once-per-game reroll
                        if self.cp_reroll_available(&player_id, home_moving) {
                            let pending = PendingReroll::BallPickup {
                                player_id: player_id.to_owned(),
                                home_moving,
                                coord: dest,
                                min_roll: pickup_min,
                                is_pro: false,
                                is_consummate_professional: true,
                            };
                            self.offer_cp_reroll(&player_id, home_moving, "pickUp", pending, &mut events);
                            return Ok(events);
                        }
                        // Offer team reroll (or Pro) if available
                        let pro_available = self.pro_reroll_available(&player_id, home_moving);
                        if self.team_reroll_available(home_moving) || pro_available {
                            let is_pro = !self.team_reroll_available(home_moving) && pro_available;
                            self.offer_reroll(home_moving, "pickUp", PendingReroll::BallPickup {
                                player_id: player_id.to_owned(),
                                home_moving,
                                coord: dest,
                                min_roll: pickup_min,
                                is_pro,
                                is_consummate_professional: false,
                            });
                            return Ok(events);
                        }
                    }
                    // No reroll (or SecureTheBall) → scatter ball
                    let scatter_dir = self.rng.d8();
                    events.push(GameEvent::BallScattered {
                        player_id: player_id.to_owned(),
                        coord: dest,
                        direction: scatter_dir,
                    });
                    self.mark_ball_moving();
                }
            }

            // Check for touchdown (only if player is carrying the ball)
            let player_has_ball = self.game.field_model.ball_coordinate == Some(dest)
                && self.game.field_model.ball_in_play;
            if player_has_ball && self.is_opponent_endzone(dest, home_moving) {
                if home_moving {
                    self.game.game_result.home.score += 1;
                } else {
                    self.game.game_result.away.score += 1;
                }
                // Award touchdown SPP to scorer
                use ffb_mechanics::mechanics::touchdown_spp;
                let td_spp = touchdown_spp(rules, false);
                self.award_spp(player_id, home_moving, td_spp);
                events.push(GameEvent::Touchdown {
                    player_id: player_id.to_owned(),
                    coord: dest,
                });
                // StarOfTheShow: once per game, grant one team reroll after scoring a touchdown
                let star_of_show = if home_moving {
                    self.game.team_home.player(player_id)
                } else {
                    self.game.team_away.player(player_id)
                }.map(|p| p.has_skill(SkillId::StarOfTheShow) && !p.used_skills.contains(&SkillId::StarOfTheShow)).unwrap_or(false);
                if star_of_show {
                    if home_moving { if let Some(p) = self.game.team_home.player_mut(player_id) { p.used_skills.insert(SkillId::StarOfTheShow); } }
                    else if let Some(p) = self.game.team_away.player_mut(player_id) { p.used_skills.insert(SkillId::StarOfTheShow); }
                    events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::StarOfTheShow as u16, used: true });
                    let td = if home_moving { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
                    td.rerolls += 1;
                }
                self.game.acting_player.clear();
                self.player_activated_this_turn = false;
                // Scoring team will kick off next
                self.game.field_model.ball_in_play = false;
                self.mark_ball_not_moving();
                self.game.home_playing = !home_moving;
                self.game.turn_mode = TurnMode::Setup;
                self.setup_phase = 0;
                // Eject SecretWeapon players BEFORE place_all_in_reserve so their state
                // is still on-pitch (Standing/Moving) during ejection. The scoring player
                // is PS_MOVING at this point — ejecting first ensures they are processed
                // (place_all_in_reserve would set them to PS_RESERVE, causing ejection to skip them).
                let sw_events = self.eject_secret_weapon_players();
                events.extend(sw_events);
                self.place_all_in_reserve();
                self.game.acting_player.current_move = 0;
                return Ok(events);
            }
        }

        self.game.acting_player.current_move = current_move;

        // PickMeUp (BB2020+): non-active team's PickMeUp players may stand up prone teammates.
        if rules != Rules::Bb2016 && self.pending_pick_me_up.is_none() {
            let eligible = self.compute_pick_me_up_eligible(!home_moving);
            if !eligible.is_empty() {
                self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                    eligible_players: eligible.clone(),
                    reason: "pickMeUp".into(),
                });
                self.pending_pick_me_up = Some(PendingPickMeUp {
                    is_home: !home_moving,
                    eligible_players: eligible,
                });
            }
        }

        Ok(events)
    }

    /// Find prone players on `is_home` team that can be assisted by a teammate with PickMeUp.
    fn compute_pick_me_up_eligible(&self, is_home: bool) -> Vec<String> {
        use std::collections::HashSet;
        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        let field = &self.game.field_model;

        // PickMeUp players: on the team, with tackle zones (standing), have PickMeUp skill
        let pick_me_up_coords: Vec<FieldCoordinate> = team.players.iter()
            .filter(|p| p.has_skill(SkillId::PickMeUp))
            .filter_map(|p| {
                let state = field.player_state(&p.id)?;
                if state.has_tacklezones() { field.player_coordinate(&p.id) } else { None }
            })
            .collect();

        if pick_me_up_coords.is_empty() {
            return vec![];
        }

        // Eligible teammates: prone, on the pitch (not box), within 3 steps of any PickMeUp player
        let mut eligible: HashSet<String> = HashSet::new();
        for teammate in &team.players {
            let state = match field.player_state(&teammate.id) {
                Some(s) => s,
                None => continue,
            };
            if state.base() != PS_PRONE {
                continue;
            }
            let coord = match field.player_coordinate(&teammate.id) {
                Some(c) => c,
                None => continue,
            };
            if coord.is_box_coordinate() {
                continue;
            }
            for &pmu_coord in &pick_me_up_coords {
                if coord.distance_in_steps(pmu_coord) <= 3 {
                    eligible.insert(teammate.id.clone());
                    break;
                }
            }
        }

        eligible.into_iter().collect()
    }

    /// Resolve a Hand-Off action: receiver makes a catch roll.
    fn apply_hand_off(
        &mut self,
        player_id: &str,
        receiver_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        use ffb_mechanics::mechanics::minimum_roll_catch_bb2016;
        let mut events = Vec::new();
        let home_passing = self.game.home_playing;
        let rules = self.game.rules;

        // MyBall / NoBall: prevents regular hand-off action
        let (has_my_ball, has_no_ball_hoff) = {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            let p = team.player(player_id);
            (p.map(|p| p.has_skill(SkillId::MyBall)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::NoBall)).unwrap_or(false))
        };
        if has_my_ball || has_no_ball_hoff {
            return Ok(events); // silently ignore — legal_actions should have prevented this
        }

        // Animosity check: if thrower has Animosity and receiver is a different-race teammate,
        // roll 2+ or the hand-off is refused.
        let (thrower_race, thrower_has_animosity, receiver_race) = {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            let thr = team.player(player_id);
            let rcv = team.player(receiver_id);
            (
                thr.and_then(|p| p.race.clone()),
                thr.map(|p| p.has_skill(SkillId::Animosity)).unwrap_or(false),
                rcv.and_then(|p| p.race.clone()),
            )
        };
        if thrower_has_animosity {
            // Only roll when both races are known and they differ.
            let races_differ = match (&thrower_race, &receiver_race) {
                (Some(tr), Some(rr)) => !tr.eq_ignore_ascii_case(rr),
                _ => false,
            };
            if races_differ {
                let roll = self.rng.d6();
                let success = is_skill_roll_successful(roll, 2);
                events.push(GameEvent::AnimosityRoll { player_id: player_id.to_owned(), roll, success });
                if !success {
                    // Hand-off refused: player's action ends here.
                    return Ok(events);
                }
            }
        }

        let rcvr_ag = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.agility).unwrap_or(3)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.agility).unwrap_or(3)
        };
        let receiver_coord = self.game.field_model.player_coordinate(receiver_id)
            .unwrap_or(FieldCoordinate::new(13, 7));

        events.push(GameEvent::HandOver {
            from_id: player_id.to_owned(),
            to_id: receiver_id.to_owned(),
        });

        let rain_mod = if self.game.weather == Weather::PouringRain { 1 } else { 0 };
        let rcvr_has_nos = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.has_skill(SkillId::NervesOfSteel)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.has_skill(SkillId::NervesOfSteel)).unwrap_or(false)
        };
        let dp_raw = self.count_disturbing_presence(receiver_coord, home_passing);
        let dp_mod = if rcvr_has_nos { 0 } else { dp_raw };
        let rcvr_has_extra_arm = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
        };
        let extra_arm_mod = if rcvr_has_extra_arm { -1 } else { 0 };
        let catch_min = match rules {
            Rules::Bb2016 => (minimum_roll_catch_bb2016(rcvr_ag, rain_mod) + dp_mod + extra_arm_mod).max(2),
            _ => (rcvr_ag + rain_mod + dp_mod + extra_arm_mod).max(2),
        };

        let rcvr_has_no_hands = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.has_skill(SkillId::NoHands)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.has_skill(SkillId::NoHands)).unwrap_or(false)
        };
        let rcvr_has_no_ball = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.has_skill(SkillId::NoBall)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.has_skill(SkillId::NoBall)).unwrap_or(false)
        };
        if rcvr_has_no_hands || rcvr_has_no_ball {
            // NoHands / NoBall: automatically fails any catch
            let scatter_dir = self.rng.d8();
            events.push(GameEvent::BallScattered {
                player_id: receiver_id.to_owned(),
                coord: receiver_coord,
                direction: scatter_dir,
            });
            self.mark_ball_moving();
            return Ok(events);
        }

        let (has_catch, has_monstrous_mouth) = if home_passing {
            let p = self.game.team_home.player(receiver_id);
            (p.map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::MonstrousMouth)).unwrap_or(false))
        } else {
            let p = self.game.team_away.player(receiver_id);
            (p.map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::MonstrousMouth)).unwrap_or(false))
        };
        let used_catch = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
        };
        let used_monstrous_mouth = if home_passing {
            self.game.team_home.player(receiver_id).map(|p| p.used_skills.contains(&SkillId::MonstrousMouth)).unwrap_or(false)
        } else {
            self.game.team_away.player(receiver_id).map(|p| p.used_skills.contains(&SkillId::MonstrousMouth)).unwrap_or(false)
        };

        let catch_roll = self.rng.d6();
        let mut caught = is_skill_roll_successful(catch_roll, catch_min);
        let mut rerolled = false;

        if !caught && has_catch && !used_catch {
            let reroll = self.rng.d6();
            caught = is_skill_roll_successful(reroll, catch_min);
            rerolled = true;
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(receiver_id) {
                p.used_skills.insert(SkillId::Catch);
            }
        } else if !caught && has_monstrous_mouth && !used_monstrous_mouth && !used_catch {
            // MonstrousMouth: free catch re-roll (mutually exclusive with Catch re-roll)
            let reroll = self.rng.d6();
            caught = is_skill_roll_successful(reroll, catch_min);
            rerolled = true;
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(receiver_id) {
                p.used_skills.insert(SkillId::MonstrousMouth);
            }
        }

        events.push(GameEvent::CatchRoll {
            player_id: receiver_id.to_owned(),
            target: catch_min,
            roll: catch_roll,
            success: caught,
            rerolled,
        });

        if caught {
            self.game.field_model.ball_coordinate = Some(receiver_coord);
            events.push(GameEvent::BallPickedUp {
                player_id: receiver_id.to_owned(),
                coord: receiver_coord,
            });
            self.mark_ball_not_moving();
            // Hand-off completion awards same SPP as a pass completion
            use ffb_mechanics::mechanics::spp_table;
            let tbl = spp_table(rules);
            self.award_spp(player_id, home_passing, tbl.completion);
            if tbl.catch > 0 {
                self.award_spp(receiver_id, home_passing, tbl.catch);
            }
        } else {
            // Failed catch — offer reroll (same logic as pass catch reroll)
            if self.cp_reroll_available(receiver_id, home_passing) {
                let pending = PendingReroll::CatchRoll {
                    receiver_id: receiver_id.to_owned(),
                    home_passing,
                    coord: receiver_coord,
                    catch_min,
                    is_pro: false,
                    is_consummate_professional: true,
                };
                self.offer_cp_reroll(receiver_id, home_passing, "catch", pending, &mut events);
                return Ok(events);
            }
            let pro_available = self.pro_reroll_available(receiver_id, home_passing);
            if self.team_reroll_available(home_passing) || pro_available {
                let is_pro = !self.team_reroll_available(home_passing) && pro_available;
                self.offer_reroll(home_passing, "catch", PendingReroll::CatchRoll {
                    receiver_id: receiver_id.to_owned(),
                    home_passing,
                    coord: receiver_coord,
                    catch_min,
                    is_pro,
                    is_consummate_professional: false,
                });
                return Ok(events);
            }
            let scatter_dir = self.rng.d8();
            events.push(GameEvent::BallScattered {
                player_id: receiver_id.to_owned(),
                coord: receiver_coord,
                direction: scatter_dir,
            });
            self.mark_ball_moving();
        }

        // GiveAndGo: after HandOff, allow movement to continue
        let has_give_and_go = {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            team.player(player_id).map(|p| p.has_skill(SkillId::GiveAndGo)).unwrap_or(false)
        };
        if has_give_and_go {
            self.game.acting_player.player_action = Some(PlayerAction::Move);
        } else {
            self.game.acting_player.has_acted = true;
        }
        Ok(events)
    }

    /// Resolve a Pass action: roll pass, handle accurate/inaccurate/fumble.
    ///
    /// Accurate → catch roll for receiver at target square.
    /// Inaccurate/Wildly Inaccurate → ball deviates from target.
    /// Fumble → ball scatters from thrower.
    fn apply_pass(
        &mut self,
        player_id: &str,
        target_coord: FieldCoordinate,
    ) -> Result<Vec<GameEvent>, RulesError> {
        use ffb_model::util::passing::passing_distance;
        use ffb_model::enums::Direction;
        use ffb_mechanics::mechanics::scatter_coordinate;

        let mut events = Vec::new();
        let home_passing = self.game.home_playing;
        let rules = self.game.rules;

        // NoBall: prevents any pass action
        {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            if team.player(player_id).map(|p| p.has_skill(SkillId::NoBall)).unwrap_or(false) {
                return Ok(events);
            }
        }

        // ShotToNothing: once per game, treat this pass as a HailMaryPass
        let shot_to_nothing_fires = {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            team.player(player_id)
                .map(|p| p.has_skill(SkillId::ShotToNothing) && !p.used_skills.contains(&SkillId::ShotToNothing))
                .unwrap_or(false)
                && !matches!(self.game.acting_player.player_action, Some(PlayerAction::HailMaryPass))
        };
        if shot_to_nothing_fires {
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::ShotToNothing); }
            events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::ShotToNothing as u16, used: true });
        }

        // HailMaryPass: ball is always wildly inaccurate; no pass roll needed
        if matches!(self.game.acting_player.player_action, Some(PlayerAction::HailMaryPass)) || shot_to_nothing_fires {
            events.push(GameEvent::PassRoll {
                player_id: player_id.to_owned(),
                target: 0,
                distance: ffb_model::enums::PassingDistance::LongBomb,
                roll: 0,
                result: ModelPassResult::Fumble,
                rerolled: false,
            });
            self.game.field_model.ball_coordinate = None;

            // Roll first scatter direction; offer BlastIt before committing if available
            let first_dir = self.rng.d8();
            let has_blast_it = {
                let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
                team.player(player_id)
                    .map(|p| p.has_skill(SkillId::BlastIt) && !p.used_skills.contains(&SkillId::BlastIt))
                    .unwrap_or(false)
            };
            let first_dest = {
                let mut d = target_coord;
                if let Some(dir) = Direction::for_roll(first_dir) {
                    let (nx, ny) = scatter_coordinate(d.x, d.y, dir, 1);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { d = nc; }
                }
                d
            };
            // Only offer BlastIt in BB2020+; BB2016 does not have this skill
            if has_blast_it && self.game.rules != Rules::Bb2016 {
                self.pending_blast_it = Some(PendingBlastIt {
                    thrower_id: player_id.to_owned(),
                    home_throwing: home_passing,
                    target_coord,
                    first_dir,
                    first_dest,
                });
                self.cached_prompt = Some(AgentPrompt::SkillUse {
                    player_id: player_id.to_owned(),
                    skill_id: SkillId::BlastIt as u16,
                    skill_name: "BlastIt".into(),
                });
                return Ok(events);
            }

            // No BlastIt — roll remaining 2 directions and resolve
            let mut dirs = vec![first_dir];
            let mut land = first_dest;
            for _ in 0..2 {
                let d = self.rng.d8();
                dirs.push(d);
                if let Some(dir) = Direction::for_roll(d) {
                    let (nx, ny) = scatter_coordinate(land.x, land.y, dir, 1);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { land = nc; }
                }
            }
            events.push(GameEvent::PassDeviate { from: target_coord, scatter_directions: dirs });
            self.game.acting_player.has_acted = true;
            self.resolve_ball_landing(land, &mut events, 5);
            return Ok(events);
        }

        let player = if home_passing {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        };
        let ag = player.map(|p| p.agility).unwrap_or(3);
        let pa = player.map(|p| p.passing).unwrap_or(4);
        let has_accurate = player.map(|p| p.has_skill(SkillId::Accurate)).unwrap_or(false);
        let has_strong_arm = player.map(|p| p.has_skill(SkillId::StrongArm)).unwrap_or(false);
        let has_nos_thrower = player.map(|p| p.has_skill(SkillId::NervesOfSteel)).unwrap_or(false);
        let has_pass_skill = player.map(|p| p.has_skill(SkillId::Pass)).unwrap_or(false);
        let has_ballista = player.map(|p| p.has_skill(SkillId::TheBallista)).unwrap_or(false);
        let has_cannoneer = player.map(|p| p.has_skill(SkillId::Cannoneer)).unwrap_or(false);
        let has_safe_pass = player.map(|p| p.has_skill(SkillId::SafePass)).unwrap_or(false);
        let strong_passing_game_str = player.map(|p| {
            if p.has_skill(SkillId::StrongPassingGame) && !p.used_skills.contains(&SkillId::StrongPassingGame) {
                p.strength as i32
            } else { 0 }
        }).unwrap_or(0);
        let used_pass_skill = if home_passing {
            self.game.team_home.player(player_id).map(|p| p.used_skills.contains(&SkillId::Pass)).unwrap_or(false)
        } else {
            self.game.team_away.player(player_id).map(|p| p.used_skills.contains(&SkillId::Pass)).unwrap_or(false)
        };
        let used_ballista = if home_passing {
            self.game.team_home.player(player_id).map(|p| p.used_skills.contains(&SkillId::TheBallista)).unwrap_or(false)
        } else {
            self.game.team_away.player(player_id).map(|p| p.used_skills.contains(&SkillId::TheBallista)).unwrap_or(false)
        };
        let thrower_coord = self.game.field_model.player_coordinate(player_id)
            .unwrap_or(FieldCoordinate::new(12, 7));

        let dist_raw = passing_distance(thrower_coord, target_coord)
            .unwrap_or(ffb_model::enums::PassingDistance::LongBomb);
        // StrongArm: upgrade distance by one category (longer throws become easier)
        let dist_after_strong_arm = if has_strong_arm {
            use ffb_model::enums::PassingDistance;
            match dist_raw {
                PassingDistance::ShortPass => PassingDistance::QuickPass,
                PassingDistance::LongPass => PassingDistance::ShortPass,
                PassingDistance::LongBomb => PassingDistance::LongPass,
                other => other,
            }
        } else {
            dist_raw
        };
        // WorkingInTandem pass variant (BB2025 — Valen): no range modifier when passing to Lucien.
        let dist = if rules == Rules::Bb2025 {
            let is_valen = if home_passing {
                self.game.team_home.player(player_id)
            } else {
                self.game.team_away.player(player_id)
            }.map(|p| {
                p.starting_skills.iter().chain(p.extra_skills.iter())
                    .any(|sw| sw.skill_id == SkillId::WorkingInTandem && sw.value.as_deref() == Some("pass"))
            }).unwrap_or(false);
            if is_valen {
                let partner_team = if home_passing { &self.game.team_home } else { &self.game.team_away };
                let lucien_at_target = partner_team.players.iter().any(|p| {
                    p.id != player_id
                        && p.starting_skills.iter().chain(p.extra_skills.iter())
                            .any(|sw| sw.skill_id == SkillId::WorkingInTandem && sw.value.as_deref() == Some("block"))
                        && self.game.field_model.player_coordinate(&p.id) == Some(target_coord)
                });
                if lucien_at_target {
                    ffb_model::enums::PassingDistance::PassToPartner
                } else {
                    dist_after_strong_arm
                }
            } else {
                dist_after_strong_arm
            }
        } else {
            dist_after_strong_arm
        };
        let pass_stat = match rules {
            Rules::Bb2016 => ag,
            _ => pa,
        };

        let sun_mod = if self.game.weather == Weather::VerySunny { 1 } else { 0 };
        // Accurate (BB2016): -1 to pass modifier (easier to hit)
        let accurate_mod = if has_accurate && rules == Rules::Bb2016 { -1 } else { 0 };
        let dp_raw = self.count_disturbing_presence(thrower_coord, home_passing);
        let dp_mod = if has_nos_thrower { 0 } else { dp_raw };
        // Cannoneer (BB2020+): -1 modifier on Long Pass or Long Bomb (makes it easier)
        let cannoneer_mod = if has_cannoneer && rules != Rules::Bb2016 {
            use ffb_model::enums::PassingDistance;
            match dist {
                PassingDistance::LongPass | PassingDistance::LongBomb => -1,
                _ => 0,
            }
        } else { 0 };
        // StrongPassingGame: once per game, add player's ST as bonus to pass roll (negative modifier)
        if strong_passing_game_str > 0 {
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::StrongPassingGame); }
            events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::StrongPassingGame as u16, used: true });
        }
        let pass_modifier_vec: Vec<Modifier> = {
            let mut v = Vec::new();
            if sun_mod > 0 { v.push(Modifier::new("Very Sunny", sun_mod, rules)); }
            if accurate_mod != 0 { v.push(Modifier::new("Accurate", accurate_mod, rules)); }
            if dp_mod > 0 { v.push(Modifier::new("Disturbing Presence", dp_mod, rules)); }
            if cannoneer_mod != 0 { v.push(Modifier::new("Cannoneer", cannoneer_mod, rules)); }
            if strong_passing_game_str > 0 { v.push(Modifier::new("StrongPassingGame", -strong_passing_game_str, rules)); }
            v
        };
        let roll = self.rng.d6();
        let mut mech_result = evaluate_pass(rules, pass_stat, roll, dist, &pass_modifier_vec, false);
        let mut pass_rerolled = false;

        // Pass skill: auto-reroll once on failed pass
        if matches!(mech_result, MechPassResult::Fumble | MechPassResult::SavedFumble | MechPassResult::WildlyInaccurate | MechPassResult::Inaccurate)
            && has_pass_skill && !used_pass_skill
        {
            let reroll = self.rng.d6();
            mech_result = evaluate_pass(rules, pass_stat, reroll, dist, &pass_modifier_vec, false);
            pass_rerolled = true;
            events.push(GameEvent::SkillUse {
                player_id: player_id.to_owned(),
                skill_id: SkillId::Pass as u16,
                used: true,
            });
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::Pass); }
        }
        // TheBallista: once per game, re-roll a failed pass (does not stack with Pass skill re-roll)
        if matches!(mech_result, MechPassResult::Fumble | MechPassResult::SavedFumble | MechPassResult::WildlyInaccurate | MechPassResult::Inaccurate)
            && has_ballista && !used_ballista && !pass_rerolled
        {
            let reroll = self.rng.d6();
            mech_result = evaluate_pass(rules, pass_stat, reroll, dist, &pass_modifier_vec, false);
            pass_rerolled = true;
            events.push(GameEvent::SkillUse {
                player_id: player_id.to_owned(),
                skill_id: SkillId::TheBallista as u16,
                used: true,
            });
            let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::TheBallista); }
        }

        let model_result = match mech_result {
            MechPassResult::Accurate => ModelPassResult::Complete,
            MechPassResult::Inaccurate => ModelPassResult::Inaccurate,
            MechPassResult::WildlyInaccurate => ModelPassResult::WildlyInaccurate,
            MechPassResult::Fumble | MechPassResult::SavedFumble => ModelPassResult::Fumble,
        };

        // Compute minimum for the event (includes Accurate/weather modifiers)
        let target_nr = match rules {
            Rules::Bb2016 => {
                use ffb_mechanics::mechanics::minimum_roll_pass_bb2016;
                minimum_roll_pass_bb2016(ag, dist, &pass_modifier_vec)
            }
            _ => {
                use ffb_mechanics::mechanics::minimum_roll_pass_bb2020;
                minimum_roll_pass_bb2020(pa, dist, &pass_modifier_vec).unwrap_or(0)
            }
        };

        events.push(GameEvent::PassRoll {
            player_id: player_id.to_owned(),
            target: target_nr,
            distance: dist,
            roll,
            result: model_result,
            rerolled: pass_rerolled,
        });

        // PassBlock / OnTheBall: opposing players with these skills may move up to 3 squares
        // before the interception check. We queue them up; after each move the agent can pick
        // the next player or decline (SelectPlayer with empty id = done).
        if !matches!(mech_result, MechPassResult::Fumble | MechPassResult::SavedFumble) {
            let opposing_team = if home_passing { &self.game.team_away } else { &self.game.team_home };
            let eligible: Vec<String> = opposing_team.players.iter()
                .filter(|p| {
                    (p.has_skill(SkillId::PassBlock) || p.has_skill(SkillId::OnTheBall))
                        && self.game.field_model.player_state(&p.id)
                            .map(|s| s.is_standing())
                            .unwrap_or(false)
                })
                .map(|p| p.id.clone())
                .collect();
            if !eligible.is_empty() {
                events.push(GameEvent::PassBlockEligible {
                    player_ids: eligible.clone(),
                    home_defending: !home_passing,
                });
                let pr_str = match mech_result {
                    MechPassResult::Accurate => "accurate",
                    MechPassResult::Inaccurate => "inaccurate",
                    MechPassResult::WildlyInaccurate => "wildly_inaccurate",
                    _ => "fumble",
                };
                let give_and_go_flag = {
                    let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
                    team.player(player_id).map(|p|
                        p.has_skill(SkillId::GiveAndGo) || p.has_skill(SkillId::RunningPass)
                    ).unwrap_or(false)
                        && matches!(dist, ffb_model::enums::PassingDistance::QuickPass)
                };
                self.pending_pass_block = Some(PendingPassBlock {
                    thrower_id: player_id.to_owned(),
                    target_coord,
                    home_passing,
                    eligible_players: eligible,
                    pass_result_str: pr_str.to_owned(),
                    give_and_go: give_and_go_flag,
                });
                return Ok(events);
            }
        }

        // Interception: only on non-fumble passes (Accurate, Inaccurate, WildlyInaccurate)
        // Each eligible opposing player gets one interception roll; first success intercepts.
        if !matches!(mech_result, MechPassResult::Fumble | MechPassResult::SavedFumble) {
            let interceptors = self.find_interceptors(home_passing, thrower_coord, target_coord);
            for iid in &interceptors {
                let (interceptor_ag, has_vll) = if home_passing {
                    let p = self.game.team_away.player(iid);
                    (p.map(|p| p.agility).unwrap_or(3), p.map(|p| p.has_skill(SkillId::VeryLongLegs)).unwrap_or(false))
                } else {
                    let p = self.game.team_home.player(iid);
                    (p.map(|p| p.agility).unwrap_or(3), p.map(|p| p.has_skill(SkillId::VeryLongLegs)).unwrap_or(false))
                };
                // VeryLongLegs: -1 to interception roll target (easier to intercept)
                let vll_mod = if has_vll { -1 } else { 0 };
                let intercept_min = (minimum_roll_intercept_edition(interceptor_ag, 0, rules) + vll_mod).max(2);
                let iroll = self.rng.d6();
                let success = is_skill_roll_successful(iroll, intercept_min);
                events.push(GameEvent::InterceptionRoll {
                    player_id: iid.clone(),
                    target: intercept_min,
                    roll: iroll,
                    success,
                });
                if success {
                    // Safe Throw: thrower rolls to cancel the interception (BB2016 only).
                    let has_safe_throw = if home_passing {
                        self.game.team_home.player(player_id).map(|p| p.has_skill(SkillId::SafeThrow)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(player_id).map(|p| p.has_skill(SkillId::SafeThrow)).unwrap_or(false)
                    };
                    let interception_cancelled = if has_safe_throw && rules == Rules::Bb2016 {
                        let st_roll = self.rng.d6();
                        let st_success = st_roll >= 4;
                        events.push(GameEvent::SafeThrowRoll {
                            player_id: player_id.to_owned(),
                            roll: st_roll,
                            success: st_success,
                        });
                        st_success
                    } else {
                        false
                    };
                    if interception_cancelled {
                        // Interception cancelled — ball continues toward target
                        continue;
                    }
                    // CloudBurster (BB2020+): on a Long Pass or longer, force the interceptor
                    // to make a second interception roll; if they fail the second roll, the
                    // interception is cancelled.
                    if rules != Rules::Bb2016 {
                        let has_cloud_burster = if home_passing {
                            self.game.team_home.player(player_id)
                        } else {
                            self.game.team_away.player(player_id)
                        }.map(|p| p.has_skill(SkillId::CloudBurster)).unwrap_or(false);
                        let is_long_enough = matches!(
                            dist_raw,
                            ffb_model::enums::PassingDistance::LongPass | ffb_model::enums::PassingDistance::LongBomb
                        );
                        if has_cloud_burster && is_long_enough {
                            events.push(GameEvent::SkillUse {
                                player_id: player_id.to_owned(),
                                skill_id: SkillId::CloudBurster as u16,
                                used: true,
                            });
                            // Force a second interception attempt
                            let iroll2 = self.rng.d6();
                            let success2 = is_skill_roll_successful(iroll2, intercept_min);
                            events.push(GameEvent::InterceptionRoll {
                                player_id: iid.clone(),
                                target: intercept_min,
                                roll: iroll2,
                                success: success2,
                            });
                            if !success2 {
                                // Second roll failed — CloudBurster cancels the interception
                                continue;
                            }
                        }
                    }
                    // Interceptor catches the ball — ball goes to the interceptor's square
                    let icoord = self.game.field_model.player_coordinate(iid)
                        .unwrap_or(target_coord);
                    self.game.field_model.ball_coordinate = Some(icoord);
                    events.push(GameEvent::BallPickedUp {
                        player_id: iid.clone(),
                        coord: icoord,
                    });
                    self.mark_ball_not_moving();
                    // Award interception SPP
                    use ffb_mechanics::mechanics::spp_table;
                    let isp = spp_table(rules).interception;
                    self.award_spp(iid, !home_passing, isp);
                    self.game.acting_player.has_acted = true;
                    return Ok(events);
                }
            }
        }

        match mech_result {
            MechPassResult::Accurate => {
                self.game.field_model.ball_coordinate = Some(target_coord);

                // Check for friendly receiver at the target square
                let receiver_id: Option<String> = if home_passing {
                    self.game.team_home.players.iter().find(|p| {
                        self.game.field_model.player_coordinate(&p.id) == Some(target_coord)
                    }).map(|p| p.id.clone())
                } else {
                    self.game.team_away.players.iter().find(|p| {
                        self.game.field_model.player_coordinate(&p.id) == Some(target_coord)
                    }).map(|p| p.id.clone())
                };

                if let Some(ref rid) = receiver_id {
                    let rcvr_ag = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.agility).unwrap_or(3)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.agility).unwrap_or(3)
                    };
                    let catch_rain_mod = if self.game.weather == Weather::PouringRain { 1 } else { 0 };
                    let rcvr_has_nos = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.has_skill(SkillId::NervesOfSteel)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.has_skill(SkillId::NervesOfSteel)).unwrap_or(false)
                    };
                    let catch_dp_raw = self.count_disturbing_presence(target_coord, home_passing);
                    let catch_dp_mod = if rcvr_has_nos { 0 } else { catch_dp_raw };
                    let rcvr_has_extra_arm = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                    };
                    let catch_extra_arm_mod = if rcvr_has_extra_arm { -1 } else { 0 };
                    let catch_min = match rules {
                        Rules::Bb2016 => (minimum_roll_catch_bb2016(rcvr_ag, catch_rain_mod) + catch_dp_mod + catch_extra_arm_mod).max(2),
                        _ => (rcvr_ag + catch_rain_mod + catch_dp_mod + catch_extra_arm_mod).max(2),
                    };

                    let has_catch = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false)
                    };
                    let used_catch = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
                    };

                    let catch_roll = self.rng.d6();
                    let mut caught = is_skill_roll_successful(catch_roll, catch_min);
                    let mut catch_rerolled = false;

                    if !caught && has_catch && !used_catch {
                        let reroll = self.rng.d6();
                        caught = is_skill_roll_successful(reroll, catch_min);
                        catch_rerolled = true;
                        let team = if home_passing { &mut self.game.team_home } else { &mut self.game.team_away };
                        if let Some(p) = team.player_mut(rid) {
                            p.used_skills.insert(SkillId::Catch);
                        }
                    }

                    events.push(GameEvent::CatchRoll {
                        player_id: rid.clone(),
                        target: catch_min,
                        roll: catch_roll,
                        success: caught,
                        rerolled: catch_rerolled,
                    });
                    if caught {
                        self.game.field_model.ball_coordinate = Some(target_coord);
                        events.push(GameEvent::BallPickedUp {
                            player_id: rid.clone(),
                            coord: target_coord,
                        });
                        self.mark_ball_not_moving();
                        // Award completion SPP to thrower + catch SPP to receiver (BB2020/2025)
                        use ffb_mechanics::mechanics::spp_table;
                        let tbl = spp_table(rules);
                        self.award_spp(player_id, home_passing, tbl.completion);
                        if tbl.catch > 0 {
                            self.award_spp(rid, home_passing, tbl.catch);
                        }
                    } else {
                        // Failed catch — ConsummateProfessional free reroll first
                        if self.cp_reroll_available(&rid, home_passing) {
                            let pending = PendingReroll::CatchRoll {
                                receiver_id: rid.clone(),
                                home_passing,
                                coord: target_coord,
                                catch_min,
                                is_pro: false,
                                is_consummate_professional: true,
                            };
                            self.offer_cp_reroll(&rid, home_passing, "catch", pending, &mut events);
                            return Ok(events);
                        }
                        let pro_available = self.pro_reroll_available(&rid, home_passing);
                        if self.team_reroll_available(home_passing) || pro_available {
                            let is_pro = !self.team_reroll_available(home_passing) && pro_available;
                            self.offer_reroll(home_passing, "catch", PendingReroll::CatchRoll {
                                receiver_id: rid.clone(),
                                home_passing,
                                coord: target_coord,
                                catch_min,
                                is_pro,
                                is_consummate_professional: false,
                            });
                            return Ok(events);
                        }
                        // No reroll → ball bounces from receiver's square
                        let scatter_dir = self.rng.d8();
                        events.push(GameEvent::BallScattered {
                            player_id: rid.clone(),
                            coord: target_coord,
                            direction: scatter_dir,
                        });
                        self.mark_ball_moving();
                        let next = if let Some(d) = ffb_model::enums::Direction::for_roll(scatter_dir) {
                            let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, 1);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { target_coord }
                        } else {
                            target_coord
                        };
                        self.resolve_ball_landing(next, &mut events, 5);
                    }
                }
            }

            MechPassResult::Inaccurate | MechPassResult::WildlyInaccurate => {
                // ConsummateProfessional: free once-per-game reroll before team reroll
                if self.cp_reroll_available(player_id, home_passing) {
                    let pending = PendingReroll::PassRoll {
                        player_id: player_id.to_owned(),
                        home_passing,
                        target_coord,
                        pass_stat,
                        target_nr,
                        is_pro: false,
                        is_consummate_professional: true,
                    };
                    self.offer_cp_reroll(player_id, home_passing, "pass", pending, &mut events);
                    return Ok(events);
                }
                // Offer team reroll (or Pro) before scattering
                let pro_available = self.pro_reroll_available(player_id, home_passing);
                if self.team_reroll_available(home_passing) || pro_available {
                    let is_pro = !self.team_reroll_available(home_passing) && pro_available;
                    self.offer_reroll(home_passing, "pass", PendingReroll::PassRoll {
                        player_id: player_id.to_owned(),
                        home_passing,
                        target_coord,
                        pass_stat,
                        target_nr,
                        is_pro,
                        is_consummate_professional: false,
                    });
                    return Ok(events);
                }

                let scatter_dir = self.rng.d8();
                let scatter_dist = self.rng.d6();
                let dest = if let Some(d) = Direction::for_roll(scatter_dir) {
                    let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, scatter_dist);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { nc } else { target_coord }
                } else {
                    target_coord
                };
                events.push(GameEvent::PassDeviate {
                    from: target_coord,
                    scatter_directions: vec![scatter_dir],
                });
                // Ball may land on a player — give them a catch attempt
                self.resolve_ball_landing(dest, &mut events, 5);
            }

            MechPassResult::Fumble | MechPassResult::SavedFumble => {
                if has_safe_pass {
                    // SafePass: fumbles don't scatter the ball — ball stays with thrower
                    events.push(GameEvent::SkillUse {
                        player_id: player_id.to_owned(),
                        skill_id: SkillId::SafePass as u16,
                        used: true,
                    });
                } else {
                    let scatter_dir = self.rng.d8();
                    let dest = if let Some(d) = Direction::for_roll(scatter_dir) {
                        let (nx, ny) = scatter_coordinate(thrower_coord.x, thrower_coord.y, d, 1);
                        let nc = FieldCoordinate::new(nx, ny);
                        if nc.is_on_pitch() { nc } else { thrower_coord }
                    } else {
                        thrower_coord
                    };
                    events.push(GameEvent::ScatterBall {
                        from: thrower_coord,
                        directions: vec![scatter_dir],
                    });
                    // Ball may land on a player after a fumble scatter
                    self.resolve_ball_landing(dest, &mut events, 5);
                }
            }
        }

        // GiveAndGo (BB2025) / RunningPass (BB2020): after a Quick Pass (not fumble), allow movement
        let was_fumble = matches!(mech_result, MechPassResult::Fumble | MechPassResult::SavedFumble);
        let was_quick_pass = matches!(dist, ffb_model::enums::PassingDistance::QuickPass);
        let has_move_after_pass = {
            let team = if home_passing { &self.game.team_home } else { &self.game.team_away };
            team.player(player_id).map(|p|
                p.has_skill(SkillId::GiveAndGo) || p.has_skill(SkillId::RunningPass)
            ).unwrap_or(false)
        };
        if has_move_after_pass && was_quick_pass && !was_fumble {
            self.game.acting_player.player_action = Some(PlayerAction::Move);
        } else {
            self.game.acting_player.has_acted = true;
        }
        Ok(events)
    }

    /// Continue pass resolution after PassBlock/OnTheBall moves.
    ///
    /// Runs interception rolls with updated player positions, then handles landing.
    fn resolve_pass_after_pass_block(
        &mut self,
        thrower_id: &str,
        target_coord: FieldCoordinate,
        home_passing: bool,
        pass_result_str: &str,
        give_and_go: bool,
    ) -> Result<Vec<GameEvent>, RulesError> {
        use ffb_mechanics::mechanics::scatter_coordinate;
        use ffb_model::enums::Direction;
        let mut events = Vec::new();
        let rules = self.game.rules;
        let thrower_coord = self.game.field_model.player_coordinate(thrower_id)
            .unwrap_or(FieldCoordinate::new(12, 7));

        // Interception check (pass_result = accurate or inaccurate — not fumble)
        if pass_result_str != "fumble" {
            let interceptors = self.find_interceptors(home_passing, thrower_coord, target_coord);
            for iid in &interceptors {
                let (interceptor_ag, has_vll2) = if home_passing {
                    let p = self.game.team_away.player(&iid);
                    (p.map(|p| p.agility).unwrap_or(3), p.map(|p| p.has_skill(SkillId::VeryLongLegs)).unwrap_or(false))
                } else {
                    let p = self.game.team_home.player(&iid);
                    (p.map(|p| p.agility).unwrap_or(3), p.map(|p| p.has_skill(SkillId::VeryLongLegs)).unwrap_or(false))
                };
                use ffb_mechanics::mechanics::minimum_roll_intercept_edition;
                let vll_mod2 = if has_vll2 { -1 } else { 0 };
                let intercept_min = (minimum_roll_intercept_edition(interceptor_ag, 0, rules) + vll_mod2).max(2);
                let iroll = self.rng.d6();
                let success = is_skill_roll_successful(iroll, intercept_min);
                events.push(GameEvent::InterceptionRoll {
                    player_id: iid.clone(),
                    target: intercept_min,
                    roll: iroll,
                    success,
                });
                if success {
                    // Safe Throw: thrower rolls to cancel the interception (BB2016 only)
                    let has_safe_throw2 = if home_passing {
                        self.game.team_home.player(thrower_id).map(|p| p.has_skill(SkillId::SafeThrow)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(thrower_id).map(|p| p.has_skill(SkillId::SafeThrow)).unwrap_or(false)
                    };
                    let cancelled2 = if has_safe_throw2 && rules == Rules::Bb2016 {
                        let st_roll = self.rng.d6();
                        let st_success = st_roll >= 4;
                        events.push(GameEvent::SafeThrowRoll {
                            player_id: thrower_id.to_owned(),
                            roll: st_roll,
                            success: st_success,
                        });
                        st_success
                    } else {
                        false
                    };
                    if cancelled2 { continue; }
                    let icoord = self.game.field_model.player_coordinate(&iid)
                        .unwrap_or(target_coord);
                    self.game.field_model.ball_coordinate = Some(icoord);
                    events.push(GameEvent::BallPickedUp { player_id: iid.clone(), coord: icoord });
                    self.mark_ball_not_moving();
                    use ffb_mechanics::mechanics::spp_table;
                    self.award_spp(&iid, !home_passing, spp_table(rules).interception);
                    self.game.acting_player.has_acted = true;
                    return Ok(events);
                }
            }
        }

        // Landing phase
        match pass_result_str {
            "accurate" => {
                self.game.field_model.ball_coordinate = Some(target_coord);
                let receiver_id: Option<String> = if home_passing {
                    self.game.team_home.players.iter()
                        .find(|p| self.game.field_model.player_coordinate(&p.id) == Some(target_coord))
                        .map(|p| p.id.clone())
                } else {
                    self.game.team_away.players.iter()
                        .find(|p| self.game.field_model.player_coordinate(&p.id) == Some(target_coord))
                        .map(|p| p.id.clone())
                };
                if let Some(ref rid) = receiver_id {
                    let rcvr_ag = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.agility).unwrap_or(3)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.agility).unwrap_or(3)
                    };
                    use ffb_mechanics::mechanics::{minimum_roll_catch_bb2016};
                    let catch_rain_mod = if self.game.weather == Weather::PouringRain { 1 } else { 0 };
                    let catch_dp_mod = self.count_disturbing_presence(target_coord, home_passing);
                    let rcvr_has_extra_arm = if home_passing {
                        self.game.team_home.player(rid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                    } else {
                        self.game.team_away.player(rid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                    };
                    let catch_extra_arm_mod = if rcvr_has_extra_arm { -1 } else { 0 };
                    let catch_min = match rules {
                        Rules::Bb2016 => (minimum_roll_catch_bb2016(rcvr_ag, catch_rain_mod) + catch_dp_mod + catch_extra_arm_mod).max(2),
                        _ => (rcvr_ag + catch_rain_mod + catch_dp_mod + catch_extra_arm_mod).max(2),
                    };
                    let catch_roll = self.rng.d6();
                    let caught = is_skill_roll_successful(catch_roll, catch_min);
                    events.push(GameEvent::CatchRoll {
                        player_id: rid.clone(), target: catch_min, roll: catch_roll,
                        success: caught, rerolled: false,
                    });
                    if caught {
                        events.push(GameEvent::BallPickedUp { player_id: rid.clone(), coord: target_coord });
                        self.mark_ball_not_moving();
                        use ffb_mechanics::mechanics::spp_table;
                        self.award_spp(thrower_id, home_passing, spp_table(rules).completion);
                    } else {
                        let d = self.rng.d8();
                        let dest = if let Some(dir) = Direction::for_roll(d) {
                            let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, dir, 1);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { target_coord }
                        } else { target_coord };
                        self.resolve_ball_landing(dest, &mut events, 5);
                    }
                }
            }
            "inaccurate" | "wildly_inaccurate" => {
                let sd = self.rng.d8();
                let sdist = self.rng.d6();
                let dest = if let Some(d) = Direction::for_roll(sd) {
                    let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, sdist);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { nc } else { target_coord }
                } else { target_coord };
                events.push(GameEvent::PassDeviate { from: target_coord, scatter_directions: vec![sd] });
                self.resolve_ball_landing(dest, &mut events, 5);
            }
            _ => { // fumble
                let sd = self.rng.d8();
                let dest = if let Some(d) = Direction::for_roll(sd) {
                    let (nx, ny) = scatter_coordinate(thrower_coord.x, thrower_coord.y, d, 1);
                    let nc = FieldCoordinate::new(nx, ny);
                    if nc.is_on_pitch() { nc } else { thrower_coord }
                } else { thrower_coord };
                events.push(GameEvent::ScatterBall { from: thrower_coord, directions: vec![sd] });
                self.resolve_ball_landing(dest, &mut events, 5);
            }
        }

        // GiveAndGo: after PassBlock resolution, if flagged, allow continued movement
        if give_and_go {
            self.game.acting_player.player_action = Some(PlayerAction::Move);
        } else {
            self.game.acting_player.has_acted = true;
        }
        Ok(events)
    }

    /// Count net foul assists for the fouling side.
    ///
    /// Offensive assists: teammates of fouler adjacent to target with tackle zones,
    /// not counting the fouler himself. A normal assist only counts if no opponent
    /// (other than the target) is adjacent to the assisting player.
    /// Defensive assists: teammates of target adjacent to fouler with tackle zones,
    /// not counting the target. A normal defensive assist only counts if fewer than
    /// 2 fouling-side players are adjacent to the defensive assister.
    /// Net assists = offensive − defensive.
    fn count_foul_assists(&self, home_fouling: bool, fouler_id: &str, target_id: &str) -> i32 {
        let fouler_coord = match self.game.field_model.player_coordinate(fouler_id) {
            Some(c) => c,
            None => return 0,
        };
        let target_coord = match self.game.field_model.player_coordinate(target_id) {
            Some(c) => c,
            None => return 0,
        };
        let fouling_team = if home_fouling { &self.game.team_home } else { &self.game.team_away };
        let defending_team = if home_fouling { &self.game.team_away } else { &self.game.team_home };

        let target_has_defensive = defending_team.players.iter()
            .find(|p| p.id == target_id)
            .map(|p| p.has_skill(SkillId::Defensive))
            .unwrap_or(false);

        // Offensive: fouling-team players adjacent to target (excl. fouler) with tackle zones
        let offensive: i32 = fouling_team.players.iter().filter(|c| c.id != fouler_id).filter(|c| {
            let cc = self.game.field_model.player_coordinate(&c.id);
            let cs = self.game.field_model.player_state(&c.id);
            match (cc, cs) {
                (Some(coord), Some(state)) => coord.is_adjacent(target_coord) && state.has_tacklezones(),
                _ => false,
            }
        }).filter(|c| {
            // PutTheBootIn: can always assist fouls, even if counter-assists exist
            if c.has_skill(SkillId::PutTheBootIn) {
                return true;
            }
            // Defensive: target with Defensive cancels assists from adjacent players
            if target_has_defensive && !c.has_skill(SkillId::Guard) {
                if let Some(cc) = self.game.field_model.player_coordinate(&c.id) {
                    if target_coord.is_adjacent(cc) {
                        return false;
                    }
                }
            }
            let cc = self.game.field_model.player_coordinate(&c.id).unwrap();
            // Normal assist: no defending-team player (other than target) adjacent to assister
            let counter = defending_team.players.iter().filter(|op| op.id != target_id).filter(|op| {
                let oc = self.game.field_model.player_coordinate(&op.id);
                let os = self.game.field_model.player_state(&op.id);
                match (oc, os) {
                    (Some(oc), Some(os)) => oc.is_adjacent(cc) && os.has_tacklezones(),
                    _ => false,
                }
            }).count();
            counter == 0
        }).count() as i32;

        // Defensive: defending-team players adjacent to fouler (excl. target) with tackle zones
        let defensive: i32 = defending_team.players.iter().filter(|c| c.id != target_id).filter(|c| {
            let cc = self.game.field_model.player_coordinate(&c.id);
            let cs = self.game.field_model.player_state(&c.id);
            match (cc, cs) {
                (Some(coord), Some(state)) => coord.is_adjacent(fouler_coord) && state.has_tacklezones(),
                _ => false,
            }
        }).filter(|c| {
            let cc = self.game.field_model.player_coordinate(&c.id).unwrap();
            // Defensive assist cancelled if 2+ fouling-side players adjacent to this defender
            let counter = fouling_team.players.iter().filter(|op| {
                let oc = self.game.field_model.player_coordinate(&op.id);
                let os = self.game.field_model.player_state(&op.id);
                match (oc, os) {
                    (Some(oc), Some(os)) => oc.is_adjacent(cc) && os.has_tacklezones(),
                    _ => false,
                }
            }).count();
            counter < 2
        }).count() as i32;

        offensive - defensive
    }

    /// Roll a full casualty result: casualty tier + serious injury type.
    ///
    /// BB2016: 2d6 casualty roll → tier (first die), then 2d6 SI roll (die1×10 + die2 index)
    /// BB2020/BB2025: d16 casualty roll → tier, then d6 SI roll if Serious Injury tier
    fn roll_serious_injury(&mut self) -> (ffb_model::enums::SeriousInjuryKind, bool) {
        use ffb_model::enums::SeriousInjuryKind;
        let rules = self.game.rules;
        match rules {
            Rules::Bb2016 => {
                let d1 = self.rng.d6();
                let d2 = self.rng.d6();
                let tier = casualty_tier_bb2016(d1);
                if tier == CasualtyTier::Dead {
                    return (SeriousInjuryKind::Dead, true);
                }
                if tier == CasualtyTier::SeriousInjury {
                    let si = serious_injury_bb2016(d1, d2);
                    return (si.unwrap_or(SeriousInjuryKind::SeriousInjuryNi), false);
                }
                (SeriousInjuryKind::SeriouslyHurt, false)
            }
            Rules::Bb2020 => {
                let roll = self.rng.d6() * 2 + self.rng.d6(); // approximate d16 with 2d6
                let tier = casualty_tier_bb2020(roll);
                if tier == CasualtyTier::Dead {
                    return (SeriousInjuryKind::Dead, true);
                }
                if tier == CasualtyTier::SeriousInjury {
                    let si_roll = self.rng.d6();
                    let si = serious_injury_bb2020(si_roll);
                    return (si.unwrap_or(SeriousInjuryKind::SeriousInjuryNi), false);
                }
                (SeriousInjuryKind::SeriouslyHurt, false)
            }
            Rules::Bb2025 => {
                let roll = self.rng.d6() * 2 + self.rng.d6();
                let tier = casualty_tier_bb2025(roll);
                if tier == CasualtyTier::Dead {
                    return (SeriousInjuryKind::Dead, true);
                }
                if tier == CasualtyTier::SeriousInjury {
                    let si_roll = self.rng.d6();
                    let si = serious_injury_bb2025(si_roll);
                    return (si.unwrap_or(SeriousInjuryKind::SeriousInjuryNi), false);
                }
                (SeriousInjuryKind::SeriouslyHurt, false)
            }
            Rules::Common => (SeriousInjuryKind::SeriouslyHurt, false),
        }
    }

    /// Returns true if the interceptor at `interceptor` lies along the path
    /// from `thrower` to `target` (within the ruler width of 1.74 squares).
    /// Translated from Java's UtilPassing.canIntercept().
    fn can_intercept(
        thrower: FieldCoordinate,
        target: FieldCoordinate,
        interceptor: FieldCoordinate,
    ) -> bool {
        let rx = (target.x - thrower.x) as f64;
        let ry = (target.y - thrower.y) as f64;
        let ix = (interceptor.x - thrower.x) as f64;
        let iy = (interceptor.y - thrower.y) as f64;
        let a = (rx - ix).powi(2) + (ry - iy).powi(2);
        let b = ix.powi(2) + iy.powi(2);
        let c = rx.powi(2) + ry.powi(2);
        if c == 0.0 { return false; }
        let d1 = (ry * (ix + 0.5) - rx * (iy + 0.5)).abs();
        let d2 = (ry * (ix + 0.5) - rx * (iy - 0.5)).abs();
        let d3 = (ry * (ix - 0.5) - rx * (iy + 0.5)).abs();
        let d4 = (ry * (ix - 0.5) - rx * (iy - 0.5)).abs();
        let d_min = d1.min(d2).min(d3).min(d4);
        (c > a) && (c > b) && (1.74 > 2.0 * d_min / c.sqrt())
    }

    /// Returns IDs of all opposing players who could legally attempt to intercept
    /// a pass from `thrower_coord` to `target_coord`. A player can intercept if
    /// they have tackle zones (or the Yoink trait, BB2020+) and their square lies
    /// along the pass path.
    fn find_interceptors(
        &self,
        home_passing: bool,
        thrower_coord: FieldCoordinate,
        target_coord: FieldCoordinate,
    ) -> Vec<String> {
        let opponent = if home_passing { &self.game.team_away } else { &self.game.team_home };
        opponent.players.iter().filter(|p| {
            let coord = self.game.field_model.player_coordinate(&p.id);
            let state = self.game.field_model.player_state(&p.id);
            // Yoink (canInterceptEasily): may attempt interception even without tackle zones.
            let has_yoink = p.has_skill(SkillId::Yoink);
            match (coord, state) {
                (Some(c), Some(s)) => (s.has_tacklezones() || has_yoink) && Self::can_intercept(thrower_coord, target_coord, c),
                _ => false,
            }
        }).map(|p| p.id.clone()).collect()
    }

    /// Resolve a Foul action against `target_id`.
    ///
    /// Rolls armor for the target; if broken, rolls injury. Detects referee
    /// spotting (doubles on armor or injury roll) and ejects the fouler if caught.
    fn apply_foul(
        &mut self,
        fouler_id: &str,
        target_id: &str,
    ) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let home_fouling = self.game.home_playing;
        let rules = self.game.rules;

        // Target's armour value and Stunty (-1 to armor rolls against them)
        let (target_av, target_has_stunty, target_has_iron_hard_skin) = if home_fouling {
            let p = self.game.team_away.player(target_id);
            (p.map(|p| p.armour).unwrap_or(8),
             p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
        } else {
            let p = self.game.team_home.player(target_id);
            (p.map(|p| p.armour).unwrap_or(8),
             p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
        };
        // IronHardSkin: ignores all foul armor modifiers (Dirty Player, assists, Stunty)
        let stunty_foul_mod = if target_has_stunty && !target_has_iron_hard_skin { -1 } else { 0 };

        // Foul assists: net adds to the armor roll total
        let foul_assist = self.count_foul_assists(home_fouling, fouler_id, target_id);

        // Dirty Player: +1 to armor and injury rolls
        let (dp_bonus, fouler_has_chainsaw, fouler_has_lone_fouler, fouler_has_sneaky_pair) = if home_fouling {
            self.game.team_home.player(fouler_id)
        } else {
            self.game.team_away.player(fouler_id)
        }.map(|p| (
            if p.has_skill(SkillId::DirtyPlayer) { 1 } else { 0 },
            p.has_skill(SkillId::Chainsaw),
            p.has_skill(SkillId::LoneFouler),
            p.has_skill(SkillId::ASneakyPair),
        )).unwrap_or((0, false, false, false));
        // ASneakyPair (BB2020+): +1 armor and +1 injury when fouling/stabbing if the partner is adjacent to target.
        let sneaky_pair_mod = if fouler_has_sneaky_pair && self.game.rules != Rules::Bb2016 {
            let target_coord = self.game.field_model.player_coordinate(target_id).unwrap_or(FieldCoordinate::new(13, 7));
            let fouler_team = if home_fouling { &self.game.team_home } else { &self.game.team_away };
            let partner_adjacent = fouler_team.players.iter()
                .filter(|p| p.id != fouler_id && p.has_skill(SkillId::ASneakyPair))
                .any(|p| {
                    let state = self.game.field_model.player_state(&p.id).unwrap_or(PlayerState::new(PS_PRONE));
                    if !state.has_tacklezones() { return false; }
                    let coord = match self.game.field_model.player_coordinate(&p.id) { Some(c) => c, None => return false };
                    coord.distance_in_steps(target_coord) <= 1
                });
            if partner_adjacent { 1 } else { 0 }
        } else { 0 };

        events.push(GameEvent::Foul {
            attacker_id: fouler_id.to_owned(),
            defender_id: target_id.to_owned(),
        });

        // Chainsaw: roll D6 for chainsaw — on 1, wielder hits themselves (injury, foul over).
        // Otherwise armor is auto-broken.
        if fouler_has_chainsaw {
            let saw_roll = self.rng.d6();
            events.push(GameEvent::ChainsawRoll { player_id: fouler_id.to_owned(), roll: saw_roll });
            if saw_roll == 1 {
                // Backfire: injury roll on fouler
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2;
                let was_cas = total >= 10;
                let was_ko = total >= 8 && !was_cas;
                let fouler_is_home = home_fouling;
                let new_state = if was_cas { PlayerState::new(PS_BADLY_HURT) }
                    else if was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else { PlayerState::new(PS_PRONE) };
                self.game.field_model.set_player_state(fouler_id, new_state);
                events.push(GameEvent::Injury {
                    player_id: fouler_id.to_owned(),
                    armor_roll: None,
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: None,
                    was_ko,
                    was_cas,
                });
                if home_fouling { self.game.turn_data_home.foul_used = true; } else { self.game.turn_data_away.foul_used = true; }
                self.game.acting_player.has_acted = true;
                let _ = fouler_is_home;
                return Ok(events);
            }
            // Chainsaw success: armor auto-breaks, skip normal armor roll
            let inj1 = self.rng.d6();
            let inj2 = self.rng.d6();
            let total = inj1 + inj2;
            let was_cas = total >= 10;
            let was_ko = total >= 8 && !was_cas;
            let (si, _is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
            let target_is_home = !home_fouling;
            let new_state = if was_cas { PlayerState::new(PS_BADLY_HURT) }
                else if was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                else { PlayerState::new(PS_PRONE) };
            self.game.field_model.set_player_state(target_id, new_state);
            events.push(GameEvent::Injury {
                player_id: target_id.to_owned(),
                armor_roll: None, // No armor roll for chainsaw
                injury_roll: Some([inj1, inj2]),
                serious_injury: si,
                was_ko,
                was_cas,
            });
            if home_fouling { self.game.turn_data_home.foul_used = true; } else { self.game.turn_data_away.foul_used = true; }
            self.game.acting_player.has_acted = true;
            let _ = target_is_home;
            return Ok(events);
        }

        // Armor roll (+foul assists + dirty player modifier; IronHardSkin blocks all modifiers)
        let eff_foul_assist = if target_has_iron_hard_skin { 0 } else { foul_assist };
        let eff_dp_bonus = if target_has_iron_hard_skin { 0 } else { dp_bonus };
        let eff_sneaky_pair = if target_has_iron_hard_skin { 0 } else { sneaky_pair_mod };
        let ar1 = self.rng.d6();
        let ar2 = self.rng.d6();
        let mut armor_broken = is_armour_broken(target_av, ar1 + ar2 + eff_foul_assist + eff_dp_bonus + eff_sneaky_pair + stunty_foul_mod, rules);
        // LoneFouler: re-roll failed armor roll once if no assists on either side
        if !armor_broken && fouler_has_lone_fouler && foul_assist == 0 {
            let rar1 = self.rng.d6();
            let rar2 = self.rng.d6();
            armor_broken = is_armour_broken(target_av, rar1 + rar2 + eff_dp_bonus + stunty_foul_mod, rules);
            events.push(GameEvent::SkillUse {
                player_id: fouler_id.to_owned(),
                skill_id: SkillId::LoneFouler as u16,
                used: true,
            });
        }

        // Injury roll (only if armor broken)
        let (inj1, inj2) = if armor_broken {
            (self.rng.d6(), self.rng.d6())
        } else {
            (0, 0)
        };

        if armor_broken {
            let target_is_home = !home_fouling;
            let niggling_mod = self.niggling_injury_mod(target_id, target_is_home);
            let total = inj1 + inj2 + eff_dp_bonus + eff_sneaky_pair + niggling_mod;
            let was_cas = total >= 10;
            let mut was_ko = total >= 8 && !was_cas;
            // ThickSkull: on KO, roll D6; on 4+, only Stunned
            if was_ko && self.check_thick_skull(target_id, target_is_home, &mut events) {
                was_ko = false;
            }
            let (si, is_dead) = if was_cas {
                let (si, dead) = self.roll_serious_injury();
                (Some(si), dead)
            } else {
                (None, false)
            };

            // Regeneration check for CAS'd target
            let regen = if was_cas {
                self.try_regeneration(target_id, target_is_home, &mut events)
            } else { false };
            let was_cas = was_cas && !regen;

            if !regen {
                let new_state = if is_dead || was_cas {
                    PlayerState::new(PS_BADLY_HURT)
                } else if was_ko {
                    PlayerState::new(PS_KNOCKED_OUT)
                } else {
                    PlayerState::new(PS_PRONE)
                };
                self.game.field_model.set_player_state(target_id, new_state);
            }
            let offered = if !regen {
                self.try_offer_apothecary(
                    target_id, target_is_home,
                    fouler_id, home_fouling,
                    ar1, ar2, inj1, inj2, was_ko, was_cas, si, is_dead,
                )
            } else { false };
            if !offered {
                if was_cas {
                    if let Some(si_kind) = si {
                        self.apply_casualty_to_player(target_id, target_is_home, si_kind);
                    }
                    // Award SPP to fouler for causing a casualty
                    use ffb_mechanics::mechanics::casualty_spp;
                    let cas_spp = casualty_spp(rules, false);
                    self.award_spp(fouler_id, home_fouling, cas_spp);
                }
                events.push(GameEvent::Injury {
                    player_id: target_id.to_owned(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            }
        } else {
            events.push(GameEvent::Injury {
                player_id: target_id.to_owned(),
                armor_roll: Some([ar1, ar2]),
                injury_roll: None,
                serious_injury: None,
                was_ko: false,
                was_cas: false,
            });
        }

        // Referee check: doubled on armor (without SneakyGit) or doubled on injury
        let fouler_has_sneaky_git = if home_fouling {
            self.game.team_home.player(fouler_id).map(|p| p.has_skill(SkillId::SneakyGit)).unwrap_or(false)
        } else {
            self.game.team_away.player(fouler_id).map(|p| p.has_skill(SkillId::SneakyGit)).unwrap_or(false)
        };
        let spotted = is_spotted_by_referee(ar1, ar2, inj1, inj2, armor_broken, fouler_has_sneaky_git);
        if spotted {
            let has_bribe = if home_fouling {
                self.game.team_home.bribes > 0
            } else {
                self.game.team_away.bribes > 0
            };
            if has_bribe {
                if home_fouling { self.game.team_home.bribes -= 1; } else { self.game.team_away.bribes -= 1; }
                // Offer bribe instead of immediate ejection
                self.pending_bribe = Some(PendingBribe {
                    fouler_id: fouler_id.to_owned(),
                    home_fouling,
                });
            } else {
                // Offer ArgueTheCall before ejecting
                self.pending_argue_the_call = Some(PendingArgueTheCall {
                    fouler_id: fouler_id.to_owned(),
                    home_fouling,
                });
                self.cached_prompt = Some(AgentPrompt::ArgueTheCall {
                    player_id: fouler_id.to_owned(),
                });
            }
        }

        // QuickFoul (BB2025): after a player's own Foul action, if not ejected, continue movement.
        // Only triggers when action is Foul (not for PileDriver auto-fouls which use player action Move/Blitz).
        let is_foul_action = matches!(
            self.game.acting_player.player_action,
            Some(PlayerAction::Foul)
        );
        let fouler_has_quick_foul = if is_foul_action && home_fouling {
            self.game.team_home.player(fouler_id)
        } else if is_foul_action {
            self.game.team_away.player(fouler_id)
        } else {
            None
        }.map(|p| p.has_skill(SkillId::QuickFoul)).unwrap_or(false);
        let ejection_pending = self.pending_bribe.is_some() || self.pending_argue_the_call.is_some();
        let fouler_still_on_pitch = self.game.field_model.player_coordinate(fouler_id).is_some();
        if fouler_has_quick_foul && !ejection_pending && fouler_still_on_pitch
            && self.game.rules == Rules::Bb2025 {
            self.game.acting_player.player_action = Some(PlayerAction::Move);
        } else {
            self.game.acting_player.has_acted = true;
        }
        Ok(events)
    }

    /// Process the kickoff event for the given 2D6 roll.
    ///
    /// Rolls additional dice as needed (weather table, coaching/fans totals, pitch invasion)
    /// and emits the appropriate events. Complex events (QuickSnap, Blitz, HighKick) that
    /// require player interaction are emitted but otherwise skipped for now.
    /// Roll MasterChef dice at the start of a new half.
    ///
    /// Each team rolls 3D6 per Master Chef they purchased; each die > 3 steals one
    /// reroll from the opponent and adds it to the chef team's count.
    fn apply_master_chef_rolls(&mut self) -> Vec<GameEvent> {
        let mut events = Vec::new();
        for is_home_chef in [true, false] {
            let chefs = if is_home_chef {
                self.game.team_home.master_chefs
            } else {
                self.game.team_away.master_chefs
            };
            if chefs <= 0 { continue; }

            let team_id = if is_home_chef {
                self.game.team_home.id.clone()
            } else {
                self.game.team_away.id.clone()
            };

            for _ in 0..chefs {
                let r1 = self.rng.d6();
                let r2 = self.rng.d6();
                let r3 = self.rng.d6();
                let stolen = [r1, r2, r3].iter().filter(|&&r| r > 3).count() as i32;

                events.push(GameEvent::MasterChefRoll { team_id: team_id.clone(), roll: r1 + r2 + r3, rerolls_stolen: stolen });

                if stolen > 0 {
                    // Steal from opponent
                    if is_home_chef {
                        let away_rr = &mut self.game.turn_data_away.rerolls;
                        let actual = stolen.min(*away_rr);
                        *away_rr -= actual;
                        self.game.turn_data_home.rerolls += actual;
                    } else {
                        let home_rr = &mut self.game.turn_data_home.rerolls;
                        let actual = stolen.min(*home_rr);
                        *home_rr -= actual;
                        self.game.turn_data_away.rerolls += actual;
                    }
                }
            }
        }
        events
    }

    /// Roll Prayers to Nuffle for each team that has purchased them.
    /// Each prayer count rolls 1D16 and emits a PrayerRoll event.
    fn apply_prayers_to_nuffle_rolls(&mut self) -> Vec<GameEvent> {
        // BB2025 has a revised prayer table vs BB2020 (positions 8, 11, 12 differ).
        let prayer_ids: &[&str; 16] = if self.game.rules == Rules::Bb2025 {
            &[
                "treacherous_trapdoor",
                "friends_with_the_ref",
                "stiletto",
                "iron_man",
                "knuckle_dusters",
                "bad_habits",
                "greasy_cleats",
                "blessing_of_nuffle",
                "moles_under_the_pitch",
                "perfect_passing",
                "dazzling_catching",
                "fan_interaction",
                "fouling_frenzy",
                "throw_a_rock",
                "under_scrutiny",
                "intensive_training",
            ]
        } else {
            &[
                "treacherous_trapdoor",
                "friends_with_the_ref",
                "stiletto",
                "iron_man",
                "knuckle_dusters",
                "bad_habits",
                "greasy_cleats",
                "blessed_statue_of_nuffle",
                "moles_under_the_pitch",
                "perfect_passing",
                "fan_interaction",
                "necessary_violence",
                "fouling_frenzy",
                "throw_a_rock",
                "under_scrutiny",
                "intensive_training",
            ]
        };
        let mut events = Vec::new();
        for is_home in [true, false] {
            let count = if is_home {
                self.game.team_home.prayers_to_nuffle
            } else {
                self.game.team_away.prayers_to_nuffle
            };
            if count <= 0 { continue; }
            let team_id = if is_home {
                self.game.team_home.id.clone()
            } else {
                self.game.team_away.id.clone()
            };
            for _ in 0..count {
                // D16: roll two D8 and subtract 1 from each, sum +1 → range 1-16
                let roll = ((self.rng.d8() - 1) + (self.rng.d8() - 1)) % 16 + 1;
                let prayer_id = prayer_ids[(roll as usize - 1) % 16];
                events.push(GameEvent::PrayerRoll {
                    team_id: team_id.clone(),
                    roll,
                    prayer_id: prayer_id.to_owned(),
                });
                // Apply simple stateless effects
                match prayer_id {
                    "friends_with_the_ref" => {
                        // ArgueTheCall succeeds on 5+ instead of 6+: store in team's reroll-like bonus
                        // Simplification: grant 1 extra reroll as the prayer benefit
                        if is_home {
                            self.game.turn_data_home.rerolls += 1;
                        } else {
                            self.game.turn_data_away.rerolls += 1;
                        }
                    }
                    "get_the_ref" => {
                        // Both teams get 1 reroll
                        self.game.turn_data_home.rerolls += 1;
                        self.game.turn_data_away.rerolls += 1;
                    }
                    _ => {}
                }
            }
        }
        events
    }

    /// Returns events plus a bool indicating whether WeatherChange NICE scatter caused a touchback.
    fn apply_kickoff_event(&mut self, kickoff_roll: i32, kickoff_touchback: bool) -> (Vec<GameEvent>, bool) {
        use ffb_model::kickoff::{kickoff_event, KickoffEventKind};
        use ffb_model::enums::{KickoffResult, Weather};

        let rules = self.game.rules;
        let mut events = Vec::new();
        let mut weather_nice_touchback = false;

        let kind = match kickoff_event(rules, kickoff_roll) {
            Some(k) => k,
            None => return (events, false),
        };

        let result = match kind {
            KickoffEventKind::GetTheRef => KickoffResult::GetTheRef,
            KickoffEventKind::HighKick => KickoffResult::HighKick,
            KickoffEventKind::CheeringFans => KickoffResult::CheeringFans,
            KickoffEventKind::WeatherChange => KickoffResult::WeatherChange,
            KickoffEventKind::BrilliantCoaching => KickoffResult::BrilliantCoaching,
            KickoffEventKind::QuickSnap => KickoffResult::QuickSnap,
            KickoffEventKind::PitchInvasion => KickoffResult::PitchInvasion,
            KickoffEventKind::Riot => KickoffResult::Riot,
            KickoffEventKind::PerfectDefence => KickoffResult::PerfectDefence,
            KickoffEventKind::ThrowARock => KickoffResult::ThrowARock,
            KickoffEventKind::TimeOut => KickoffResult::TimeOut,
            KickoffEventKind::SolidDefence => KickoffResult::SolidDefence,
            KickoffEventKind::OficiousRef => KickoffResult::OficiousRef,
            KickoffEventKind::Blitz => KickoffResult::Blitz,
            KickoffEventKind::Charge => KickoffResult::Charge,
            KickoffEventKind::DodgySnack => KickoffResult::DodgySnack,
        };
        events.push(GameEvent::KickoffResultEvent { result });

        match kind {
            KickoffEventKind::WeatherChange => {
                let w1 = self.rng.d6();
                let w2 = self.rng.d6();
                let weather = Weather::for_roll(w1 + w2);
                self.game.weather = weather;
                events.push(GameEvent::WeatherChange { weather });
                // Java BB2025: if weather becomes NICE and no touchback, scatter ball 3 times.
                // Matches StepApplyKickoffResult.handleWeatherChange() lines 548-566.
                if weather == Weather::Nice && !kickoff_touchback {
                    if let Some(mut ball_coord) = self.game.field_model.ball_coordinate {
                        use ffb_mechanics::mechanics::scatter_coordinate;
                        use ffb_model::enums::Direction;
                        for _ in 0..3 {
                            let roll = self.rng.d8();
                            if let Some(dir) = Direction::for_roll(roll) {
                                let (nx, ny) = scatter_coordinate(ball_coord.x, ball_coord.y, dir, 1);
                                let nc = FieldCoordinate::new(nx, ny);
                                if nc.is_on_pitch() {
                                    ball_coord = nc;
                                } else {
                                    weather_nice_touchback = true;
                                    break;
                                }
                            }
                        }
                        self.game.field_model.ball_coordinate = Some(ball_coord);
                    }
                }
            }

            KickoffEventKind::BrilliantCoaching => {
                let home_roll = self.rng.d6();
                let away_roll = self.rng.d6();
                // FanFavourite: +1 per on-pitch FanFavourite player (BB2016 only)
                let home_ff = self.count_fan_favourites_on_pitch(true);
                let away_ff = self.count_fan_favourites_on_pitch(false);
                let home_total = home_roll
                    + self.game.team_home.fan_factor
                    + self.game.team_home.assistant_coaches
                    + home_ff;
                let away_total = away_roll
                    + self.game.team_away.fan_factor
                    + self.game.team_away.assistant_coaches
                    + away_ff;
                if home_total >= away_total {
                    self.game.turn_data_home.rerolls += 1;
                }
                if away_total >= home_total {
                    self.game.turn_data_away.rerolls += 1;
                }
            }

            KickoffEventKind::CheeringFans => {
                let home_roll = self.rng.d6();
                let away_roll = self.rng.d6();
                let home_ff = self.count_fan_favourites_on_pitch(true);
                let away_ff = self.count_fan_favourites_on_pitch(false);
                let home_total = home_roll
                    + self.game.team_home.fan_factor
                    + self.game.team_home.cheerleaders
                    + home_ff;
                let away_total = away_roll
                    + self.game.team_away.fan_factor
                    + self.game.team_away.cheerleaders
                    + away_ff;
                if home_total >= away_total {
                    self.game.turn_data_home.rerolls += 1;
                }
                if away_total >= home_total {
                    self.game.turn_data_away.rerolls += 1;
                }
            }

            KickoffEventKind::GetTheRef => {
                self.game.turn_data_home.rerolls += 1;
                self.game.turn_data_away.rerolls += 1;
            }

            KickoffEventKind::Riot => {
                // Riot: roll D6 for the active team's turn adjustment
                let riot_roll = self.rng.d6();
                events.push(GameEvent::KickoffRiot);
                // Roll 1-3: turn advances (receiving team loses 1 turn)
                // Roll 4-6: turn retreats (receiving team gains 1 turn back, if they had turns used)
                let receiving_home = self.game.home_first_offense;
                let turn_data = if receiving_home {
                    &mut self.game.turn_data_home
                } else {
                    &mut self.game.turn_data_away
                };
                if riot_roll <= 3 {
                    turn_data.turn_nr = (turn_data.turn_nr + 1).min(8);
                } else if turn_data.turn_nr > 1 {
                    turn_data.turn_nr -= 1;
                }
            }

            KickoffEventKind::PitchInvasion => {
                // Matches Java BB2025 StepApplyKickoffResult.handlePitchInvasion():
                // 1. Roll D6 for each team (+dedicated_fans).
                // 2. Roll D3 for stun count.
                // 3. if totalHome <= totalAway: stun `stunned` home players (D{N} pick).
                //    if totalHome >= totalAway: stun `stunned` away players (D{N} pick).
                let home_roll = self.rng.d6();
                let away_roll = self.rng.d6();
                events.push(GameEvent::KickoffPitchInvasion { home_roll, away_roll });

                let home_ff = self.game.team_home.fan_factor;
                let away_ff = self.game.team_away.fan_factor;
                let total_home = home_roll + home_ff;
                let total_away = away_roll + away_ff;

                let stun_count = self.rng.d3();

                if total_home <= total_away {
                    let mut standing: Vec<String> = self.game.team_home.players.iter()
                        .filter(|p| self.game.field_model.player_state(&p.id)
                            .map(|s| s.is_standing()).unwrap_or(false))
                        .map(|p| p.id.clone())
                        .collect();
                    for _ in 0..stun_count {
                        if standing.is_empty() { break; }
                        let n = standing.len() as u32;
                        let idx = self.rng.die(n) as usize - 1;
                        let pid = standing.remove(idx);
                        let has_bac = self.game.team_home.players.iter()
                            .find(|p| p.id == pid)
                            .map(|p| p.has_skill(SkillId::BallAndChain))
                            .unwrap_or(false);
                        if has_bac {
                            // BallAndChain = immune to stun (stays Standing).
                            // Java still calls rollInjury() → 2 extra d6 dice consumed.
                            self.rng.d6(); self.rng.d6();
                        } else {
                            // Java stunPlayer → dropPlayer(STUNNED) but STUNNED has base=PRONE in state hash
                            self.game.field_model.set_player_state(&pid, PlayerState::new(PS_PRONE));
                        }
                        events.push(GameEvent::KickoffPitchInvasionStun { player_id: pid });
                    }
                }
                if total_home >= total_away {
                    let mut standing: Vec<String> = self.game.team_away.players.iter()
                        .filter(|p| self.game.field_model.player_state(&p.id)
                            .map(|s| s.is_standing()).unwrap_or(false))
                        .map(|p| p.id.clone())
                        .collect();
                    for _ in 0..stun_count {
                        if standing.is_empty() { break; }
                        let n = standing.len() as u32;
                        let idx = self.rng.die(n) as usize - 1;
                        let pid = standing.remove(idx);
                        let has_bac = self.game.team_away.players.iter()
                            .find(|p| p.id == pid)
                            .map(|p| p.has_skill(SkillId::BallAndChain))
                            .unwrap_or(false);
                        if has_bac {
                            self.rng.d6(); self.rng.d6();
                        } else {
                            self.game.field_model.set_player_state(&pid, PlayerState::new(PS_PRONE));
                        }
                        events.push(GameEvent::KickoffPitchInvasionStun { player_id: pid });
                    }
                }
            }

            KickoffEventKind::ThrowARock => {
                // Each team randomly stuns one standing player from the opposing side
                for (team_players, is_home_victim) in [
                    (self.game.team_away.players.iter().map(|p| p.id.clone()).collect::<Vec<_>>(), false),
                    (self.game.team_home.players.iter().map(|p| p.id.clone()).collect::<Vec<_>>(), true),
                ] {
                    let standing: Vec<String> = team_players.into_iter()
                        .filter(|pid| self.game.field_model.player_state(pid).map(|s| s.is_standing()).unwrap_or(false))
                        .collect();
                    if !standing.is_empty() {
                        let pick = self.rng.d6() as usize % standing.len();
                        let pid = &standing[pick];
                        self.game.field_model.set_player_state(pid, PlayerState::new(PS_STUNNED));
                        events.push(GameEvent::KickoffThrowARock { player_id: Some(pid.clone()) });
                        let _ = is_home_victim;
                    }
                }
            }

            KickoffEventKind::HighKick => {
                // Receiving team may move one eligible player to the ball landing square.
                // Skip if a receiving player is already at ball coordinate.
                let receiving_home = self.game.home_first_offense;
                let ball_coord = self.game.field_model.ball_coordinate;
                let receiver_at_ball = ball_coord.and_then(|bc| {
                    let team = if receiving_home { &self.game.team_home } else { &self.game.team_away };
                    team.players.iter().find(|p| {
                        self.game.field_model.player_coordinate(&p.id) == Some(bc)
                    }).map(|p| p.id.clone())
                });
                if receiver_at_ball.is_none() {
                    // Collect eligible receiving-team players: standing, not pinned by opponent TZs.
                    let opp_positions: Vec<FieldCoordinate> = {
                        let opp = if receiving_home { &self.game.team_away } else { &self.game.team_home };
                        opp.players.iter().filter_map(|p| {
                            let state = self.game.field_model.player_state(&p.id)?;
                            if state.has_tacklezones() {
                                self.game.field_model.player_coordinate(&p.id)
                            } else { None }
                        }).collect()
                    };
                    let recv_team = if receiving_home { &self.game.team_home } else { &self.game.team_away };
                    let eligible: Vec<String> = recv_team.players.iter().filter_map(|p| {
                        let state = self.game.field_model.player_state(&p.id)?;
                        if !state.is_standing() { return None; }
                        let coord = self.game.field_model.player_coordinate(&p.id)?;
                        let pinned = opp_positions.iter().any(|&oc| {
                            (coord.x - oc.x).abs() <= 1 && (coord.y - oc.y).abs() <= 1
                        });
                        if pinned { return None; }
                        Some(p.id.clone())
                    }).collect();
                    if !eligible.is_empty() {
                        self.pending_high_kick = Some(eligible);
                    }
                }
            }

            KickoffEventKind::QuickSnap => {
                // Java rolls rollDice(3) for nrOfPlayersAllowed = roll + 3 before granting movement bonus.
                let _qs_roll = self.rng.d3();
                // Receiving team gets +1 MA for all players this turn (no dodge needed for the extra square).
                let receiving_home = self.game.home_first_offense;
                if receiving_home {
                    self.game.turn_data_home.quick_snap_bonus = 1;
                } else {
                    self.game.turn_data_away.quick_snap_bonus = 1;
                }
            }

            KickoffEventKind::Blitz => {
                // Kicking team gets a free full turn (TurnMode::Blitz) before regular play begins.
                self.blitz_kickoff_pending = true;
            }

            KickoffEventKind::SolidDefence => {
                // Kicking team may reorganize: roll D3+3 eligible players may each move 2 squares back.
                let kicking_is_home = !self.game.home_first_offense;
                let roll = self.rng.d3(); // D3, matches Java's rollDice(3)
                let allowed = roll + 3; // 4–6
                // Eligible: on pitch, not adjacent to standing opponents.
                let opp_positions: Vec<FieldCoordinate> = {
                    let opp = if kicking_is_home { &self.game.team_away } else { &self.game.team_home };
                    opp.players.iter().filter_map(|p| {
                        let s = self.game.field_model.player_state(&p.id)?;
                        if s.has_tacklezones() { self.game.field_model.player_coordinate(&p.id) } else { None }
                    }).collect()
                };
                let acting_team = if kicking_is_home { &self.game.team_home } else { &self.game.team_away };
                let eligible: Vec<String> = acting_team.players.iter().filter_map(|p| {
                    let s = self.game.field_model.player_state(&p.id)?;
                    if !s.is_standing() { return None; }
                    let c = self.game.field_model.player_coordinate(&p.id)?;
                    let pinned = opp_positions.iter().any(|&oc| (c.x - oc.x).abs() <= 1 && (c.y - oc.y).abs() <= 1);
                    if pinned { return None; }
                    Some(p.id.clone())
                }).collect();
                events.push(GameEvent::SwarmingPlayersRoll {
                    team_id: acting_team.id.clone(),
                    roll,
                });
                if !eligible.is_empty() {
                    self.pending_solid_defence = Some(PendingSolidDefence {
                        eligible,
                        remaining: allowed.min(acting_team.players.len() as i32),
                        kicking_is_home,
                        is_charge: false,
                    });
                }
            }

            KickoffEventKind::PerfectDefence => {
                // Kicking team may completely re-setup.
                // Simplified: grant two extra rerolls (full re-setup would enter Setup mode again).
                let kicking_home = !self.game.home_first_offense;
                if kicking_home {
                    self.game.turn_data_home.rerolls += 2;
                } else {
                    self.game.turn_data_away.rerolls += 2;
                }
            }

            KickoffEventKind::TimeOut => {
                // Java BB2025 StepApplyKickoffResult.handleTimeout():
                // Both turn counters advance by +1 if kicking team is early (turn < 6),
                // or retreat by -1 if kicking team is late (turn >= 6).
                //
                // Rust vs Java turn_nr offset: Rust keeps the kicking team at turn_nr=0
                // until the receiving team's first EndTurn (which increments it to 1).
                // Java initialises all turn counters to 1 before kickoff, so the kicking
                // team is already at 1 when the kickoff event fires.
                //
                // To match Java: use max(1, actual_kicking_turn) as the effective starting
                // value, compute java_result = effective + modifier, then:
                //   receiving_team.turn_nr = java_result          (visible turn)
                //   kicking_team.turn_nr   = java_result - 1      (incremented to java_result
                //                                                    by receiving team's EndTurn)
                let kicking_turn = if self.game.home_playing {
                    self.game.turn_data_home.turn_nr
                } else {
                    self.game.turn_data_away.turn_nr
                };
                let java_effective = kicking_turn.max(1);
                let turn_modifier: i32 = if java_effective >= 6 { -1 } else { 1 };
                let java_result = (java_effective + turn_modifier).max(0);
                let receiving_home = self.game.home_first_offense;
                if receiving_home {
                    self.game.turn_data_home.turn_nr = java_result;       // receiving
                    self.game.turn_data_away.turn_nr = (java_result - 1).max(0); // kicking
                } else {
                    self.game.turn_data_away.turn_nr = java_result;       // receiving
                    self.game.turn_data_home.turn_nr = (java_result - 1).max(0); // kicking
                }
            }

            KickoffEventKind::OficiousRef => {
                // A random player is ejected from each team.
                for is_home in [true, false] {
                    let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                    let standing: Vec<String> = team.players.iter()
                        .filter(|p| self.game.field_model.player_state(&p.id).map(|s| s.base() <= PS_STUNNED && s.base() >= PS_STANDING).unwrap_or(false))
                        .map(|p| p.id.clone())
                        .collect();
                    if !standing.is_empty() {
                        let pick = self.rng.d6() as usize % standing.len();
                        let pid = &standing[pick];
                        self.game.field_model.set_player_state(pid, PlayerState::new(PS_RESERVE));
                        self.game.field_model.player_coordinates.remove(pid);
                        events.push(GameEvent::SecretWeaponBan { player_id: pid.clone() });
                    }
                }
            }

            KickoffEventKind::DodgySnack => {
                // Java: rollDice(6) for home + rollDice(6) for away.
                // If rollAway >= rollHome: randomPlayer(homeOnField) = rollDice(N)-1 index.
                // If rollHome >= rollAway: randomPlayer(awayOnField) = rollDice(N)-1 index.
                // Then dodgySnackEffect per selected player: rollDice(6); if 1 → reserve box.
                let roll_home = self.rng.d6();
                let roll_away = self.rng.d6();

                let home_on_field: Vec<String> = self.game.team_home.players.iter()
                    .filter(|p| self.game.field_model.player_coordinate(&p.id).is_some())
                    .map(|p| p.id.clone())
                    .collect();
                let away_on_field: Vec<String> = self.game.team_away.players.iter()
                    .filter(|p| self.game.field_model.player_coordinate(&p.id).is_some())
                    .map(|p| p.id.clone())
                    .collect();

                let home_picked = if roll_away >= roll_home && !home_on_field.is_empty() {
                    let idx = self.rng.die(home_on_field.len() as u32) as usize - 1;
                    Some(home_on_field[idx].clone())
                } else {
                    None
                };
                let away_picked = if roll_home >= roll_away && !away_on_field.is_empty() {
                    let idx = self.rng.die(away_on_field.len() as u32) as usize - 1;
                    Some(away_on_field[idx].clone())
                } else {
                    None
                };

                // Apply effect: roll==1 → player goes to reserve box; else gets enhancement.
                if let Some(pid) = home_picked {
                    let roll = self.rng.d6();
                    if roll == 1 {
                        self.game.field_model.player_coordinates.remove(&pid);
                        self.game.field_model.set_player_state(&pid, PlayerState::new(PS_RESERVE));
                    }
                }
                if let Some(pid) = away_picked {
                    let roll = self.rng.d6();
                    if roll == 1 {
                        self.game.field_model.player_coordinates.remove(&pid);
                        self.game.field_model.set_player_state(&pid, PlayerState::new(PS_RESERVE));
                    }
                }
            }

            KickoffEventKind::Charge => {
                // BB2025: receiving team may move D3+3 eligible players 2 squares forward.
                let receiving_is_home = self.game.home_first_offense;
                let roll = self.rng.d3(); // D3, matches Java's rollDice(3)
                let allowed = roll + 3; // 4–6
                let opp_positions: Vec<FieldCoordinate> = {
                    let opp = if receiving_is_home { &self.game.team_away } else { &self.game.team_home };
                    opp.players.iter().filter_map(|p| {
                        let s = self.game.field_model.player_state(&p.id)?;
                        if s.has_tacklezones() { self.game.field_model.player_coordinate(&p.id) } else { None }
                    }).collect()
                };
                let acting_team = if receiving_is_home { &self.game.team_home } else { &self.game.team_away };
                let eligible: Vec<String> = acting_team.players.iter().filter_map(|p| {
                    let s = self.game.field_model.player_state(&p.id)?;
                    if !s.is_standing() { return None; }
                    let c = self.game.field_model.player_coordinate(&p.id)?;
                    let pinned = opp_positions.iter().any(|&oc| (c.x - oc.x).abs() <= 1 && (c.y - oc.y).abs() <= 1);
                    if pinned { return None; }
                    Some(p.id.clone())
                }).collect();
                events.push(GameEvent::SwarmingPlayersRoll {
                    team_id: acting_team.id.clone(),
                    roll,
                });
                if !eligible.is_empty() {
                    self.pending_solid_defence = Some(PendingSolidDefence {
                        eligible,
                        remaining: allowed.min(acting_team.players.len() as i32),
                        kicking_is_home: !receiving_is_home,
                        is_charge: true,
                    });
                }
            }
        }

        (events, weather_nice_touchback)
    }

    /// Resolve a pending reroll: either consume it (re-roll) or execute the failure.
    fn resolve_pending_reroll(&mut self, pending: PendingReroll, use_reroll: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();

        if use_reroll {
            // Emit a ReRoll event whenever a reroll is actually used
            let (is_home, action_name) = match &pending {
                PendingReroll::Dodge { home_moving, .. } => (*home_moving, "Dodge"),
                PendingReroll::GoForIt { home_moving, .. } => (*home_moving, "GoForIt"),
                PendingReroll::BallPickup { home_moving, .. } => (*home_moving, "PickUp"),
                PendingReroll::PassRoll { home_passing, .. } => (*home_passing, "Pass"),
                PendingReroll::CatchRoll { home_passing, .. } => (*home_passing, "Catch"),
                PendingReroll::Leap { home_moving, .. } => (*home_moving, "Leap"),
                PendingReroll::Block { home_attacking, .. } => (*home_attacking, "Block"),
            };
            let team_id = if is_home {
                self.game.team_home.id.clone()
            } else {
                self.game.team_away.id.clone()
            };
            events.push(GameEvent::ReRoll {
                team_id,
                source: ReRollSource::new("TeamReRoll"),
                rerolled_action: action_name.to_owned(),
            });
        }

        match pending {
            PendingReroll::Dodge { player_id, home_moving, origin_coord, dest, path_remaining, min_roll, is_pro, is_consummate_professional } => {
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&player_id, home_moving, is_pro, is_consummate_professional, &mut events);
                    if can_reroll {
                        let roll = self.rng.d6();
                        let success = is_skill_roll_successful(roll, min_roll);
                        events.push(GameEvent::DodgeRoll {
                            player_id: player_id.clone(),
                            target: min_roll,
                            roll,
                            success,
                            rerolled: true,
                        });
                        if success {
                            // Continue moving from dest with remaining path
                            let cur_state = self.game.field_model.player_state(&player_id)
                                .unwrap_or(PlayerState::new(PS_STANDING));
                            self.game.field_model.set_player_state(
                                &player_id,
                                cur_state.change_base(PS_MOVING),
                            );
                            events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: dest });
                            if !path_remaining.is_empty() {
                                let more = self.apply_move(&player_id, &path_remaining)?;
                                events.extend(more);
                            }
                            return Ok(events);
                        }
                    }
                }
                // SteadyFooting: on 6, player doesn't fall
                if !self.try_steady_footing(&player_id, home_moving, &mut events) {
                    // Reroll failed (or declined) → prone at dest with armor/injury roll
                    events.push(GameEvent::PlayerFellDown { player_id: player_id.clone(), coord: dest });
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(&player_id, origin_coord, home_moving) {
                        events.push(scatter_ev);
                    }
                    let fall_evs = self.apply_fall_injury(&player_id, home_moving, 0);
                    events.extend(fall_evs);
                }
            }

            PendingReroll::GoForIt { player_id, home_moving, origin_coord, dest, path_remaining, min_roll, is_pro, is_consummate_professional } => {
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&player_id, home_moving, is_pro, is_consummate_professional, &mut events);
                    if can_reroll {
                        let roll = self.rng.d6();
                        let success = is_skill_roll_successful(roll, min_roll);
                        events.push(GameEvent::GoForItRoll {
                            player_id: player_id.clone(),
                            target: min_roll,
                            roll,
                            success,
                            rerolled: true,
                        });
                        if success {
                            let cur_state = self.game.field_model.player_state(&player_id)
                                .unwrap_or(PlayerState::new(PS_STANDING));
                            self.game.field_model.set_player_state(
                                &player_id,
                                cur_state.change_base(PS_MOVING),
                            );
                            events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: dest });
                            if !path_remaining.is_empty() {
                                let more = self.apply_move(&player_id, &path_remaining)?;
                                events.extend(more);
                            }
                            return Ok(events);
                        }
                    }
                }
                // SteadyFooting: on 6, player doesn't fall
                if !self.try_steady_footing(&player_id, home_moving, &mut events) {
                    // Failed / declined → prone at dest with armor/injury roll
                    events.push(GameEvent::PlayerFellDown { player_id: player_id.clone(), coord: dest });
                    if let Some(scatter_ev) = self.scatter_ball_if_carried(&player_id, origin_coord, home_moving) {
                        events.push(scatter_ev);
                    }
                    let fall_evs = self.apply_fall_injury(&player_id, home_moving, 0);
                    events.extend(fall_evs);
                }
            }

            PendingReroll::BallPickup { player_id, home_moving, coord, min_roll, is_pro, is_consummate_professional } => {
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&player_id, home_moving, is_pro, is_consummate_professional, &mut events);
                    if can_reroll {
                        let roll = self.rng.d6();
                        let success = is_skill_roll_successful(roll, min_roll);
                        if success {
                            events.push(GameEvent::BallPickedUp { player_id, coord });
                            self.mark_ball_not_moving();
                        } else {
                            let scatter_dir = self.rng.d8();
                            events.push(GameEvent::BallScattered {
                                player_id,
                                coord,
                                direction: scatter_dir,
                            });
                            self.mark_ball_moving();
                        }
                        return Ok(events);
                    }
                }
                // Declined or Loner failed → scatter
                let scatter_dir = self.rng.d8();
                events.push(GameEvent::BallScattered {
                    player_id,
                    coord,
                    direction: scatter_dir,
                });
                self.mark_ball_moving();
            }

            PendingReroll::PassRoll { player_id, home_passing, target_coord, pass_stat, target_nr, is_pro, is_consummate_professional } => {
                let rules = self.game.rules;
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&player_id, home_passing, is_pro, is_consummate_professional, &mut events);
                    if !can_reroll {
                        // Loner failed — scatter from target
                        use ffb_model::enums::Direction;
                        use ffb_mechanics::mechanics::scatter_coordinate;
                        let scatter_dir = self.rng.d8();
                        let scatter_dist = self.rng.d6();
                        let dest = if let Some(d) = Direction::for_roll(scatter_dir) {
                            let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, scatter_dist);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { target_coord }
                        } else { target_coord };
                        self.game.field_model.ball_coordinate = Some(dest);
                        events.push(GameEvent::BallScattered { player_id, coord: target_coord, direction: scatter_dir });
                        self.mark_ball_moving();
                        self.resolve_ball_landing(dest, &mut events, 5);
                        return Ok(events);
                    }
                    let thrower_coord = self.game.field_model.player_coordinate(&player_id)
                        .unwrap_or(FieldCoordinate::new(12, 7));
                    let dist = ffb_model::util::passing::passing_distance(thrower_coord, target_coord)
                        .unwrap_or(ffb_model::enums::PassingDistance::LongBomb);
                    let roll = self.rng.d6();
                    let mech_result = evaluate_pass(rules, pass_stat, roll, dist, &[], false);
                    let model_result = match mech_result {
                        MechPassResult::Accurate => ModelPassResult::Complete,
                        MechPassResult::Inaccurate => ModelPassResult::Inaccurate,
                        MechPassResult::WildlyInaccurate => ModelPassResult::WildlyInaccurate,
                        MechPassResult::Fumble | MechPassResult::SavedFumble => ModelPassResult::Fumble,
                    };
                    events.push(GameEvent::PassRoll {
                        player_id: player_id.clone(),
                        target: target_nr,
                        distance: dist,
                        roll,
                        result: model_result,
                        rerolled: true,
                    });
                    if matches!(mech_result, MechPassResult::Accurate) {
                        self.game.field_model.ball_coordinate = Some(target_coord);
                    } else {
                        let scatter_dir = self.rng.d8();
                        let scatter_dist = self.rng.d6();
                        use ffb_model::enums::Direction;
                        use ffb_mechanics::mechanics::scatter_coordinate;
                        let dest = if let Some(d) = Direction::for_roll(scatter_dir) {
                            let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, scatter_dist);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { target_coord }
                        } else { target_coord };
                        self.game.field_model.ball_coordinate = Some(dest);
                        events.push(GameEvent::BallScattered {
                            player_id,
                            coord: target_coord,
                            direction: scatter_dir,
                        });
                        self.mark_ball_moving();
                        self.resolve_ball_landing(dest, &mut events, 5);
                    }
                } else {
                    // Declined → scatter from target
                    use ffb_model::enums::Direction;
                    use ffb_mechanics::mechanics::scatter_coordinate;
                    let scatter_dir = self.rng.d8();
                    let scatter_dist = self.rng.d6();
                    let dest = if let Some(d) = Direction::for_roll(scatter_dir) {
                        let (nx, ny) = scatter_coordinate(target_coord.x, target_coord.y, d, scatter_dist);
                        let nc = FieldCoordinate::new(nx, ny);
                        if nc.is_on_pitch() { nc } else { target_coord }
                    } else { target_coord };
                    self.game.field_model.ball_coordinate = Some(dest);
                    events.push(GameEvent::BallScattered {
                        player_id,
                        coord: target_coord,
                        direction: scatter_dir,
                    });
                    self.mark_ball_moving();
                    self.resolve_ball_landing(dest, &mut events, 5);
                }
            }

            PendingReroll::CatchRoll { receiver_id, home_passing, coord, catch_min, is_pro, is_consummate_professional } => {
                let rules = self.game.rules;
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&receiver_id, home_passing, is_pro, is_consummate_professional, &mut events);
                    if !can_reroll {
                        use ffb_model::enums::Direction;
                        use ffb_mechanics::mechanics::scatter_coordinate;
                        let scatter_dir = self.rng.d8();
                        events.push(GameEvent::BallScattered { player_id: receiver_id, coord, direction: scatter_dir });
                        self.mark_ball_moving();
                        let next = if let Some(d) = Direction::for_roll(scatter_dir) {
                            let (nx, ny) = scatter_coordinate(coord.x, coord.y, d, 1);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { coord }
                        } else { coord };
                        self.resolve_ball_landing(next, &mut events, 5);
                        return Ok(events);
                    }
                    let roll = self.rng.d6();
                    let caught = is_skill_roll_successful(roll, catch_min);
                    events.push(GameEvent::CatchRoll {
                        player_id: receiver_id.clone(),
                        target: catch_min,
                        roll,
                        success: caught,
                        rerolled: true,
                    });
                    if caught {
                        self.game.field_model.ball_coordinate = Some(coord);
                        events.push(GameEvent::BallPickedUp { player_id: receiver_id.clone(), coord });
                        self.mark_ball_not_moving();
                    } else {
                        use ffb_model::enums::Direction;
                        use ffb_mechanics::mechanics::scatter_coordinate;
                        let scatter_dir = self.rng.d8();
                        events.push(GameEvent::BallScattered {
                            player_id: receiver_id.clone(),
                            coord,
                            direction: scatter_dir,
                        });
                        self.mark_ball_moving();
                        let next = if let Some(d) = Direction::for_roll(scatter_dir) {
                            let (nx, ny) = scatter_coordinate(coord.x, coord.y, d, 1);
                            let nc = FieldCoordinate::new(nx, ny);
                            if nc.is_on_pitch() { nc } else { coord }
                        } else { coord };
                        self.resolve_ball_landing(next, &mut events, 5);
                    }
                } else {
                    // Declined reroll → scatter from receiver's square
                    use ffb_model::enums::Direction;
                    use ffb_mechanics::mechanics::scatter_coordinate;
                    let scatter_dir = self.rng.d8();
                    events.push(GameEvent::BallScattered {
                        player_id: receiver_id,
                        coord,
                        direction: scatter_dir,
                    });
                    self.mark_ball_moving();
                    let next = if let Some(d) = Direction::for_roll(scatter_dir) {
                        let (nx, ny) = scatter_coordinate(coord.x, coord.y, d, 1);
                        let nc = FieldCoordinate::new(nx, ny);
                        if nc.is_on_pitch() { nc } else { coord }
                    } else { coord };
                    self.resolve_ball_landing(next, &mut events, 5);
                }
            }

            PendingReroll::Leap { player_id, home_moving, origin_coord, dest, path_remaining, min_roll, is_pro, is_consummate_professional } => {
                if use_reroll {
                    let can_reroll = self.check_reroll_constraint(&player_id, home_moving, is_pro, is_consummate_professional, &mut events);
                    if can_reroll {
                        let roll = self.rng.d6();
                        let success = roll >= min_roll;
                        events.push(GameEvent::JumpRoll {
                            player_id: player_id.clone(),
                            target: min_roll,
                            roll,
                            success,
                        });
                        if success {
                            let cur_state = self.game.field_model.player_state(&player_id)
                                .unwrap_or(PlayerState::new(PS_STANDING));
                            self.game.field_model.set_player_state(
                                &player_id,
                                cur_state.change_base(PS_MOVING),
                            );
                            events.push(GameEvent::PlayerMoved { player_id: player_id.clone(), coord: dest });
                            if !path_remaining.is_empty() {
                                let more = self.apply_move(&player_id, &path_remaining)?;
                                events.extend(more);
                            }
                            return Ok(events);
                        }
                    }
                }
                // Failed / declined → prone at dest with armor/injury roll
                events.push(GameEvent::PlayerFellDown { player_id: player_id.clone(), coord: dest });
                if let Some(scatter_ev) = self.scatter_ball_if_carried(&player_id, origin_coord, home_moving) {
                    events.push(scatter_ev);
                }
                let is_home = self.game.is_home_team(&player_id);
                let fall_evs = self.apply_fall_injury(&player_id, is_home, 0);
                events.extend(fall_evs);
            }

            PendingReroll::Block { attacker_id, home_attacking, ctx, original_result, is_pro } => {
                if use_reroll {
                    let can = self.check_reroll_constraint(&attacker_id, home_attacking, is_pro, false, &mut events);
                    if can {
                        // Re-roll all block dice
                        let n_dice = ctx.results.len() as i32;
                        let attacker_picks = n_dice >= 0;
                        let n_rolls = (n_dice.unsigned_abs() as usize).max(1);
                        let new_dice: Vec<i32> = (0..n_rolls).map(|_| self.rng.d6()).collect();
                        let new_results: Vec<BlockResult> = new_dice.iter().map(|&d| block_result_for_roll(d)).collect();
                        let new_chosen = Self::pick_best_block_result(&new_results, attacker_picks);
                        let new_idx = new_results.iter().position(|&r| r == new_chosen).unwrap_or(0) as i32;
                        events.push(GameEvent::BlockRoll {
                            attacker_id: attacker_id.clone(),
                            defender_id: ctx.defender_id.clone(),
                            nr_of_dice: n_dice,
                            dice: new_dice,
                            selected_index: new_idx,
                            own_choice: attacker_picks,
                            rerolled: true,
                        });
                        let mut new_ctx = ctx;
                        new_ctx.results = new_results;
                        let resolve_events = self.resolve_block_result(new_chosen, new_ctx)?;
                        events.extend(resolve_events);
                        return Ok(events);
                    }
                }
                // Declined or failed Loner — apply original bad result
                let resolve_events = self.resolve_block_result(original_result, ctx)?;
                events.extend(resolve_events);
            }
        }

        Ok(events)
    }

    /// True if the active team has a team reroll available and hasn't used one this turn.
    fn team_reroll_available(&self, is_home: bool) -> bool {
        use ffb_model::enums::LeaderState;
        let td = if is_home { &self.game.turn_data_home } else { &self.game.turn_data_away };
        if td.reroll_used { return false; }
        td.rerolls > 0 || td.leader_state == LeaderState::Available || td.lord_of_chaos_state == LeaderState::Available
    }

    /// Consume one team reroll for `is_home` team and mark reroll_used for the turn.
    fn consume_team_reroll(&mut self, is_home: bool) {
        use ffb_model::enums::LeaderState;
        let td = if is_home { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
        if td.rerolls > 0 {
            td.rerolls -= 1;
        } else if td.leader_state == LeaderState::Available {
            td.leader_state = LeaderState::Used;
        } else if td.lord_of_chaos_state == LeaderState::Available {
            td.lord_of_chaos_state = LeaderState::Used;
        }
        td.reroll_used = true;
    }

    /// Refresh Leader state at the start of the active team's turn.
    ///
    /// If a standing player with Leader is on the pitch, set leader_state to Available
    /// (unless already Used this half).
    fn refresh_leader_state(&mut self, is_home: bool) -> Option<GameEvent> {
        use ffb_model::enums::LeaderState;
        let td = if is_home { &self.game.turn_data_home } else { &self.game.turn_data_away };
        if td.leader_state == LeaderState::Used { return None; }

        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        let leader_player = team.players.iter().find(|p| {
            if !p.has_skill(SkillId::Leader) { return false; }
            let state = self.game.field_model.player_state(&p.id)
                .unwrap_or(PlayerState::new(PS_RESERVE));
            state.has_tacklezones()
        }).map(|p| p.id.clone());

        if let Some(lid) = leader_player {
            let td_mut = if is_home { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
            let newly_available = td_mut.leader_state == LeaderState::None;
            if newly_available {
                td_mut.leader_state = LeaderState::Available;
            }
            Some(GameEvent::Leader { player_id: lid, reroll_available: true })
        } else {
            None
        }
    }

    /// Refresh LordOfChaos state at the start of the active team's turn (like Leader).
    /// LordOfChaos player on pitch → team gets one extra reroll per half.
    fn refresh_lord_of_chaos_state(&mut self, is_home: bool) -> Option<GameEvent> {
        use ffb_model::enums::LeaderState;
        let td = if is_home { &self.game.turn_data_home } else { &self.game.turn_data_away };
        if td.lord_of_chaos_state == LeaderState::Used { return None; }

        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        let loc_player = team.players.iter().find(|p| {
            if !p.has_skill(SkillId::LordOfChaos) { return false; }
            let state = self.game.field_model.player_state(&p.id).unwrap_or(PlayerState::new(PS_RESERVE));
            state.has_tacklezones()
        }).map(|p| p.id.clone());

        if let Some(lid) = loc_player {
            let td_mut = if is_home { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
            if td_mut.lord_of_chaos_state == LeaderState::None {
                td_mut.lord_of_chaos_state = LeaderState::Available;
            }
            Some(GameEvent::SkillUse { player_id: lid, skill_id: SkillId::LordOfChaos as u16, used: true })
        } else {
            None
        }
    }

    /// Check if a player with Loner must first pass a D6 roll before using a team reroll.
    ///
    /// Always consumes the team reroll. Returns true if the reroll may proceed,
    /// false if Loner failed (reroll wasted, original result stands).
    fn check_loner_reroll(&mut self, player_id: &str, is_home: bool, events: &mut Vec<GameEvent>) -> bool {
        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        let player = team.player(player_id);
        let has_loner = player.map(|p| p.has_skill(SkillId::Loner)).unwrap_or(false);

        // TwoForOne (BB2020): Grak/Crumbleberry pair — if partner is KO'd or Casualty, Loner becomes 2+
        let loner_threshold = if has_loner && player.map(|p| p.has_skill(SkillId::TwoForOne)).unwrap_or(false) {
            let partner_hurt = team.players.iter().any(|p| {
                p.id != player_id
                    && p.has_skill(SkillId::TwoForOne)
                    && self.game.field_model.player_state(&p.id)
                        .map(|s| s.is_ko() || s.is_casualty())
                        .unwrap_or(false)
            });
            if partner_hurt { 2 } else { 4 }
        } else {
            4
        };

        self.consume_team_reroll(is_home);

        // TeamCaptain (BB2025): roll 1d6 after consuming reroll; on 6 the reroll is not lost.
        let team_captain_events = self.check_team_captain_save(is_home);
        events.extend(team_captain_events);

        if has_loner {
            let roll = self.rng.d6();
            let success = roll >= loner_threshold;
            events.push(GameEvent::LonerRoll { player_id: player_id.to_owned(), roll, success });
            success
        } else {
            true
        }
    }

    /// TeamCaptain (BB2025): if a TeamCaptain is on the field for `is_home` team, roll 1d6.
    /// On 6, restore the just-consumed reroll (undo the decrement). Returns events.
    fn check_team_captain_save(&mut self, is_home: bool) -> Vec<GameEvent> {
        use ffb_model::enums::Rules;
        if self.game.rules == Rules::Bb2016 {
            return vec![];
        }
        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
        let team_id = team.id.clone();
        let has_captain = team.players.iter().any(|p| {
            p.has_skill(SkillId::TeamCaptain)
                && self.game.field_model.player_coordinate(&p.id).is_some()
        });
        if !has_captain {
            return vec![];
        }
        let roll = self.rng.d6();
        let reroll_saved = roll >= 6;
        if reroll_saved {
            let td = if is_home { &mut self.game.turn_data_home } else { &mut self.game.turn_data_away };
            td.rerolls += 1;
            td.reroll_used = false;
        }
        vec![GameEvent::TeamCaptainRoll { team_id, roll, reroll_saved }]
    }

    /// True if the player has Pro skill and hasn't used it this turn.
    fn pro_reroll_available(&self, player_id: &str, is_home: bool) -> bool {
        if is_home {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        }.map(|p| p.has_skill(SkillId::Pro) && !p.used_skills.contains(&SkillId::Pro)).unwrap_or(false)
    }

    /// Validate and consume either a ConsummateProfessional (free), Pro (4+ D6), or team/Loner reroll.
    ///
    /// Returns true if the reroll succeeds (i.e., the original roll may be retried).
    fn check_reroll_constraint(&mut self, player_id: &str, is_home: bool, is_pro: bool, is_consummate_professional: bool, events: &mut Vec<GameEvent>) -> bool {
        if is_consummate_professional {
            // Skill already marked used when the reroll was offered — free reroll, always succeeds
            return true;
        }
        if is_pro {
            let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) {
                p.used_skills.insert(SkillId::Pro);
            }
            let roll = self.rng.d6();
            let success = roll >= 4;
            events.push(GameEvent::ProRoll { player_id: player_id.to_owned(), roll, success });
            success
        } else {
            self.check_loner_reroll(player_id, is_home, events)
        }
    }

    /// True if the player has ConsummateProfessional and hasn't used it this game.
    fn cp_reroll_available(&self, player_id: &str, is_home: bool) -> bool {
        if is_home {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        }.map(|p| p.has_skill(SkillId::ConsummateProfessional) && !p.used_skills.contains(&SkillId::ConsummateProfessional)).unwrap_or(false)
    }

    /// Mark ConsummateProfessional as used and emit SkillUse event, then offer a free reroll.
    fn offer_cp_reroll(&mut self, player_id: &str, is_home: bool, action_name: &str, pending: PendingReroll, events: &mut Vec<GameEvent>) {
        let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
        if let Some(p) = team.player_mut(player_id) {
            p.used_skills.insert(SkillId::ConsummateProfessional);
        }
        events.push(GameEvent::SkillUse { player_id: player_id.to_owned(), skill_id: SkillId::ConsummateProfessional as u16, used: true });
        self.offer_reroll(is_home, action_name, pending);
    }

    /// Set up the engine to pause for a team-reroll offer.
    /// Mark the ball as "moving" (on the ground, waiting to be picked up).
    /// Called after kickoff scatter, ball scatter from injury, or catch failure.
    fn mark_ball_moving(&mut self) {
        self.game.field_model.ball_moving = true;
    }

    /// Mark the ball as no longer "moving" (a player has picked it up or it's out of play).
    fn mark_ball_not_moving(&mut self) {
        self.game.field_model.ball_moving = false;
    }

    fn offer_reroll(&mut self, is_home: bool, action_name: &str, pending: PendingReroll) {
        let team_id = if is_home {
            self.game.team_home.id.clone()
        } else {
            self.game.team_away.id.clone()
        };
        self.pending_reroll = Some(pending);
        self.cached_prompt = Some(AgentPrompt::ReRollOffer {
            source: ReRollSource::new("TeamReRoll"),
            action: action_name.to_owned(),
            team_id,
        });
    }

    /// Add SPP to a player identified by `player_id` and `is_home`.
    ///
    /// Updates `current_spps` and `career_spps`. No level-up logic yet.
    fn award_spp(&mut self, player_id: &str, is_home: bool, amount: i32) {
        let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
        if let Some(p) = team.player_mut(player_id) {
            p.current_spps += amount;
            p.career_spps += amount;
        }
    }

    /// After the ball lands at `coord`, check if a player is there and roll a catch.
    #[cfg_attr(test, allow(dead_code))]
    pub(crate) fn resolve_ball_landing_test_hook(&mut self, coord: FieldCoordinate, events: &mut Vec<GameEvent>) {
        self.resolve_ball_landing(coord, events, 5);
    }

    pub(crate) fn resolve_throw_in_test_hook(&mut self, coord: FieldCoordinate, events: &mut Vec<GameEvent>) {
        self.resolve_throw_in(coord, events);
    }
    /// After the ball lands at `coord`, check if a player is there and roll a catch.
    /// On a failed catch (or empty square) the ball bounces one square (D8 direction).
    /// Recurses up to `max_bounces` times to prevent infinite loops.
    fn resolve_ball_landing(&mut self, coord: FieldCoordinate, events: &mut Vec<GameEvent>, max_bounces: u8) {
        use ffb_model::enums::Direction;
        use ffb_mechanics::mechanics::scatter_coordinate;

        let rules = self.game.rules;

        // Find a standing player at this square (either team)
        let catcher: Option<(String, bool)> = {
            let home_p = self.game.team_home.players.iter().find(|p| {
                self.game.field_model.player_coordinate(&p.id) == Some(coord)
                    && self.game.field_model.player_state(&p.id)
                        .map(|s| s.has_tacklezones())
                        .unwrap_or(false)
            }).map(|p| (p.id.clone(), true));
            if home_p.is_some() {
                home_p
            } else {
                self.game.team_away.players.iter().find(|p| {
                    self.game.field_model.player_coordinate(&p.id) == Some(coord)
                        && self.game.field_model.player_state(&p.id)
                            .map(|s| s.has_tacklezones())
                            .unwrap_or(false)
                }).map(|p| (p.id.clone(), false))
            }
        };

        if let Some((pid, is_home)) = catcher {
            let ag = if is_home {
                self.game.team_home.player(&pid).map(|p| p.agility).unwrap_or(3)
            } else {
                self.game.team_away.player(&pid).map(|p| p.agility).unwrap_or(3)
            };
            let dp_mod = self.count_disturbing_presence(coord, is_home);
            let has_extra_arm = if is_home {
                self.game.team_home.player(&pid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
            } else {
                self.game.team_away.player(&pid).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
            };
            let extra_arm_mod = if has_extra_arm { -1 } else { 0 };
            // BlastIt (BB2020+): thrower's teammates get -1 to catch target on HMP scatter
            let blast_it_mod = if self.blast_it_catch_bonus && is_home == self.game.home_playing { -1 } else { 0 };
            let catch_min = match rules {
                Rules::Bb2016 => (minimum_roll_catch_bb2016(ag, 0) + dp_mod + extra_arm_mod + blast_it_mod).max(2),
                _ => (ag + dp_mod + extra_arm_mod + blast_it_mod).max(2),
            };
            let has_catch = if is_home {
                self.game.team_home.player(&pid).map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false)
            } else {
                self.game.team_away.player(&pid).map(|p| p.has_skill(SkillId::Catch)).unwrap_or(false)
            };
            let used_catch = if is_home {
                self.game.team_home.player(&pid).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
            } else {
                self.game.team_away.player(&pid).map(|p| p.used_skills.contains(&SkillId::Catch)).unwrap_or(false)
            };

            let roll = self.rng.d6();
            let mut caught = is_skill_roll_successful(roll, catch_min);
            let mut rerolled = false;

            if !caught && has_catch && !used_catch {
                let reroll = self.rng.d6();
                caught = is_skill_roll_successful(reroll, catch_min);
                rerolled = true;
                let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                if let Some(p) = team.player_mut(&pid) {
                    p.used_skills.insert(SkillId::Catch);
                }
            }

            events.push(GameEvent::CatchRoll {
                player_id: pid.clone(),
                target: catch_min,
                roll,
                success: caught,
                rerolled,
            });

            if caught {
                self.game.field_model.ball_coordinate = Some(coord);
                events.push(GameEvent::BallPickedUp { player_id: pid.clone(), coord });
                self.mark_ball_not_moving();
                // QuickBite: after catch, if opponent adjacent and skill unused, auto-apply injury
                {
                    let qb_avail = if is_home {
                        self.game.team_home.player(&pid)
                    } else {
                        self.game.team_away.player(&pid)
                    }.map(|p| p.has_skill(SkillId::QuickBite) && !p.used_skills.contains(&SkillId::QuickBite)).unwrap_or(false);
                    if qb_avail {
                        let opponent_team = if is_home { &self.game.team_away } else { &self.game.team_home };
                        let adjacent_opp: Option<(String, i32)> = opponent_team.players.iter()
                            .find(|op| {
                                self.game.field_model.player_coordinate(&op.id)
                                    .map(|oc| oc.is_adjacent(coord))
                                    .unwrap_or(false)
                                    && self.game.field_model.player_state(&op.id)
                                        .map(|s| s.has_tacklezones()).unwrap_or(false)
                            })
                            .map(|op| (op.id.clone(), op.armour));
                        if let Some((opp_id, opp_av)) = adjacent_opp {
                            let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                            if let Some(p) = team.player_mut(&pid) { p.used_skills.insert(SkillId::QuickBite); }
                            events.push(GameEvent::SkillUse { player_id: pid.clone(), skill_id: SkillId::QuickBite as u16, used: true });
                            let ar1 = self.rng.d6(); let ar2 = self.rng.d6();
                            let armor_broken = is_armour_broken(opp_av, ar1 + ar2, rules);
                            events.push(GameEvent::Injury { player_id: opp_id.clone(), armor_roll: Some([ar1, ar2]), injury_roll: None, serious_injury: None, was_ko: false, was_cas: false });
                            if armor_broken {
                                let inj1 = self.rng.d6(); let inj2 = self.rng.d6();
                                let total = inj1 + inj2;
                                let was_cas = total >= 10; let was_ko = total >= 8 && !was_cas;
                                let new_state = if was_cas { PS_BADLY_HURT } else if was_ko { PS_KNOCKED_OUT } else { PS_PRONE };
                                self.game.field_model.set_player_state(&opp_id, PlayerState::new(new_state));
                                events.push(GameEvent::Injury { player_id: opp_id.clone(), armor_roll: None, injury_roll: Some([inj1, inj2]), serious_injury: None, was_ko, was_cas });
                            }
                        }
                    }
                }
                // Check for touchdown: catcher in opponent's endzone
                if self.is_opponent_endzone(coord, is_home) {
                    if is_home {
                        self.game.game_result.home.score += 1;
                    } else {
                        self.game.game_result.away.score += 1;
                    }
                    events.push(GameEvent::Touchdown { player_id: pid, coord });
                    self.game.field_model.ball_in_play = false;
                    self.mark_ball_not_moving();
                    self.game.acting_player.clear();
                    self.player_activated_this_turn = false;
                    self.game.home_playing = !is_home;
                    self.game.turn_mode = TurnMode::Setup;
                    self.setup_phase = 0;
                    self.place_all_in_reserve();
                }
                return;
            }
            // Failed catch: ball bounces (fall through)
        } else {
            // Empty square: check for DivingCatch — any adjacent standing player with unused DivingCatch
            let diving_catcher: Option<(String, bool)> = {
                let adj = self.game.field_model.adjacent_on_pitch(coord);
                let mut found: Option<(String, bool)> = None;
                'outer: for ac in adj {
                    for is_home in [true, false] {
                        let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                        for p in &team.players {
                            if !p.has_skill(SkillId::DivingCatch) { continue; }
                            if p.used_skills.contains(&SkillId::DivingCatch) { continue; }
                            if self.game.field_model.player_coordinate(&p.id) != Some(ac) { continue; }
                            if !self.game.field_model.player_state(&p.id).map(|s| s.has_tacklezones()).unwrap_or(false) { continue; }
                            found = Some((p.id.clone(), is_home));
                            break 'outer;
                        }
                    }
                }
                found
            };
            if let Some((dc_id, is_home)) = diving_catcher {
                // Mark DivingCatch as used
                let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                if let Some(p) = team.player_mut(&dc_id) {
                    p.used_skills.insert(SkillId::DivingCatch);
                }
                events.push(GameEvent::SkillUse {
                    player_id: dc_id.clone(),
                    skill_id: SkillId::DivingCatch as u16,
                    used: true,
                });
                let ag = if is_home {
                    self.game.team_home.player(&dc_id).map(|p| p.agility).unwrap_or(3)
                } else {
                    self.game.team_away.player(&dc_id).map(|p| p.agility).unwrap_or(3)
                };
                let dp_mod = self.count_disturbing_presence(coord, is_home);
                let dc_has_extra_arm = if is_home {
                    self.game.team_home.player(&dc_id).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                } else {
                    self.game.team_away.player(&dc_id).map(|p| p.has_skill(SkillId::ExtraArms)).unwrap_or(false)
                };
                let dc_extra_arm_mod = if dc_has_extra_arm { -1 } else { 0 };
                // DivingCatch: +1 penalty on catch target; ExtraArm offsets by -1
                let catch_min = match rules {
                    Rules::Bb2016 => (minimum_roll_catch_bb2016(ag, 0) + 1 + dp_mod + dc_extra_arm_mod).max(2),
                    _ => (ag + 1 + dp_mod + dc_extra_arm_mod).max(2),
                };
                let roll = self.rng.d6();
                let caught = is_skill_roll_successful(roll, catch_min);
                events.push(GameEvent::CatchRoll {
                    player_id: dc_id.clone(),
                    target: catch_min,
                    roll,
                    success: caught,
                    rerolled: false,
                });
                if caught {
                    self.game.field_model.ball_coordinate = Some(coord);
                    events.push(GameEvent::BallPickedUp { player_id: dc_id.clone(), coord });
                    self.mark_ball_not_moving();
                    if self.is_opponent_endzone(coord, is_home) {
                        if is_home { self.game.game_result.home.score += 1; } else { self.game.game_result.away.score += 1; }
                        events.push(GameEvent::Touchdown { player_id: dc_id, coord });
                        self.game.field_model.ball_in_play = false;
                        self.mark_ball_not_moving();
                        self.game.acting_player.clear();
                        self.player_activated_this_turn = false;
                        self.game.home_playing = !is_home;
                        self.game.turn_mode = TurnMode::Setup;
                        self.setup_phase = 0;
                        self.place_all_in_reserve();
                    }
                    return;
                }
                // Failed DivingCatch: ball bounces from coord (fall through)
            } else {
                self.game.field_model.ball_coordinate = Some(coord);
                return;
            }
        }

        // Ball bounces — if we're out of bounce budget, stop
        if max_bounces == 0 {
            self.game.field_model.ball_coordinate = Some(coord);
            return;
        }

        let bounce_dir = self.rng.d8();
        let (nx, ny) = if let Some(d) = Direction::for_roll(bounce_dir) {
            scatter_coordinate(coord.x, coord.y, d, 1)
        } else {
            (coord.x, coord.y)
        };
        let next = FieldCoordinate::new(nx, ny);

        events.push(GameEvent::BallScattered {
            player_id: String::new(),
            coord,
            direction: bounce_dir,
        });
        self.mark_ball_moving();

        if next.is_on_pitch() {
            self.game.field_model.ball_coordinate = Some(next);
            self.resolve_ball_landing(next, events, max_bounces - 1);
        } else {
            self.resolve_throw_in(next, events);
        }
    }

    /// Resolve a throw-in when the ball leaves the pitch at `off_pitch_coord`.
    /// Finds the nearest in-bounds edge square, rolls throw-in direction and distance, lands ball.
    fn resolve_throw_in(&mut self, off_pitch_coord: FieldCoordinate, events: &mut Vec<GameEvent>) {
        use ffb_mechanics::mechanics::{throw_in_distance, throw_in_direction_for_roll, scatter_coordinate};

        let rules = self.game.rules;

        // Clamp to the nearest in-bounds pitch square for scatter starting point.
        // Valid pitch squares: x in 0..=25, y in 0..=14.
        let edge_x = off_pitch_coord.x.clamp(0, 25);
        let edge_y = off_pitch_coord.y.clamp(0, 14);
        let edge_coord = FieldCoordinate::new(edge_x, edge_y);

        // throw_in_direction_for_roll expects the off-pitch coordinate to determine which edge was crossed.
        // It checks x < 1 (left), x > 24 (right), y > 13 (bottom), y < 1 (top).
        let dir_roll = self.rng.d6();
        let dist1 = self.rng.d6();
        let dist2 = self.rng.d6();
        let distance = throw_in_distance(dist1, dist2, rules);
        let direction = throw_in_direction_for_roll(off_pitch_coord.x, off_pitch_coord.y, dir_roll);

        events.push(GameEvent::ThrowIn {
            coord: edge_coord,
            direction: dir_roll,
            distance,
        });

        // Move ball along throw-in direction by distance squares from the edge square
        let (nx, ny) = scatter_coordinate(edge_x, edge_y, direction, distance);
        let land = FieldCoordinate::new(nx, ny);

        if land.is_on_pitch() {
            self.game.field_model.ball_coordinate = Some(land);
            self.resolve_ball_landing(land, events, 5);
        } else {
            // Ball goes off the other side — another throw-in
            self.resolve_throw_in(land, events);
        }
    }

    /// Offer the apothecary after an injury if the team has one available.
    /// Returns true if an apothecary offer was set up (engine will pause for response).
    fn try_offer_apothecary(
        &mut self,
        player_id: &str,
        player_is_home: bool,
        attacker_id: &str,
        attacker_is_home: bool,
        ar1: i32, ar2: i32,
        inj1: i32, inj2: i32,
        was_ko: bool,
        was_cas: bool,
        si: Option<ffb_model::enums::SeriousInjuryKind>,
        is_dead: bool,
    ) -> bool {
        // Apothecary only applies to casualty results (total 10+). KO and stunned are not treated.
        if !was_cas { return false; }
        let apothecaries = if player_is_home { self.game.team_home.apothecaries } else { self.game.team_away.apothecaries };
        if apothecaries <= 0 { return false; }
        // Consume the apothecary
        if player_is_home { self.game.team_home.apothecaries -= 1; } else { self.game.team_away.apothecaries -= 1; }
        self.pending_apothecary = Some(PendingApothecary {
            player_id: player_id.to_owned(),
            player_is_home,
            attacker_id: attacker_id.to_owned(),
            attacker_is_home,
            ar1, ar2, inj1, inj2,
            was_ko, was_cas,
            si,
            is_dead,
        });
        true
    }

    /// Resolve the apothecary decision after the team has responded.
    fn resolve_apothecary(&mut self, apo: PendingApothecary, use_apothecary: bool, _player_id: &str) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        events.push(GameEvent::ApothecaryChoice { player_id: apo.player_id.clone(), healed: use_apothecary });
        if use_apothecary {
            // Re-roll the injury
            let inj1 = self.rng.d6();
            let inj2 = self.rng.d6();
            let total = inj1 + inj2;
            let new_was_cas = total >= 10;
            let new_was_ko = total >= 8 && !new_was_cas;
            let (new_si, new_is_dead) = if new_was_cas {
                let (s, d) = self.roll_serious_injury();
                (Some(s), d)
            } else {
                (None, false)
            };
            // Choose the better outcome for the injured player
            // Priority: stunned > ko > cas > dead
            let original_score = if apo.is_dead { 4 } else if apo.was_cas { 3 } else if apo.was_ko { 2 } else { 1 };
            let new_score = if new_is_dead { 4 } else if new_was_cas { 3 } else if new_was_ko { 2 } else { 1 };
            let (use_inj1, use_inj2, use_was_cas, use_was_ko, use_si, use_is_dead) = if new_score < original_score {
                (inj1, inj2, new_was_cas, new_was_ko, new_si, new_is_dead)
            } else {
                (apo.inj1, apo.inj2, apo.was_cas, apo.was_ko, apo.si, apo.is_dead)
            };
            let new_state = if use_is_dead || use_was_cas { PlayerState::new(PS_BADLY_HURT) }
                else if use_was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                else { PlayerState::new(PS_PRONE) };
            self.game.field_model.set_player_state(&apo.player_id, new_state);
            if use_was_cas {
                use ffb_mechanics::mechanics::casualty_spp;
                let cas_spp = casualty_spp(self.game.rules, false);
                self.award_spp(&apo.attacker_id, apo.attacker_is_home, cas_spp);
                if let Some(si_kind) = use_si {
                    self.apply_casualty_to_player(&apo.player_id.clone(), apo.player_is_home, si_kind);
                }
            }
            events.push(GameEvent::Injury {
                player_id: apo.player_id,
                armor_roll: Some([apo.ar1, apo.ar2]),
                injury_roll: Some([use_inj1, use_inj2]),
                serious_injury: use_si,
                was_ko: use_was_ko,
                was_cas: use_was_cas,
            });
        } else {
            // Keep original result — state was already set, just emit the final event
            if apo.was_cas {
                if let Some(si_kind) = apo.si {
                    self.apply_casualty_to_player(&apo.player_id.clone(), apo.player_is_home, si_kind);
                }
            }
            events.push(GameEvent::Injury {
                player_id: apo.player_id,
                armor_roll: Some([apo.ar1, apo.ar2]),
                injury_roll: Some([apo.inj1, apo.inj2]),
                serious_injury: apo.si,
                was_ko: apo.was_ko,
                was_cas: apo.was_cas,
            });
        }
        Ok(events)
    }

    /// Resolve the bribe decision after the fouling team has responded.
    fn resolve_bribe(&mut self, bribe: PendingBribe, use_bribe: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        if use_bribe {
            let roll = self.rng.d6();
            let success = roll >= 2; // bribe succeeds on 2-6
            events.push(GameEvent::BribesRoll {
                player_id: bribe.fouler_id.clone(),
                roll,
                success,
            });
            if !success {
                // Bribe failed: player still ejected
                self.game.field_model.set_player_state(&bribe.fouler_id, PlayerState::new(PS_RESERVE));
                self.game.field_model.player_coordinates.remove(&bribe.fouler_id);
                events.push(GameEvent::SecretWeaponBan { player_id: bribe.fouler_id });
            }
            // If success: player stays on field (already standing)
        } else {
            // No bribe: player is ejected immediately
            self.game.field_model.set_player_state(&bribe.fouler_id, PlayerState::new(PS_RESERVE));
            self.game.field_model.player_coordinates.remove(&bribe.fouler_id);
            events.push(GameEvent::SecretWeaponBan { player_id: bribe.fouler_id });
        }
        Ok(events)
    }

    fn resolve_argue_the_call(&mut self, atc: PendingArgueTheCall, argue: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let eject_player = |game: &mut Game, events: &mut Vec<GameEvent>, fouler_id: &str, home_fouling: bool| {
            game.field_model.set_player_state(fouler_id, PlayerState::new(PS_RESERVE));
            game.field_model.player_coordinates.remove(fouler_id);
            events.push(GameEvent::PlayerEjected { player_id: fouler_id.to_owned() });
            if home_fouling { game.turn_data_home.foul_used = true; } else { game.turn_data_away.foul_used = true; }
        };

        if argue {
            // Roll 2D6: 11-12 = success (player stays), 2 = fail + coach banned, else fail
            let roll = self.rng.d6() + self.rng.d6();
            let success = roll >= 11;
            let coach_banned = roll == 2;
            events.push(GameEvent::ArgueTheCall {
                player_id: atc.fouler_id.clone(),
                roll,
                success,
            });
            if success {
                // Argument successful: player not ejected
            } else {
                eject_player(&mut self.game, &mut events, &atc.fouler_id, atc.home_fouling);
                if coach_banned {
                    let team_id = if atc.home_fouling {
                        self.game.team_home.id.clone()
                    } else {
                        self.game.team_away.id.clone()
                    };
                    events.push(GameEvent::CoachBanned { team_id });
                }
            }
        } else {
            // Coach declined to argue: eject player immediately
            eject_player(&mut self.game, &mut events, &atc.fouler_id, atc.home_fouling);
        }
        self.game.acting_player.clear();
        self.player_activated_this_turn = false;
        Ok(events)
    }

    fn resolve_blast_it(&mut self, bi: PendingBlastIt, use_it: bool) -> Result<Vec<GameEvent>, RulesError> {
        use ffb_model::enums::Direction;
        use ffb_mechanics::mechanics::scatter_coordinate;

        let mut events = Vec::new();
        events.push(GameEvent::SkillUse {
            player_id: bi.thrower_id.clone(),
            skill_id: SkillId::BlastIt as u16,
            used: use_it,
        });

        // Determine the first scatter direction to use
        let first_dir = if use_it {
            // Mark skill used and reroll the first direction
            let team = if bi.home_throwing { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(&bi.thrower_id) {
                p.used_skills.insert(SkillId::BlastIt);
            }
            self.blast_it_catch_bonus = true;
            self.rng.d8() // reroll
        } else {
            bi.first_dir // use original
        };

        // Compute first destination
        let first_dest = {
            let mut d = bi.target_coord;
            if let Some(dir) = Direction::for_roll(first_dir) {
                let (nx, ny) = scatter_coordinate(d.x, d.y, dir, 1);
                let nc = FieldCoordinate::new(nx, ny);
                if nc.is_on_pitch() { d = nc; }
            }
            d
        };

        // Roll remaining 2 scatter directions
        let mut dirs = vec![first_dir];
        let mut land = first_dest;
        for _ in 0..2 {
            let d = self.rng.d8();
            dirs.push(d);
            if let Some(dir) = Direction::for_roll(d) {
                let (nx, ny) = scatter_coordinate(land.x, land.y, dir, 1);
                let nc = FieldCoordinate::new(nx, ny);
                if nc.is_on_pitch() { land = nc; }
            }
        }
        events.push(GameEvent::PassDeviate { from: bi.target_coord, scatter_directions: dirs });
        self.game.acting_player.has_acted = true;
        self.resolve_ball_landing(land, &mut events, 5);
        // Clear bonus after ball resolves
        self.blast_it_catch_bonus = false;
        Ok(events)
    }

    fn resolve_saboteur(&mut self, sab: PendingSaboteur, use_it: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        if !use_it {
            events.push(GameEvent::SkillUse {
                player_id: sab.player_id.clone(),
                skill_id: SkillId::Saboteur as u16,
                used: false,
            });
            // Resume follow-up if pending
            if let Some(fu) = self.pending_follow_up.take() {
                self.cached_prompt = Some(AgentPrompt::FollowUp {
                    attacker_id: fu.attacker_id.clone(),
                    target_coord: fu.attacker_to,
                });
                self.pending_follow_up = Some(fu);
            }
            return Ok(events);
        }
        // Roll D6: on 4+ the target (opponent) is also knocked down.
        let roll = self.rng.d6();
        let success = roll >= 4;
        events.push(GameEvent::SkillUse {
            player_id: sab.player_id.clone(),
            skill_id: SkillId::Saboteur as u16,
            used: success,
        });
        if success {
            let target_state = self.game.field_model.player_state(&sab.target_id)
                .unwrap_or(PlayerState::new(PS_STANDING));
            if target_state.is_standing() {
                self.game.field_model.set_player_state(
                    &sab.target_id,
                    target_state.change_base(PS_PRONE),
                );
                let target_coord = self.game.field_model.player_coordinate(&sab.target_id)
                    .unwrap_or(FieldCoordinate::new(0, 0));
                events.push(GameEvent::PlayerFellDown {
                    player_id: sab.target_id.clone(),
                    coord: target_coord,
                });
            }
        }
        // Resume follow-up if pending
        if let Some(fu) = self.pending_follow_up.take() {
            self.cached_prompt = Some(AgentPrompt::FollowUp {
                attacker_id: fu.attacker_id.clone(),
                target_coord: fu.attacker_to,
            });
            self.pending_follow_up = Some(fu);
        }
        Ok(events)
    }

    fn resolve_piling_on(&mut self, po: PendingPilingOn, use_it: bool) -> Result<Vec<GameEvent>, RulesError> {
        let mut events = Vec::new();
        let rules = self.game.rules;
        if !use_it {
            events.push(GameEvent::SkillUse {
                player_id: po.attacker_id.clone(),
                skill_id: SkillId::PilingOn as u16,
                used: false,
            });
            return Ok(events);
        }
        // Attacker goes prone
        let att_state = self.game.field_model.player_state(&po.attacker_id)
            .unwrap_or(PlayerState::new(PS_STANDING));
        self.game.field_model.set_player_state(&po.attacker_id, att_state.change_base(PS_PRONE));
        let att_coord = self.game.field_model.player_coordinate(&po.attacker_id)
            .unwrap_or(FieldCoordinate::new(12, 7));
        events.push(GameEvent::PlayerFellDown { player_id: po.attacker_id.clone(), coord: att_coord });
        events.push(GameEvent::SkillUse {
            player_id: po.attacker_id.clone(),
            skill_id: SkillId::PilingOn as u16,
            used: true,
        });
        // Mark Piling On used
        if po.home_attacking {
            if let Some(p) = self.game.team_home.player_mut(&po.attacker_id) {
                p.used_skills.insert(SkillId::PilingOn);
            }
        } else if let Some(p) = self.game.team_away.player_mut(&po.attacker_id) {
            p.used_skills.insert(SkillId::PilingOn);
        }
        let (def_av, def_stunty_po) = if po.home_attacking {
            let p = self.game.team_away.player(&po.defender_id);
            (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false))
        } else {
            let p = self.game.team_home.player(&po.defender_id);
            (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false))
        };
        let stunty_po_mod = if def_stunty_po { -1 } else { 0 };
        const PILING_ON_BONUS: i32 = 2;
        if po.armor_broken {
            // Re-roll injury with +2
            let inj1 = self.rng.d6();
            let inj2 = self.rng.d6();
            let total = inj1 + inj2 + PILING_ON_BONUS;
            let was_cas = total >= 10;
            let was_ko = total >= 8 && !was_cas;
            let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
            let defender_is_home = !po.home_attacking;
            let regen = if was_cas { self.try_regeneration(&po.defender_id, defender_is_home, &mut events) } else { false };
            let was_cas = was_cas && !regen;
            let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                else if !regen { PlayerState::new(PS_PRONE) }
                else { PlayerState::new(PS_RESERVE) };
            if !regen { self.game.field_model.set_player_state(&po.defender_id, new_state); }
            if was_cas {
                use ffb_mechanics::mechanics::casualty_spp;
                let cas_spp = casualty_spp(rules, false);
                self.award_spp(&po.attacker_id, po.home_attacking, cas_spp);
                if let Some(si_kind) = si {
                    self.apply_casualty_to_player(&po.defender_id, defender_is_home, si_kind);
                }
            }
            events.push(GameEvent::Injury {
                player_id: po.defender_id.clone(),
                armor_roll: None,
                injury_roll: Some([inj1, inj2]),
                serious_injury: si,
                was_ko,
                was_cas,
            });
        } else {
            // Re-roll armor with +2
            let ar1 = self.rng.d6();
            let ar2 = self.rng.d6();
            let armor_broken = is_armour_broken(def_av, ar1 + ar2 + PILING_ON_BONUS + stunty_po_mod, rules);
            if armor_broken {
                let inj1 = self.rng.d6();
                let inj2 = self.rng.d6();
                let total = inj1 + inj2;
                let was_cas = total >= 10;
                let was_ko = total >= 8 && !was_cas;
                let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                let defender_is_home = !po.home_attacking;
                let regen = if was_cas { self.try_regeneration(&po.defender_id, defender_is_home, &mut events) } else { false };
                let was_cas = was_cas && !regen;
                let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                    else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                    else if !regen { PlayerState::new(PS_PRONE) }
                    else { PlayerState::new(PS_RESERVE) };
                if !regen { self.game.field_model.set_player_state(&po.defender_id, new_state); }
                if was_cas {
                    use ffb_mechanics::mechanics::casualty_spp;
                    let cas_spp = casualty_spp(rules, false);
                    self.award_spp(&po.attacker_id, po.home_attacking, cas_spp);
                    if let Some(si_kind) = si {
                        self.apply_casualty_to_player(&po.defender_id, defender_is_home, si_kind);
                    }
                }
                events.push(GameEvent::Injury {
                    player_id: po.defender_id.clone(),
                    armor_roll: Some([ar1, ar2]),
                    injury_roll: Some([inj1, inj2]),
                    serious_injury: si,
                    was_ko,
                    was_cas,
                });
            } else {
                // Armor not broken — check WeepingDagger (BB2016): 5+ on D6 treats armor as broken
                let has_weeping_dagger = if po.home_attacking {
                    self.game.team_home.player(&po.attacker_id)
                } else {
                    self.game.team_away.player(&po.attacker_id)
                }.map(|p| p.has_skill(SkillId::WeepingDagger) && rules == Rules::Bb2016)
                    .unwrap_or(false);

                let mut armor_broken_by_dagger = false;
                if has_weeping_dagger {
                    let wd_roll = self.rng.d6();
                    armor_broken_by_dagger = wd_roll >= 5;
                    events.push(GameEvent::WeepingDaggerRoll {
                        player_id: po.attacker_id.clone(),
                        roll: wd_roll,
                    });
                }

                if armor_broken_by_dagger {
                    let inj1 = self.rng.d6();
                    let inj2 = self.rng.d6();
                    let total = inj1 + inj2;
                    let was_cas = total >= 10;
                    let was_ko = total >= 8 && !was_cas;
                    let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
                    let defender_is_home = !po.home_attacking;
                    let regen = if was_cas { self.try_regeneration(&po.defender_id, defender_is_home, &mut events) } else { false };
                    let was_cas = was_cas && !regen;
                    let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                        else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                        else if !regen { PlayerState::new(PS_PRONE) }
                        else { PlayerState::new(PS_RESERVE) };
                    if !regen { self.game.field_model.set_player_state(&po.defender_id, new_state); }
                    if was_cas {
                        use ffb_mechanics::mechanics::casualty_spp;
                        let cas_spp = casualty_spp(rules, false);
                        self.award_spp(&po.attacker_id, po.home_attacking, cas_spp);
                        if let Some(si_kind) = si {
                            self.apply_casualty_to_player(&po.defender_id, defender_is_home, si_kind);
                        }
                    }
                    events.push(GameEvent::Injury {
                        player_id: po.defender_id.clone(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: Some([inj1, inj2]),
                        serious_injury: si,
                        was_ko,
                        was_cas,
                    });
                } else {
                    events.push(GameEvent::Injury {
                        player_id: po.defender_id.clone(),
                        armor_roll: Some([ar1, ar2]),
                        injury_roll: None,
                        serious_injury: None,
                        was_ko: false,
                        was_cas: false,
                    });
                }
            }
        }
        Ok(events)
    }

    /// Roll for Regeneration on a CAS result. Returns `true` if the player regenerates.
    ///
    /// On success (4+): player is placed in RESERVE, `was_cas` is cleared, event emitted.
    /// On failure: no change, caller still applies the casualty normally.
    fn try_regeneration(&mut self, player_id: &str, is_home: bool, events: &mut Vec<GameEvent>) -> bool {
        let has_regen = if is_home {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        }.map(|p| p.has_skill(SkillId::Regeneration)).unwrap_or(false);

        if !has_regen { return false; }

        let roll = self.rng.d6();
        let success = roll >= 4;
        events.push(GameEvent::RegenerationRoll {
            player_id: player_id.to_owned(),
            roll,
            success,
        });
        if success {
            self.game.field_model.set_player_state(player_id, PlayerState::new(PS_RESERVE));
            self.game.field_model.player_coordinates.remove(player_id);
        }
        success
    }

    /// SteadyFooting (BB2025): when the player would fall, roll D6. On 6, they don't fall.
    /// Returns true if the player was saved (no fall), false if they still fall.
    fn try_steady_footing(&mut self, player_id: &str, is_home: bool, events: &mut Vec<GameEvent>) -> bool {
        if self.game.rules != Rules::Bb2025 { return false; }
        let has_sf = if is_home {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        }.map(|p| p.has_skill(SkillId::SteadyFooting)).unwrap_or(false);
        if !has_sf { return false; }
        let roll = self.rng.d6();
        let success = roll >= 6;
        events.push(GameEvent::SkillUse {
            player_id: player_id.to_owned(),
            skill_id: SkillId::SteadyFooting as u16,
            used: success,
        });
        success
    }

    /// Build HitAndRun context: finds adjacent empty squares not in opponent TZ for the attacker.
    #[cfg(test)]
    pub(crate) fn build_hit_and_run_pub(&self, attacker_id: &str, home_attacking: bool) -> Option<PendingHitAndRun> {
        self.build_hit_and_run(attacker_id, home_attacking)
    }
    /// Returns Some(PendingHitAndRun) if the skill applies and squares exist, None otherwise.
    /// HitAndRun is BB2020+ only and requires the attacker to be standing.
    fn build_hit_and_run(&self, attacker_id: &str, home_attacking: bool) -> Option<PendingHitAndRun> {
        let rules = self.game.rules;
        if rules == Rules::Bb2016 { return None; }
        let has_har = if home_attacking {
            self.game.team_home.player(attacker_id)
        } else {
            self.game.team_away.player(attacker_id)
        }.map(|p| p.has_skill(SkillId::HitAndRun)).unwrap_or(false);
        if !has_har { return None; }
        // Attacker must still be standing
        let state = self.game.field_model.player_state(attacker_id)?;
        if state.base() != PS_STANDING { return None; }
        let pos = self.game.field_model.player_coordinate(attacker_id)?;
        let opponent_team = if home_attacking { &self.game.team_away } else { &self.game.team_home };
        let squares: Vec<FieldCoordinate> = pos.neighbours().into_iter()
            .filter(|c| c.is_on_pitch())
            .filter(|c| self.game.field_model.player_at(*c).is_none())
            .filter(|c| {
                // Destination must not be adjacent to any opponent with tackle zones
                !opponent_team.players.iter().any(|opp| {
                    let opp_coord = self.game.field_model.player_coordinate(&opp.id);
                    let opp_state = self.game.field_model.player_state(&opp.id);
                    opp_coord.map(|oc| oc.is_adjacent(*c)).unwrap_or(false)
                        && opp_state.map(|s| s.has_tacklezones()).unwrap_or(false)
                })
            })
            .collect();
        if squares.is_empty() { return None; }
        Some(PendingHitAndRun {
            attacker_id: attacker_id.to_owned(),
            home_attacking,
            valid_squares: squares,
        })
    }

    /// Build PendingPutridRegurgitation if the attacker has the skill (unused) and the defender is still on pitch.
    fn build_putrid_regurgitation(
        &self,
        attacker_id: &str,
        defender_id: &str,
        home_attacking: bool,
    ) -> Option<PendingPutridRegurgitation> {
        let has_unused = if home_attacking {
            self.game.team_home.player(attacker_id)
        } else {
            self.game.team_away.player(attacker_id)
        }.map(|p| {
            p.has_skill(SkillId::PutridRegurgitation)
                && !p.used_skills.contains(&SkillId::PutridRegurgitation)
        }).unwrap_or(false);
        if !has_unused { return None; }
        // Defender must still be on pitch (not carted off)
        if self.game.field_model.player_coordinate(defender_id).is_none() { return None; }
        Some(PendingPutridRegurgitation {
            attacker_id: attacker_id.to_owned(),
            defender_id: defender_id.to_owned(),
            home_attacking,
        })
    }

    /// Returns `Some(true)` if the player belongs to the home team, `Some(false)` for away,
    /// or `None` if the player ID is not found on either team.
    fn player_is_home(&self, player_id: &str) -> Option<bool> {
        if self.game.team_home.has_player(player_id) {
            Some(true)
        } else if self.game.team_away.has_player(player_id) {
            Some(false)
        } else {
            None
        }
    }

    /// Apply a confirmed serious injury to the player's permanent record.
    ///
    /// Records the injury in `stat_injuries` and reduces the relevant stat.
    /// Call this once a casualty result is finalised (after any apothecary decision).
    fn apply_casualty_to_player(&mut self, player_id: &str, is_home: bool, si: SeriousInjuryKind) {
        let rules = self.game.rules;
        let player = if is_home {
            self.game.team_home.player_mut(player_id)
        } else {
            self.game.team_away.player_mut(player_id)
        };
        if let Some(p) = player {
            p.stat_injuries.push(si);
            match si.injury_attribute() {
                Some(InjuryAttribute::Ma) => {
                    p.movement = apply_lasting_injury(p.movement, PlayerStatKey::Ma, rules);
                }
                Some(InjuryAttribute::St) => {
                    p.strength = apply_lasting_injury(p.strength, PlayerStatKey::St, rules);
                }
                Some(InjuryAttribute::Ag) => {
                    p.agility = apply_lasting_injury(p.agility, PlayerStatKey::Ag, rules);
                }
                Some(InjuryAttribute::Pa) => {
                    p.passing = apply_lasting_injury(p.passing, PlayerStatKey::Pa, rules);
                }
                Some(InjuryAttribute::Av) => {
                    p.armour = apply_lasting_injury(p.armour, PlayerStatKey::Av, rules);
                }
                Some(InjuryAttribute::Ni) => {
                    p.niggling_injuries += 1;
                }
                None => {}
            }
        }
    }

    /// Return the niggling injury modifier for a player receiving an injury roll (BB2016 only).
    ///
    /// In BB2016 each niggling injury on the defender adds +1 to their opponent's injury roll.
    fn niggling_injury_mod(&self, defender_id: &str, defender_is_home: bool) -> i32 {
        if self.game.rules != Rules::Bb2016 { return 0; }
        let team = if defender_is_home { &self.game.team_home } else { &self.game.team_away };
        team.player(defender_id).map(|p| p.niggling_injuries).unwrap_or(0)
    }

    /// Run negatrait check (BoneHead / ReallyStupid / WildAnimal / BloodLust) for the activated player.
    ///
    /// Returns events. On failure, deactivates and confuses/resets the player (or for BloodLust,
    /// sets `pending_blood_lust` so the agent must choose a teammate to bite).
    fn check_negatrait(&mut self, player_id: &str, pa: PlayerAction) -> Vec<GameEvent> {
        let is_home = match self.player_is_home(player_id) {
            Some(b) => b,
            None => return vec![],
        };
        let rules = self.game.rules;
        let (has_bone_head, has_really_stupid, has_wild_animal, has_blood_lust, has_take_root, has_animal_savagery, has_unchannelled_fury) = {
            let team = if is_home { &self.game.team_home } else { &self.game.team_away };
            match team.player(player_id) {
                Some(p) => (
                    p.has_skill(SkillId::BoneHead),
                    p.has_skill(SkillId::ReallyStupid),
                    p.has_skill(SkillId::WildAnimal),
                    p.has_skill(SkillId::BloodLust),
                    p.has_skill(SkillId::TakeRoot) && rules == Rules::Bb2016,
                    p.has_skill(SkillId::AnimalSavagery),
                    p.has_skill(SkillId::UnchannelledFury),
                ),
                None => return vec![],
            }
        };

        if !has_bone_head && !has_really_stupid && !has_wild_animal && !has_blood_lust && !has_take_root && !has_animal_savagery && !has_unchannelled_fury {
            return vec![];
        }

        // TakeRoot (BB2016): roll at activation. On 4+, player may act normally.
        // On 1-3, player becomes Rooted — can still block/pass/hand-off but cannot move.
        if has_take_root {
            let used_take_root = {
                let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                team.player(player_id).map(|p| p.used_skills.contains(&SkillId::TakeRoot)).unwrap_or(false)
            };
            if !used_take_root {
                let roll = self.rng.d6();
                let rooted = roll < 4;
                let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::TakeRoot); }
                if rooted {
                    // Mark player state as Rooted so movement is blocked
                    let state = self.game.field_model.player_state(player_id)
                        .unwrap_or(PlayerState::new(PS_STANDING));
                    self.game.field_model.set_player_state(player_id, state.change_rooted(true));
                }
                return vec![GameEvent::ConfusionRoll {
                    player_id: player_id.to_owned(),
                    roll,
                    confused: rooted,
                }];
            }
            return vec![];
        }

        // Blood Lust: roll separately from the confusion negatraits (vampires don't get confused).
        if has_blood_lust {
            let bl_roll = self.rng.d6();
            let bl_success = is_skill_roll_successful(bl_roll, 2);
            let mut events = vec![GameEvent::BloodLustRoll {
                player_id: player_id.to_owned(),
                roll: bl_roll,
                success: bl_success,
            }];
            if !bl_success {
                // Must bite an adjacent teammate before proceeding.
                let adj_teammates: Vec<String> = self.game.field_model
                    .player_coordinate(player_id)
                    .map(|c| {
                        self.game.field_model.adjacent_on_pitch(c).into_iter()
                            .filter_map(|ac| self.game.field_model.player_at(ac).cloned())
                            .filter(|tid| {
                                if is_home { self.game.team_home.has_player(tid) }
                                else { self.game.team_away.has_player(tid) }
                            })
                            .collect()
                    })
                    .unwrap_or_default();
                if adj_teammates.is_empty() {
                    // No teammate available: player is badly hurt (auto-removed from game).
                    let coord = self.game.field_model.player_coordinate(player_id)
                        .unwrap_or(FieldCoordinate::new(13, 7));
                    events.push(GameEvent::PlayerFellDown { player_id: player_id.to_owned(), coord });
                    events.push(GameEvent::Injury {
                        player_id: player_id.to_owned(),
                        armor_roll: None,
                        injury_roll: None,
                        serious_injury: None,
                        was_ko: false,
                        was_cas: true,
                    });
                    self.game.field_model.set_player_state(
                        player_id,
                        PlayerState::new(PS_BADLY_HURT),
                    );
                    self.game.acting_player.clear();
                } else {
                    self.pending_blood_lust = Some(player_id.to_owned());
                    self.cached_prompt = Some(AgentPrompt::PlayerChoice {
                        eligible_players: adj_teammates,
                        reason: "blood_lust_bite".into(),
                    });
                }
            }
            return events;
        }

        // Animal Savagery (BB2020): roll 4+ (2+ if blocking/blitzing).
        // On failure, player lashes out at an adjacent player with an armor roll.
        if has_animal_savagery {
            let used = {
                let team = if is_home { &self.game.team_home } else { &self.game.team_away };
                team.player(player_id).map(|p| p.used_skills.contains(&SkillId::AnimalSavagery)).unwrap_or(false)
            };
            if !used {
                let good_conditions = matches!(pa,
                    PlayerAction::Block | PlayerAction::Blitz | PlayerAction::StandUpBlitz |
                    PlayerAction::BlitzMove | PlayerAction::MultipleBlock);
                let min_roll = if good_conditions { 2 } else { 4 };
                let roll = self.rng.d6();
                let success = roll >= min_roll;
                {
                    let team = if is_home { &mut self.game.team_home } else { &mut self.game.team_away };
                    if let Some(p) = team.player_mut(player_id) { p.used_skills.insert(SkillId::AnimalSavagery); }
                }
                if !success {
                    // Find all adjacent players (opponents or teammates)
                    let adj_targets: Vec<(String, bool)> = self.game.field_model
                        .player_coordinate(player_id)
                        .map(|c| {
                            self.game.field_model.adjacent_on_pitch(c).into_iter()
                                .filter_map(|ac| self.game.field_model.player_at(ac).cloned())
                                .map(|tid| {
                                    let is_home_player = self.game.team_home.has_player(&tid);
                                    (tid, is_home_player)
                                })
                                .collect()
                        })
                        .unwrap_or_default();
                    if !adj_targets.is_empty() {
                        // Lash out at first adjacent player (simplified: random choice not needed for correctness)
                        let (target_id, target_is_home) = adj_targets.into_iter().next().unwrap();
                        let target_av = if target_is_home {
                            self.game.team_home.player(&target_id).map(|p| p.armour).unwrap_or(8)
                        } else {
                            self.game.team_away.player(&target_id).map(|p| p.armour).unwrap_or(8)
                        };
                        let ar1 = self.rng.d6();
                        let ar2 = self.rng.d6();
                        let armor_broken = ffb_mechanics::mechanics::is_armour_broken(target_av, ar1 + ar2, rules);
                        if armor_broken {
                            let inj1 = self.rng.d6();
                            let inj2 = self.rng.d6();
                            let total = inj1 + inj2;
                            let was_cas = total >= 10;
                            let was_ko = total >= 8 && !was_cas;
                            let new_state = if was_ko || was_cas {
                                PlayerState::new(PS_KNOCKED_OUT)
                            } else {
                                PlayerState::new(PS_PRONE)
                            };
                            self.game.field_model.set_player_state(&target_id, new_state);
                            return vec![
                                GameEvent::AnimalSavagery { player_id: player_id.to_owned(), roll, success: false },
                                GameEvent::Injury {
                                    player_id: target_id,
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: Some([inj1, inj2]),
                                    serious_injury: None,
                                    was_ko,
                                    was_cas,
                                },
                            ];
                        } else {
                            return vec![
                                GameEvent::AnimalSavagery { player_id: player_id.to_owned(), roll, success: false },
                                GameEvent::Injury {
                                    player_id: target_id,
                                    armor_roll: Some([ar1, ar2]),
                                    injury_roll: None,
                                    serious_injury: None,
                                    was_ko: false,
                                    was_cas: false,
                                },
                            ];
                        }
                    } else {
                        // No adjacent players: action ends with player standing confused
                        let state = self.game.field_model.player_state(player_id)
                            .unwrap_or(PlayerState::new(PS_STANDING));
                        self.game.field_model.set_player_state(player_id,
                            state.change_base(PS_STANDING).change_active(false));
                        self.game.acting_player.clear();
                        return vec![GameEvent::AnimalSavagery { player_id: player_id.to_owned(), roll, success: false }];
                    }
                }
                return vec![GameEvent::AnimalSavagery { player_id: player_id.to_owned(), roll, success: true }];
            }
            return vec![];
        }

        // UnchannelledFury: like WildAnimal but for Chaos players. Roll at activation.
        // On 2+ with good conditions (blitz/block), or 4+ without: action proceeds.
        // On fail, player's activation is cancelled (no confusion, just ends turn).
        if has_unchannelled_fury {
            let good_conditions = matches!(pa,
                PlayerAction::Block | PlayerAction::Blitz | PlayerAction::StandUpBlitz
                | PlayerAction::BlitzMove | PlayerAction::MultipleBlock
            );
            let minimum_roll = if good_conditions { 2 } else { 4 };
            let roll = self.rng.d6();
            let failed = !is_skill_roll_successful(roll, minimum_roll);
            if failed {
                // Cancel the action — player stays standing but active flag cleared
                let state = self.game.field_model.player_state(player_id)
                    .unwrap_or(PlayerState::new(PS_STANDING));
                self.game.field_model.set_player_state(player_id,
                    state.change_base(PS_STANDING).change_active(false));
                self.game.acting_player.clear();
            }
            return vec![GameEvent::ConfusionRoll {
                player_id: player_id.to_owned(),
                roll,
                confused: failed,
            }];
        }

        let roll = self.rng.d6();

        let good_conditions = if has_bone_head {
            true
        } else if has_really_stupid {
            // Good conditions: at least one adjacent friendly teammate without ReallyStupid.
            // Exception: when throwing a teammate, always good conditions.
            if matches!(pa, PlayerAction::ThrowTeamMate | PlayerAction::ThrowTeamMateMove) {
                true
            } else {
                let coord = self.game.field_model.player_coordinate(player_id);
                if let Some(c) = coord {
                    let adj_coords = self.game.field_model.adjacent_on_pitch(c);
                    let friendly_ids: Vec<String> = adj_coords.iter()
                        .filter_map(|ac| self.game.field_model.player_at(*ac).cloned())
                        .filter(|pid| {
                            let same_team = if is_home {
                                self.game.team_home.has_player(pid)
                            } else {
                                self.game.team_away.has_player(pid)
                            };
                            same_team
                        })
                        .collect();
                    let team2 = if is_home { &self.game.team_home } else { &self.game.team_away };
                    friendly_ids.iter().any(|fid| {
                        team2.player(fid).map(|fp| !fp.has_skill(SkillId::ReallyStupid)).unwrap_or(false)
                    })
                } else {
                    false
                }
            }
        } else {
            // WildAnimal: good when blocking or blitzing
            matches!(pa, PlayerAction::Block | PlayerAction::Blitz | PlayerAction::StandUpBlitz)
        };

        let minimum_roll = if good_conditions { 2 } else { 4 };
        let confused = !is_skill_roll_successful(roll, minimum_roll);

        if confused {
            let state = self.game.field_model.player_state(player_id)
                .unwrap_or(PlayerState::new(PS_STANDING));
            let is_standing_up = state.base() == PS_PRONE; // was prone and standing up
            let new_state = if has_wild_animal {
                // Wild Animal on failure: stays standing (not confused), action ends
                state.change_base(PS_STANDING).change_active(false)
            } else if is_standing_up {
                // Was standing up (prone → standing): set to PRONE, deactivate
                state.change_base(PS_PRONE).change_active(false)
            } else {
                state.change_confused(true).change_active(false)
            };
            self.game.field_model.set_player_state(player_id, new_state);
            self.game.acting_player.clear();
        }

        vec![GameEvent::ConfusionRoll {
            player_id: player_id.to_owned(),
            roll,
            confused,
        }]
    }

    /// Apply armor/injury roll for a player who fell prone (failed dodge, GFI, leap, etc.).
    ///
    /// Returns (armor_roll_result, was_ko, was_cas, emitted_events) where was_ko/was_cas
    /// reflect the final outcome after applying ThickSkull, Decay, and Regeneration.
    fn apply_fall_injury(&mut self, player_id: &str, is_home: bool, arm_bar_mod: i32) -> Vec<GameEvent> {
        let mut events = Vec::new();
        let rules = self.game.rules;
        let (av, has_stunty, has_iron_hard_skin) = if is_home {
            let p = self.game.team_home.player(player_id);
            (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
        } else {
            let p = self.game.team_away.player(player_id);
            (p.map(|p| p.armour).unwrap_or(8), p.map(|p| p.has_skill(SkillId::Stunty)).unwrap_or(false),
             p.map(|p| p.has_skill(SkillId::IronHardSkin)).unwrap_or(false))
        };
        let stunty_mod = if has_stunty && !has_iron_hard_skin { -1 } else { 0 };
        // IronHardSkin: blocks ArmBar modifier as well as Stunty
        let eff_arm_bar_mod = if has_iron_hard_skin { 0 } else { arm_bar_mod };
        let ar1 = self.rng.d6();
        let ar2 = self.rng.d6();
        let base_total = ar1 + ar2 + stunty_mod;
        let mut armor_broken = is_armour_broken(av, base_total, rules);
        let mut arm_bar_on_injury = false;
        if !armor_broken && eff_arm_bar_mod > 0 {
            // ArmBar: add +1 to armor roll; if still doesn't break, add to injury roll
            armor_broken = is_armour_broken(av, base_total + eff_arm_bar_mod, rules);
            if !armor_broken {
                arm_bar_on_injury = true; // ArmBar applies to injury roll instead
            }
        }
        if armor_broken {
            let inj1 = self.rng.d6();
            let inj2 = self.rng.d6();
            let niggling_mod = self.niggling_injury_mod(player_id, is_home);
            let inj_arm_bar = if arm_bar_on_injury { eff_arm_bar_mod } else { 0 };
            let total = inj1 + inj2 + niggling_mod + inj_arm_bar;
            let mut was_cas = total >= 10;
            let mut was_ko = total >= 8 && !was_cas;
            if was_ko && self.check_thick_skull(player_id, is_home, &mut events) {
                was_ko = false;
            }
            let has_decay = if is_home {
                self.game.team_home.player(player_id)
            } else {
                self.game.team_away.player(player_id)
            }.map(|p| p.has_skill(SkillId::Decay)).unwrap_or(false);
            if has_decay && !was_cas && !was_ko {
                was_cas = true;
            }
            let (si, is_dead) = if was_cas { let (s, d) = self.roll_serious_injury(); (Some(s), d) } else { (None, false) };
            let regen = if was_cas {
                self.try_regeneration(player_id, is_home, &mut events)
            } else { false };
            let was_cas = was_cas && !regen;
            let new_state = if !regen && (is_dead || was_cas) { PlayerState::new(PS_BADLY_HURT) }
                else if !regen && was_ko { PlayerState::new(PS_KNOCKED_OUT) }
                else if !regen { PlayerState::new(PS_PRONE) }
                else { PlayerState::new(PS_RESERVE) };
            if !regen { self.game.field_model.set_player_state(player_id, new_state); }
            if was_cas {
                if let Some(si_kind) = si {
                    self.apply_casualty_to_player(player_id, is_home, si_kind);
                }
            }
            events.push(GameEvent::Injury {
                player_id: player_id.to_owned(),
                armor_roll: Some([ar1, ar2]),
                injury_roll: Some([inj1, inj2]),
                serious_injury: si,
                was_ko,
                was_cas,
            });
        } else {
            // Armor holds — player goes prone (stunned)
            let cur = self.game.field_model.player_state(player_id).unwrap_or(PlayerState::new(PS_STANDING));
            self.game.field_model.set_player_state(player_id, cur.change_active(false).change_base(PS_PRONE));
            events.push(GameEvent::Injury {
                player_id: player_id.to_owned(),
                armor_roll: Some([ar1, ar2]),
                injury_roll: None,
                serious_injury: None,
                was_ko: false,
                was_cas: false,
            });
        }
        events
    }

    /// Scatter the ball from `ball_at` if the ball is there and `player_id` is the carrier.
    /// Returns the BallScattered event if emitted, None otherwise.
    /// Respects SafePairOfHands (ball not dropped on fall).
    /// `ball_at` must be the square where the ball was BEFORE the player was repositioned.
    fn scatter_ball_if_carried(&mut self, player_id: &str, ball_at: FieldCoordinate, is_home: bool) -> Option<GameEvent> {
        let coord = ball_at;
        if self.game.field_model.ball_coordinate != Some(coord) || !self.game.field_model.ball_in_play {
            return None;
        }
        let has_sph = if is_home {
            self.game.team_home.player(player_id)
        } else {
            self.game.team_away.player(player_id)
        }.map(|p| p.has_skill(SkillId::SafePairOfHands)).unwrap_or(false);
        if has_sph { return None; }
        let dir = self.rng.d8();
        self.game.field_model.ball_moving = true;
        Some(GameEvent::BallScattered { player_id: player_id.to_owned(), coord, direction: dir })
    }

    /// ArmBar: if an adjacent opponent with tackle zones at `source_coord` has ArmBar, returns 1.
    fn arm_bar_mod_at(&self, source_coord: FieldCoordinate, mover_is_home: bool) -> i32 {
        for ac in self.game.field_model.adjacent_on_pitch(source_coord) {
            let Some(tid) = self.game.field_model.player_at(ac) else { continue };
            let is_opp = if mover_is_home { self.game.team_away.has_player(tid) } else { self.game.team_home.has_player(tid) };
            if !is_opp { continue; }
            let has_tz = self.game.field_model.player_state(tid).map(|s| s.has_tacklezones()).unwrap_or(false);
            if !has_tz { continue; }
            let opp = if mover_is_home { self.game.team_away.player(tid) } else { self.game.team_home.player(tid) };
            if opp.map(|p| p.has_skill(SkillId::ArmBar)).unwrap_or(false) {
                return 1;
            }
        }
        0
    }

    /// ThickSkull: when a player is KO'd, roll D6. On 4+, they are only Stunned (Prone) instead.
    /// Returns true if the KO was downgraded to Stunned.
    fn check_thick_skull(&mut self, player_id: &str, is_home: bool, events: &mut Vec<GameEvent>) -> bool {
        let has_thick_skull = if is_home {
            self.game.team_home.player(player_id).map(|p| p.has_skill(SkillId::ThickSkull)).unwrap_or(false)
        } else {
            self.game.team_away.player(player_id).map(|p| p.has_skill(SkillId::ThickSkull)).unwrap_or(false)
        };
        if !has_thick_skull { return false; }
        let roll = self.rng.d6();
        let saved = roll >= 4;
        events.push(GameEvent::SkillUse {
            player_id: player_id.to_owned(),
            skill_id: SkillId::ThickSkull as u16,
            used: saved,
        });
        saved
    }

    /// Reset all players to reserve at the end of a drive.
    ///
    /// - RIP stays RIP
    /// - Seriously injured / Badly Hurt: set to reserve (MNG handling is post-game)
    /// - KO'd: roll D6; on 4+ recover to reserve, otherwise stay KO'd (off-pitch but KO state)
    /// - All others (on-pitch, stunned, prone): set to reserve
    fn place_all_in_reserve(&mut self) {
        // Track home/away per player so we can look up inducement bonuses.
        let all_ids: Vec<(String, bool)> = self.game.team_home.players.iter()
            .map(|p| (p.id.clone(), true))
            .chain(self.game.team_away.players.iter().map(|p| (p.id.clone(), false)))
            .collect();
        let home_kegs = self.game.team_home.bloodweiser_kegs;
        let away_kegs = self.game.team_away.bloodweiser_kegs;
        for (pid, is_home) in &all_ids {
            let state = self.game.field_model.player_state(pid)
                .unwrap_or(PlayerState::new(PS_RESERVE));
            // Dead players stay dead
            if state.base() == PS_RIP { continue; }
            // Permanently injured/dead players: leave them in their box.
            if state.base() == PS_BADLY_HURT || state.base() == PS_SERIOUS_INJURY { continue; }
            // Note: PS_BANNED players (sent off for Secret Weapon) DO come back for the next
            // drive's setup in Blood Bowl — they are NOT permanently removed. Fall through to
            // the normal Reserve placement below.
            // Exhausted players (SwelteringHeat): move off pitch preserving EXHAUSTED state
            if state.base() == PS_EXHAUSTED {
                self.game.field_model.player_coordinates.remove(pid.as_str());
                continue;
            }
            // KO'd players roll D6 for recovery (4+ = recover, kegs add to roll)
            if state.base() == PS_KNOCKED_OUT {
                let mut recovery_roll = self.rng.d6();
                // BugmansXXXXXX: reroll when recovery roll is 1 (Regular — resets per turn)
                let bugmans_avail = if *is_home {
                    self.game.team_home.player(pid)
                } else {
                    self.game.team_away.player(pid)
                }.map(|p| p.has_skill(SkillId::BugmansXXXXXX) && !p.used_skills.contains(&SkillId::BugmansXXXXXX)).unwrap_or(false);
                if bugmans_avail && recovery_roll == 1 {
                    if *is_home { if let Some(p) = self.game.team_home.player_mut(pid) { p.used_skills.insert(SkillId::BugmansXXXXXX); } }
                    else if let Some(p) = self.game.team_away.player_mut(pid) { p.used_skills.insert(SkillId::BugmansXXXXXX); }
                    recovery_roll = self.rng.d6();
                }
                let keg_bonus = if *is_home { home_kegs } else { away_kegs };
                if recovery_roll + keg_bonus >= 4 {
                    self.game.field_model.set_player_state(pid, PlayerState::new(PS_RESERVE));
                }
                // If recovery fails, they remain KO'd (no coordinate)
                self.game.field_model.player_coordinates.remove(pid.as_str());
                continue;
            }
            self.game.field_model.set_player_state(pid, PlayerState::new(PS_RESERVE));
            self.game.field_model.player_coordinates.remove(pid.as_str());
        }
    }

    /// Eject all SecretWeapon and KeenPlayer players at end of drive.
    /// IllBeBack: skip first ejection of a SecretWeapon player once per game.
    /// Remove all card-applied temporary skills from affected players and emit CardDeactivated events.
    fn clear_card_temporary_skills(&mut self) -> Vec<GameEvent> {
        if self.card_temporary_skills.is_empty() {
            return Vec::new();
        }
        let mut events = Vec::new();
        let card_skills = std::mem::take(&mut self.card_temporary_skills);
        let mut seen_cards = std::collections::HashSet::new();
        for (player_id, skill_id, card_id) in &card_skills {
            let target_is_home = self.game.team_home.has_player(player_id);
            let team = if target_is_home { &mut self.game.team_home } else { &mut self.game.team_away };
            if let Some(p) = team.player_mut(player_id) {
                p.temporary_skills.retain(|sw| sw.skill_id != *skill_id);
            }
            if seen_cards.insert(card_id.clone()) {
                events.push(GameEvent::CardDeactivated { card_id: card_id.clone() });
            }
        }
        events
    }

    fn eject_secret_weapon_players(&mut self) -> Vec<GameEvent> {
        use std::collections::HashSet as SWHashSet;
        let mut events = Vec::new();
        // Clear any card-applied temporary skills at drive end.
        let card_events = self.clear_card_temporary_skills();
        events.extend(card_events);

        // Java's reportSecretWeaponsUsed(): for SW players with penalty > 0 (Stunty Leeg-style),
        // roll 2d6 BEFORE the argue phase. HOME team first (nr sorted), then AWAY (nr sorted).
        // Players that roll BELOW penalty escape ejection (sw_penalty_exempt); all others stay.
        // This consumes game RNG dice matching Java's StepEndTurn.reportSecretWeaponsUsed().
        let mut sw_penalty_exempt: SWHashSet<String> = SWHashSet::new();
        {
            let sw_penalty = |p: &ffb_model::model::player::Player| -> i32 {
                p.starting_skills.iter()
                    .find(|s| s.skill_id == SkillId::SecretWeapon)
                    .and_then(|s| s.value.as_ref())
                    .and_then(|v| v.parse::<i32>().ok())
                    .unwrap_or(0)
            };
            // Collect: home (nr sorted) then away (nr sorted), only those with penalty > 0
            let mut penalty_players: Vec<(String, i32)> = Vec::new();
            {
                let mut home_sw: Vec<(i32, String, i32)> = self.game.team_home.players.iter()
                    .filter(|p| p.has_skill(SkillId::SecretWeapon))
                    .map(|p| (p.nr, p.id.clone(), sw_penalty(p)))
                    .filter(|&(_, _, pen)| pen > 0)
                    .collect();
                home_sw.sort_by_key(|&(nr, _, _)| nr);
                penalty_players.extend(home_sw.into_iter().map(|(_, id, pen)| (id, pen)));
            }
            {
                let mut away_sw: Vec<(i32, String, i32)> = self.game.team_away.players.iter()
                    .filter(|p| p.has_skill(SkillId::SecretWeapon))
                    .map(|p| (p.nr, p.id.clone(), sw_penalty(p)))
                    .filter(|&(_, _, pen)| pen > 0)
                    .collect();
                away_sw.sort_by_key(|&(nr, _, _)| nr);
                penalty_players.extend(away_sw.into_iter().map(|(_, id, pen)| (id, pen)));
            }
            for (pid, penalty) in penalty_players {
                let total = self.rng.d6_two();
                if total < penalty {
                    // Rolled below penalty: player escapes ejection (like a successful Stunty Leeg check)
                    sw_penalty_exempt.insert(pid);
                }
                // If total >= penalty: stays in the ejection list (will be argued and/or ejected)
            }
        }

        // Collect SW player IDs per team sorted by jersey number (matching Java's order).
        // AWAY first to match Java's StepEndTurn: askForArgueTheCall(away) before home.
        let sw_away: Vec<String> = {
            let mut v: Vec<(i32, String)> = self.game.team_away.players.iter()
                .filter(|p| p.has_skill(SkillId::SecretWeapon) && !sw_penalty_exempt.contains(&p.id))
                .map(|p| (p.nr, p.id.clone())).collect();
            v.sort_by_key(|&(nr, _)| nr);
            v.into_iter().map(|(_, id)| id).collect()
        };
        let sw_home: Vec<String> = {
            let mut v: Vec<(i32, String)> = self.game.team_home.players.iter()
                .filter(|p| p.has_skill(SkillId::SecretWeapon) && !sw_penalty_exempt.contains(&p.id))
                .map(|p| (p.nr, p.id.clone())).collect();
            v.sort_by_key(|&(nr, _)| nr);
            v.into_iter().map(|(_, id)| id).collect()
        };

        // Process each team's SW players with the Argue the Call mechanic.
        // Java: DiceInterpreter.isArgueTheCallSuccessful(roll) = roll > 5 (d6=6 only reverses).
        //       DiceInterpreter.isCoachBanned(roll) = roll < 2 (d6=1 → coach banned).
        // When coach is banned: NO more argue dice for remaining players (loop continues but skips roll).
        for (sw_team, is_home) in [(&sw_away, false), (&sw_home, true)] {
            let mut coach_banned = false;
            for pid in sw_team {
                // IllBeBack: skip first ejection (once per game)
                let ill_be_back = if is_home {
                    self.game.team_home.player(pid)
                } else {
                    self.game.team_away.player(pid)
                }.map(|p| p.has_skill(SkillId::IllBeBack) && !p.used_skills.contains(&SkillId::IllBeBack)).unwrap_or(false);
                if ill_be_back {
                    if is_home { if let Some(p) = self.game.team_home.player_mut(pid) { p.used_skills.insert(SkillId::IllBeBack); } }
                    else if let Some(p) = self.game.team_away.player_mut(pid) { p.used_skills.insert(SkillId::IllBeBack); }
                    events.push(GameEvent::SkillUse { player_id: pid.clone(), skill_id: SkillId::IllBeBack as u16, used: true });
                    continue;
                }

                let state = self.game.field_model.player_state(pid).unwrap_or(PlayerState::new(PS_RESERVE));
                // Skip players already dead or ejected.
                if state.base() == PS_RIP || state.base() == PS_BANNED {
                    continue;
                }
                // Skip off-pitch players (reserve / KO box / dugout).
                // Do NOT restrict to PS_STANDING — scoring players have PS_MOVING state
                // during touchdown resolution and must still be ejected.
                if matches!(state.base(),
                    b if b == PS_RESERVE || b == PS_KNOCKED_OUT
                        || b == PS_BADLY_HURT || b == PS_SERIOUS_INJURY)
                {
                    continue;
                }

                if coach_banned {
                    // No argue dice: coach already banned. Ejection still proceeds.
                    self.game.field_model.set_player_state(pid, PlayerState::new(PS_BANNED));
                    self.game.field_model.player_coordinates.remove(pid.as_str());
                    events.push(GameEvent::SecretWeaponBan { player_id: pid.clone() });
                    continue;
                }

                // Argue the Call: roll d6 (matches Java's DiceRoller.rollArgueTheCall() = rollDice(6)).
                let argue_roll = self.rng.d6();
                if argue_roll > 5 {
                    // d6=6: argue succeeded, ejection reversed. Player stays on field.
                    continue;
                }
                if argue_roll < 2 {
                    // d6=1: coach is banned for the rest of this team's argues.
                    coach_banned = true;
                }
                // d6=1-5: ejection proceeds. PS_BANNED = "Reserve" in state hash (matches Java).
                self.game.field_model.set_player_state(pid, PlayerState::new(PS_BANNED));
                self.game.field_model.player_coordinates.remove(pid.as_str());
                events.push(GameEvent::SecretWeaponBan { player_id: pid.clone() });
            }
        }
        // KeenPlayer: always ejected at end of drive (no bribe/IllBeBack exemption)
        let kp_ids: Vec<(String, bool)> = self.game.team_home.players.iter()
            .filter(|p| p.has_skill(SkillId::KeenPlayer) && !p.has_skill(SkillId::SecretWeapon))
            .map(|p| (p.id.clone(), true))
            .chain(self.game.team_away.players.iter()
                .filter(|p| p.has_skill(SkillId::KeenPlayer) && !p.has_skill(SkillId::SecretWeapon))
                .map(|p| (p.id.clone(), false)))
            .collect();
        for (pid, _) in &kp_ids {
            let state = self.game.field_model.player_state(pid).unwrap_or(PlayerState::new(PS_RESERVE));
            if state.base() != PS_RIP {
                self.game.field_model.set_player_state(pid, PlayerState::new(PS_BADLY_HURT));
                self.game.field_model.player_coordinates.remove(pid.as_str());
                events.push(GameEvent::SecretWeaponBan { player_id: pid.clone() });
            }
        }
        events
    }
}

