    #[test]
    fn move_action_updates_player_coordinate() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("p1", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Place player and set as active
        engine.game.field_model.set_player_coordinate("p1", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("p1", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.acting_player.set_player("p1".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // Move one square in an open field (no tackle zones, no GFI)
        let path = vec![FieldCoordinate::new(6, 7)];
        let events = engine.apply(TeamSide::Home, Action::Move { path }).unwrap();

        // Player should have moved (at least one PlayerMoved event, unless GFI rolled)
        let new_coord = engine.game.field_model.player_coordinate("p1");
        // In an open field with MA=6 and current_move=0, no GFI and no TZ — always moves
        assert_eq!(new_coord, Some(FieldCoordinate::new(6, 7)));
        assert!(events.iter().any(|e| matches!(e, GameEvent::PlayerMoved { .. })));
    }

