    #[test]
    fn foul_assist_cancelled_by_defender_adjacent_to_helper() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("fouler", 1));
        home.players.push(make_test_player("helper", 2));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("target", 1));
        away.players.push(make_test_player("canceller", 2));
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        engine.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("helper", FieldCoordinate::new(12, 8));
        engine.game.field_model.set_player_state("helper", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
        // canceller adjacent to helper with tackle zones → cancels the offensive assist
        engine.game.field_model.set_player_coordinate("canceller", FieldCoordinate::new(13, 8));
        engine.game.field_model.set_player_state("canceller", PlayerState::new(PS_STANDING));

        let assists = engine.count_foul_assists(true, "fouler", "target");
        assert_eq!(assists, 0, "offensive assist cancelled by adjacent defender");
    }

