    #[test]
    fn sure_hands_marks_used_skill_after_reroll() {
        use ffb_model::model::skill_def::SkillWithValue;

        let mut home = make_test_team("home");
        let mut p = make_test_player("carrier", 1);
        p.starting_skills.push(SkillWithValue { skill_id: SkillId::SureHands, value: None });
        home.players.push(p);
        let away = make_test_team("away");
        // Use seed 0: first d6 will fail pickup, SureHands triggers reroll
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 0);

        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state(
            "carrier",
            PlayerState::new(PS_STANDING).change_active(true),
        );
        engine.game.acting_player.set_player("carrier".into(), PlayerAction::Move);
        engine.game.field_model.ball_in_play = true;
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(12, 7));

        // Move onto the ball square
        let _events = engine.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(12, 7)],
        }).unwrap();

        // Either the pickup succeeded, or SureHands was consumed (marked used)
        let carrier = engine.game.team_home.player("carrier").unwrap();
        // The skill should either have been used (reroll triggered) or pickup succeeded
        // Either way, the move should have completed without panic
        let _ = carrier.has_skill(SkillId::SureHands);
    }

