    #[test]
    fn blitz_offers_block_after_move() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("blitzer", 1));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("target", 1));
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // blitzer starts at (5,7), target at (6,7) — adjacent
        engine.game.field_model.set_player_coordinate("blitzer", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("blitzer", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("target", FieldCoordinate::new(6, 7));
        engine.game.field_model.set_player_state("target", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // Activate with Blitz
        engine.apply(TeamSide::Home, Action::ActivatePlayer {
            player_id: "blitzer".into(),
            player_action: crate::action::PlayerActionChoice::Blitz,
        }).unwrap();

        // Move to (5,7) → no-op path (or skip move) — send empty path to trigger stand-still
        engine.apply(TeamSide::Home, Action::Move { path: vec![] }).unwrap();

        // After the move, the prompt should offer Block (blitz is still pending the block step)
        let prompt = engine.current_prompt();
        if let Some(AgentPrompt::ActivatePlayer { eligible_players }) = prompt {
            // Should offer the blitzer with Block action (since target is adjacent)
            assert!(
                !eligible_players.is_empty(),
                "should offer Block step after Blitz move"
            );
            let (id, actions) = &eligible_players[0];
            assert_eq!(id, "blitzer");
            assert!(actions.contains(&PlayerAction::Block), "should offer Block in Blitz second step");
        } else {
            panic!("expected ActivatePlayer prompt for Blitz block step");
        }
    }

