    #[test]
    fn kickoff_get_the_ref_gives_both_teams_a_reroll() {
        // Roll 2 in BB2020 = GetTheRef
        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        let home_rerolls_before = engine.game.turn_data_home.rerolls;
        let away_rerolls_before = engine.game.turn_data_away.rerolls;

        let _ = engine.apply_kickoff_event(2, false);

        assert_eq!(
            engine.game.turn_data_home.rerolls,
            home_rerolls_before + 1,
            "GetTheRef must give home team +1 reroll"
        );
        assert_eq!(
            engine.game.turn_data_away.rerolls,
            away_rerolls_before + 1,
            "GetTheRef must give away team +1 reroll"
        );
    }

