        let mut home = make_test_team("home");
        home.rerolls = 2;
        let mut away = make_test_team("away");
        away.rerolls = 0;
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        assert!(engine.team_reroll_available(true), "home team should have rerolls (2)");
        assert!(!engine.team_reroll_available(false), "away team has 0 rerolls");

        // Consuming marks reroll_used and decrements
        engine.consume_team_reroll(true);
        assert_eq!(engine.game.turn_data_home.rerolls, 1);
