    // ── Group 4a: Apothecary ─────────────────────────────────────────────────

    #[test]
    fn apothecary_is_not_offered_for_ko() {
        let mut home = make_test_team("home");
        home.apothecaries = 1;
        home.players.push(make_test_player("victim", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Simulate a KO injury: try_offer_apothecary with was_ko=true → must return false
        let offered = engine.try_offer_apothecary(
            "victim", true,
            "attacker", false,
            3, 5,   // ar
            4, 4,   // inj (total 8 = KO)
            true,   // was_ko
            false,  // was_cas
            None,
            false,
        );
        assert!(!offered, "apothecary must NOT be offered for KO");
        assert!(engine.pending_apothecary.is_none(), "no pending apothecary for KO");
    }

    #[test]
    fn apothecary_is_offered_for_casualty() {
        let mut home = make_test_team("home");
        home.apothecaries = 1;
        home.players.push(make_test_player("victim", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        let offered = engine.try_offer_apothecary(
            "victim", true,
            "attacker", false,
            3, 5, 5, 5,
            false, // was_ko
            true,  // was_cas
            None,
            false,
        );
        assert!(offered, "apothecary must be offered for casualty");
        assert!(engine.pending_apothecary.is_some());
        // Apothecary count should be decremented
        assert_eq!(engine.game.team_home.apothecaries, 0);
    }

