    #[test]
    fn bribe_resolved_immediately_ejects_fouler() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("fouler", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        engine.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING));
        engine.pending_bribe = Some(PendingBribe {
            fouler_id: "fouler".into(),
            home_fouling: true,
        });
        engine.compute_next_prompt();

        // Decline the bribe → immediate ejection
        let events = engine.apply(TeamSide::Home, Action::UseBribe { use_bribe: false }).unwrap();

        assert!(engine.pending_bribe.is_none());
        let state = engine.game.field_model.player_state("fouler").unwrap();
        assert_eq!(state.base(), PS_RESERVE, "fouler must be ejected to reserve");
        assert!(events.iter().any(|e| matches!(e, GameEvent::SecretWeaponBan { .. })));
    }

    #[test]
    fn bribe_roll_success_player_not_ejected() {
        // We need the bribe roll to succeed (2-6). Use seed that produces d6 >= 2.
        // The engine's RNG will produce a bribe roll. We set pending_bribe directly.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("fouler", 1));
        let away = make_test_team("away");
        // Seed 5: first d6 should be >= 2 (almost certainly with any reasonable RNG)
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 5);

        engine.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING));
        engine.pending_bribe = Some(PendingBribe {
            fouler_id: "fouler".into(),
            home_fouling: true,
        });

        let events = engine.apply(TeamSide::Home, Action::UseBribe { use_bribe: true }).unwrap();

        // Must emit a BribesRoll event
        assert!(events.iter().any(|e| matches!(e, GameEvent::BribesRoll { .. })));
        // Check bribe cleared
        assert!(engine.pending_bribe.is_none());
    }

    // ── Group 6: Crowd surfing ────────────────────────────────────────────────

    #[test]
    fn crowd_surf_with_armor_roll() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("att", 1));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("def", 1));
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Defender at y=0 (top sideline), attacker pushes from y=1 (south).
        // Push cone = squares North of defender = (x-1,-1), (x,-1), (x+1,-1) — all off-pitch (y<0).
        // This is a textbook crowd surf.
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 1));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(12, 0));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // Inject a pending block choice with Pow result so crowd surf triggers
        engine.pending_block_choice = Some(PendingBlockChoice {
            attacker_id: "att".into(),
            defender_id: "def".into(),
            home_attacking: true,
            results: vec![BlockResult::Pow],
            att_has_block: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_wrestle: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(12, 1),
            defender_coord: FieldCoordinate::new(12, 0),
            def_has_sidestep: false,
            def_has_wrestle: false,
        });
        engine.cached_prompt = Some(AgentPrompt::BlockChoice {
            attacker_id: "att".into(),
            defender_id: "def".into(),
            dice: vec![6],
            own_choice: true,
            nr_of_dice: 1,
        });

        let events = engine.apply(TeamSide::Home, Action::BlockChoice { die_index: 0 }).unwrap();

        // Defender should have no field coordinate (removed from pitch)
        assert!(engine.game.field_model.player_coordinate("def").is_none(),
            "crowd surfed player should have no field coordinate");
        // Must have an Injury event with an armor_roll (crowd surf does armor roll)
        assert!(events.iter().any(|e| matches!(e, GameEvent::Injury { .. })),
            "crowd surf must emit an Injury event");
        // Must NOT have set up a Pushback prompt
        assert!(!matches!(engine.current_prompt(), Some(AgentPrompt::Pushback { .. })),
            "should not prompt for pushback after crowd surf");
    }

