    #[test]
    fn brilliant_coaching_counts_fan_factor_and_assistants() {
        let mut home = make_test_team("home");
        home.fan_factor = 3;
        home.assistant_coaches = 2;
        let mut away = make_test_team("away");
        away.fan_factor = 1;
        away.assistant_coaches = 0;
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        let home_rerolls_before = engine.game.turn_data_home.rerolls;
        let away_rerolls_before = engine.game.turn_data_away.rerolls;

        // BrilliantCoaching is roll=7 in BB2020 kickoff table
        let (events, _) = engine.apply_kickoff_event(7, false);

        assert!(events.iter().any(|e| matches!(e, GameEvent::KickoffResultEvent { .. })));
        // With fan_factor+assistants, the home team almost certainly outscores away on bonus alone
        // (home=3+2=5 bonus, away=1+0=1 bonus) regardless of die roll
        // So home MUST get the reroll; away might also get one if tie
        assert!(
            engine.game.turn_data_home.rerolls > home_rerolls_before
                || engine.game.turn_data_away.rerolls > away_rerolls_before,
            "BrilliantCoaching must grant at least one reroll"
        );
    }

    #[test]
    fn throw_a_rock_stuns_a_standing_player() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("h1", 1));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("a1", 1));
        // ThrowARock is roll 11 in BB2016 kickoff table
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 42);

        // Place both players on the pitch
        engine.game.field_model.set_player_coordinate("h1", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("h1", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("a1", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("a1", PlayerState::new(PS_STANDING));

        let _ = engine.apply_kickoff_event(11, false);

        // At least one player must be stunned
        let h1_stunned = engine.game.field_model.player_state("h1")
            .map(|s| s.base() == PS_STUNNED).unwrap_or(false);
        let a1_stunned = engine.game.field_model.player_state("a1")
            .map(|s| s.base() == PS_STUNNED).unwrap_or(false);
        assert!(h1_stunned || a1_stunned, "ThrowARock must stun at least one standing player");
    }

