        engine.game.home_first_offense = true;
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(14, 7));
        engine.game.field_model.ball_in_play = true;
        engine.game.field_model.set_player_coordinate("recv1", FieldCoordinate::new(16, 7));
