    #[test]
    fn riotous_rookies_event_emitted_at_kickoff() {
        // When a team has riotous_rookies > 0 and a kickoff happens, RiotousRookies event is emitted.
        use crate::legal_actions::TeamSide;
        let home = make_test_team("home");
        let mut away = make_test_team("away");
        away.riotous_rookies = 1; // away team has 1 riotous rookies inducement
        let kicker_id = "away_kicker";
        away.players.push(make_test_player(kicker_id, 10));
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 1);

        // Set up a minimal state for KickBall
        engine.game.turn_mode = TurnMode::Kickoff;
        engine.game.home_playing = false; // away kicks
        engine.game.home_first_offense = true;
        let kicker_coord = FieldCoordinate::new(5, 7);
        engine.game.field_model.set_player_state(kicker_id, PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate(kicker_id, kicker_coord);

        let target = FieldCoordinate::new(18, 7);
        let events = engine.apply(TeamSide::Away, Action::KickBall { coord: target }).unwrap();

        assert!(
            events.iter().any(|e| matches!(e, GameEvent::RiotousRookies { team_id, .. } if team_id == "away")),
            "RiotousRookies event must be emitted for away team that has riotous_rookies > 0"
        );
    }

