    #[test]
    fn riotous_rookies_player_count_is_positive() {
        // Roll is 2D6+1 (min 3), so player_count >= 1 for count=1.
        use crate::legal_actions::TeamSide;
        let home = make_test_team("home");
        let mut away = make_test_team("away");
        away.riotous_rookies = 1;
        let kicker_id = "away_kicker";
        away.players.push(make_test_player(kicker_id, 10));

        for seed in 0..10u64 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2016, seed);
            engine.game.turn_mode = TurnMode::Kickoff;
            engine.game.home_playing = false;
            engine.game.home_first_offense = true;
            let kicker_coord = FieldCoordinate::new(5, 7);
            engine.game.field_model.set_player_state(kicker_id, PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate(kicker_id, kicker_coord);

            let events = engine.apply(TeamSide::Away, Action::KickBall { coord: FieldCoordinate::new(18, 7) }).unwrap();

            let rookies_event = events.iter().find(|e| matches!(e, GameEvent::RiotousRookies { .. }));
            if let Some(GameEvent::RiotousRookies { player_count, .. }) = rookies_event {
                assert!(*player_count >= 3, "2D6+1 with count=1 should give >= 3 players, got {player_count}");
            }
        }
    }

    #[test]
    fn putrid_regurgitation_marks_skill_used_after_acceptance() {
        // After accepting PutridRegurgitation, the skill must be in used_skills.
        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_skill("att", 1, SkillId::PutridRegurgitation));
        let mut away = make_test_team("away");
        let mut def = make_test_player("def", 1);
        def.armour = 9; // high AV so no injury after vomit (keep it clean)
        away.players.push(def);
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_PRONE));
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("att".into(), PlayerAction::Block);

        engine.pending_putrid_regurgitation = Some(PendingPutridRegurgitation {
            attacker_id: "att".into(),
            defender_id: "def".into(),
            home_attacking: true,
        });
        engine.cached_prompt = Some(AgentPrompt::SkillUse {
            player_id: "att".into(),
            skill_id: SkillId::PutridRegurgitation as u16,
            skill_name: "Putrid Regurgitation".into(),
        });

        engine.apply(TeamSide::Home, Action::UseSkill {
            skill_id: SkillId::PutridRegurgitation,
            use_skill: true,
        }).unwrap();

        let used = engine.game.team_home.player("att")
            .map(|p| p.used_skills.contains(&SkillId::PutridRegurgitation))
            .unwrap_or(false);
        assert!(used, "PutridRegurgitation must be in used_skills after being accepted");
    }

