    fn make_test_player_with_skill(id: &str, nr: i32, skill: SkillId) -> ffb_model::model::player::Player {
        let mut p = make_test_player(id, nr);
        p.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(skill)];
        p
    }

    #[test]
    fn two_heads_limits_tackle_zone_penalty_to_one() {
        // Two Heads: effective TZs for dodge capped at 1. A player surrounded by 3 TZs
        // should roll against the same target as if they had only 1 TZ.
        let mut home = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.agility = 3; // BB2020: need 3+ base → 4+ with 1 TZ, 6+ with 3 TZ normally
        mover.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::TwoHeads)];
        home.players.push(mover);

        let mut away = make_test_team("away");
        // Three defenders to create TZs at destination (3, 7)
        for i in 1..=3 {
            let mut def = make_test_player(&format!("def{}", i), i + 10);
            away.players.push(def);
        }
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Place mover at (2,7), defenders adjacent to (3,7)
        engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(2, 7));
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def1", FieldCoordinate::new(4, 7));
        engine.game.field_model.set_player_state("def1", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def2", FieldCoordinate::new(3, 6));
        engine.game.field_model.set_player_state("def2", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def3", FieldCoordinate::new(4, 6));
        engine.game.field_model.set_player_state("def3", PlayerState::new(PS_STANDING));

        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // Attempt to move mover into the TZ zone — must emit a DodgeRoll
        let events = engine.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(3, 7)],
        }).unwrap();

        // Must emit a DodgeRoll (TZ present, effective_tzs ≥ 1)
        let dodge = events.iter().find_map(|e| {
            if let GameEvent::DodgeRoll { target, .. } = e { Some(*target) } else { None }
        });
        assert!(dodge.is_some(), "Two Heads dodge should still roll");
        // With Two Heads, min 1 TZ → target = 3 + 1 = 4 in BB2020 (not 3+3=6)
        assert_eq!(dodge.unwrap(), 4, "Two Heads limits to 1 TZ penalty: target should be 4");
    }

    #[test]
    fn break_tackle_reduces_dodge_target_for_strong_player() {
        // BB2020: Break Tackle uses (7-ST) instead of AG when ST-target < AG-target.
        // Player with ST=5 (7-5=2) and AG=4+ (target 4): Break Tackle gives 2+1TZ=3 vs normal 4+1TZ=5.
        let mut home = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.agility = 4;   // BB2020: base 4+ (target 4)
        mover.strength = 5;  // ST 5: 7-5=2, better than 4
        mover.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::BreakTackle)];
        home.players.push(mover);

        let mut away = make_test_team("away");
        let def = make_test_player("def1", 11);
        away.players.push(def);
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(2, 7));
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def1", FieldCoordinate::new(4, 7));
        engine.game.field_model.set_player_state("def1", PlayerState::new(PS_STANDING));

        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let events = engine.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(3, 7)],
        }).unwrap();

        let dodge_target = events.iter().find_map(|e| {
            if let GameEvent::DodgeRoll { target, .. } = e { Some(*target) } else { None }
        });
        assert!(dodge_target.is_some(), "should roll dodge");
        // Break Tackle: target = (7-5) + 1 TZ = 3, better than normal (4 + 1 = 5)
        assert_eq!(dodge_target.unwrap(), 3, "Break Tackle with ST 5 vs AG 4+ should give target 3");
    }

    #[test]
    fn horns_adds_one_strength_when_blitzing() {
        // Horns: attacker gets +1 ST when performing a Blitz action.
        // ST 2 vs ST 3 normally = -2 dice (defender picks). With Horns = ST 3 vs ST 3 = 1 die.
        let mut home = make_test_team("home");
        let mut att = make_test_player("att", 1);
        att.strength = 2;
        att.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Horns)];
        home.players.push(att);

        let mut away = make_test_team("away");
        let mut def = make_test_player("def", 2);
        def.strength = 3;
        away.players.push(def);

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("att".into(), PlayerAction::Blitz);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let events = engine.apply(TeamSide::Home, Action::Block {
            defender_id: "def".into(),
        }).unwrap();

        let block_roll = events.iter().find_map(|e| {
            if let GameEvent::BlockRoll { nr_of_dice, own_choice, .. } = e {
                Some((*nr_of_dice, *own_choice))
            } else { None }
        });
        assert!(block_roll.is_some(), "should have block roll");
        let (nr_dice, own_choice) = block_roll.unwrap();
        // ST 2+1(Horns) = 3 vs ST 3 → 1 die, attacker picks
        assert_eq!(nr_dice, 1, "Horns should equalise ST giving 1 die");
        assert!(own_choice, "attacker should pick when equal ST");
    }

