    #[test]
    fn dirty_player_increases_foul_armor_roll() {
        // Dirty Player: fouler gets +1 to armor roll. With high foul assist,
        // armor break should be more likely. We verify no error and the event fires.
        let mut home = make_test_team("home");
        let mut fouler = make_test_player("fouler", 1);
        fouler.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::DirtyPlayer)];
        home.players.push(fouler);

        let mut away = make_test_team("away");
        let mut target = make_test_player("target", 2);
        target.armour = 1; // AV 1 → always breaks armor even without modifier
        away.players.push(target);

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
        engine.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let result = engine.apply(TeamSide::Home, Action::Foul {
            target_id: "target".into(),
        });
        assert!(result.is_ok(), "Dirty Player foul must not error");
        let events = result.unwrap();
        assert!(events.iter().any(|e| matches!(e, GameEvent::Foul { .. })), "must emit Foul event");
        // Armor is AV 1 → always breaks: must emit injury
        assert!(events.iter().any(|e| matches!(e, GameEvent::Injury { .. })), "AV 1 target must suffer injury");
    }

