    #[test]
    fn tentacles_emits_escape_roll_when_player_moves_from_adjacent_square() {
        // Opponent with Tentacles adjacent to mover's start. Moving away must emit EscapeRoll.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut away = make_test_team("away");
        let tentacles_opp = make_test_player_with_skill("opp", 2, SkillId::Tentacles);
        away.players.push(tentacles_opp);

        // Use seed that gives high rolls (escape succeeds) so we can see the event
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 99);
        engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        // Tentacles opp adjacent to mover
        engine.game.field_model.set_player_coordinate("opp", FieldCoordinate::new(6, 7));
        engine.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // Move mover away from opp
        let events = engine.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(4, 7)],
        }).unwrap();

        assert!(
            events.iter().any(|e| matches!(e, GameEvent::EscapeRoll { player_id, .. } if player_id == "mover")),
            "EscapeRoll must be emitted when moving away from Tentacles opponent"
        );
    }

    #[test]
    fn tentacles_stops_movement_on_failed_escape() {
        // Seed 0 → low rolls → escape fails → mover stays at source.
        let mut home = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.strength = 1; // weak → hard to escape strong Tentacles
        home.players.push(mover);
        let mut away = make_test_team("away");
        let mut opp = make_test_player("opp", 2);
        opp.strength = 6; // very strong Tentacles
        opp.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Tentacles)];
        away.players.push(opp);

        // Seed 0 produces very low rolls
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 0);
        engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("opp", FieldCoordinate::new(6, 7));
        engine.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let events = engine.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(4, 7)],
        }).unwrap();

        let escape_event = events.iter().find(|e| matches!(e, GameEvent::EscapeRoll { .. }));
        if let Some(GameEvent::EscapeRoll { success: false, .. }) = escape_event {
            // If escape failed, mover must still be at source
            assert_eq!(
                engine.game.field_model.player_coordinate("mover"),
                Some(FieldCoordinate::new(5, 7)),
                "Mover must remain at source when Tentacles escape fails"
            );
        }
        // else escape succeeded → just check the event was emitted
    }

