    #[test]
    fn diving_tackle_increases_dodge_target() {
        // Opponent with DivingTackle at source. Dodge target should be +2 higher.
        // Compare two engines: one with DivingTackle opp, one without.
        let setup_engine = |with_dt: bool| {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("mover", 1);
            mover.agility = 3;
            home.players.push(mover);
            let mut away = make_test_team("away");
            // Tackle zone blocker at destination
            away.players.push(make_test_player("blocker", 2));
            if with_dt {
                let dt_opp = make_test_player_with_skill("dt_opp", 3, SkillId::DivingTackle);
                away.players.push(dt_opp);
            }
            let mut engine = GameEngine::new(home, away, Rules::Bb2016, 42);
            engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(5, 7));
            engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            // Blocker at dest creates TZ
            engine.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(7, 7));
            engine.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
            if with_dt {
                // DT opp adjacent to source
                engine.game.field_model.set_player_coordinate("dt_opp", FieldCoordinate::new(6, 7));
                engine.game.field_model.set_player_state("dt_opp", PlayerState::new(PS_STANDING));
            }
            engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            engine
        };

        let mut eng_no_dt = setup_engine(false);
        let events_no = eng_no_dt.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(6, 7)],
        }).unwrap();

        let mut eng_dt = setup_engine(true);
        let events_dt = eng_dt.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(6, 7)],
        }).unwrap();

        let target_no_dt = events_no.iter().find_map(|e| {
            if let GameEvent::DodgeRoll { target, .. } = e { Some(*target) } else { None }
        });
        let target_dt = events_dt.iter().find_map(|e| {
            if let GameEvent::DodgeRoll { target, .. } = e { Some(*target) } else { None }
        });

        if let (Some(t_no), Some(t_dt)) = (target_no_dt, target_dt) {
            assert_eq!(t_dt, t_no + 2, "DivingTackle should add +2 to dodge target");
        }
    }

