        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        // Place leader on pitch with TZ
        engine.game.field_model.set_player_coordinate("leader_p", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("leader_p", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.cached_prompt = Some(AgentPrompt::ActivatePlayer { eligible_players: vec![] });

        // Home team ends their turn
