    #[test]
    fn wrestle_defender_prompted_when_attacker_has_block_on_both_down() {
        // Scenario: attacker has Block (stays standing on BothDown), defender has Wrestle.
        // Engine should prompt defender for Wrestle use.
        // Skill flags are injected via PendingBlockChoice directly.
        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 42);
        // Place both players on the pitch adjacent to each other
        engine.game.field_model.set_player_coordinate("home_p1", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_coordinate("away_p1", FieldCoordinate::new(14, 7));
        engine.game.field_model.set_player_state("home_p1", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_state("away_p1", PlayerState::new(PS_STANDING));

        // Inject a BothDown result
        let ctx = PendingBlockChoice {
            attacker_id: "home_p1".into(),
            defender_id: "away_p1".into(),
            home_attacking: true,
            results: vec![BlockResult::BothDown],
            att_has_block: true,
            att_has_wrestle: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(13, 7),
            defender_coord: FieldCoordinate::new(14, 7),
            def_has_sidestep: false,
            def_has_wrestle: true,
        };
        let events = engine.resolve_block_result(BlockResult::BothDown, ctx).unwrap();
        // Should NOT have fallen yet; should be waiting for Wrestle prompt
        assert!(engine.pending_wrestle.is_some(), "should be waiting for Wrestle choice");
        let prompt = engine.current_prompt();
        assert!(
            matches!(prompt, Some(AgentPrompt::SkillUse { skill_id, .. }) if *skill_id == SkillId::Wrestle as u16),
            "should prompt for Wrestle use, got {:?}", prompt
        );
        // Prompt should be directed at the defender (has Wrestle)
        assert!(
            matches!(prompt, Some(AgentPrompt::SkillUse { player_id, .. }) if player_id == "away_p1"),
            "Wrestle prompt should target defender"
        );
        let _ = events;
    }

    #[test]
    fn wrestle_both_fall_when_defender_uses_it() {
        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 42);
        engine.game.field_model.set_player_coordinate("home_p1", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_coordinate("away_p1", FieldCoordinate::new(14, 7));
        engine.game.field_model.set_player_state("home_p1", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_state("away_p1", PlayerState::new(PS_STANDING));

        // Simulate: pending Wrestle offer to defender (asking_attacker = false)
        let ctx = PendingBlockChoice {
            attacker_id: "home_p1".into(),
            defender_id: "away_p1".into(),
            home_attacking: true,
            results: vec![BlockResult::BothDown],
            att_has_block: true,
            att_has_wrestle: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(13, 7),
            defender_coord: FieldCoordinate::new(14, 7),
            def_has_sidestep: false,
            def_has_wrestle: true,
        };
        engine.pending_wrestle = Some(PendingWrestle { ctx, asking_attacker: false });

        // Defender uses Wrestle → both fall
        let pw = engine.pending_wrestle.take().unwrap();
        let events = engine.resolve_wrestle(pw, true).unwrap();

        let attacker_state = engine.game.field_model.player_state("home_p1").unwrap();
        let defender_state = engine.game.field_model.player_state("away_p1").unwrap();
        assert_eq!(attacker_state.base(), PS_PRONE, "attacker should be prone after Wrestle");
        assert_eq!(defender_state.base(), PS_PRONE, "defender should be prone after Wrestle");
        assert!(events.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::Wrestle as u16)),
            "Wrestle SkillUse event should be emitted");
        assert!(events.iter().filter(|e| matches!(e, GameEvent::PlayerFellDown { .. })).count() == 2,
            "both players should have PlayerFellDown events");
    }

