    #[test]
    fn pro_reroll_emits_pro_roll_event_and_marks_used() {
        let mut home = make_test_team("home");
        let mut p = make_test_player("pro_p", 1);
        p.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Pro)];
        home.players.push(p);
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("pro_p", FieldCoordinate::new(7, 7));
        engine.game.field_model.set_player_state("pro_p", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("pro_p".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.turn_data_home.rerolls = 0; // no team reroll — only Pro

        // Inject Pro dodge pending reroll
        engine.pending_reroll = Some(PendingReroll::Dodge {
            player_id: "pro_p".into(),
            home_moving: true,
            origin_coord: FieldCoordinate::new(6, 7),
            dest: FieldCoordinate::new(7, 7),
            path_remaining: vec![],
            min_roll: 4,
            is_pro: true,
            is_consummate_professional: false,
        });

        let events = engine.apply(TeamSide::Home, Action::UseReRoll { use_reroll: true }).unwrap();

        // Must emit a ProRoll event
        assert!(
            events.iter().any(|e| matches!(e, GameEvent::ProRoll { player_id, .. } if player_id == "pro_p")),
            "Pro reroll must emit ProRoll event"
        );

        // Pro must be marked as used in player's used_skills
        let used = engine.game.team_home.player("pro_p").unwrap().used_skills.contains(&SkillId::Pro);
        assert!(used, "Pro skill must be marked used after Pro reroll");

        // Team reroll must NOT be consumed
        assert_eq!(engine.game.turn_data_home.rerolls, 0, "team rerolls unaffected by Pro reroll");
    }

