    #[test]
    fn always_hungry_fail_emits_escape_roll() {
        // Use a seed where d6 returns 1 for the AH roll (fail)
        // Find a seed that makes the first d6 roll be 1
        let mut home = make_test_team("home");
        let mut thrower = make_test_player("thrower", 1);
        thrower.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::AlwaysHungry)];
        home.players.push(thrower);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("thrown", 1));

        // Try seeds until we get AH fail (roll == 1)
        let mut found = false;
        for seed in 0u64..200 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("thrown", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("thrown", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("thrower".into(), PlayerAction::ThrowTeamMate);
            engine.game.home_playing = true;

            let events = engine.apply(TeamSide::Home, Action::ThrowTeamMate {
                player_id: "thrown".into(),
                coord: FieldCoordinate::new(20, 7),
            }).unwrap();

            let ah_event = events.iter().find_map(|e| match e {
                GameEvent::AlwaysHungry { success, .. } => Some(*success),
                _ => None,
            });
            if ah_event == Some(false) {
                // AH failed — must have EscapeRoll
                assert!(
                    events.iter().any(|e| matches!(e, GameEvent::EscapeRoll { player_id, .. } if player_id == "thrown")),
                    "AH fail must emit EscapeRoll for thrown player (seed {seed})"
                );
                found = true;
                break;
            }
        }
        assert!(found, "Could not find a seed where AlwaysHungry fails in first 200 seeds");
    }

    #[test]
    fn always_hungry_success_no_escape_roll() {
        let mut home = make_test_team("home");
        let mut thrower = make_test_player("thrower", 1);
        thrower.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::AlwaysHungry)];
        home.players.push(thrower);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("thrown", 1));

        // Find a seed where AH succeeds
        let mut found = false;
        for seed in 0u64..200 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("thrown", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("thrown", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("thrower".into(), PlayerAction::ThrowTeamMate);
            engine.game.home_playing = true;

            let events = engine.apply(TeamSide::Home, Action::ThrowTeamMate {
                player_id: "thrown".into(),
                coord: FieldCoordinate::new(20, 7),
            }).unwrap();

            let ah_success = events.iter().find_map(|e| match e {
                GameEvent::AlwaysHungry { success, .. } => Some(*success),
                _ => None,
            });
            if ah_success == Some(true) {
                assert!(
                    !events.iter().any(|e| matches!(e, GameEvent::EscapeRoll { .. })),
                    "AH success must NOT emit EscapeRoll (seed {seed})"
                );
                // Must emit RightStuffRoll (TTM proceeds)
                assert!(
                    events.iter().any(|e| matches!(e, GameEvent::RightStuffRoll { .. })),
                    "AH success must proceed to TTM (RightStuffRoll, seed {seed})"
                );
                found = true;
                break;
            }
        }
        assert!(found, "Could not find a seed where AlwaysHungry succeeds in first 200 seeds");
    }

