    #[test]
    fn juggernaut_when_blitzing_treats_both_down_as_block_for_attacker() {
        // Juggernaut + blitz: on BothDown, attacker keeps standing (acts like Block)
        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("home_p1", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_coordinate("away_p1", FieldCoordinate::new(14, 7));
        engine.game.field_model.set_player_state("home_p1", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_state("away_p1", PlayerState::new(PS_STANDING));

        // Juggernaut active means att_has_block = true via juggernaut_active
        let ctx = PendingBlockChoice {
            attacker_id: "home_p1".into(),
            defender_id: "away_p1".into(),
            home_attacking: true,
            results: vec![BlockResult::BothDown],
            att_has_block: true, // Juggernaut grants this when blitzing
            att_has_wrestle: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_juggernaut: true,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(13, 7),
            defender_coord: FieldCoordinate::new(14, 7),
            def_has_sidestep: false,
            def_has_wrestle: false,
        };
        let events = engine.resolve_block_result(BlockResult::BothDown, ctx).unwrap();

        // Attacker should NOT fall (Juggernaut = Block for BothDown)
        let att_state = engine.game.field_model.player_state("home_p1").unwrap();
        assert_ne!(att_state.base(), PS_PRONE, "Juggernaut blitz: attacker must not fall on BothDown");

        // Defender should fall
        let def_state = engine.game.field_model.player_state("away_p1").unwrap();
        assert_eq!(def_state.base(), PS_PRONE, "Juggernaut blitz: defender must fall on BothDown");
        let _ = events;
    }

