    #[test]
    fn leap_into_occupied_square_succeeds() {
        // Player with Leap skill enters a square occupied by an opponent; seed 3 → roll=3 ≥ 2 = success.
        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_skill("leaper", 1, SkillId::Leap));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("blocker", 1));
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 3);
        engine.game.field_model.set_player_coordinate("leaper", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("leaper", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));

        engine.game.acting_player.player_id = Some("leaper".into());
        let events = engine.apply_move("leaper", &[FieldCoordinate::new(11, 7)]).unwrap();

        let has_jump = events.iter().any(|e| matches!(e, GameEvent::JumpRoll { success: true, .. }));
        assert!(has_jump, "Leap success must emit JumpRoll with success=true");
        let moved = events.iter().any(|e| matches!(e, GameEvent::PlayerMoved { coord, .. } if coord.x == 11));
        assert!(moved, "Player must move to the leapt square");
    }

    #[test]
    fn leap_into_occupied_square_fails_player_goes_prone() {
        // Find a seed that produces a roll of exactly 1 (guaranteed fail for target=2).
        let mut fail_seed = None;
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player_with_skill("leaper", 1, SkillId::Leap));
            let mut away = make_test_team("away");
            away.players.push(make_test_player("blocker", 1));
            let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
            eng.game.field_model.set_player_coordinate("leaper", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("leaper", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(11, 7));
            eng.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
            eng.game.turn_data_home.rerolls = 0;
            eng.game.turn_data_home.reroll_used = true;
            eng.game.acting_player.player_id = Some("leaper".into());
            let evs = eng.apply_move("leaper", &[FieldCoordinate::new(11, 7)]).unwrap();
            if evs.iter().any(|e| matches!(e, GameEvent::JumpRoll { success: false, .. })) {
                fail_seed = Some(seed);
                break;
            }
        }
        let seed = fail_seed.expect("must find a seed producing a leap failure within 200 tries");

        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_skill("leaper", 1, SkillId::Leap));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("blocker", 1));
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, seed);
        engine.game.field_model.set_player_coordinate("leaper", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("leaper", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
        // Exhaust all rerolls so no reroll is offered after the failed leap.
        engine.game.turn_data_home.rerolls = 0;
        engine.game.turn_data_home.reroll_used = true;
        engine.game.acting_player.player_id = Some("leaper".into());
        let events = engine.apply_move("leaper", &[FieldCoordinate::new(11, 7)]).unwrap();

        let has_jump_fail = events.iter().any(|e| matches!(e, GameEvent::JumpRoll { success: false, .. }));
        assert!(has_jump_fail, "Failed leap must emit JumpRoll with success=false");
        let fell = events.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { .. }));
        assert!(fell, "Failed leap must make player fall prone");
        let has_injury = events.iter().any(|e| matches!(e, GameEvent::Injury { .. }));
        assert!(has_injury, "Failed leap must trigger armor/injury roll");
        let state = engine.game.field_model.player_state("leaper").unwrap();
        assert_ne!(state.base(), PS_STANDING, "Player must not be standing after failed leap");
    }

