    // ── Group 27: Decay, Regeneration ────────────────────────────────────────

    fn make_decay_engine(seed: u64) -> GameEngine {
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        home.players.push(make_test_player("attacker", 1));
        let mut away = make_test_team("away");
        let mut defender = make_test_player("defender", 1);
        defender.armour = 1; // Always breaks on any 2d6
        defender.extra_skills.push(SkillWithValue::new(SkillId::Decay));
        away.players.push(defender);
        let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
        // Place attacker at edge; defender one step further into crowd range
        eng.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(24, 7));
        eng.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(25, 7));
        eng.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
        eng.game.turn_data_home.rerolls = 0;
        eng.game.home_playing = true;
        eng
    }

    #[test]
    fn decay_turns_bh_into_cas() {
        // Defender with Decay at edge of pitch → crowd surf → armor always breaks (AV=1).
        // Any BH injury result (total 2-7) must become CAS due to Decay.
        // Scan seeds until we find one where the injury without Decay would be BH
        // but with Decay becomes CAS.
        let mut found = false;
        for seed in 0..500u64 {
            let mut eng = make_decay_engine(seed);
            let ctx = PendingBlockChoice {
                attacker_id: "attacker".into(),
                defender_id: "defender".into(),
                home_attacking: true,
                results: vec![BlockResult::Pow],
                att_has_block: false,
                att_has_wrestle: false,
                att_has_claws: false,
                att_has_mb: false,
                att_has_piling_on: false,
                att_has_grab: false,
                att_has_juggernaut: false,
                att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
                attacker_coord: FieldCoordinate::new(24, 7),
                defender_coord: FieldCoordinate::new(25, 7),
                def_has_sidestep: false,
                def_has_wrestle: false,
            };
            if let Ok(evs) = eng.resolve_block_result(BlockResult::Pow, ctx) {
                // Crowd surf path: injury emitted immediately (no PushTo needed)
                if let Some(GameEvent::Injury { was_cas, armor_roll: Some(_), injury_roll: Some(rolls), .. }) = evs.iter().find(|e| matches!(e, GameEvent::Injury { armor_roll: Some(_), .. })) {
                    // If was_cas=true and injury roll total < 8, Decay upgraded the result
                    let inj_total = rolls[0] + rolls[1];
                    if *was_cas && inj_total < 8 {
                        found = true;
                        break;
                    }
                }
            }
        }
        assert!(found, "Decay must upgrade BH (inj total < 8) to CAS in 500 seeds");
    }

    fn make_regen_engine(seed: u64) -> GameEngine {
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        home.players.push(make_test_player("attacker", 1));
        let mut away = make_test_team("away");
        let mut defender = make_test_player("defender", 1);
        defender.armour = 1; // Always breaks on any 2d6
        defender.extra_skills.push(SkillWithValue::new(SkillId::Regeneration));
        away.players.push(defender);
        let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
        eng.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(24, 7));
        eng.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(25, 7));
        eng.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
        eng.game.turn_data_home.rerolls = 0;
        eng.game.home_playing = true;
        eng
    }

    fn crowd_surf_ctx() -> PendingBlockChoice {
        PendingBlockChoice {
            attacker_id: "attacker".into(),
            defender_id: "defender".into(),
            home_attacking: true,
            results: vec![BlockResult::Pow],
            att_has_block: false,
            att_has_wrestle: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(24, 7),
            defender_coord: FieldCoordinate::new(25, 7),
            def_has_sidestep: false,
            def_has_wrestle: false,
        }
    }

    #[test]
    fn regeneration_can_recover_from_cas() {
        // Player with Regeneration: on a CAS result, roll 4+; success → player goes to Reserve.
        let mut found_seed = None;
        for seed in 0..500u64 {
            let mut eng = make_regen_engine(seed);
            if let Ok(evs) = eng.resolve_block_result(BlockResult::Pow, crowd_surf_ctx()) {
                let regen_ok = evs.iter().any(|e| matches!(e, GameEvent::RegenerationRoll { success: true, .. }));
                if regen_ok {
                    let state = eng.game.field_model.player_state("defender").unwrap_or(PlayerState::new(PS_STANDING));
                    if state.base() == PS_RESERVE {
                        found_seed = Some(seed);
                        break;
                    }
                }
            }
        }
        assert!(found_seed.is_some(), "Regeneration must be able to recover a CAS'd player to Reserve");
    }

    #[test]
    fn regeneration_roll_emitted_on_cas() {
        // RegenerationRoll event must be emitted when a Regeneration player is CAS'd.
        let mut found = false;
        for seed in 0..200u64 {
            let mut eng = make_regen_engine(seed);
            if let Ok(evs) = eng.resolve_block_result(BlockResult::Pow, crowd_surf_ctx()) {
                if evs.iter().any(|e| matches!(e, GameEvent::RegenerationRoll { .. })) {
                    found = true;
                    break;
                }
            }
        }
        assert!(found, "RegenerationRoll event must be emitted when Regeneration player is CAS'd");
    }

    // ── Group 28: Half-time reset and turn progression ────────────────────────

    #[test]
    fn half_time_resets_rerolls_and_advances_half() {
        // After both teams complete 8 turns, half resets and rerolls restore.
        // turn_nr starts at 1 (set at kickoff) and becomes 9 after 8 EndTurns.
        // Home did 8 turns (turn_nr=9). Away is on their 8th turn (turn_nr=8, about to become 9).
        let mut home = make_test_team("home");
        home.rerolls = 2;
        let mut away = make_test_team("away");
        away.rerolls = 3;
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.turn_data_home.turn_nr = 9; // home already done all 8 turns
        engine.game.turn_data_away.turn_nr = 8; // away on their 8th turn
        engine.game.turn_data_home.rerolls = 0;
        engine.game.turn_data_away.rerolls = 0;
        engine.game.half = 1;
        engine.game.home_first_offense = true;
        engine.game.home_playing = false; // away is ending their last turn
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.status = ffb_model::enums::GameStatus::Active;

        // Trigger end-turn to trip half-time logic
        let events = engine.apply(TeamSide::Away, Action::EndTurn).unwrap();

        assert_eq!(engine.game.half, 2, "Half must advance to 2 after first half ends");
        assert_eq!(engine.game.turn_data_home.turn_nr, 0, "Turn counter must reset for second half");
        assert_eq!(engine.game.turn_data_away.turn_nr, 0, "Turn counter must reset for second half");
        assert_eq!(engine.game.turn_data_home.rerolls, 2, "Home team rerolls must restore from team.rerolls");
        assert_eq!(engine.game.turn_data_away.rerolls, 3, "Away team rerolls must restore from team.rerolls");
        assert!(!events.is_empty(), "EndTurn at half-time must emit events");
    }

    #[test]
    fn game_ends_after_second_half_complete() {
        // After both teams complete all 16 turns (8+8), game must be Finished.
        // Away is ending their last turn (turn_nr=8→9); home already done (turn_nr=9).
        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.turn_data_home.turn_nr = 9;
        engine.game.turn_data_away.turn_nr = 8;
        engine.game.half = 2;
        engine.game.home_playing = false;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.status = ffb_model::enums::GameStatus::Active;

        let _events = engine.apply(TeamSide::Away, Action::EndTurn).unwrap();

        assert!(engine.game.is_finished(), "Game must be Finished after second half ends");
        assert!(matches!(engine.game.turn_mode, TurnMode::EndGame), "TurnMode must be EndGame at game end");
    }

