    // ── Group 33: injury path completeness ────────────────────────────────────

    #[test]
    fn ko_player_state_is_knocked_out() {
        // After a block that results in KO (injury total 8-9), player state = PS_KNOCKED_OUT.
        use ffb_model::model::skill_def::SkillWithValue;
        // Find a seed where crowd surf produces KO (not CAS)
        let mut found = false;
        for seed in 0..200u64 {
            let mut h = make_test_team("home");
            h.players.push(make_test_player("attacker", 1));
            let mut a = make_test_team("away");
            let mut d = make_test_player("defender", 1);
            d.armour = 1;
            a.players.push(d);
            let mut eng = GameEngine::new(h, a, Rules::Bb2016, seed);
            eng.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(24, 7));
            eng.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(25, 7));
            eng.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
            if let Ok(evs) = eng.resolve_block_result(BlockResult::Pow, crowd_surf_ctx()) {
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { was_ko: true, .. })) {
                    let state = eng.game.field_model.player_state("defender").unwrap_or(PlayerState::new(PS_STANDING));
                    assert_eq!(state.base(), PS_KNOCKED_OUT, "KO'd player must have PS_KNOCKED_OUT state");
                    found = true;
                    break;
                }
            }
        }
        assert!(found, "Must find a KO result in 200 seeds");
    }

    // ── Group 34: FoulAppearance and Chainsaw ────────────────────────────────

    #[test]
    fn foul_appearance_can_cancel_block() {
        // Defender with FoulAppearance; attacker must roll 2+. Find seed where it fails (roll=1).
        use ffb_model::model::skill_def::SkillWithValue;
        let mut found = false;
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player("attacker", 1));
            let mut away = make_test_team("away");
            let mut d = make_test_player("scary", 1);
            d.extra_skills.push(SkillWithValue::new(SkillId::FoulAppearance));
            away.players.push(d);
            let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
            eng.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_coordinate("scary", FieldCoordinate::new(14, 7));
            eng.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("scary", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("attacker".into(), PlayerAction::Block);
            eng.game.home_playing = true;
            if let Ok(evs) = eng.apply_block("attacker", "scary") {
                if evs.iter().any(|e| matches!(e, GameEvent::FoulAppearanceRoll { failed: true, .. })) {
                    // Block was cancelled — no BlockRoll event
                    assert!(!evs.iter().any(|e| matches!(e, GameEvent::BlockRoll { .. })),
                        "FoulAppearance fail must cancel the block (no BlockRoll)");
                    found = true;
                    break;
                }
            }
        }
        assert!(found, "FoulAppearance must be able to cancel a block in 200 seeds");
    }

