    #[test]
    fn chainsaw_backfire_injures_wielder() {
        // Chainsaw foul with die=1: wielder is injured, no foul against target.
        use ffb_model::model::skill_def::SkillWithValue;
        let mut found = false;
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            let mut fouler = make_test_player("fouler", 1);
            fouler.extra_skills.push(SkillWithValue::new(SkillId::Chainsaw));
            home.players.push(fouler);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("target", 1));
            let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
            eng.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(14, 7));
            eng.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
            eng.game.home_playing = true;
            if let Ok(evs) = eng.apply_foul("fouler", "target") {
                if let Some(GameEvent::ChainsawRoll { roll: 1, .. }) = evs.iter().find(|e| matches!(e, GameEvent::ChainsawRoll { .. })) {
                    // Backfire: fouler self-injury
                    assert!(evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, .. } if player_id == "fouler")),
                        "Chainsaw backfire must injure the wielder");
                    found = true;
                    break;
                }
            }
        }
        assert!(found, "Chainsaw must be able to backfire (roll=1) in 200 seeds");
    }

    #[test]
    fn chainsaw_success_injures_target_without_armor_roll() {
        // Chainsaw success: target is injured, no armor roll (armor_roll = None).
        use ffb_model::model::skill_def::SkillWithValue;
        let mut found = false;
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            let mut fouler = make_test_player("fouler", 1);
            fouler.extra_skills.push(SkillWithValue::new(SkillId::Chainsaw));
            home.players.push(fouler);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("target", 1));
            let mut eng = GameEngine::new(home, away, Rules::Bb2016, seed);
            eng.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(14, 7));
            eng.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
            eng.game.home_playing = true;
            if let Ok(evs) = eng.apply_foul("fouler", "target") {
                let saw_roll = evs.iter().find_map(|e| if let GameEvent::ChainsawRoll { roll, .. } = e { Some(*roll) } else { None });
                if let Some(r) = saw_roll {
                    if r >= 2 {
                        let target_injury = evs.iter().find(|e| matches!(e, GameEvent::Injury { player_id, armor_roll: None, .. } if player_id == "target"));
                        if target_injury.is_some() {
                            found = true;
                            break;
                        }
                    }
                }
            }
        }
        assert!(found, "Chainsaw success must injure target with no armor roll in 200 seeds");
    }

