    #[test]
    fn use_reroll_action_consumes_team_reroll() {
        // Apply a move that can fail pickup, offer reroll, accept it — reroll count decreases.
        for seed in 0..200u64 {
            let mut h = make_test_team("home");
            h.players.push(make_test_player("carrier", 1));
            let mut eng = GameEngine::new(h, make_test_team("away"), Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(11, 7));
            eng.game.field_model.ball_in_play = true;
            eng.game.acting_player.set_player("carrier".into(), PlayerAction::Move);
            eng.game.home_playing = true;
            let initial = eng.game.turn_data_home.rerolls;
            if let Ok(_) = eng.apply_move("carrier", &[FieldCoordinate::new(11, 7)]) {
                if matches!(eng.current_prompt(), Some(AgentPrompt::ReRollOffer { .. })) {
                    let side = crate::legal_actions::TeamSide::Home;
                    let _ = eng.apply(side, crate::action::Action::UseReRoll { use_reroll: true });
                    assert_eq!(eng.game.turn_data_home.rerolls, initial - 1);
                    return;
                }
            }
        }
    }

