    #[test]
    fn kick_skill_emits_skill_use_on_kickoff() {
        // Kicking team has a player with Kick — SkillUse event must be emitted.
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        let mut kicker = make_test_player("kicker", 1);
        kicker.extra_skills.push(SkillWithValue::new(SkillId::Kick));
        home.players.push(kicker);
        // Place kicker on pitch (kicking team = away when home_first_offense = true)
        // Actually: kicking team is !home_first_offense. Use home_first_offense=false (home kicks).
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.turn_mode = TurnMode::Kickoff;
        engine.game.home_first_offense = false; // home is kicking
        engine.game.home_playing = true;
        engine.game.field_model.set_player_coordinate("kicker", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("kicker", PlayerState::new(PS_STANDING));
        let evs = engine.apply(crate::legal_actions::TeamSide::Home,
            crate::action::Action::KickBall { coord: FieldCoordinate::new(19, 7) }).unwrap();
        assert!(evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. }
            if *skill_id == SkillId::Kick as u16)),
            "Kick skill must emit SkillUse event on kickoff");
    }

