    #[test]
    fn pass_block_eligible_event_emitted_when_opponent_has_skill() {
        // When opposing team has PassBlock, PassBlockEligible event fires on any non-fumble pass.
        use ffb_model::model::skill_def::SkillWithValue;
        let target = FieldCoordinate::new(15, 7);
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player("thrower", 1));
            let mut away = make_test_team("away");
            let mut blocker = make_test_player("blocker", 1);
            blocker.extra_skills.push(SkillWithValue::new(SkillId::PassBlock));
            away.players.push(blocker);
            let mut engine = GameEngine::new(home, away, Rules::Bb2016, seed);
            engine.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(10, 7));
            engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(20, 7));
            engine.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(10, 7));
            engine.game.field_model.ball_in_play = true;
            engine.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);
            engine.game.home_playing = true;
            engine.game.turn_data_home.rerolls = 0;
            // Use the full apply() path so compute_next_prompt() fires
            let evs = engine.apply(crate::legal_actions::TeamSide::Home,
                crate::action::Action::Pass { coord: target }).unwrap();
            if evs.iter().any(|e| matches!(e, GameEvent::PassBlockEligible { .. })) {
                assert!(matches!(engine.current_prompt(),
                    Some(AgentPrompt::PlayerChoice { reason, .. }) if reason == "passBlock"),
                    "Engine must prompt for PassBlock move");
                return;
            }
        }
        panic!("PassBlockEligible must be emitted on at least one non-fumble pass in 200 seeds");
    }

    #[test]
    fn pass_block_decline_resolves_pass() {
        // When agent declines PassBlock (empty player_id), pass resolves normally.
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        home.players.push(make_test_player("thrower", 1));
        let mut away = make_test_team("away");
        let mut blocker = make_test_player("blocker", 1);
        blocker.extra_skills.push(SkillWithValue::new(SkillId::PassBlock));
        away.players.push(blocker);
        let mut engine = GameEngine::new(home, away, Rules::Bb2016, 42);
        engine.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(20, 7));
        engine.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(10, 7));
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);
        engine.game.home_playing = true;
        engine.game.turn_data_home.rerolls = 0;
        let _ = engine.apply(crate::legal_actions::TeamSide::Home,
            crate::action::Action::Pass { coord: FieldCoordinate::new(15, 7) }).unwrap();
        // Decline pass block with empty player_id
        let side = crate::legal_actions::TeamSide::Away;
        let evs2 = engine.apply(side, crate::action::Action::SelectPlayer { player_id: String::new() }).unwrap();
        // Pass should now be resolved — ball should have a position
        assert!(engine.game.field_model.ball_coordinate.is_some());
        let _ = evs2; // pass resolved without panic
    }

