    #[test]
    fn prayers_to_nuffle_roll_in_1_to_16_range() {
        let mut home = make_test_team("home");
        home.prayers_to_nuffle = 3;
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 99);
        let events = engine.apply_prayers_to_nuffle_rolls();
        for e in &events {
            if let GameEvent::PrayerRoll { roll, .. } = e {
                assert!(*roll >= 1 && *roll <= 16, "Prayer roll must be 1-16, got {roll}");
            }
        }
        let prayer_events: Vec<_> = events.iter().filter(|e| matches!(e, GameEvent::PrayerRoll { .. })).collect();
        assert_eq!(prayer_events.len(), 3, "Should emit one PrayerRoll per prayer count");
    }

