    // ── Group 44: Block reroll ────────────────────────────────────────────────

    #[test]
    fn block_skull_offers_team_reroll_when_available() {
        // When a Skull is rolled and the attacker has a team reroll, the engine should offer it.
        // Scan seeds to find one that produces a Skull with no-choice (1 die scenario)
        let mut found_seed = None;
        for seed in 0u64..500 {
            let home = make_test_team("home");
            let away = make_test_team("away");
            let mut engine = GameEngine::new(home, away, Rules::Bb2020, seed);
            engine.game.turn_data_home.rerolls = 2;
            engine.game.turn_data_home.reroll_used = false;
            engine.game.field_model.set_player_coordinate("p1", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("p1", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("p2", FieldCoordinate::new(14, 7));
            engine.game.field_model.set_player_state("p2", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("p1".into(), PlayerAction::Block);
            engine.game.home_playing = true;
            // Add players to teams
            engine.game.team_home.players.push(make_test_player("p1", 1));
            engine.game.team_away.players.push(make_test_player("p2", 2));
            let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "p2".into() }).unwrap();
            // If the block result was a skull, a reroll should be offered
            let block_roll = evs.iter().find(|e| matches!(e, GameEvent::BlockRoll { .. }));
            if let Some(GameEvent::BlockRoll { dice, .. }) = block_roll {
                if dice.iter().any(|&d| d == 1) {
                    // Skull roll — check if reroll prompt is up
                    if matches!(engine.current_prompt(), Some(AgentPrompt::ReRollOffer { .. })) {
                        found_seed = Some(seed);
                        break;
                    }
                }
            }
        }
        assert!(found_seed.is_some(), "should find seed where Skull triggers ReRollOffer");
    }

    #[test]
    fn block_skull_accepted_reroll_retries_block() {
        // If the reroll is accepted, a new BlockRoll event with rerolled=true should appear.
        for seed in 0u64..500 {
            let home = make_test_team("home");
            let away = make_test_team("away");
            let mut engine = GameEngine::new(home, away, Rules::Bb2020, seed);
            engine.game.turn_data_home.rerolls = 2;
            engine.game.turn_data_home.reroll_used = false;
            engine.game.field_model.set_player_coordinate("p1", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("p1", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("p2", FieldCoordinate::new(14, 7));
            engine.game.field_model.set_player_state("p2", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("p1".into(), PlayerAction::Block);
            engine.game.home_playing = true;
            engine.game.team_home.players.push(make_test_player("p1", 1));
            engine.game.team_away.players.push(make_test_player("p2", 2));
            let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "p2".into() }).unwrap();
            let block_roll = evs.iter().find(|e| matches!(e, GameEvent::BlockRoll { .. }));
            if let Some(GameEvent::BlockRoll { dice, .. }) = block_roll {
                if dice.iter().any(|&d| d == 1) {
                    if matches!(engine.current_prompt(), Some(AgentPrompt::ReRollOffer { .. })) {
                        let evs2 = engine.apply(TeamSide::Home, Action::UseReRoll { use_reroll: true }).unwrap();
                        let rerolled = evs2.iter().any(|e| matches!(e, GameEvent::BlockRoll { rerolled: true, .. }));
                        assert!(rerolled, "accepted block reroll should emit BlockRoll with rerolled=true");
                        return;
                    }
                }
            }
        }
        // If we reach here, we didn't find a skull — that's technically possible but unusual
    }

    // ── Group 45: OnTheBall during kickoff ──────────────────────────────────

    #[test]
    fn on_the_ball_kickoff_emits_eligible_event() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Receiving team has an OnTheBall player — should see PassBlockEligible event after kickoff scatter.
        // Setup guarantees no touchback and no PI stun of receiver:
        //   - Kick from (19,7): any d8 direction with d6 1-6 stays within away's half and on-pitch.
        //   - away.fan_factor=20: total_away = 21-26 always beats total_home = 1-6, so PI never stuns away.
        //   - No home players on pitch: PI stun pool for home is empty, so no stun occurs.
        let mut home = make_test_team("home");
        home.fan_factor = 0;
        home.dedicated_fans = 0;
        let kicker = make_test_player("kicker", 1);
        home.players.push(kicker);

        let mut away = make_test_team("away");
        away.fan_factor = 20;
        away.dedicated_fans = 20;
        let mut receiver = make_test_player("receiver", 1);
        receiver.extra_skills.push(SkillWithValue::new(SkillId::OnTheBall));
        away.players.push(receiver);

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.home_first_offense = false; // away team receives
        engine.game.home_playing = true; // home kicks
        engine.game.turn_mode = TurnMode::Kickoff;
        // No home players on pitch so PI stun pool for home is empty
        engine.game.field_model.set_player_coordinate("receiver", FieldCoordinate::new(19, 7));
        engine.game.field_model.set_player_state("receiver", PlayerState::new(PS_STANDING));

        // Kick from (19,7): scatter in any direction stays in away's half and on-pitch — guaranteed no touchback
        let evs = engine.apply(TeamSide::Home, Action::KickBall {
            coord: FieldCoordinate::new(19, 7),
        }).unwrap();

        // Should emit PassBlockEligible for the OnTheBall player
        assert!(
            evs.iter().any(|e| matches!(e, GameEvent::PassBlockEligible { .. })),
            "OnTheBall player should trigger PassBlockEligible on kickoff"
        );
    }

