    #[test]
    fn fend_prevents_attacker_follow_up() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("att", 1));
        let mut away = make_test_team("away");
        let mut defender = make_test_player("def", 2);
        defender.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Fend)];
        away.players.push(defender);
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.turn_data_home.reroll_used = true;
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.pending_push = Some(PendingPush {
            attacker_id: "att".into(),
            defender_id: "def".into(),
            home_attacking: true,
            push_squares: vec![FieldCoordinate::new(14, 7)],
            do_armor: false,
            attacker_coord: FieldCoordinate::new(12, 7),
            def_has_stand_firm: false,
            def_has_fend: true,
        });
        engine.cached_prompt = Some(AgentPrompt::Pushback {
            attacker_id: "att".into(),
            defender_id: "def".into(),
            squares: vec![FieldCoordinate::new(14, 7)],
        });
        let evs = engine.apply(TeamSide::Home, Action::PushTo { coord: FieldCoordinate::new(14, 7) }).unwrap();
        // Fend should emit SkillUse and no follow-up prompt
        assert!(evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::Fend as u16)),
            "Fend must emit SkillUse event");
        assert!(!matches!(engine.current_prompt(), Some(AgentPrompt::FollowUp { .. })),
            "Fend should prevent follow-up prompt");
    }

