    #[test]
    fn sure_feet_auto_rerolls_failed_gfi() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Scan seeds to find one where first GFI roll = 1 (fail) but SureFeet reroll succeeds (≥2)
        let mut found_seed = None;
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut runner = make_test_player("runner", 1);
            runner.movement = 1;
            runner.extra_skills.push(SkillWithValue::new(SkillId::SureFeet));
            home.players.push(runner);
            let away = make_test_team("away");
            let mut engine = GameEngine::new(home, away, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("runner", FieldCoordinate::new(5, 7));
            engine.game.field_model.set_player_state("runner", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.acting_player.set_player("runner".into(), PlayerAction::Move);
            engine.game.acting_player.current_move = 1;
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            let evs = engine.apply(TeamSide::Home, Action::Move {
                path: vec![FieldCoordinate::new(6, 7)],
            }).unwrap();
            let rerolled_gfi = evs.iter().any(|e| matches!(e,
                GameEvent::GoForItRoll { rerolled: true, success: true, .. }
            ));
            if rerolled_gfi {
                found_seed = Some(seed);
                break;
            }
        }
        assert!(found_seed.is_some(), "should find a seed where SureFeet auto-rerolls a failed GFI successfully");
    }

    #[test]
    fn sure_feet_not_used_twice_in_same_turn() {
        use ffb_model::model::skill_def::SkillWithValue;
        // If SureFeet was already used, it should NOT fire again
        let mut home = make_test_team("home");
        let mut runner = make_test_player("runner", 1);
        runner.movement = 1;
        runner.extra_skills.push(SkillWithValue::new(SkillId::SureFeet));
        home.players.push(runner);
        let away = make_test_team("away");
        // Use a seed that would trigger GFI fail
        let mut found = false;
        for seed in 0u64..500 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("runner", FieldCoordinate::new(5, 7));
            engine.game.field_model.set_player_state("runner", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.acting_player.set_player("runner".into(), PlayerAction::Move);
            engine.game.acting_player.current_move = 1;
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            // Mark SureFeet as already used
            if let Some(p) = engine.game.team_home.player_mut("runner") {
                p.used_skills.insert(SkillId::SureFeet);
            }
            let evs = engine.apply(TeamSide::Home, Action::Move {
                path: vec![FieldCoordinate::new(6, 7)],
            }).unwrap();
            // If GFI failed (player fell), SureFeet should NOT have produced a rerolled=true event
            let had_rerolled_gfi = evs.iter().any(|e| matches!(e, GameEvent::GoForItRoll { rerolled: true, .. }));
            if evs.iter().any(|e| matches!(e, GameEvent::GoForItRoll { success: false, .. })) {
                assert!(!had_rerolled_gfi, "SureFeet used twice in same turn");
                found = true;
                break;
            }
        }
        assert!(found, "should find a seed with a failed GFI to verify SureFeet not reused");
    }



