    // ── Group 48: DivingCatch ─────────────────────────────────────────────────

    #[test]
    fn diving_catch_player_attempts_catch_on_adjacent_ball_land() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Scan seeds to find one where the DivingCatch roll succeeds
        let ball_land_coord = FieldCoordinate::new(7, 7);
        let dc_coord = FieldCoordinate::new(8, 7); // adjacent to ball landing square

        let mut found_caught = false;
        for seed in 0u64..200 {
            let mut home = make_test_team("home");
            let mut dc_player = make_test_player("dc", 1);
            dc_player.agility = 4; // target = 4+1=5, decent chance
            dc_player.starting_skills = vec![SkillWithValue::new(SkillId::DivingCatch)];
            home.players.push(dc_player);
            let away = make_test_team("away");

            let mut engine = GameEngine::new(home, away, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("dc", dc_coord);
            engine.game.field_model.set_player_state("dc", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(0, 0));
            engine.game.field_model.ball_in_play = true;

            let mut events = Vec::new();
            engine.resolve_ball_landing_test_hook(ball_land_coord, &mut events);

            let has_catch_roll = events.iter().any(|e| matches!(e, GameEvent::CatchRoll { player_id, .. } if player_id == "dc"));
            let has_skill_use = events.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, .. } if *skill_id == SkillId::DivingCatch as u16));

            assert!(has_catch_roll, "seed {seed}: DivingCatch player should attempt catch when ball lands adjacent");
            assert!(has_skill_use, "seed {seed}: DivingCatch SkillUse event should be emitted");

            if events.iter().any(|e| matches!(e, GameEvent::BallPickedUp { .. })) {
                found_caught = true;
                break;
            }
        }
        assert!(found_caught, "DivingCatch should succeed on some seed");
    }

    #[test]
    fn diving_catch_not_used_when_player_on_same_square() {
        use ffb_model::model::skill_def::SkillWithValue;
        let ball_land_coord = FieldCoordinate::new(7, 7);

        let mut home = make_test_team("home");
        // Normal player (no DivingCatch) at ball landing square
        let mut normal_player = make_test_player("normal", 1);
        normal_player.agility = 4;
        home.players.push(normal_player);
        // DivingCatch player adjacent
        let mut dc_player = make_test_player("dc", 2);
        dc_player.starting_skills = vec![SkillWithValue::new(SkillId::DivingCatch)];
        home.players.push(dc_player);
        let away = make_test_team("away");

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("normal", ball_land_coord);
        engine.game.field_model.set_player_state("normal", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("dc", FieldCoordinate::new(8, 7));
        engine.game.field_model.set_player_state("dc", PlayerState::new(PS_STANDING));

        let mut events = Vec::new();
        engine.resolve_ball_landing_test_hook(ball_land_coord, &mut events);

        // The player on the square gets the normal catch, NOT the DivingCatch player
        assert!(events.iter().any(|e| matches!(e, GameEvent::CatchRoll { player_id, .. } if player_id == "normal")),
            "normal player on landing square should catch, not DC player");
        assert!(!events.iter().any(|e| matches!(e, GameEvent::CatchRoll { player_id, .. } if player_id == "dc")),
            "DivingCatch player should not catch when ball lands on a player");
    }

