    // ── Group 50: NervesOfSteel ───────────────────────────────────────────────

    #[test]
    fn nerves_of_steel_suppresses_dp_on_pass() {
        use ffb_model::model::skill_def::SkillWithValue;
        let thrower_coord = FieldCoordinate::new(5, 7);
        let target_coord = FieldCoordinate::new(10, 7);
        let dp_coord = FieldCoordinate::new(7, 7); // within 3 of thrower

        let mut home = make_test_team("home");
        let mut thrower = make_test_player("thrower", 1);
        thrower.passing = 3;
        thrower.extra_skills.push(SkillWithValue::new(SkillId::NervesOfSteel));
        home.players.push(thrower);
        let mut away = make_test_team("away");
        let mut dp_player = make_test_player("dp", 2);
        dp_player.starting_skills = vec![SkillWithValue::new(SkillId::DisturbingPresence)];
        away.players.push(dp_player);

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("thrower", thrower_coord);
        engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("dp", dp_coord);
        engine.game.field_model.set_player_state("dp", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(thrower_coord);
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.turn_data_home.reroll_used = true;

        let evs = engine.apply(TeamSide::Home, Action::Pass { coord: target_coord }).unwrap();
        let pass_target = evs.iter().find_map(|e| match e {
            GameEvent::PassRoll { target, .. } => Some(*target),
            _ => None,
        });

        let dp_count = engine.count_disturbing_presence(thrower_coord, true);
        assert_eq!(dp_count, 1, "DP player within 3 squares should be counted");
        assert!(pass_target.is_some(), "should emit a pass roll");
        // NervesOfSteel: DP suppressed → target = pa(3) + dist_mod(1 for short pass) = 4, not 5
        // Without NOS: target = 3 + 1(dist) + 1(DP) = 5
        assert!(pass_target.unwrap() <= 4,
            "NervesOfSteel should suppress DP: target should be ≤4 (base+distance), got {}", pass_target.unwrap());
    }

