    // ── Group 51: BigHand ─────────────────────────────────────────────────────

    #[test]
    fn big_hand_suppresses_dp_on_pickup() {
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        let mut picker = make_test_player("picker", 1);
        picker.agility = 4;
        picker.extra_skills.push(SkillWithValue::new(SkillId::BigHand));
        home.players.push(picker);

        let mut away = make_test_team("away");
        let mut dp_player = make_test_player("dp", 2);
        dp_player.starting_skills = vec![SkillWithValue::new(SkillId::DisturbingPresence)];
        away.players.push(dp_player);

        let ball_coord = FieldCoordinate::new(6, 7);
        let picker_start = FieldCoordinate::new(5, 7);
        let dp_coord = FieldCoordinate::new(8, 7); // 2 squares away from ball — within 3

        // Find a seed where a d6 would fail without BigHand (roll ≤ ag=4, with dp target=5) but
        // succeed with BigHand (target = ag=4, no dp). Test by verifying the count_disturbing_presence
        // count is suppressed to zero effective modifier.
        let mut engine = GameEngine::new(
            make_team_with_big_hand("home", "picker", 4),
            make_team_with_dp("away", "dp"),
            Rules::Bb2020, 42,
        );
        engine.game.field_model.set_player_coordinate("picker", picker_start);
        engine.game.field_model.set_player_state("picker", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("dp", dp_coord);
        engine.game.field_model.set_player_state("dp", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(ball_coord);
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("picker".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.turn_data_home.reroll_used = true;

        // With BigHand, DP should not affect the pickup target
        // dp_count=1 normally, but BigHand suppresses it
        let dp_raw = engine.count_disturbing_presence(ball_coord, true);
        assert_eq!(dp_raw, 1, "DP player at distance 2 should count without suppression");
        // After move, verify the pickup_min used was ag=4 (not ag+1=5)
        let evs = engine.apply(TeamSide::Home, Action::Move { path: vec![ball_coord] }).unwrap();
        // If there's a CatchRoll/PickupRoll event, target should be ≤ ag(4), not ≥5
        if let Some(pickup_target) = evs.iter().find_map(|e| match e {
            GameEvent::CatchRoll { target, .. } => Some(*target),
            _ => None,
        }) {
            assert!(pickup_target <= 4,
                "BigHand should suppress DP, pickup target should be ≤4 (ag=4), got {pickup_target}");
        }
        // No panic and no engine error is also a valid outcome if ball was picked up successfully
    }

