    // ── Group 60: StandFirm ───────────────────────────────────────────────────

    #[test]
    fn stand_firm_prevents_defender_movement_on_pushback() {
        use ffb_model::model::skill_def::SkillWithValue;
        // StandFirm: on Pushback/Pow, defender can choose not to be pushed.
        // In BB2020, StandFirm lets the defender stay in their square instead of being pushed.
        let mut found_stand_firm_use = false;
        for seed in 0..100u64 {
            let mut home_t = make_test_team("home");
            let mut attacker = make_test_player("att", 1);
            attacker.strength = 3;
            home_t.players.push(attacker);

            let mut away_t = make_test_team("away");
            let mut defender = make_test_player("def", 2);
            defender.strength = 3;
            defender.armour = 10; // Very high AV so no injury
            defender.starting_skills = vec![SkillWithValue::new(SkillId::StandFirm)];
            away_t.players.push(defender);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            let att_coord = FieldCoordinate::new(5, 7);
            let def_coord = FieldCoordinate::new(6, 7);
            engine.game.field_model.set_player_coordinate("att", att_coord);
            engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("def", def_coord);
            engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap();
            let mut all_evs = evs;

            // Drain block choice
            while matches!(engine.current_prompt(), Some(AgentPrompt::BlockChoice { .. })) {
                let more = engine.apply(TeamSide::Home, Action::BlockChoice { die_index: 0 }).unwrap();
                all_evs.extend(more);
            }

            // Check if StandFirm SkillUse was offered
            if all_evs.iter().any(|e| matches!(
                e,
                GameEvent::SkillUse { skill_id, .. } if *skill_id == SkillId::StandFirm as u16
            )) || matches!(engine.current_prompt(), Some(AgentPrompt::SkillUse { .. })) {
                found_stand_firm_use = true;
                break;
            }
            // Also check that defender didn't move (if StandFirm auto-resolved)
            let def_pos_after = engine.game.field_model.player_coordinate("def");
            if def_pos_after == Some(def_coord) {
                // Defender stayed in place — StandFirm might have auto-applied
                found_stand_firm_use = true;
                break;
            }
        }
        assert!(found_stand_firm_use, "StandFirm should be used or defender should stay in place in 100 seeds");
    }

    // ── Group 61: Pass skill ──────────────────────────────────────────────────

    #[test]
    fn pass_skill_rerolls_failed_pass() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Pass skill: auto-reroll on failed pass result.
        // Use a passer with PA/AG=6 (always fails BB2020: target would be 6+) so first roll likely fails,
        // but then set up so many seeds that at least one exercises the reroll path.
        let mut found_reroll = false;
        for seed in 0..500u64 {
            let mut home_t = make_test_team("home");
            let mut passer = make_test_player("passer", 1);
            passer.passing = 6; // 6+ to pass — usually fails
            passer.agility = 3;
            passer.starting_skills = vec![SkillWithValue::new(SkillId::Pass)];
            home_t.players.push(passer);

            let mut away_t = make_test_team("away");
            let mut catcher = make_test_player("catcher", 2);
            catcher.agility = 6; // always catches
            away_t.players.push(catcher);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            let passer_coord = FieldCoordinate::new(5, 7);
            let catcher_coord = FieldCoordinate::new(7, 7);
            engine.game.field_model.set_player_coordinate("passer", passer_coord);
            engine.game.field_model.set_player_state("passer", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("catcher", catcher_coord);
            engine.game.field_model.set_player_state("catcher", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(passer_coord);
            engine.game.field_model.ball_in_play = true;
            engine.game.acting_player.set_player("passer".into(), PlayerAction::Pass);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let evs = engine.apply(TeamSide::Home, Action::Pass { coord: catcher_coord }).unwrap_or_default();

            // Look for a PassRoll event with rerolled=true
            if evs.iter().any(|e| matches!(e, GameEvent::PassRoll { rerolled: true, .. })) {
                found_reroll = true;
                break;
            }
            // Also check for SkillUse with Pass skill_id
            if evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, .. } if *skill_id == SkillId::Pass as u16)) {
                found_reroll = true;
                break;
            }
        }
        assert!(found_reroll, "Pass skill should trigger a reroll on failed pass in 500 seeds");
    }

    #[test]
    fn pass_skill_not_reused_in_same_turn() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Pass skill is once per turn. Pre-mark it as used and verify no reroll occurs.
        let mut found_no_reroll = false;
        for seed in 0..200u64 {
            let mut home_t = make_test_team("home");
            let mut passer = make_test_player("passer", 1);
            passer.passing = 6; // usually fails
            passer.agility = 3;
            passer.starting_skills = vec![SkillWithValue::new(SkillId::Pass)];
            home_t.players.push(passer);

            let mut away_t = make_test_team("away");
            let catcher = make_test_player("catcher", 2);
            away_t.players.push(catcher);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            // Mark Pass skill as already used
            if let Some(p) = engine.game.team_home.player_mut("passer") {
                p.used_skills.insert(SkillId::Pass);
            }

            let passer_coord = FieldCoordinate::new(5, 7);
            let catcher_coord = FieldCoordinate::new(7, 7);
            engine.game.field_model.set_player_coordinate("passer", passer_coord);
            engine.game.field_model.set_player_state("passer", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("catcher", catcher_coord);
            engine.game.field_model.set_player_state("catcher", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(passer_coord);
            engine.game.field_model.ball_in_play = true;
            engine.game.acting_player.set_player("passer".into(), PlayerAction::Pass);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let evs = engine.apply(TeamSide::Home, Action::Pass { coord: catcher_coord }).unwrap_or_default();

            // No PassRoll with rerolled=true should appear
            let has_reroll = evs.iter().any(|e| matches!(e, GameEvent::PassRoll { rerolled: true, .. }));
            if !has_reroll {
                found_no_reroll = true;
                break;
            }
        }
        assert!(found_no_reroll, "Pass skill already used should not trigger reroll");
    }

    // ── Group 62: Wrestle ─────────────────────────────────────────────────────

    #[test]
    fn wrestle_triggers_on_both_down_result() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Wrestle: on a BothDown block result, defender with Wrestle can make both fall.
        // Attacker must have Block (so they'd stay standing on BothDown) for defender Wrestle to be offered.
        let mut found_wrestle = false;
        for seed in 0..500u64 {
            let mut home_t = make_test_team("home");
            let mut attacker = make_test_player("att", 1);
            attacker.strength = 3;
            attacker.starting_skills = vec![SkillWithValue::new(SkillId::Block)]; // attacker stays on BothDown
            home_t.players.push(attacker);

            let mut away_t = make_test_team("away");
            let mut defender = make_test_player("def", 2);
            defender.strength = 3; // equal ST = 1 die, BothDown is common
            defender.armour = 10;
            defender.starting_skills = vec![SkillWithValue::new(SkillId::Wrestle)];
            away_t.players.push(defender);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            let att_coord = FieldCoordinate::new(5, 7);
            let def_coord = FieldCoordinate::new(6, 7);
            engine.game.field_model.set_player_coordinate("att", att_coord);
            engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("def", def_coord);
            engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
            let mut all_evs = evs;

            // Drain block choice
            while matches!(engine.current_prompt(), Some(AgentPrompt::BlockChoice { .. })) {
                let more = engine.apply(TeamSide::Home, Action::BlockChoice { die_index: 0 }).unwrap_or_default();
                all_evs.extend(more);
            }
            // If offered Wrestle (may be asked to attacker then defender), accept it
            // Attacker is Home, defender is Away
            for _ in 0..2 {
                if let Some(AgentPrompt::SkillUse { player_id: ref pid, skill_id, .. }) = engine.current_prompt() {
                    if *skill_id == SkillId::Wrestle as u16 {
                        let side = if pid == "att" { TeamSide::Home } else { TeamSide::Away };
                        let more = engine.apply(side, Action::UseSkill { skill_id: SkillId::Wrestle, use_skill: true }).unwrap_or_default();
                        all_evs.extend(more);
                    } else { break; }
                } else { break; }
            }

            if all_evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::Wrestle as u16)) {
                found_wrestle = true;
                break;
            }
        }
        assert!(found_wrestle, "Wrestle should be triggered on BothDown in 500 seeds");
    }

