    // ── Group 64: PrehensileTail ──────────────────────────────────────────────

    #[test]
    fn prehensile_tail_adds_dodge_when_leaving_adjacent_square() {
        use ffb_model::model::skill_def::SkillWithValue;
        // PrehensileTail: when leaving a square adjacent to an opponent with PrehensileTail,
        // the dodge target is increased by +1 even if the destination has no TZs.
        // Setup: mover leaves PT opponent's TZ but destination is clear.
        // Without PT: no dodge roll at all (no TZ at destination).
        // With PT: dodge roll IS triggered (prehensile_tail_mod = 1 forces a roll).
        let dest_coord = FieldCoordinate::new(4, 7);
        let mover_coord = FieldCoordinate::new(5, 7);
        let opp_coord = FieldCoordinate::new(6, 7);

        // Without PT: no DodgeRoll expected (dest has no TZ)
        let mut home_t = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.agility = 4;
        home_t.players.push(mover);
        let mut away_t = make_test_team("away");
        let opp = make_test_player("opp", 2);
        away_t.players.push(opp);
        let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("mover", mover_coord);
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("opp", opp_coord);
        engine.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        let evs_no_pt = engine.apply(TeamSide::Home, Action::Move { path: vec![dest_coord] }).unwrap_or_default();
        let has_dodge_no_pt = evs_no_pt.iter().any(|e| matches!(e, GameEvent::DodgeRoll { .. }));

        // With PT: DodgeRoll should be triggered
        let mut home_t2 = make_test_team("home");
        let mut mover2 = make_test_player("mover", 1);
        mover2.agility = 4;
        home_t2.players.push(mover2);
        let mut away_t2 = make_test_team("away");
        let mut opp_pt = make_test_player("opp", 2);
        opp_pt.starting_skills = vec![SkillWithValue::new(SkillId::PrehensileTail)];
        away_t2.players.push(opp_pt);
        let mut engine2 = GameEngine::new(home_t2, away_t2, Rules::Bb2020, 42);
        engine2.game.field_model.set_player_coordinate("mover", mover_coord);
        engine2.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine2.game.field_model.set_player_coordinate("opp", opp_coord);
        engine2.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
        engine2.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine2.game.home_playing = true;
        engine2.game.turn_mode = TurnMode::Regular;
        let evs_pt = engine2.apply(TeamSide::Home, Action::Move { path: vec![dest_coord] }).unwrap_or_default();
        let has_dodge_pt = evs_pt.iter().any(|e| matches!(e, GameEvent::DodgeRoll { .. }));

        assert!(!has_dodge_no_pt, "No PT: moving to clear destination should not require a dodge");
        assert!(has_dodge_pt, "PT: leaving adjacent PT opponent should trigger a dodge");
    }

    #[test]
    fn prehensile_tail_increases_dodge_target_when_also_in_tz() {
        use ffb_model::model::skill_def::SkillWithValue;
        // When moving into a destination that has 1 TZ AND source has a PT opponent,
        // the target should be higher than with just the 1 TZ.
        // Setup: dest adjacent to opp_close (1 TZ), source adjacent to opp_pt (has PT).
        let mover_coord = FieldCoordinate::new(5, 7);
        let opp_close_coord = FieldCoordinate::new(4, 7); // adjacent to dest (3,7)
        let opp_pt_coord = FieldCoordinate::new(6, 7);    // adjacent to source (5,7)
        let dest_coord = FieldCoordinate::new(3, 7);      // adjacent to opp_close

        let check_target = |with_pt: bool| -> Option<i32> {
            let mut home_t = make_test_team("home");
            let mut mover = make_test_player("mover", 1);
            mover.agility = 4;
            home_t.players.push(mover);
            let mut away_t = make_test_team("away");
            let opp_close = make_test_player("opp_close", 2);
            away_t.players.push(opp_close);
            if with_pt {
                let mut opp_pt = make_test_player("opp_pt", 3);
                opp_pt.starting_skills = vec![SkillWithValue::new(SkillId::PrehensileTail)];
                away_t.players.push(opp_pt);
            }
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, 42);
            engine.game.field_model.set_player_coordinate("mover", mover_coord);
            engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("opp_close", opp_close_coord);
            engine.game.field_model.set_player_state("opp_close", PlayerState::new(PS_STANDING));
            if with_pt {
                engine.game.field_model.set_player_coordinate("opp_pt", opp_pt_coord);
                engine.game.field_model.set_player_state("opp_pt", PlayerState::new(PS_STANDING));
            }
            engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            let evs = engine.apply(TeamSide::Home, Action::Move { path: vec![dest_coord] }).unwrap_or_default();
            evs.iter().find_map(|e| match e {
                GameEvent::DodgeRoll { target, .. } => Some(*target),
                _ => None,
            })
        };

        let target_no_pt = check_target(false);
        let target_with_pt = check_target(true);
        assert!(target_no_pt.is_some(), "Without PT: dodge should be triggered by destination TZ");
        assert!(target_with_pt.is_some(), "With PT: dodge should also be triggered");
        assert!(target_with_pt.unwrap() > target_no_pt.unwrap(),
            "PT should add +1 to dodge target: {} vs {}", target_with_pt.unwrap(), target_no_pt.unwrap());
    }

