    // ── Group 67: Disturbing Presence suppression skills ──────────────────────

    #[test]
    fn nerves_of_steel_suppresses_dp_on_catch_from_pass() {
        use ffb_model::model::skill_def::SkillWithValue;
        // NervesOfSteel: suppress DP modifier on catch roll.
        let mut found_suppressed = false;
        for seed in 0..200u64 {
            // Setup: catcher with NervesOfSteel, passer without it
            // Multiple DP opponents around catcher — NervesOfSteel should keep target normal
            let mut home_t = make_test_team("home");
            let mut passer = make_test_player("passer", 1);
            passer.passing = 2; // good passer
            home_t.players.push(passer);
            let mut catcher = make_test_player("catcher", 2);
            catcher.agility = 4;
            catcher.starting_skills = vec![SkillWithValue::new(SkillId::NervesOfSteel)];
            home_t.players.push(catcher);

            let mut away_t = make_test_team("away");
            let mut dp1 = make_test_player("dp1", 3);
            dp1.starting_skills = vec![SkillWithValue::new(SkillId::DisturbingPresence)];
            let mut dp2 = make_test_player("dp2", 4);
            dp2.starting_skills = vec![SkillWithValue::new(SkillId::DisturbingPresence)];
            away_t.players.push(dp1);
            away_t.players.push(dp2);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            let passer_coord = FieldCoordinate::new(3, 7);
            let catcher_coord = FieldCoordinate::new(8, 7);
            let dp1_coord = FieldCoordinate::new(8, 6);
            let dp2_coord = FieldCoordinate::new(8, 8);
            engine.game.field_model.set_player_coordinate("passer", passer_coord);
            engine.game.field_model.set_player_state("passer", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("catcher", catcher_coord);
            engine.game.field_model.set_player_state("catcher", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("dp1", dp1_coord);
            engine.game.field_model.set_player_state("dp1", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("dp2", dp2_coord);
            engine.game.field_model.set_player_state("dp2", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(passer_coord);
            engine.game.field_model.ball_in_play = true;
            engine.game.acting_player.set_player("passer".into(), PlayerAction::Pass);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            // Apply pass — resolve pass block offers if any
            let mut evs = engine.apply(TeamSide::Home, Action::Pass { coord: catcher_coord }).unwrap_or_default();
            while matches!(engine.current_prompt(), Some(AgentPrompt::PlayerChoice { .. })) {
                let more = engine.apply(TeamSide::Away, Action::SelectPlayer { player_id: String::new() }).unwrap_or_default();
                evs.extend(more);
            }

            // Find catch roll event; target should be ag=4 (no DP modifier due to NervesOfSteel)
            if let Some(catch_target) = evs.iter().find_map(|e| match e {
                GameEvent::CatchRoll { target, player_id, .. } if player_id == "catcher" => Some(*target),
                _ => None,
            }) {
                // ag=4 in BB2020, with 0 DP (NervesOfSteel) = target 4
                // without NervesOfSteel would be 4 + 2 = 6
                if catch_target <= 4 {
                    found_suppressed = true;
                    break;
                }
            }
        }
        assert!(found_suppressed, "NervesOfSteel should suppress DP on catch roll in 200 seeds");
    }

