    #[test]
    fn take_root_prevents_movement_on_failure() {
        use ffb_model::model::skill_def::SkillWithValue;
        // TakeRoot fail: player cannot move (apply_move returns empty).
        let mut found_rooted = false;
        for seed in 0..500u64 {
            let mut home_t = make_test_team("home");
            let mut p = make_test_player("rooted_p", 1);
            p.starting_skills = vec![SkillWithValue::new(SkillId::TakeRoot)];
            home_t.players.push(p);
            let away_t = make_test_team("away");

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2016, seed);
            let start_coord = FieldCoordinate::new(5, 7);
            engine.game.field_model.set_player_coordinate("rooted_p", start_coord);
            engine.game.field_model.set_player_state("rooted_p", PlayerState::new(PS_STANDING));
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            engine.game.turn_data_home.turn_nr = 1;

            let act_evs = engine.apply(TeamSide::Home, Action::ActivatePlayer {
                player_id: "rooted_p".into(),
                player_action: crate::action::PlayerActionChoice::Move,
            }).unwrap_or_default();

            let confused = act_evs.iter().any(|e| matches!(e, GameEvent::ConfusionRoll { confused: true, .. }));
            if confused {
                // Player should be rooted: movement blocked
                let move_evs = engine.apply(TeamSide::Home, Action::Move {
                    path: vec![FieldCoordinate::new(6, 7)],
                }).unwrap_or_default();
                let moved = engine.game.field_model.player_coordinate("rooted_p");
                if moved == Some(start_coord) {
                    found_rooted = true;
                    break;
                }
                let _ = move_evs;
            }
        }
        assert!(found_rooted, "TakeRoot fail should prevent movement in 500 seeds");
    }

