    // ── Group 70: Injury path complete ───────────────────────────────────────

    #[test]
    fn injury_from_block_can_produce_rip() {
        // A player that is killed (RIP) should be marked as seriously injured permanently.
        // Verify that an extremely high armor + injury roll combination can produce RIP.
        let mut found_rip = false;
        for seed in 0..2000u64 {
            let mut home_t = make_test_team("home");
            let mut att = make_test_player("att", 1);
            att.strength = 5;
            att.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::MightyBlow)];
            home_t.players.push(att);
            let mut away_t = make_test_team("away");
            let mut def = make_test_player("def", 2);
            def.strength = 2;
            def.armour = 1; // very low armor
            away_t.players.push(def);

            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            let att_coord = FieldCoordinate::new(5, 7);
            let def_coord = FieldCoordinate::new(6, 7);
            engine.game.field_model.set_player_coordinate("att", att_coord);
            engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.set_player_coordinate("def", def_coord);
            engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let mut all_evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
            while matches!(engine.current_prompt(), Some(AgentPrompt::BlockChoice { .. })) {
                let more = engine.apply(TeamSide::Home, Action::BlockChoice { die_index: 0 }).unwrap_or_default();
                all_evs.extend(more);
            }
            while matches!(engine.current_prompt(), Some(AgentPrompt::Pushback { .. })) {
                let squares = match engine.current_prompt() {
                    Some(AgentPrompt::Pushback { squares, .. }) => squares.clone(),
                    _ => vec![],
                };
                let sq = squares.first().copied().unwrap_or(FieldCoordinate::new(7, 7));
                let more = engine.apply(TeamSide::Home, Action::PushTo { coord: sq }).unwrap_or_default();
                all_evs.extend(more);
            }

            if all_evs.iter().any(|e| matches!(e, GameEvent::Injury { was_cas: true, .. })) {
                // Check defender is RIP or CAS
                let def_state = engine.game.field_model.player_state("def");
                if def_state.map(|s| s.base() == PS_RIP || s.base() == PS_SERIOUS_INJURY || s.base() == PS_BADLY_HURT).unwrap_or(false) {
                    found_rip = true;
                    break;
                }
            }
        }
        assert!(found_rip, "Should be able to produce a CAS result in 2000 seeds with MightyBlow + low AV");
    }

