    #[test]
    fn dump_off_declined_proceeds_with_block() {
        use ffb_model::model::skill_def::SkillWithValue;
        // If DumpOff is declined, the block should proceed normally.
        let mut home_t = make_test_team("home");
        let mut att = make_test_player("att", 1);
        att.strength = 5;
        home_t.players.push(att);

        let mut away_t = make_test_team("away");
        let mut bc = make_test_player("bc", 2);
        bc.starting_skills = vec![SkillWithValue::new(SkillId::DumpOff)];
        bc.armour = 1; // low armor so block results are visible
        away_t.players.push(bc);

        let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, 42);
        let att_coord = FieldCoordinate::new(5, 7);
        let bc_coord = FieldCoordinate::new(6, 7);
        engine.game.field_model.set_player_coordinate("att", att_coord);
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("bc", bc_coord);
        engine.game.field_model.set_player_state("bc", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(bc_coord);
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let _ = engine.apply(TeamSide::Home, Action::Block { defender_id: "bc".into() }).unwrap_or_default();

        // If DumpOff prompt is pending, decline it
        if matches!(engine.current_prompt(), Some(AgentPrompt::SkillUse { skill_id, .. }) if *skill_id == SkillId::DumpOff as u16) {
            let more = engine.apply(TeamSide::Away, Action::UseSkill { skill_id: SkillId::DumpOff, use_skill: false }).unwrap_or_default();
            // After declining, block should have resolved (either BlockRoll or a prompt for block choice)
            assert!(
                more.iter().any(|e| matches!(e, GameEvent::BlockRoll { .. }))
                || matches!(engine.current_prompt(), Some(AgentPrompt::BlockChoice { .. })),
                "After declining DumpOff, block should proceed"
            );
        }
    }

