    // ── Group 76: KickoffReturn (BB2020) ──────────────────────────────────────

    #[test]
    fn kickoff_return_prompt_offered_after_kickoff_when_eligible() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Set up engine mid-kickoff state: home team is receiving, away kicked.
        // A home player with KickoffReturn at x=10 (not LOS, no adj opp) should trigger the prompt.
        let mut home_t = make_test_team("home");
        let mut kr_player = make_test_player("kr_player", 1);
        kr_player.starting_skills = vec![SkillWithValue::new(SkillId::KickOffReturn)];
        home_t.players.push(kr_player);
        let away_t = make_test_team("away");
        let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, 42);

        // Simulate post-kickoff state: home is receiving, ball landed in home half
        engine.game.home_first_offense = true; // home receives
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(20, 7));
        engine.game.field_model.ball_in_play = true;
        engine.game.field_model.set_player_coordinate("kr_player", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("kr_player", PlayerState::new(PS_STANDING));
        // No adjacent opponents

        // Directly set the pending state as the engine would after a kick
        engine.pending_kickoff_return = Some(vec!["kr_player".into()]);
        engine.compute_next_prompt();

        let prompt = engine.current_prompt();
        assert!(matches!(prompt, Some(AgentPrompt::KickoffReturn { .. })),
            "KickoffReturn prompt must be offered when eligible player exists");
        if let Some(AgentPrompt::KickoffReturn { eligible_players }) = prompt {
            assert!(eligible_players.contains(&"kr_player".to_string()),
                "Eligible player must be listed in KickoffReturn prompt");
        }
    }

    #[test]
    fn kickoff_return_player_moves_toward_ball() {
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home_t = make_test_team("home");
        let mut kr_player = make_test_player("kr_player", 1);
        kr_player.starting_skills = vec![SkillWithValue::new(SkillId::KickOffReturn)];
        home_t.players.push(kr_player);
        let away_t = make_test_team("away");
        let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, 42);

        let player_start = FieldCoordinate::new(10, 7);
        let ball_pos = FieldCoordinate::new(13, 7);
        engine.game.field_model.ball_coordinate = Some(ball_pos);
        engine.game.field_model.ball_in_play = true;
        engine.game.field_model.set_player_coordinate("kr_player", player_start);
        engine.game.field_model.set_player_state("kr_player", PlayerState::new(PS_STANDING));
        engine.pending_kickoff_return = Some(vec!["kr_player".into()]);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let events = engine.apply(TeamSide::Home, Action::SelectPlayer { player_id: "kr_player".into() }).unwrap();

        // Player should have moved toward ball (x increased by up to 3)
        let new_coord = engine.game.field_model.player_coordinate("kr_player").unwrap();
        assert!(new_coord.x > player_start.x, "KickoffReturn player must move toward ball");
        assert!(new_coord.x <= player_start.x + 3, "KickoffReturn player must move at most 3 squares");
        assert!(events.iter().any(|e| matches!(e, GameEvent::PlayerMoved { player_id, .. } if player_id == "kr_player")),
            "KickoffReturn must emit PlayerMoved event");
        assert!(engine.pending_kickoff_return.is_none(), "pending_kickoff_return must be cleared after move");
    }

