    // ── Group 77: AnimalSavagery (BB2020) ─────────────────────────────────────

    #[test]
    fn animal_savagery_success_emits_event() {
        use ffb_model::model::skill_def::SkillWithValue;
        // On success (roll 4+), AnimalSavagery event is emitted with success=true.
        // We test this by brute-forcing seeds until one succeeds.
        let mut found_success = false;
        for seed in 0u64..200 {
            let mut home_t = make_test_team("home");
            let mut player = make_test_player("savage", 1);
            player.starting_skills = vec![SkillWithValue::new(SkillId::AnimalSavagery)];
            home_t.players.push(player);
            let away_t = make_test_team("away");
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("savage", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("savage", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("savage".into(), PlayerAction::Move);
            engine.game.home_playing = true;

            let evs = engine.check_negatrait("savage", PlayerAction::Move);
            if evs.iter().any(|e| matches!(e, GameEvent::AnimalSavagery { success: true, .. })) {
                found_success = true;
                break;
            }
        }
        assert!(found_success, "AnimalSavagery must sometimes succeed and emit success=true event");
    }

    #[test]
    fn animal_savagery_failure_emits_lashout_with_adjacent_opponent() {
        use ffb_model::model::skill_def::SkillWithValue;
        // On failure (roll 1-3 with bad conditions = moving), player lashes out.
        // Place an opponent adjacent to force lash-out, then verify AnimalSavagery event emitted.
        let mut found_failure = false;
        for seed in 0u64..500 {
            let mut home_t = make_test_team("home");
            let mut player = make_test_player("savage", 1);
            player.starting_skills = vec![SkillWithValue::new(SkillId::AnimalSavagery)];
            home_t.players.push(player);
            let mut away_t = make_test_team("away");
            let mut opp = make_test_player("opp", 1);
            opp.armour = 7;
            away_t.players.push(opp);
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("savage", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("savage", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("opp", FieldCoordinate::new(14, 7));
            engine.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("savage".into(), PlayerAction::Move);
            engine.game.home_playing = true;

            let evs = engine.check_negatrait("savage", PlayerAction::Move);
            if evs.iter().any(|e| matches!(e, GameEvent::AnimalSavagery { success: false, .. })) {
                // Failure: should have lashed out at adjacent opponent
                found_failure = true;
                // Also must have an Injury event for the opponent
                let has_injury = evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, .. } if player_id == "opp"));
                assert!(has_injury, "AnimalSavagery failure must produce Injury event for adjacent opponent");
                break;
            }
        }
        assert!(found_failure, "AnimalSavagery must sometimes fail (roll 1-3) when not blocking");
    }

    #[test]
    fn animal_savagery_failure_no_adjacent_ends_action() {
        use ffb_model::model::skill_def::SkillWithValue;
        // On failure with no adjacent players, action ends with player deactivated.
        let mut found_no_adj_failure = false;
        for seed in 0u64..500 {
            let mut home_t = make_test_team("home");
            let mut player = make_test_player("savage", 1);
            player.starting_skills = vec![SkillWithValue::new(SkillId::AnimalSavagery)];
            home_t.players.push(player);
            let away_t = make_test_team("away");
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("savage", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("savage", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("savage".into(), PlayerAction::Move);
            engine.game.home_playing = true;

            let evs = engine.check_negatrait("savage", PlayerAction::Move);
            if evs.iter().any(|e| matches!(e, GameEvent::AnimalSavagery { success: false, .. })) {
                found_no_adj_failure = true;
                // No adjacent players → no injury event, but action ended
                let has_injury = evs.iter().any(|e| matches!(e, GameEvent::Injury { .. }));
                assert!(!has_injury, "No adjacent players: AnimalSavagery failure must not produce Injury");
                break;
            }
        }
        assert!(found_no_adj_failure, "AnimalSavagery must sometimes fail when no adjacent players");
    }

    #[test]
    fn animal_savagery_good_conditions_uses_2plus_threshold() {
        use ffb_model::model::skill_def::SkillWithValue;
        // In good conditions (blocking), minimum roll is 2. A roll of 2 should succeed.
        // We verify the good-conditions path: when blocking, almost always succeeds.
        let mut successes = 0u32;
        let mut trials = 0u32;
        for seed in 0u64..100 {
            let mut home_t = make_test_team("home");
            let mut player = make_test_player("savage", 1);
            player.starting_skills = vec![SkillWithValue::new(SkillId::AnimalSavagery)];
            home_t.players.push(player);
            let away_t = make_test_team("away");
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("savage", FieldCoordinate::new(13, 7));
            engine.game.field_model.set_player_state("savage", PlayerState::new(PS_STANDING));
            engine.game.home_playing = true;
            trials += 1;
            let evs = engine.check_negatrait("savage", PlayerAction::Block);
            if evs.iter().any(|e| matches!(e, GameEvent::AnimalSavagery { success: true, .. })) {
                successes += 1;
            }
        }
        // 2+ means 5/6 ≈ 83% success; with 100 trials should get ≥ 70
        assert!(successes > 70, "Good conditions (Block) should succeed >70% of the time, got {successes}/{trials}");
    }

    // ── Group 78: SafeThrow (BB2016) ──────────────────────────────────────────

    #[test]
    fn safe_throw_emits_roll_when_interception_succeeds() {
        use ffb_model::model::skill_def::SkillWithValue;
        // SafeThrow: after a successful interception, thrower rolls 4+ to cancel it.
        // Set up a pass with an interceptor adjacent to the flight path, thrower has SafeThrow.
        // Verify that when interception succeeds, a SafeThrowRoll event is emitted.
        let mut found = false;
        for seed in 0u64..200 {
            let mut home_t = make_test_team("home");
            let mut passer = make_test_player("passer", 1);
            passer.agility = 4;
            passer.starting_skills = vec![SkillWithValue::new(SkillId::SafeThrow)];
            home_t.players.push(passer);
            let mut away_t = make_test_team("away");
            let mut interceptor = make_test_player("interceptor", 2);
            interceptor.agility = 4;
            away_t.players.push(interceptor);
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2016, seed);
            engine.game.field_model.set_player_coordinate("passer", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("passer", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("interceptor", FieldCoordinate::new(17, 7));
            engine.game.field_model.set_player_state("interceptor", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("passer".into(), PlayerAction::Pass);
            engine.game.home_playing = true;

            let target = FieldCoordinate::new(22, 7);
            let evs = engine.apply(TeamSide::Home, Action::Pass { coord: target }).unwrap_or_default();
            if evs.iter().any(|e| matches!(e, GameEvent::InterceptionRoll { success: true, .. }))
                && evs.iter().any(|e| matches!(e, GameEvent::SafeThrowRoll { .. })) {
                found = true;
                break;
            }
        }
        assert!(found, "SafeThrowRoll must be emitted when interception succeeds and thrower has SafeThrow");
    }

    #[test]
    fn safe_throw_not_emitted_without_skill() {
        // Without SafeThrow, no SafeThrowRoll event should be emitted even on successful interception.
        let mut interception_happened = false;
        let mut safe_throw_emitted = false;
        for seed in 0u64..200 {
            let mut home_t = make_test_team("home");
            let mut passer = make_test_player("passer", 1);
            passer.agility = 4;
            home_t.players.push(passer);
            let mut away_t = make_test_team("away");
            let mut interceptor = make_test_player("interceptor", 2);
            interceptor.agility = 4;
            away_t.players.push(interceptor);
            let mut engine = GameEngine::new(home_t, away_t, Rules::Bb2016, seed);
            engine.game.field_model.set_player_coordinate("passer", FieldCoordinate::new(12, 7));
            engine.game.field_model.set_player_state("passer", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("interceptor", FieldCoordinate::new(17, 7));
            engine.game.field_model.set_player_state("interceptor", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("passer".into(), PlayerAction::Pass);
            engine.game.home_playing = true;

            let target = FieldCoordinate::new(22, 7);
            let evs = engine.apply(TeamSide::Home, Action::Pass { coord: target }).unwrap_or_default();
            if evs.iter().any(|e| matches!(e, GameEvent::InterceptionRoll { success: true, .. })) {
                interception_happened = true;
                if evs.iter().any(|e| matches!(e, GameEvent::SafeThrowRoll { .. })) {
                    safe_throw_emitted = true;
                }
                break;
            }
        }
        if interception_happened {
            assert!(!safe_throw_emitted, "SafeThrowRoll must NOT be emitted without SafeThrow skill");
        }
        // If no interception happened in 200 seeds, the test is vacuously correct (interception is rare)
    }

