    // ── Group 89: ScatterPlayer (crowd surf) ──────────────────────────────────

    #[test]
    fn crowd_surf_emits_scatter_player_event() {
        // Place defender at edge of pitch so push goes into crowd
        let mut home = make_test_team("home");
        home.players.push(make_test_player("attacker", 1));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("defender", 1));

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Place defender at x=0 (leftmost column), attacker one step to the right
        engine.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(1, 7));
        engine.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(0, 7));
        engine.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        // All push squares from (0,7) going West are off-pitch → crowd surf
        let ctx = PendingBlockChoice {
            attacker_id: "attacker".into(),
            defender_id: "defender".into(),
            home_attacking: true,
            results: vec![BlockResult::Pow],
            att_has_block: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_wrestle: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
                att_has_woodland_fury: false,
                att_has_consummate_professional: false,
                att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(1, 7),
            defender_coord: FieldCoordinate::new(0, 7),
            def_has_sidestep: false,
            def_has_wrestle: false,
        };

        let mut events_gathered = Vec::new();
        for _ in 0..50 {
            let mut e2 = GameEngine::new(make_test_team("home"), make_test_team("away"), Rules::Bb2020, 42);
            e2.game.team_home.players.push(make_test_player("attacker", 1));
            e2.game.team_away.players.push(make_test_player("defender", 1));
            e2.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(1, 7));
            e2.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING));
            e2.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(0, 7));
            e2.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
            if let Ok(evs) = e2.resolve_block_result(BlockResult::Pow, ctx.clone()) {
                events_gathered.extend(evs);
                break;
            }
        }

        assert!(
            events_gathered.iter().any(|e| matches!(e, GameEvent::ScatterPlayer { player_id, .. } if player_id == "defender")),
            "crowd surf must emit ScatterPlayer event for the defender"
        );
    }

