        // When an agent declines PassBlock (sends empty player_id), emit PassBlock { player_id: None }
        let mut home = make_test_team("home");
        home.players.push(make_test_player("passer", 1));
        let mut away = make_test_team("away");
        let mut blocker = make_test_player("pb_player", 1);
        blocker.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::PassBlock)];
        away.players.push(blocker);

