    #[test]
    fn kickoff_cheering_fans_may_grant_reroll() {
        use ffb_model::enums::KickoffResult;
        // BB2020 roll 6 = CheeringFans
        let mut engine = make_kickoff_engine(Rules::Bb2020, 42);
        engine.game.team_home.fan_factor = 6;
        engine.game.team_away.fan_factor = 0;
        let home_rr_before = engine.game.turn_data_home.rerolls;
        let away_rr_before = engine.game.turn_data_away.rerolls;
        let (events, _) = engine.apply_kickoff_event(6, false);
        assert!(
            events.iter().any(|e| matches!(e, GameEvent::KickoffResultEvent { result }
                if *result == KickoffResult::CheeringFans)),
            "must emit KickoffResultEvent(CheeringFans)"
        );
        // With very high home fan_factor, home should get the reroll
        let total_new_rerolls = (engine.game.turn_data_home.rerolls - home_rr_before)
            + (engine.game.turn_data_away.rerolls - away_rr_before);
        assert!(total_new_rerolls <= 2, "CheeringFans grants at most 1 reroll per team");
    }

