    fn kickoff_oficiously_ref_ejects_one_player_per_team() {
        use ffb_model::enums::KickoffResult;
        // BB2020 roll 11 = OficiousRef — ejects one player from each team
        let mut home = make_test_team("home");
        home.players.push(make_test_player("h1", 1));
        home.players.push(make_test_player("h2", 2));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("a1", 1));
        away.players.push(make_test_player("a2", 2));

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("h1", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("h1", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("h2", FieldCoordinate::new(6, 7));
        engine.game.field_model.set_player_state("h2", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("a1", FieldCoordinate::new(18, 7));
        engine.game.field_model.set_player_state("a1", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("a2", FieldCoordinate::new(19, 7));
        engine.game.field_model.set_player_state("a2", PlayerState::new(PS_STANDING));

        let (events, _) = engine.apply_kickoff_event(11, false);
        assert!(
            events.iter().any(|e| matches!(e, GameEvent::KickoffResultEvent { result }
                if *result == KickoffResult::OficiousRef)),
            "must emit KickoffResultEvent(OficiousRef)"
        );
        let bans: Vec<_> = events.iter().filter(|e| matches!(e, GameEvent::SecretWeaponBan { .. })).collect();
        assert_eq!(bans.len(), 2, "OficiousRef must eject one player from each team (2 bans)");
    }

