    // ── Group 98: Bloodweiser Kegs + KO recovery ──────────────────────────────

    #[test]
    fn bloodweiser_kegs_improve_ko_recovery() {
        // Seed 42 gives d6 rolls. We use many kegs (value=3) to force recovery on any roll.
        let mut home = make_test_team("home");
        home.bloodweiser_kegs = 3; // adds 3 to every recovery roll → always ≥ 4
        home.players.push(make_test_player("ko_p", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        engine.game.field_model.set_player_coordinate("ko_p", FieldCoordinate::new(5, 5));
        engine.game.field_model.set_player_state("ko_p", PlayerState::new(PS_KNOCKED_OUT));

        engine.place_all_in_reserve();

        let state = engine.game.field_model.player_state("ko_p");
        assert_eq!(
            state.map(|s| s.base()),
            Some(PS_RESERVE),
            "With 3 kegs, any D6 roll must result in KO recovery to reserve"
        );
    }

    #[test]
    fn no_kegs_ko_player_may_stay_knocked_out() {
        // With seed 0 and no kegs the first d6 roll is 1, so recovery fails (1 < 4).
        let mut home = make_test_team("home");
        home.players.push(make_test_player("ko_p", 1));
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 0);

        engine.game.field_model.set_player_coordinate("ko_p", FieldCoordinate::new(5, 5));
        engine.game.field_model.set_player_state("ko_p", PlayerState::new(PS_KNOCKED_OUT));

        engine.place_all_in_reserve();

        let state = engine.game.field_model.player_state("ko_p");
        // Either recovered (PS_RESERVE) or still KO'd — just must not panic.
        // The real invariant is that the player is no longer on-pitch (no coordinate).
        assert!(
            engine.game.field_model.player_coordinate("ko_p").is_none(),
            "KO'd player must be removed from pitch after drive end regardless of recovery roll"
        );
        let base = state.map(|s| s.base()).unwrap_or(PS_RESERVE);
        assert!(
            base == PS_RESERVE || base == PS_KNOCKED_OUT,
            "Player must end up in RESERVE or KNOCKED_OUT, got {:?}", base
        );
    }

