    #[test]
    fn fireball_applies_decay_and_cas_correctly() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Fireball path: if armor breaks, injury is rolled with +1 mod.
        // With Decay and injury ≥ BH, should become CAS.
        let mut home = make_test_team("home");
        let mut fragile = make_test_player("fragile", 1);
        fragile.armour = 1; // always breaks armor
        fragile.starting_skills.push(SkillWithValue::new(SkillId::Decay));
        home.players.push(fragile);
        let away = make_test_team("away");

        let blast = FieldCoordinate::new(5, 5);
        // Find a seed where injury total is BH (not KO/CAS initially) so Decay upgrades it
        let mut found_cas = false;
        for seed in 0u64..200 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("fragile", blast);
            engine.game.field_model.set_player_state("fragile", PlayerState::new(PS_STANDING));
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;

            let events = engine.apply(TeamSide::Away, Action::WizardSpell {
                spell: crate::action::WizardSpellChoice::Fireball,
                coord: blast,
            }).unwrap();
            if events.iter().any(|e| matches!(e, GameEvent::Injury { player_id, was_cas: true, .. } if player_id == "fragile")) {
                found_cas = true;
                break;
            }
        }
        assert!(found_cas, "Fireball + Decay player must produce CAS in some seed");
    }

