    // ── Group 110: Defensive skill ────────────────────────────────────────────

    #[test]
    fn defensive_cancels_attacker_assist_adjacent_to_defender() {
        use ffb_model::model::skill_def::SkillWithValue;
        // Defensive: when the defender has Defensive, attacker's teammates adjacent to the
        // defender cannot assist the blocker (they'd normally be able to).
        let mut home = make_test_team("home");
        let attacker = make_test_player("att", 1); // strength 3
        let mut helper = make_test_player("helper", 2); // strength 3, would assist
        home.players.push(attacker);
        home.players.push(helper.clone());

        let mut away = make_test_team("away");
        let mut defender = make_test_player("def", 3); // strength 3
        defender.starting_skills.push(SkillWithValue::new(SkillId::Defensive));
        away.players.push(defender);

        let att_coord = FieldCoordinate::new(10, 7);
        let def_coord = FieldCoordinate::new(11, 7);
        // Helper is adjacent to the defender → Defensive should cancel their assist
        let helper_coord = FieldCoordinate::new(11, 8);

        let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("att", att_coord);
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def", def_coord);
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("helper", helper_coord);
        engine.game.field_model.set_player_state("helper", PlayerState::new(PS_STANDING));

        // With Defensive: helper is next to defender → helper cannot assist → att_assists = 0
        let att_assists_with_defensive = engine.count_block_assists(true, def_coord, "att", "def");
        assert_eq!(att_assists_with_defensive, 0,
            "Defensive must cancel assist from helper adjacent to defender");

        // Without Defensive: helper CAN assist (no counter-assist at helper's square)
        away.players[0].starting_skills.clear(); // remove Defensive
        let mut engine2 = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, 42);
        engine2.game.field_model.set_player_coordinate("att", att_coord);
        engine2.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
        engine2.game.field_model.set_player_coordinate("def", def_coord);
        engine2.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine2.game.field_model.set_player_coordinate("helper", helper_coord);
        engine2.game.field_model.set_player_state("helper", PlayerState::new(PS_STANDING));

        let att_assists_without_defensive = engine2.count_block_assists(true, def_coord, "att", "def");
        assert_eq!(att_assists_without_defensive, 1,
            "Without Defensive, helper adjacent to defender can assist");
    }

