    // ── Group 117: MightyBlow injury modifier ─────────────────────────────────

    #[test]
    fn mighty_blow_adds_one_to_injury_roll_as_well() {
        use ffb_model::model::skill_def::SkillWithValue;
        // MightyBlow should add +1 to both armor and injury roll.
        // Use av=1 (always breaks), equal ST so single die. Count KO/CAS rate.
        let mut home = make_test_team("home");
        let mut att = make_test_player("att", 1);
        att.strength = 3;
        att.starting_skills.push(SkillWithValue::new(SkillId::MightyBlow));
        home.players.push(att);

        let mut away = make_test_team("away");
        let mut def = make_test_player("def", 2);
        def.strength = 3;
        def.armour = 1; // always breaks
        away.players.push(def);

        let att_coord = FieldCoordinate::new(10, 7);
        let def_coord = FieldCoordinate::new(11, 7);

        let mut kas_with_mb = 0;
        let mut total_injuries = 0;
        for seed in 0u64..1000 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            engine.game.field_model.set_player_coordinate("att", att_coord);
            engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
            engine.game.field_model.set_player_coordinate("def", def_coord);
            engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("att".into(), PlayerAction::Block);

            // Single die (equal ST), auto-resolved. May be Pow, Pushback, BothDown, or Skull.
            let block_evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
            // If block needs push (Pow or PowPushback), auto-push to adjacent square
            if block_evs.iter().any(|e| matches!(e, GameEvent::BlockRoll { .. }))
                && engine.current_prompt().is_none()
            {
                // Auto-resolved block, check if pending push
                let push_evs = engine.apply(TeamSide::Home, Action::PushTo { coord: FieldCoordinate::new(12, 7) }).unwrap_or_default();
                if push_evs.iter().any(|e| matches!(e, GameEvent::Injury { .. })) {
                    total_injuries += 1;
                    if push_evs.iter().any(|e| matches!(e, GameEvent::Injury { was_cas: true, .. } | GameEvent::Injury { was_ko: true, .. })) {
                        kas_with_mb += 1;
                    }
                }
            }
        }
        // With MB +1 injury, expect elevated KO/CAS proportion vs injuries
        // avg 2d6+1 = 8 → KO at 8-9 is common. At least 20% of injuries should be KO/CAS.
        if total_injuries > 0 {
            let kas_rate = kas_with_mb as f64 / total_injuries as f64;
            assert!(kas_rate > 0.3, "MightyBlow +1 injury should give KO/CAS rate >30%, got {kas_rate:.2} ({kas_with_mb}/{total_injuries})");
        }
        // If no injuries in 1000 blocks (e.g., all BothDown/Skull), test is vacuous
    }

