    #[test]
    fn putrid_regurgitation_offered_after_block_knockdown() {
        // After a block knockdown (knocked_down=true in PendingFollowUp), if the attacker
        // has PutridRegurgitation, the engine should offer SkillUse prompt after FollowUp.
        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_skill("att", 1, SkillId::PutridRegurgitation));
        let mut away = make_test_team("away");
        let mut def = make_test_player("def", 1);
        away.players.push(def);
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_PRONE));

        // Inject a follow-up with knocked_down=true (Pow result)
        engine.pending_follow_up = Some(PendingFollowUp {
            attacker_id: "att".into(),
            attacker_from: FieldCoordinate::new(12, 7),
            attacker_to: FieldCoordinate::new(13, 7),
            defender_id: "def".into(),
            knocked_down: true,
        });
        engine.cached_prompt = Some(AgentPrompt::FollowUp {
            attacker_id: "att".into(),
            target_coord: FieldCoordinate::new(13, 7),
        });

        engine.apply(TeamSide::Home, Action::FollowUp { follow_up: false }).unwrap();

        assert!(
            matches!(engine.current_prompt(), Some(AgentPrompt::SkillUse { skill_id, .. })
                if *skill_id == SkillId::PutridRegurgitation as u16),
            "engine must offer PutridRegurgitation after block knockdown"
        );
    }

