        assert!(events.iter().any(|e| matches!(e, GameEvent::BreatheFireRoll { prone: true, .. })),
            "roll 4-5 must emit BreatheFireRoll with prone=true");
        assert!(events.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { .. })),
            "prone result must emit PlayerFellDown");
        // No Injury event (prone without armor roll)
