        let mut engine = GameEngine::new(home, away, Rules::Bb2020, seed);
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("att".into(), PlayerAction::BreatheFire);

        let events = engine.apply_breathe_fire("att", true, "def").unwrap();

