    // ── Group 125: MesmerisingDance skill ─────────────────────────────────────

    #[test]
    fn mesmerising_dance_rerolls_failed_gaze() {
        // MesmerisingDance: when HypnoticGaze fails, the skill triggers a reroll.
        // Find a seed where first gaze roll fails; with MesmerisingDance it should be rerolled.
        let mut found_seed = None;
        for seed in 0..500u64 {
            let mut home = make_test_team("home");
            let mut gazer = make_test_player("gazer", 1);
            gazer.agility = 2; // low AG = harder to succeed (need 2+ in BB2025)
            gazer.starting_skills = vec![
                ffb_model::model::skill_def::SkillWithValue::new(SkillId::HypnoticGaze),
                ffb_model::model::skill_def::SkillWithValue::new(SkillId::MesmerisingDance),
            ];
            home.players.push(gazer);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("target", 1));
            let mut eng = GameEngine::new(home, away, Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("gazer", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("gazer", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(11, 7));
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.acting_player.set_player("gazer".into(), PlayerAction::Gaze);
            let evs = eng.apply(TeamSide::Home, Action::HypnoticGaze { target_id: "target".into() }).unwrap();
            // Check if MesmerisingDance was used (2+ HypnoticGazeRoll events emitted)
            let gaze_rolls = evs.iter().filter(|e| matches!(e, GameEvent::HypnoticGazeRoll { .. })).count();
            if gaze_rolls >= 2 {
                found_seed = Some(seed);
                break;
            }
        }
        assert!(found_seed.is_some(),
            "MesmerisingDance must trigger a reroll on failed Gaze within 500 seeds");

        let seed = found_seed.unwrap();
        let mut home = make_test_team("home");
        let mut gazer = make_test_player("gazer", 1);
        gazer.agility = 2;
        gazer.starting_skills = vec![
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::HypnoticGaze),
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::MesmerisingDance),
        ];
        home.players.push(gazer);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("target", 1));
        let mut engine = GameEngine::new(home, away, Rules::Bb2025, seed);
        engine.game.field_model.set_player_coordinate("gazer", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("gazer", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("target", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state("target", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("gazer".into(), PlayerAction::Gaze);

        let events = engine.apply(TeamSide::Home, Action::HypnoticGaze { target_id: "target".into() }).unwrap();

        let gaze_rolls = events.iter().filter(|e| matches!(e, GameEvent::HypnoticGazeRoll { .. })).count();
        assert_eq!(gaze_rolls, 2, "MesmerisingDance must emit a second HypnoticGazeRoll on reroll");
        assert!(events.iter().any(|e| matches!(e, GameEvent::SkillUse { used: true, .. })),
            "MesmerisingDance use must emit a SkillUse event");
    }

