    #[test]
    fn pump_up_the_crowd_grants_reroll_on_block_cas() {
        // PumpUpTheCrowd: when attacker with this skill causes a CAS via block, team gets a reroll.
        // Use 200 seeds to find one that produces a CAS; verify reroll count increases.
        let mut found = false;
        for seed in 0..500u64 {
            let mut h = make_test_team("home");
            let mut a = make_test_player_with_skill("att", 1, SkillId::PumpUpTheCrowd);
            a.strength = 5;
            h.players.push(a);
            let mut aw = make_test_team("away");
            let mut d = make_test_player("def", 1);
            d.strength = 1;
            d.armour = 3; // very easy to break armor
            aw.players.push(d);
            let mut eng = GameEngine::new(h, aw, Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            let rerolls_before = eng.game.turn_data_home.rerolls;
            let push = PendingPush {
                attacker_id: "att".into(),
                defender_id: "def".into(),
                home_attacking: true,
                push_squares: vec![FieldCoordinate::new(14, 7)],
                do_armor: true,
                attacker_coord: FieldCoordinate::new(12, 7),
                def_has_stand_firm: false,
                def_has_fend: false,
            };
            let evs = eng.resolve_push(push, FieldCoordinate::new(14, 7)).unwrap();
            let was_cas = evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, was_cas, .. } if player_id == "def" && *was_cas));
            if was_cas {
                assert!(eng.game.turn_data_home.rerolls > rerolls_before,
                    "PumpUpTheCrowd: team rerolls must increase after block CAS (seed {})", seed);
                assert_eq!(eng.game.turn_data_home.rerolls_pump_up_the_crowd_one_drive, 1,
                    "PumpUpTheCrowd tracking counter must be set");
                found = true;
                break;
            }
        }
        assert!(found, "Could not find a CAS result in 500 seeds — adjust test setup");
    }

