    // ── Group 134: VeryLongLegs leap modifier ─────────────────────────────────

    #[test]
    fn very_long_legs_reduces_leap_target() {
        // VeryLongLegs: -1 modifier to leap/jump target. AG=3 → target (7-3)=4+ normally; with VLL → 3+.
        // Compare leap success rates over many seeds.
        let count_leap_success = |has_vll: bool| -> usize {
            let mut successes = 0;
            for seed in 0..200u64 {
                let mut home = make_test_team("home");
                let mut mover = if has_vll {
                    make_test_player_with_skill("mover", 1, SkillId::VeryLongLegs)
                } else {
                    make_test_player("mover", 1)
                };
                mover.agility = 3;
                mover.movement = 6;
                mover.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Leap));
                home.players.push(mover);
                let mut away = make_test_team("away");
                let blocker = make_test_player("blocker", 2);
                away.players.push(blocker);
                let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
                eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(8, 7));
                eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
                // blocker occupies the destination square
                eng.game.field_model.set_player_coordinate("blocker", FieldCoordinate::new(9, 7));
                eng.game.field_model.set_player_state("blocker", PlayerState::new(PS_STANDING));
                eng.game.home_playing = true;
                eng.game.turn_mode = TurnMode::Regular;
                eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
                let evs = eng.apply(TeamSide::Home, crate::action::Action::Move { path: vec![FieldCoordinate::new(9, 7)] });
                let Ok(evs) = evs else { continue };
                if evs.iter().any(|e| matches!(e, GameEvent::JumpRoll { success: true, .. })) {
                    successes += 1;
                }
            }
            successes
        };
        let success_no_vll = count_leap_success(false);
        let success_with_vll = count_leap_success(true);
        // VeryLongLegs lowers the target, so success rate should be higher or equal
        assert!(success_with_vll >= success_no_vll,
            "VeryLongLegs ({} successes) should make leap easier than without ({} successes)",
            success_with_vll, success_no_vll);
    }

