    #[test]
    fn no_ball_player_cannot_catch() {
        // A NoBall receiver on a hand-off automatically drops the ball.
        let mut home = make_test_team("home");
        let thrower = make_test_player("thrower", 1);
        let mut receiver = make_test_player_with_skill("receiver", 2, SkillId::NoBall);
        receiver.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::NoBall));
        home.players.push(thrower);
        home.players.push(receiver);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 0);
        let thrower_coord = FieldCoordinate::new(5, 7);
        let receiver_coord = FieldCoordinate::new(6, 7);
        eng.game.field_model.set_player_coordinate("thrower", thrower_coord);
        eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_coordinate("receiver", receiver_coord);
        eng.game.field_model.set_player_state("receiver", PlayerState::new(PS_STANDING));
        eng.game.field_model.ball_coordinate = Some(thrower_coord);
        eng.game.field_model.ball_in_play = true;
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.acting_player.set_player("thrower".into(), PlayerAction::HandOver);
        let evs = eng.apply(TeamSide::Home, crate::action::Action::HandOff { receiver_id: "receiver".into() }).unwrap();
        // The hand-off succeeds (thrower has no NoBall) but receiver has NoBall → scatter
        assert!(
            evs.iter().any(|e| matches!(e, GameEvent::BallScattered { .. })),
            "NoBall receiver must scatter the ball on catch"
        );
    }

