        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.acting_player.set_player("thrower".into(), PlayerAction::HandOver);
        let _ = eng.apply(TeamSide::Home, crate::action::Action::HandOff { receiver_id: "receiver".into() }).unwrap();
        // GiveAndGo: thrower should still be the acting player, not yet done
