    // ── Group 137: Bullseye skill ─────────────────────────────────────────────

    #[test]
    fn bullseye_accurate_ttm_lands_at_target() {
        // Bullseye + Accurate TTM throw → player lands at coord without scatter.
        // We run many seeds and count how often the thrown player ends at the target coord.
        let target = FieldCoordinate::new(15, 7);
        let mut at_target = 0usize;
        let mut not_at_target = 0usize;
        for seed in 0..200u64 {
            let mut home = make_test_team("home");
            let mut thrower = make_test_player_with_skill("thrower", 1, SkillId::Bullseye);
            thrower.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Bullseye));
            thrower.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::ThrowTeamMate));
            thrower.agility = 6; // high PA → will often roll Accurate
            thrower.passing = 2; // BB2020+ PA stat
            home.players.push(thrower);
            let mut thrown = make_test_player("thrown", 2);
            thrown.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::RightStuff));
            home.players.push(thrown);
            let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("thrown", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("thrown", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("thrower".into(), PlayerAction::ThrowTeamMate);
            let evs = eng.apply(TeamSide::Home, crate::action::Action::ThrowTeamMate {
                player_id: "thrown".into(),
                coord: target,
            });
            let Ok(evs) = evs else { continue };
            // Check for accurate throw
            let is_accurate = evs.iter().any(|e| matches!(e, GameEvent::ThrowTeamMateRoll { result, .. }
                if *result == ffb_model::enums::PassResult::Complete));
            if !is_accurate { continue }
            // On Bullseye accurate: player at target
            let final_coord = eng.game.field_model.player_coordinate("thrown");
            if final_coord == Some(target) {
                at_target += 1;
            } else {
                not_at_target += 1;
            }
        }
        assert!(at_target > 0, "At least some Bullseye accurate throws should land at target");
        assert_eq!(not_at_target, 0, "All Bullseye accurate throws must land at target, got {} not at target", not_at_target);
    }

