    // ── Group 138: LethalFlight skill ─────────────────────────────────────────

    #[test]
    fn lethal_flight_increases_injury_when_landing_on_opponent() {
        // LethalFlight: when a TTM player (with LethalFlight) lands on an opponent,
        // +1 to armor (and potentially injury) roll.
        // We compare how often armor breaks: LethalFlight vs not.
        let target = FieldCoordinate::new(15, 7);
        let count_armor_breaks = |has_lf: bool| -> usize {
            let mut breaks = 0;
            for seed in 0..300u64 {
                let mut home = make_test_team("home");
                let mut thrower = make_test_player("thrower", 1);
                thrower.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::ThrowTeamMate));
                thrower.agility = 6;
                thrower.passing = 2;
                home.players.push(thrower);
                let mut thrown = if has_lf {
                    let mut t = make_test_player_with_skill("thrown", 2, SkillId::LethalFlight);
                    t.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::LethalFlight));
                    t.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::RightStuff));
                    t
                } else {
                    let mut t = make_test_player("thrown", 2);
                    t.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::RightStuff));
                    t
                };
                thrown.agility = 3;
                home.players.push(thrown);
                let mut away = make_test_team("away");
                let mut defender = make_test_player("defender", 3);
                defender.armour = 10; // high AV so LethalFlight matters
                away.players.push(defender);
                let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
                eng.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(12, 7));
                eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
                eng.game.field_model.set_player_coordinate("thrown", FieldCoordinate::new(12, 7));
                eng.game.field_model.set_player_state("thrown", PlayerState::new(PS_STANDING));
                // Place defender at target square so collision occurs
                eng.game.field_model.set_player_coordinate("defender", target);
                eng.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
                eng.game.home_playing = true;
                eng.game.turn_mode = TurnMode::Regular;
                eng.game.acting_player.set_player("thrower".into(), PlayerAction::ThrowTeamMate);
                let evs = eng.apply(TeamSide::Home, crate::action::Action::ThrowTeamMate {
                    player_id: "thrown".into(),
                    coord: target,
                });
                let Ok(evs) = evs else { continue };
                // Count injury events with injury_roll (armor broken)
                let had_break = evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, injury_roll: Some(_), .. }
                    if player_id == "defender"));
                if had_break { breaks += 1; }
            }
            breaks
        };
        let breaks_no_lf = count_armor_breaks(false);
        let breaks_with_lf = count_armor_breaks(true);
        assert!(breaks_with_lf >= breaks_no_lf,
            "LethalFlight ({} breaks) should cause at least as many armor breaks as without ({} breaks)",
            breaks_with_lf, breaks_no_lf);
    }

