    // ── Group 141: IronHardSkin vs foul modifiers ─────────────────────────────

    #[test]
    fn iron_hard_skin_blocks_dirty_player_on_foul() {
        // IronHardSkin: Dirty Player +1 should NOT apply to foul armor roll.
        // Compare break rates: IronHardSkin target with DirtyPlayer fouler vs without.
        // With IronHardSkin, DirtyPlayer should NOT increase break rate.
        let count_breaks = |target_has_ihs: bool, fouler_has_dp: bool| -> usize {
            let mut breaks = 0;
            for seed in 0..300u64 {
                let mut home = make_test_team("home");
                let mut fouler = if fouler_has_dp {
                    let mut p = make_test_player_with_skill("fouler", 1, SkillId::DirtyPlayer);
                    p.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::DirtyPlayer));
                    p
                } else {
                    make_test_player("fouler", 1)
                };
                fouler.strength = 3;
                home.players.push(fouler);
                let mut away = make_test_team("away");
                let mut target = if target_has_ihs {
                    let mut p = make_test_player_with_skill("target", 2, SkillId::IronHardSkin);
                    p.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::IronHardSkin));
                    p
                } else {
                    make_test_player("target", 2)
                };
                target.armour = 9;
                away.players.push(target);
                let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
                let fouler_coord = FieldCoordinate::new(12, 7);
                let target_coord = FieldCoordinate::new(13, 7);
                eng.game.field_model.set_player_coordinate("fouler", fouler_coord);
                eng.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
                eng.game.field_model.set_player_coordinate("target", target_coord);
                eng.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
                eng.game.home_playing = true;
                eng.game.turn_mode = TurnMode::Regular;
                eng.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
                let evs = eng.apply(TeamSide::Home, crate::action::Action::Foul { target_id: "target".into() }).unwrap_or_default();
                let broke = evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, injury_roll: Some(_), .. } if player_id == "target"));
                if broke { breaks += 1; }
            }
            breaks
        };
        let ihs_no_dp = count_breaks(true, false);
        let ihs_with_dp = count_breaks(true, true);
        let no_ihs_with_dp = count_breaks(false, true);
        // IronHardSkin should make DirtyPlayer irrelevant
        assert!((ihs_with_dp as i32 - ihs_no_dp as i32).abs() <= 20,
            "IronHardSkin must block DirtyPlayer modifier: ihs+dp={} vs ihs_only={}",
            ihs_with_dp, ihs_no_dp);
        // Without IronHardSkin, DirtyPlayer should increase break rate
        assert!(no_ihs_with_dp > ihs_with_dp,
            "Without IronHardSkin, DirtyPlayer should break more (no_ihs+dp={} vs ihs+dp={})",
            no_ihs_with_dp, ihs_with_dp);
    }

