    #[test]
    fn hit_and_run_prompts_after_follow_up_when_safe_square_available() {
        use ffb_model::model::skill_def::SkillWithValue;
        // HitAndRun: after block + follow-up, attacker with HitAndRun is offered a HitAndRun prompt
        // if there is an adjacent empty square not in opponent TZ.
        let mut home = make_test_team("home");
        let mut att = make_test_player_with_skill("att", 1, SkillId::HitAndRun);
        att.starting_skills.push(SkillWithValue::new(SkillId::HitAndRun));
        att.strength = 5;
        home.players.push(att);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("def", 2));
        // Find a seed where block result = Pushback (no both-down, no skull)
        for seed in 0..300u64 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            let att_coord = FieldCoordinate::new(12, 7);
            let def_coord = FieldCoordinate::new(13, 7);
            eng.game.field_model.set_player_coordinate("att", att_coord);
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", def_coord);
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Block { defender_id: "def".into() });
            // If block choice prompt, pick first die
            if matches!(eng.current_prompt(), Some(AgentPrompt::BlockChoice { .. })) {
                let _ = eng.apply(TeamSide::Home, crate::action::Action::BlockChoice { die_index: 0 });
            }
            // If pushback prompt, push to adjacent square
            if matches!(eng.current_prompt(), Some(AgentPrompt::Pushback { .. })) {
                let _ = eng.apply(TeamSide::Home, crate::action::Action::PushTo { coord: FieldCoordinate::new(14, 7) });
            }
            // If follow-up, accept
            if matches!(eng.current_prompt(), Some(AgentPrompt::FollowUp { .. })) {
                let _ = eng.apply(TeamSide::Home, crate::action::Action::FollowUp { follow_up: false });
            }
            // Now check if HitAndRun prompt appears
            if matches!(eng.current_prompt(), Some(AgentPrompt::HitAndRun { .. })) {
                return; // success
            }
        }
        panic!("HitAndRun prompt should appear after block+follow-up with safe squares available");
    }

