    // ── Group 145: SteadyFooting skill ────────────────────────────────────────

    #[test]
    fn steady_footing_can_prevent_gfi_fall_on_6() {
        use ffb_model::model::skill_def::SkillWithValue;
        // SteadyFooting: player with skill sometimes avoids a failed GFI (roll 6 = saved).
        // Statistically over many seeds, the fall rate should be lower than without the skill.
        let count_falls = |has_sf: bool| -> usize {
            let mut falls = 0;
            for seed in 0..500u64 {
                let mut home = make_test_team("home");
                let mut mover = if has_sf {
                    let mut p = make_test_player_with_skill("mover", 1, SkillId::SteadyFooting);
                    p.starting_skills.push(SkillWithValue::new(SkillId::SteadyFooting));
                    p
                } else {
                    make_test_player("mover", 1)
                };
                mover.movement = 4; // MA4, need GFI for 5th step
                home.players.push(mover);
                let away = make_test_team("away");
                let mut eng = GameEngine::new(home, away, Rules::Bb2025, seed);
                eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(5, 7));
                eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
                eng.game.home_playing = true;
                eng.game.turn_mode = TurnMode::Regular;
                eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
                // Disable rerolls so GFI fails go straight to fall (no reroll offer)
                eng.game.turn_data_home.rerolls = 0;
                // Move 5 squares (last one = GFI)
                let path = vec![
                    FieldCoordinate::new(6, 7), FieldCoordinate::new(7, 7),
                    FieldCoordinate::new(8, 7), FieldCoordinate::new(9, 7),
                    FieldCoordinate::new(10, 7),
                ];
                let evs = eng.apply(TeamSide::Home, crate::action::Action::Move { path: path.clone() }).unwrap_or_default();
                if evs.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "mover")) {
                    falls += 1;
                }
            }
            falls
        };
        let falls_with_sf = count_falls(true);
        let falls_without_sf = count_falls(false);
        // SteadyFooting should reduce falls by roughly 1/6 (on 6)
        // With 500 seeds, a ~1/2 GFI fail rate would give ~250 falls without. With SF, ~250 * 5/6 ≈ 208.
        // So falls_with_sf should be meaningfully less than falls_without_sf
        assert!(falls_with_sf < falls_without_sf,
            "SteadyFooting must reduce GFI fall rate: sf={} vs no_sf={}", falls_with_sf, falls_without_sf);
    }

