    #[test]
    fn saboteur_prompts_skill_use_when_attacker_falls_on_skull() {
        // Saboteur: when attacker rolls Skull and falls, they may use Saboteur to try to
        // knock down the defender (4+). The engine should emit a SkillUse prompt.
        // We loop over seeds until the attacker rolls a Skull result.
        let mut home = make_test_team("home");
        let mut attacker = make_test_player_with_skill("att", 1, SkillId::Saboteur);
        attacker.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Saboteur));
        attacker.strength = 3;
        home.players.push(attacker);
        let mut away = make_test_team("away");
        let mut defender = make_test_player("def", 2);
        defender.strength = 3;
        away.players.push(defender);

        let mut found_prompt = false;
        for seed in 0..500u64 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(5, 7));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(6, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            // No rerolls so skull goes straight to resolution
            eng.game.turn_data_home.rerolls = 0;

            let evs = eng.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
            // If attacker fell (skull) and has Saboteur, expect a SkillUse prompt
            let attacker_fell = evs.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "att"));
            if attacker_fell {
                // Engine should now have a Saboteur SkillUse prompt
                if matches!(eng.current_prompt(), Some(AgentPrompt::SkillUse { skill_id, .. }) if *skill_id == SkillId::Saboteur as u16) {
                    found_prompt = true;
                    break;
                }
            }
        }
        assert!(found_prompt, "Saboteur must prompt for SkillUse when attacker falls on Skull");
    }

    #[test]
    fn saboteur_knocks_down_defender_on_success() {
        // Saboteur: when used and roll is 4+, defender (target) goes prone.
        let mut home = make_test_team("home");
        let mut attacker = make_test_player_with_skill("att", 1, SkillId::Saboteur);
        attacker.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Saboteur));
        attacker.strength = 3;
        home.players.push(attacker);
        let mut away = make_test_team("away");
        let mut defender = make_test_player("def", 2);
        defender.strength = 3;
        away.players.push(defender);

        let mut found_knockdown = false;
        for seed in 0..1000u64 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(5, 7));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(6, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            eng.game.turn_data_home.rerolls = 0;

            let evs = eng.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
            let attacker_fell = evs.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "att"));
            if attacker_fell && matches!(eng.current_prompt(), Some(AgentPrompt::SkillUse { skill_id, .. }) if *skill_id == SkillId::Saboteur as u16) {
                // Use Saboteur
                let sab_evs = eng.apply(TeamSide::Home, Action::UseSkill { skill_id: SkillId::Saboteur, use_skill: true }).unwrap_or_default();
                let defender_also_fell = sab_evs.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "def"));
                let skill_used = sab_evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used, .. } if *skill_id == SkillId::Saboteur as u16 && *used));
                if defender_also_fell && skill_used {
                    found_knockdown = true;
                    break;
                }
            }
        }
        assert!(found_knockdown, "Saboteur 4+ must knock down the defender and emit SkillUse");
    }

