    #[test]
    fn cloud_burster_emits_skill_use_on_long_pass_interception() {
        // CloudBurster: thrower with skill forces a second interception roll on Long Pass or longer.
        // Test: over many seeds, at least once the CloudBurster SkillUse event is emitted.
        let mut home = make_test_team("home");
        let mut thrower = make_test_player_with_skill("thrower", 1, SkillId::CloudBurster);
        thrower.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::CloudBurster));
        thrower.agility = 3;
        thrower.passing = 3;
        home.players.push(thrower);

        let mut away = make_test_team("away");
        let mut interceptor = make_test_player("inter", 2);
        interceptor.agility = 4; // better AG for more interceptions
        away.players.push(interceptor);

        let mut found = false;
        for seed in 0..500u64 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            // Place thrower at (5,7), interceptor at (12,7) — Long Pass range (7+ squares away)
            eng.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(5, 7));
            eng.game.field_model.set_player_coordinate("inter", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("inter", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);
            eng.game.turn_data_home.rerolls = 0;

            // Pass to a square far away (Long Pass distance)
            let target = FieldCoordinate::new(19, 7);
            let evs = eng.apply(TeamSide::Home, Action::Pass { coord: target }).unwrap_or_default();
            if evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used, .. }
                if *skill_id == SkillId::CloudBurster as u16 && *used))
            {
                found = true;
                break;
            }
        }
        assert!(found, "CloudBurster must emit SkillUse event on Long Pass interception");
    }

