    #[test]
    fn pick_me_up_success_stands_up_prone_player() {
        // On a roll of 5+, the selected prone teammate stands up.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut away = make_test_team("away");
        let mut pmu_player = make_test_player_with_skill("pmu", 3, SkillId::PickMeUp);
        pmu_player.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::PickMeUp));
        away.players.push(pmu_player);
        away.players.push(make_test_player("prone_mate", 4));

        let mut found_success = false;
        for seed in 0..200u64 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_coordinate("pmu", FieldCoordinate::new(14, 7));
            eng.game.field_model.set_player_coordinate("prone_mate", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("pmu", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_state("prone_mate", PlayerState::new(PS_PRONE));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            eng.game.turn_data_home.rerolls = 0;

            let _ = eng.apply(TeamSide::Home, Action::Move { path: vec![FieldCoordinate::new(11, 7)] }).unwrap();

            if !matches!(eng.current_prompt(), Some(AgentPrompt::PlayerChoice { reason, .. }) if reason == "pickMeUp") {
                continue;
            }

            let evs = eng.apply(TeamSide::Away, Action::SelectPlayer { player_id: "prone_mate".into() }).unwrap();
            let roll_event = evs.iter().find(|e| matches!(e, GameEvent::PickMeUpRoll { player_id, .. } if player_id == "prone_mate"));
            if let Some(GameEvent::PickMeUpRoll { success: true, .. }) = roll_event {
                // Verify player is now standing
                let state = eng.game.field_model.player_state("prone_mate").unwrap();
                assert!(state.is_standing(), "PickMeUp success: prone_mate must be standing");
                found_success = true;
                break;
            }
        }
        assert!(found_success, "PickMeUp success (5+) must occur in 200 seeds");
    }

    #[test]
    fn pick_me_up_decline_clears_prompt() {
        // Sending empty SelectPlayer declines PickMeUp and clears the prompt.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut away = make_test_team("away");
        let mut pmu_player = make_test_player_with_skill("pmu", 3, SkillId::PickMeUp);
        pmu_player.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::PickMeUp));
        away.players.push(pmu_player);
        away.players.push(make_test_player("prone_mate", 4));

        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 0);
        eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_coordinate("pmu", FieldCoordinate::new(14, 7));
        eng.game.field_model.set_player_coordinate("prone_mate", FieldCoordinate::new(13, 7));
        eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_state("pmu", PlayerState::new(PS_STANDING));
        eng.game.field_model.set_player_state("prone_mate", PlayerState::new(PS_PRONE));
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        eng.game.turn_data_home.rerolls = 0;

        let _ = eng.apply(TeamSide::Home, Action::Move { path: vec![FieldCoordinate::new(11, 7)] }).unwrap();
        assert!(matches!(eng.current_prompt(), Some(AgentPrompt::PlayerChoice { reason, .. }) if reason == "pickMeUp"));

        let _ = eng.apply(TeamSide::Away, Action::SelectPlayer { player_id: String::new() }).unwrap();
        assert!(!matches!(eng.current_prompt(), Some(AgentPrompt::PlayerChoice { reason, .. }) if reason == "pickMeUp"),
            "After declining PickMeUp, prompt must not be pickMeUp");
        // Player must still be prone
        let state = eng.game.field_model.player_state("prone_mate").unwrap();
        assert!(!state.is_standing(), "PickMeUp declined: prone_mate must remain prone");
    }

