    // ── Group 150b: LookIntoMyEyes ─────────────────────────────────────────

    #[test]
    fn look_into_my_eyes_rolls_and_steals_ball_on_success() {
        // Gazer has LookIntoMyEyes; gaze succeeds; target holds ball; roll 2+ → steal ball.
        let mut home = make_test_team("home");
        let mut gazer = make_test_player("gazer", 1);
        gazer.agility = 3;
        gazer.starting_skills = vec![
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::HypnoticGaze),
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::LookIntoMyEyes),
        ];
        home.players.push(gazer);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("carrier", 2));

        // Seed 10: HypnoticGaze target = AG3 (need 3+), then LookIntoMyEyes (2+)
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 10);
        eng.game.field_model.set_player_coordinate("gazer", FieldCoordinate::new(12, 7));
        eng.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(13, 7));
        eng.game.field_model.set_player_state("gazer", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
        eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(13, 7));
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.acting_player.set_player("gazer".into(), PlayerAction::Gaze);
        eng.game.turn_data_home.rerolls = 0;
        eng.game.turn_data_away.rerolls = 0;

        let events = eng.apply(TeamSide::Home, Action::HypnoticGaze { target_id: "carrier".into() }).unwrap();

        let has_gaze_roll = events.iter().any(|e| matches!(e, GameEvent::HypnoticGazeRoll { .. }));
        assert!(has_gaze_roll, "HypnoticGazeRoll must be emitted");

        let has_eyes_roll = events.iter().any(|e| matches!(e, GameEvent::LookIntoMyEyesRoll { .. }));
        // LookIntoMyEyes only rolls when gaze succeeds AND target has ball
        if let Some(GameEvent::HypnoticGazeRoll { success, .. }) = events.iter().find(|e| matches!(e, GameEvent::HypnoticGazeRoll { .. })) {
            if *success {
                assert!(has_eyes_roll, "LookIntoMyEyesRoll must be emitted when gaze succeeds and target has ball");
                if let Some(GameEvent::LookIntoMyEyesRoll { success: eye_ok, .. }) = events.iter().find(|e| matches!(e, GameEvent::LookIntoMyEyesRoll { .. })) {
                    if *eye_ok {
                        assert_eq!(eng.game.field_model.ball_coordinate, Some(FieldCoordinate::new(12, 7)),
                            "ball should move to gazer on LookIntoMyEyes success");
                    }
                }
            }
        }
    }

    #[test]
    fn look_into_my_eyes_not_triggered_when_target_has_no_ball() {
        // Gazer has LookIntoMyEyes; gaze succeeds; target has NO ball → no LookIntoMyEyes roll.
        let mut home = make_test_team("home");
        let mut gazer = make_test_player("gazer", 1);
        gazer.agility = 6; // near-certain gaze success
        gazer.starting_skills = vec![
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::HypnoticGaze),
            ffb_model::model::skill_def::SkillWithValue::new(SkillId::LookIntoMyEyes),
        ];
        home.players.push(gazer);
        let mut away = make_test_team("away");
        away.players.push(make_test_player("no_ball_opp", 2));

        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.field_model.set_player_coordinate("gazer", FieldCoordinate::new(12, 7));
        eng.game.field_model.set_player_coordinate("no_ball_opp", FieldCoordinate::new(13, 7));
        eng.game.field_model.set_player_state("gazer", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_state("no_ball_opp", PlayerState::new(PS_STANDING));
        // ball is elsewhere — target does NOT hold it
        eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(5, 5));
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.acting_player.set_player("gazer".into(), PlayerAction::Gaze);
        eng.game.turn_data_home.rerolls = 0;
        eng.game.turn_data_away.rerolls = 0;

        let events = eng.apply(TeamSide::Home, Action::HypnoticGaze { target_id: "no_ball_opp".into() }).unwrap();
        assert!(
            !events.iter().any(|e| matches!(e, GameEvent::LookIntoMyEyesRoll { .. })),
            "LookIntoMyEyesRoll must NOT be emitted when target does not hold the ball"
        );
    }

