    #[test]
    fn taunt_used_forces_attacker_to_follow_up() {
        // Defender uses Taunt → attacker automatically moves to defender's old square.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("att", 1));
        let mut away = make_test_team("away");
        let mut defender = make_test_player_with_skill("def", 2, SkillId::Taunt);
        defender.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Taunt));
        away.players.push(defender);

        let mut eng = GameEngine::new(home, away, Rules::Bb2025, 0);
        eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(14, 7)); // defender already pushed here

        // Inject pending taunt state
        eng.pending_taunt = Some(PendingTaunt {
            defender_id: "def".into(),
            defender_is_home: false,
            follow_up: PendingFollowUp {
                attacker_id: "att".into(),
                attacker_from: FieldCoordinate::new(12, 7),
                attacker_to: FieldCoordinate::new(13, 7), // defender's old square
                defender_id: "def".into(),
                knocked_down: false,
            },
        });

        let events = eng.apply(TeamSide::Away, Action::UseSkill { skill_id: SkillId::Taunt, use_skill: true }).unwrap();

        assert_eq!(
            eng.game.field_model.player_coordinate("att"),
            Some(FieldCoordinate::new(13, 7)),
            "attacker must be moved to defender's old square when Taunt is used"
        );
        assert!(
            events.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::Taunt as u16)),
            "SkillUse(Taunt, used=true) must be emitted"
        );
    }

