    // ── Group 152: ASneakyPair ────────────────────────────────────────────

    #[test]
    fn a_sneaky_pair_adds_armor_mod_when_partner_adjacent_to_target() {
        // Two players with ASneakyPair; one fouls the target while the partner is adjacent.
        // Over many seeds the pair should break armor at a higher rate than without the bonus.
        let mut home = make_test_team("home");
        let mut fouler = make_test_player("fouler", 1);
        fouler.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::ASneakyPair)];
        let mut partner = make_test_player("partner", 2);
        partner.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::ASneakyPair)];
        home.players.push(fouler);
        home.players.push(partner);

        let mut away = make_test_team("away");
        // High armor target so we can detect the +1 bonus
        let mut target = make_test_player("target", 3);
        target.armour = 11; // Very hard to break without a bonus
        away.players.push(target);

        let mut breaks_with_pair = 0u32;
        let mut breaks_without_pair = 0u32;

        for seed in 0u64..500 {
            // WITH partner adjacent (both with ASneakyPair adjacent to target)
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_coordinate("partner", FieldCoordinate::new(13, 6)); // adjacent to target
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("partner", PlayerState::new(PS_STANDING)); // has tackle zones
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
            eng.game.turn_data_home.rerolls = 0;
            eng.game.turn_data_away.rerolls = 0;
            if let Ok(evs) = eng.apply(TeamSide::Home, Action::Foul { target_id: "target".into() }) {
                // injury_roll: Some means armor was actually broken (injury_roll: None = armor held)
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { injury_roll: Some(_), .. })) {
                    breaks_with_pair += 1;
                }
            }

            // WITHOUT partner (partner is far away)
            let mut eng2 = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            eng2.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
            eng2.game.field_model.set_player_coordinate("partner", FieldCoordinate::new(1, 1)); // far away
            eng2.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
            eng2.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
            eng2.game.field_model.set_player_state("partner", PlayerState::new(PS_STANDING));
            eng2.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng2.game.home_playing = true;
            eng2.game.turn_mode = TurnMode::Regular;
            eng2.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
            eng2.game.turn_data_home.rerolls = 0;
            eng2.game.turn_data_away.rerolls = 0;
            if let Ok(evs) = eng2.apply(TeamSide::Home, Action::Foul { target_id: "target".into() }) {
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { injury_roll: Some(_), .. })) {
                    breaks_without_pair += 1;
                }
            }
        }

        assert!(
            breaks_with_pair > breaks_without_pair,
            "ASneakyPair should break armor more often when partner is adjacent ({} vs {})",
            breaks_with_pair, breaks_without_pair
        );
    }

    #[test]
    fn a_sneaky_pair_no_bonus_when_partner_not_adjacent() {
        // Only one player with ASneakyPair present — no partner bonus.
        let mut home = make_test_team("home");
        let mut fouler = make_test_player("fouler", 1);
        fouler.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::ASneakyPair)];
        home.players.push(fouler);
        home.players.push(make_test_player("other", 2)); // no ASneakyPair, far away

        let mut away = make_test_team("away");
        away.players.push(make_test_player("target", 3));

        // With no partner, behavior should match no-skill foul on the same seeds
        let mut breaks_lone_asp = 0u32;
        let mut breaks_no_skill = 0u32;

        for seed in 0u64..200 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("fouler", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_coordinate("other", FieldCoordinate::new(1, 1));
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("fouler", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_state("other", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("fouler".into(), PlayerAction::Foul);
            eng.game.turn_data_home.rerolls = 0;
            if let Ok(evs) = eng.apply(TeamSide::Home, Action::Foul { target_id: "target".into() }) {
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { injury_roll: Some(_), .. })) {
                    breaks_lone_asp += 1;
                }
            }

            // No skill baseline
            let mut home2 = make_test_team("home");
            home2.players.push(make_test_player("fouler2", 1));
            let mut eng2 = GameEngine::new(home2, away.clone(), Rules::Bb2025, seed);
            eng2.game.field_model.set_player_coordinate("fouler2", FieldCoordinate::new(12, 7));
            eng2.game.field_model.set_player_coordinate("target", FieldCoordinate::new(13, 7));
            eng2.game.field_model.set_player_state("fouler2", PlayerState::new(PS_STANDING).change_active(true));
            eng2.game.field_model.set_player_state("target", PlayerState::new(PS_PRONE));
            eng2.game.home_playing = true;
            eng2.game.turn_mode = TurnMode::Regular;
            eng2.game.acting_player.set_player("fouler2".into(), PlayerAction::Foul);
            eng2.game.turn_data_home.rerolls = 0;
            if let Ok(evs) = eng2.apply(TeamSide::Home, Action::Foul { target_id: "target".into() }) {
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { injury_roll: Some(_), .. })) {
                    breaks_no_skill += 1;
                }
            }
        }

        // Should be approximately equal (within statistical noise)
        let diff = (breaks_lone_asp as i32 - breaks_no_skill as i32).abs();
        assert!(diff <= 20, "Lone ASneakyPair should not significantly change armor break rate: {} vs {}", breaks_lone_asp, breaks_no_skill);
    }

