    #[test]
    fn then_i_started_blastin_success_applies_injury_to_target() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_skill("blaster", 1, SkillId::ThenIStartedBlastin));

        let mut away = make_test_team("away");
        let mut target = make_test_player("target", 2);
        target.armour = 2; // very low armor → always breaks
        away.players.push(target);

        let mut injured_count = 0u32;
        for seed in 0u64..100 {
            let mut eng = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("blaster", FieldCoordinate::new(6, 7));
            eng.game.field_model.set_player_coordinate("target", FieldCoordinate::new(14, 7));
            eng.game.field_model.set_player_state("blaster", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_state("target", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 0;
            eng.apply(TeamSide::Home, Action::ActivatePlayer {
                player_id: "blaster".into(),
                player_action: crate::action::PlayerActionChoice::Move,
            }).unwrap();
            // Select the target
            if let Ok(evs) = eng.apply(TeamSide::Home, Action::SelectPlayer { player_id: "target".into() }) {
                // 3+ on D6 succeeds; armor 2 always breaks; count injuries
                if evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, injury_roll: Some(_), .. } if player_id == "target")) {
                    injured_count += 1;
                }
            }
        }
        // 3+ succeeds ~66.7% of the time; over 100 seeds expect >30 injuries
        assert!(injured_count > 30, "Expected >30 target injuries over 100 seeds (got {})", injured_count);
    }

