        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.acting_player.set_player("griff".into(), PlayerAction::Block);
        // No team rerolls available
        engine.game.turn_data_home.rerolls = 0;

        // Inject a Skull result directly
        engine.pending_block_choice = Some(PendingBlockChoice {
            attacker_id: "griff".into(),
            defender_id: "def".into(),
            home_attacking: true,
            results: vec![BlockResult::Skull],
            att_has_block: false,
            att_has_claws: false,
            att_has_mb: false,
            att_has_piling_on: false,
            att_has_grab: false,
            att_has_wrestle: false,
            att_has_juggernaut: false,
            att_has_strip_ball: false,
            att_has_brawler: false,
            att_has_hatred: false,
            att_has_woodland_fury: false,
            att_has_consummate_professional: true,
            att_has_working_in_tandem_block: false,
            is_blitz: false,
            attacker_coord: FieldCoordinate::new(12, 7),
            defender_coord: FieldCoordinate::new(13, 7),
            def_has_sidestep: false,
            def_has_wrestle: false,
        });
