        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("griff", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("griff", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
