    // ── Group 156: TwoForOne (BB2020, Grak & Crumbleberry) ───────────────────

    #[test]
    fn two_for_one_loner_normal_threshold_when_partner_healthy() {
        // With partner healthy, Loner is 4+ (standard)
        let mut home = make_test_team("home");
        let mut grak = make_test_player("grak", 1);
        grak.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Loner));
        grak.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::TwoForOne));
        home.players.push(grak);
        let mut crumble = make_test_player("crumble", 2);
        crumble.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::TwoForOne));
        home.players.push(crumble);

        let mut away = make_test_team("away");
        away.players.push(make_test_player("def", 3));

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("grak", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("grak", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("crumble", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("crumble", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_data_home.rerolls = 10; // plenty of rerolls

        // Simulate loner check by injecting a pending reroll for Grak
        let mut loner_rolls = Vec::new();
        for seed in 0..30 {
            let mut eng = GameEngine::new(
                engine.game.team_home.clone(),
                engine.game.team_away.clone(),
                Rules::Bb2020, seed,
            );
            eng.game.field_model = engine.game.field_model.clone();
            eng.game.turn_data_home.rerolls = 1;
            let mut evts = Vec::new();
            let success = eng.check_loner_reroll("grak", true, &mut evts);
            if let Some(GameEvent::LonerRoll { roll, .. }) = evts.iter().find(|e| matches!(e, GameEvent::LonerRoll { .. })) {
                loner_rolls.push((*roll, success));
            }
        }
        // Verify: roll 1-3 fails, roll 4-6 succeeds (standard 4+ threshold)
        for (roll, success) in &loner_rolls {
            if *roll < 4 {
                assert!(!success, "Loner should fail on roll {} when partner healthy", roll);
            } else {
                assert!(success, "Loner should succeed on roll {} when partner healthy", roll);
            }
        }
    }

    #[test]
    fn two_for_one_loner_reduced_threshold_when_partner_ko() {
        // With partner KO'd, Loner becomes 2+ (rolls 1 fail, 2+ succeed)
        let mut home = make_test_team("home");
        let mut grak = make_test_player("grak", 1);
        grak.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Loner));
        grak.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::TwoForOne));
        home.players.push(grak);
        let mut crumble = make_test_player("crumble", 2);
        crumble.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::TwoForOne));
        home.players.push(crumble);

        let mut away = make_test_team("away");
        away.players.push(make_test_player("def", 3));

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("grak", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("grak", PlayerState::new(PS_STANDING));
        // Crumbleberry is KO'd
        engine.game.field_model.set_player_coordinate("crumble", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("crumble", PlayerState::new(PS_KNOCKED_OUT));
        engine.game.home_playing = true;
        engine.game.turn_data_home.rerolls = 10;

        // Check loner with reduced threshold
        let mut loner_rolls = Vec::new();
        for seed in 0..30 {
            let mut eng = GameEngine::new(
                engine.game.team_home.clone(),
                engine.game.team_away.clone(),
                Rules::Bb2020, seed,
            );
            eng.game.field_model = engine.game.field_model.clone();
            eng.game.turn_data_home.rerolls = 1;
            let mut evts = Vec::new();
            let success = eng.check_loner_reroll("grak", true, &mut evts);
            if let Some(GameEvent::LonerRoll { roll, .. }) = evts.iter().find(|e| matches!(e, GameEvent::LonerRoll { .. })) {
                loner_rolls.push((*roll, success));
            }
        }
        // With partner KO'd: roll 1 fails, 2+ succeeds
        for (roll, success) in &loner_rolls {
            if *roll < 2 {
                assert!(!success, "Loner(2+) should fail on roll {} when partner KO'd", roll);
            } else {
                assert!(success, "Loner(2+) should succeed on roll {} when partner KO'd", roll);
            }
        }
    }

    // ── Group 157: WisdomOfTheWhiteDwarf (BB2020) ─────────────────────────────

    #[test]
    fn wisdom_grants_temporary_skill_to_adjacent_teammate() {
        let mut home = make_test_team("home");
        let mut grombrindal = make_test_player("grombrindal", 1);
        grombrindal.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::WisdomOfTheWhiteDwarf));
        home.players.push(grombrindal);
        home.players.push(make_test_player("teammate", 2));

        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        // Place Grombrindal adjacent to teammate
        engine.game.field_model.set_player_coordinate("grombrindal", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("grombrindal", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("teammate", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("teammate", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;

        // Activating the teammate should trigger the WisdomOfTheWhiteDwarf prompt
        let _ = engine.apply(TeamSide::Home, Action::ActivatePlayer {
            player_id: "teammate".into(),
            player_action: crate::action::PlayerActionChoice::Move,
        }).unwrap();

        assert!(
            matches!(engine.cached_prompt, Some(AgentPrompt::SelectSkill { ref player_id, .. }) if player_id == "teammate"),
            "WisdomOfTheWhiteDwarf should prompt SelectSkill for the teammate"
        );

        // Agent selects MightyBlow as the granted skill
        let grant_events = engine.apply(TeamSide::Home, Action::SelectSkill {
            skill_id: SkillId::MightyBlow,
        }).unwrap();

        assert!(
            grant_events.iter().any(|e| matches!(e,
                GameEvent::SkillUse { player_id, skill_id: sid, used: true }
                if player_id == "teammate" && *sid == SkillId::MightyBlow as u16
            )),
            "SelectSkill must emit SkillUse(MightyBlow) for teammate"
        );

        // Temporary skill is on the teammate
        let teammate = engine.game.team_home.player("teammate").unwrap();
        assert!(
            teammate.temporary_skills.iter().any(|s| s.skill_id == SkillId::MightyBlow),
            "teammate should have MightyBlow in temporary_skills after wisdom grant"
        );

        // Grombrindal's used_skills has WisdomOfTheWhiteDwarf
        let grombr = engine.game.team_home.player("grombrindal").unwrap();
        assert!(
            grombr.used_skills.contains(&SkillId::WisdomOfTheWhiteDwarf),
            "Grombrindal should have WisdomOfTheWhiteDwarf in used_skills after granting"
        );
    }

