    #[test]
    fn wisdom_temporary_skill_cleared_on_next_activation() {
        let mut home = make_test_team("home");
        let mut grombrindal = make_test_player("grombrindal", 1);
        grombrindal.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::WisdomOfTheWhiteDwarf));
        home.players.push(grombrindal);
        home.players.push(make_test_player("first", 2));
        home.players.push(make_test_player("second", 3));

        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("grombrindal", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("grombrindal", PlayerState::new(PS_STANDING));
        // first is adjacent to grombrindal
        engine.game.field_model.set_player_coordinate("first", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("first", PlayerState::new(PS_STANDING));
        // second is away from grombrindal
        engine.game.field_model.set_player_coordinate("second", FieldCoordinate::new(1, 7));
        engine.game.field_model.set_player_state("second", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;

        // Activate first player, grant BreakTackle
        let _ = engine.apply(TeamSide::Home, Action::ActivatePlayer {
            player_id: "first".into(),
            player_action: crate::action::PlayerActionChoice::Move,
        }).unwrap();
        let _ = engine.apply(TeamSide::Home, Action::SelectSkill {
            skill_id: SkillId::BreakTackle,
        }).unwrap();
        assert!(
            engine.game.team_home.player("first").unwrap().temporary_skills.iter().any(|s| s.skill_id == SkillId::BreakTackle),
            "first should have BreakTackle in temporary_skills"
        );

        // Now the first player does their move (simulate HasActed)
        engine.game.acting_player.has_acted = true;
        // Reset acting player
        engine.game.acting_player.player_id = None;
        // Activate second player — this should clear temporary_skills from all team players
        let _ = engine.apply(TeamSide::Home, Action::ActivatePlayer {
            player_id: "second".into(),
            player_action: crate::action::PlayerActionChoice::Move,
        }).unwrap();

        assert!(
            engine.game.team_home.player("first").unwrap().temporary_skills.is_empty(),
            "first's temporary_skills should be cleared when a new player activates"
        );
    }

    // ── Group 158: BallAndChain (BB2020) ─────────────────────────────────────

    #[test]
    fn ball_and_chain_auto_moves_player_each_step() {
        let mut home = make_test_team("home");
        let mut bac_player = make_test_player("bac", 1);
        bac_player.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::BallAndChain));
        bac_player.movement = 4; // 4 steps
        home.players.push(bac_player);

        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("bac", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("bac", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("bac".into(), ffb_model::enums::PlayerAction::Move);

        // Apply Move with empty path — BallAndChain should auto-resolve
        let events = engine.apply_ball_and_chain_move("bac").unwrap();

        // Must emit PlayerMoved or PlayerFellDown or ScatterPlayer events
        let moved = events.iter().filter(|e| matches!(e,
            GameEvent::PlayerMoved { player_id, .. } | GameEvent::ScatterPlayer { player_id, .. }
            if player_id == "bac")).count();
        assert!(moved > 0 || events.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "bac")),
            "BallAndChain should produce movement or fall events");
    }

    #[test]
    fn ball_and_chain_ignores_provided_path() {
        let mut home = make_test_team("home");
        let mut bac_player = make_test_player("bac", 1);
        bac_player.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::BallAndChain));
        bac_player.movement = 3;
        home.players.push(bac_player);

        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("bac", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("bac", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("bac".into(), ffb_model::enums::PlayerAction::Move);

        // Provide a specific path — BallAndChain must NOT follow it
        let explicit_path = vec![
            FieldCoordinate::new(12, 8),
            FieldCoordinate::new(12, 9),
            FieldCoordinate::new(12, 10),
        ];
        let events = engine.apply(crate::legal_actions::TeamSide::Home, Action::Move { path: explicit_path }).unwrap();

        // Player should NOT be at (12, 10) — BallAndChain chose random direction
        // (highly unlikely to randomly end at exactly (12,10) in 3 steps from (12,7))
        // Check that some movement events were produced
        let has_movement = events.iter().any(|e| matches!(e,
            GameEvent::PlayerMoved { .. } | GameEvent::ScatterPlayer { .. } | GameEvent::PlayerFellDown { .. }));
        assert!(has_movement, "BallAndChain move must produce movement events");
    }

    #[test]
    fn ball_and_chain_knocks_down_opponent_in_path() {
        let mut home = make_test_team("home");
        let mut bac_player = make_test_player("bac", 1);
        bac_player.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::BallAndChain));
        bac_player.movement = 6;
        bac_player.strength = 5; // strong flail
        home.players.push(bac_player);
        let mut away = make_test_team("away");
        // Place an opponent in a known adjacent square
        away.players.push(make_test_player("victim", 2));
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("bac", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("bac", PlayerState::new(PS_STANDING));

        // Try many seeds to find one where BallAndChain moves into (13, 7)
        let mut found_hit = false;
        for seed in 0..200 {
            let mut home2 = make_test_team("home");
            let mut bac2 = make_test_player("bac", 1);
            bac2.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::BallAndChain));
            bac2.movement = 1;
            home2.players.push(bac2);
            let mut away2 = make_test_team("away");
            away2.players.push(make_test_player("victim", 2));
            let mut eng = GameEngine::new(home2, away2, Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("bac", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("bac", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_coordinate("victim", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("victim", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.acting_player.set_player("bac".into(), ffb_model::enums::PlayerAction::Move);

            let events = eng.apply_ball_and_chain_move("bac").unwrap();
            // If bac moved to (13,7), victim should have an Injury event
            if events.iter().any(|e| matches!(e, GameEvent::Injury { player_id, .. } if player_id == "victim")) {
                found_hit = true;
                // BallAndChain player should also have fallen prone
                assert!(
                    events.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "bac")),
                    "BallAndChain player should fall after hitting an opponent"
                );
                break;
            }
        }
        assert!(found_hit, "In 200 seeds, BallAndChain with MA=1 should hit the opponent at least once");
    }

