    #[test]
    fn fumblerooskie_use_skill_emits_event() {
        let mut home = make_test_team("home");
        let mut carrier = make_test_player("carrier", 1);
        carrier.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Fumblerooskie));
        home.players.push(carrier);

        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(12, 7));
        engine.game.field_model.ball_in_play = true;
        engine.game.home_playing = true;
        engine.game.acting_player.set_player("carrier".into(), ffb_model::enums::PlayerAction::Move);

        let events = engine.apply(TeamSide::Home, Action::UseSkill {
            skill_id: SkillId::Fumblerooskie,
            use_skill: true,
        }).unwrap();

        assert!(
            events.iter().any(|e| matches!(e,
                GameEvent::SkillUse { player_id, skill_id: sid, used: true }
                if player_id == "carrier" && *sid == SkillId::Fumblerooskie as u16
            )),
            "Fumblerooskie use_skill=true must emit SkillUse event"
        );

        // Ball stays at carrier's original square
        assert_eq!(
            engine.game.field_model.ball_coordinate,
            Some(FieldCoordinate::new(12, 7)),
            "Ball should remain at carrier's original square after Fumblerooskie"
        );
    }

