    // ── Group 160: ViolentInnovator (BB2025) ────────────────────────────────

    #[test]
    fn violent_innovator_grants_spp_for_stab_cas_in_bb2025() {
        let mut home = make_test_team("home");
        let mut att = make_test_player("att", 1);
        att.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Stab));
        att.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::ViolentInnovator));
        home.players.push(att);
        let mut away = make_test_team("away");
        let mut def = make_test_player("def", 2);
        def.armour = 1; // very weak armor — almost always breaks
        away.players.push(def);

        // Try many seeds to get a CAS result
        let mut got_spp = false;
        for seed in 0..200 {
            let mut home2 = make_test_team("home");
            let mut att2 = make_test_player("att", 1);
            att2.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Stab));
            att2.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::ViolentInnovator));
            home2.players.push(att2);
            let mut away2 = make_test_team("away");
            let mut def2 = make_test_player("def", 2);
            def2.armour = 1;
            away2.players.push(def2);
            let mut eng = GameEngine::new(home2, away2, Rules::Bb2025, seed);
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.home_playing = true;
            eng.game.acting_player.set_player("att".into(), ffb_model::enums::PlayerAction::Stab);
            let evs = eng.apply(TeamSide::Home, Action::Stab { defender_id: "def".into() }).unwrap_or_default();
            if evs.iter().any(|e| matches!(e, GameEvent::Injury { was_cas: true, .. })) {
                // ViolentInnovator should have granted SPP
                let spp = eng.game.team_home.player("att").map(|p| p.current_spps).unwrap_or(0);
                assert!(spp > 0, "ViolentInnovator should grant SPP for Stab CAS in BB2025 (seed {seed})");
                got_spp = true;
                break;
            }
        }
        assert!(got_spp, "should get a CAS in 200 seeds");
    }

