    #[test]
    fn blast_it_accepted_emits_skill_use_and_deviate() {
        use ffb_model::model::skill_def::SkillWithValue;
        // BlastIt accepted: SkillUse(used=true) + PassDeviate must be emitted, skill marked used.
        let mut home = make_test_team("home");
        let mut thrower = make_test_player("thrower", 1);
        thrower.extra_skills = vec![
            SkillWithValue::new(SkillId::HailMaryPass),
            SkillWithValue::new(SkillId::BlastIt),
        ];
        home.players.push(thrower);
        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        let tc = FieldCoordinate::new(5, 7);
        engine.game.field_model.set_player_coordinate("thrower", tc);
        engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.ball_coordinate = Some(tc);
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("thrower".into(), PlayerAction::HailMaryPass);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let _ = engine.apply(TeamSide::Home, Action::Pass { coord: FieldCoordinate::new(22, 7) }).unwrap();
        // Accept BlastIt
        let events = engine.apply(TeamSide::Home, Action::UseSkill { skill_id: SkillId::BlastIt, use_skill: true }).unwrap();

        let skill_used = events.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::BlastIt as u16));
        let has_deviate = events.iter().any(|e| matches!(e, GameEvent::PassDeviate { .. }));
        let blast_marked = engine.game.team_home.player("thrower").unwrap().used_skills.contains(&SkillId::BlastIt);

        assert!(skill_used, "BlastIt accept must emit SkillUse(used=true)");
        assert!(has_deviate, "BlastIt accept must emit PassDeviate with 3 directions");
        assert!(blast_marked, "BlastIt must be marked used in player's used_skills");
    }

    #[test]
    fn blast_it_declined_still_completes_hmp() {
        use ffb_model::model::skill_def::SkillWithValue;
        // BlastIt declined: original first direction is used, HMP completes normally.
        let mut home = make_test_team("home");
        let mut thrower = make_test_player("thrower", 1);
        thrower.extra_skills = vec![
            SkillWithValue::new(SkillId::HailMaryPass),
            SkillWithValue::new(SkillId::BlastIt),
        ];
        home.players.push(thrower);
        let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        let tc = FieldCoordinate::new(5, 7);
        engine.game.field_model.set_player_coordinate("thrower", tc);
        engine.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.ball_coordinate = Some(tc);
        engine.game.field_model.ball_in_play = true;
        engine.game.acting_player.set_player("thrower".into(), PlayerAction::HailMaryPass);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;

        let _ = engine.apply(TeamSide::Home, Action::Pass { coord: FieldCoordinate::new(22, 7) }).unwrap();
        let events = engine.apply(TeamSide::Home, Action::UseSkill { skill_id: SkillId::BlastIt, use_skill: false }).unwrap();

        let skill_event = events.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: false, .. } if *skill_id == SkillId::BlastIt as u16));
        let has_deviate = events.iter().any(|e| matches!(e, GameEvent::PassDeviate { .. }));
        let blast_not_marked = !engine.game.team_home.player("thrower").unwrap().used_skills.contains(&SkillId::BlastIt);

        assert!(skill_event, "BlastIt decline must emit SkillUse(used=false)");
        assert!(has_deviate, "BlastIt declined must still emit PassDeviate");
        assert!(blast_not_marked, "BlastIt must NOT be marked used when declined");
    }

