    // ── Group 167: TeamCaptain skill (BB2025) ────────────────────────────────

    #[test]
    fn team_captain_saves_reroll_on_six() {
        // TeamCaptain (BB2025): after consuming a team reroll, if a TeamCaptain is on the
        // field and the d6 roll is 6, the reroll is restored (not consumed).
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        let mut captain = make_test_player("cap", 1);
        captain.starting_skills = vec![SkillWithValue::new(SkillId::TeamCaptain)];
        home.players.push(captain);
        let mut mover = make_test_player("mover", 2);
        mover.movement = 6;
        mover.agility = 3;
        home.players.push(mover);

        let mut away = make_test_team("away");
        let mut tackler = make_test_player("tackler", 1);
        away.players.push(tackler);

        // Find seed where check_team_captain_save rolls 6, restoring reroll.
        // Use a deterministic seed search.
        for seed in 0u64..2000 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2025, seed);
            // Place TeamCaptain on the field
            engine.game.field_model.set_player_coordinate("cap", FieldCoordinate::new(5, 5));
            engine.game.field_model.set_player_state("cap", PlayerState::new(PS_STANDING));
            // Give home team 1 reroll
            engine.game.turn_data_home.rerolls = 1;
            engine.game.turn_data_home.reroll_used = false;

            // Simulate consuming the reroll then calling check_team_captain_save
            engine.game.turn_data_home.rerolls -= 1;
            engine.game.turn_data_home.reroll_used = true;
            let events = engine.check_team_captain_save(true);

            if let Some(GameEvent::TeamCaptainRoll { roll, reroll_saved, .. }) = events.first() {
                if *reroll_saved {
                    assert_eq!(*roll, 6, "TeamCaptain must roll exactly 6 to save");
                    assert_eq!(engine.game.turn_data_home.rerolls, 1, "Reroll must be restored");
                    assert!(!engine.game.turn_data_home.reroll_used, "reroll_used must be cleared");
                    return;
                }
            }
        }
        panic!("No seed produced a TeamCaptain save within 2000 tries");
    }

    #[test]
    fn team_captain_no_save_on_less_than_six() {
        // TeamCaptain: on rolls 1-5, the reroll IS consumed (not saved).
        use ffb_model::model::skill_def::SkillWithValue;
        let mut home = make_test_team("home");
        let mut captain = make_test_player("cap", 1);
        captain.starting_skills = vec![SkillWithValue::new(SkillId::TeamCaptain)];
        home.players.push(captain);

        for seed in 0u64..2000 {
            let mut engine = GameEngine::new(home.clone(), make_test_team("away"), Rules::Bb2025, seed);
            engine.game.field_model.set_player_coordinate("cap", FieldCoordinate::new(5, 5));
            engine.game.field_model.set_player_state("cap", PlayerState::new(PS_STANDING));
            engine.game.turn_data_home.rerolls = 0;
            engine.game.turn_data_home.reroll_used = true;

            let events = engine.check_team_captain_save(true);

            if let Some(GameEvent::TeamCaptainRoll { roll, reroll_saved, .. }) = events.first() {
                if !*reroll_saved && *roll < 6 {
                    assert_eq!(engine.game.turn_data_home.rerolls, 0, "Reroll must not be restored on <6");
                    assert!(engine.game.turn_data_home.reroll_used, "reroll_used stays true");
                    return;
                }
            }
        }
        panic!("No seed produced a non-save roll within 2000 tries");
    }

