    // ── Group 168: SecureTheBall action (BB2025) ─────────────────────────────

    #[test]
    fn secure_the_ball_succeeds_with_two_plus_roll() {
        // SecureTheBall (BB2025): player at ball square picks up with 2+ instead of normal pickup.
        // Verify that a player with agility 1 can still secure the ball (2+ is much easier).
        let mut home = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.agility = 1; // Normal pickup would be very hard, but SecureTheBall is 2+
        home.players.push(mover);

        for seed in 0u64..2000 {
            let mut engine = GameEngine::new(home.clone(), make_test_team("away"), Rules::Bb2025, seed);
            let ball_coord = FieldCoordinate::new(10, 7);
            engine.game.field_model.set_player_coordinate("mover", ball_coord);
            engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING));
            engine.game.field_model.ball_coordinate = Some(ball_coord);
            engine.game.field_model.ball_in_play = true;
            engine.game.home_playing = true;

            // Activate with SecureTheBall — pickup roll happens immediately at activation.
            let result = engine.apply(TeamSide::Home, Action::ActivatePlayer {
                player_id: "mover".into(),
                player_action: crate::action::PlayerActionChoice::SecureTheBall,
            });
            assert!(result.is_ok(), "SecureTheBall activation must not error");
            assert!(engine.game.turn_data_home.secure_the_ball_used,
                "secure_the_ball_used must be set after activation");

            let events = result.unwrap();

            // Check for BallPickedUp (success) — with 2+ roll most seeds should succeed
            if events.iter().any(|e| matches!(e, GameEvent::BallPickedUp { .. })) {
                return;
            }
        }
        panic!("SecureTheBall with ag=1 should succeed frequently within 2000 seeds");
    }

