    #[test]
    fn quick_snap_allows_extra_movement() {
        // A player with MA=1 should be able to move 2 squares when quick_snap_bonus=1.
        let mut home = make_test_team("home");
        let mut mover = make_test_player("mover", 1);
        mover.movement = 1; // normally can only move 1 + 2 GFI
        home.players.push(mover);
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        engine.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.turn_data_home.quick_snap_bonus = 1; // simulate QuickSnap

        // With MA=1+1=2, moving 2 squares should NOT require GFI
        let path = vec![
            FieldCoordinate::new(11, 7),
            FieldCoordinate::new(12, 7),
        ];
        let events = engine.apply_move("mover", &path).unwrap_or_default();
        let new_coord = engine.game.field_model.player_coordinate("mover").unwrap_or(FieldCoordinate::new(10, 7));
        // Movement should reach the destination without GFI
        assert!(new_coord.x >= 11, "QuickSnap bonus must allow extra movement square");
        assert!(events.iter().any(|e| matches!(e, GameEvent::PlayerMoved { player_id, .. } if player_id == "mover")),
            "QuickSnap move must emit PlayerMoved event");
    }

