        engine.game.home_playing = false; // away is kicking

        // Blitz kickoff sets the flag
        engine.blitz_kickoff_pending = true;

        // Simulate KickBall transition: blitz path
        engine.game.home_playing = !engine.game.home_first_offense; // kicking team = away
