        engine.player_activated_this_turn = false;

        assert_eq!(engine.game.turn_mode, TurnMode::Blitz, "Blitz kickoff must set TurnMode::Blitz");
        assert!(!engine.game.home_playing, "Blitz kickoff: kicking team (away) must be active");
