        let home = make_test_team("home");
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Set up blitz kickoff state: away kicked, home receives, now in Blitz mode (away playing)
        engine.game.home_first_offense = true;
        engine.game.home_playing = false; // away kicking team is active
        engine.game.turn_mode = TurnMode::Blitz;
        engine.blitz_kickoff_pending = true;
