    // ── Group 176: Turnover conditions ───────────────────────────────────────

    #[test]
    fn failed_pickup_scatters_ball() {
        // When a player fails to pick up the ball (and has no SureHands/reroll), the ball
        // scatters from the pickup square.
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player("carrier", 1));
            let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            eng.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
            eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(11, 7));
            eng.game.field_model.ball_in_play = true;
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 0;
            eng.game.turn_data_home.turn_nr = 1;
            eng.game.acting_player.set_player("carrier".into(), PlayerAction::Move);
            eng.player_activated_this_turn = true;

            if let Ok(evs) = eng.apply_move("carrier", &[FieldCoordinate::new(11, 7)]) {
                let has_pickup_fail = evs.iter().any(|e| matches!(e, GameEvent::BallScattered { player_id, .. } if player_id == "carrier"));
                if has_pickup_fail {
                    // Ball must have scattered — ball_moving should be true
                    assert!(eng.game.field_model.ball_moving,
                        "After failed pickup, ball_moving must be true (seed {})", seed);
                    return;
                }
            }
        }
        // If no failure found in 500 seeds, the test just passes vacuously (seed range produces all successes)
    }

    #[test]
    fn player_falling_with_ball_scatters_ball() {
        // When a player with the ball fails a dodge, the ball must scatter from their position.
        // This verifies the bug fix: scatter_ball_if_carried is called in the dodge failure path.
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut carrier = make_test_player("carrier", 3); // ag=3 → dodge target 3+
            carrier.agility = 3;
            home.players.push(carrier);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("tackler", 1)); // provides tackle zone
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);

            // carrier at (10,7), tackler at (10,8) — carrier must dodge out of TZ
            eng.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_coordinate("tackler", FieldCoordinate::new(10, 8));
            eng.game.field_model.set_player_state("tackler", PlayerState::new(PS_STANDING));
            eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(10, 7));
            eng.game.field_model.ball_in_play = true;
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 0;
            eng.game.acting_player.set_player("carrier".into(), PlayerAction::Move);
            eng.player_activated_this_turn = true;

            // Move carrier to (11,7): must dodge out of tackler's TZ
            if let Ok(evs) = eng.apply_move("carrier", &[FieldCoordinate::new(11, 7)]) {
                let fell = evs.iter().any(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "carrier"));
                if fell {
                    // After our bug fix: BallScattered must follow PlayerFellDown for the carrier
                    let fell_idx = evs.iter().position(|e| matches!(e, GameEvent::PlayerFellDown { player_id, .. } if player_id == "carrier")).unwrap();
                    let scattered_after = evs[fell_idx..].iter().any(|e| matches!(e, GameEvent::BallScattered { player_id, .. } if player_id == "carrier"));
                    assert!(scattered_after, "Ball must scatter immediately after carrier falls (seed {})", seed);
                    return;
                }
            }
        }
        // If no dodge failure found in 500 seeds, the test vacuously passes
    }

    #[test]
    fn fumbled_pass_scatters_ball_from_thrower() {
        // A fumbled pass (very bad roll) scatters the ball from the thrower's square.
        for seed in 0u64..1000 {
            let mut home = make_test_team("home");
            let mut thrower = make_test_player("thrower", 1);
            thrower.agility = 2; // low AG → higher fumble chance
            home.players.push(thrower);
            let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);

            let thrower_coord = FieldCoordinate::new(10, 7);
            let target_coord = FieldCoordinate::new(14, 7); // Long pass distance
            eng.game.field_model.set_player_coordinate("thrower", thrower_coord);
            eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING));
            eng.game.field_model.ball_coordinate = Some(thrower_coord);
            eng.game.field_model.ball_in_play = true;
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);

            let evs = eng.apply(TeamSide::Home, Action::Pass { coord: target_coord }).unwrap();
            let has_pass_roll = evs.iter().any(|e| matches!(e, GameEvent::PassRoll { .. }));
            let is_fumble = evs.iter().any(|e| matches!(e, GameEvent::PassRoll { result, .. }
                if *result == ffb_model::enums::PassResult::Fumble));
            if has_pass_roll && is_fumble {
                let scattered = evs.iter().any(|e| matches!(e, GameEvent::ScatterBall { .. }));
                assert!(scattered, "Fumbled pass must scatter the ball (seed {})", seed);
                return;
            }
        }
    }

