    // ── Group 180: Injury outcomes in block context ──────────────────────────

    #[test]
    fn block_emits_block_roll_event() {
        // Any block must emit at least one BlockRoll event.
        let mut home = make_test_team("home");
        home.players.push(make_test_player_with_st("attacker", 1, 3));
        let mut away = make_test_team("away");
        away.players.push(make_test_player("defender", 2));
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);

        eng.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING));
        eng.game.field_model.set_player_coordinate("defender", FieldCoordinate::new(11, 7));
        eng.game.field_model.set_player_state("defender", PlayerState::new(PS_STANDING));
        eng.game.home_playing = true;
        eng.game.acting_player.set_player("attacker".into(), PlayerAction::Block);

        let evs = eng.apply_block("attacker", "defender").unwrap();
        assert!(evs.iter().any(|ev| matches!(ev, GameEvent::BlockRoll { .. })),
            "apply_block must emit at least one BlockRoll event");
    }

    #[test]
    fn ball_scatters_from_defender_when_carrier_falls_during_block() {
        // When the defender has the ball and is knocked prone (Pow/PowPushback),
        // the ball must scatter from the defender's square.
        for seed in 0u64..1000 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player_with_st("attacker", 1, 5)); // high ST
            let mut away = make_test_team("away");
            let mut carrier = make_test_player("carrier", 2);
            carrier.strength = 1; // attacker gets 2 dice
            away.players.push(carrier);
            let mut e = GameEngine::new(home, away, Rules::Bb2020, seed);

            let carrier_coord = FieldCoordinate::new(11, 7);
            e.game.field_model.set_player_coordinate("attacker", FieldCoordinate::new(10, 7));
            e.game.field_model.set_player_state("attacker", PlayerState::new(PS_STANDING));
            e.game.field_model.set_player_coordinate("carrier", carrier_coord);
            e.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
            e.game.field_model.ball_coordinate = Some(carrier_coord);
            e.game.field_model.ball_in_play = true;
            e.game.home_playing = true;
            e.game.acting_player.set_player("attacker".into(), PlayerAction::Block);

            if let Ok(evs) = e.apply_block("attacker", "carrier") {
                let carrier_fell = evs.iter().any(|ev| matches!(ev, GameEvent::PlayerFellDown { player_id, .. } if player_id == "carrier"));
                if carrier_fell {
                    let ball_scattered = evs.iter().any(|ev| matches!(ev, GameEvent::BallScattered { .. }));
                    assert!(ball_scattered,
                        "Ball must scatter when defender with ball falls (seed {})", seed);
                    return;
                }
            }
        }
        // If carrier never fell in 1000 seeds, vacuously pass
    }

    // ── Group 181: Reroll and pending state management ───────────────────────

    #[test]
    fn pending_reroll_cleared_on_decline() {
        // When agent declines the reroll offer, pending_reroll must be cleared.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        eng.game.turn_data_home.rerolls = 1;
        // Manually place in a pending reroll state to test resolution
        eng.pending_reroll = Some(PendingReroll::GoForIt {
            player_id: "mover".to_owned(),
            home_moving: true,
            origin_coord: FieldCoordinate::new(10, 7),
            dest: FieldCoordinate::new(11, 7),
            path_remaining: vec![],
            min_roll: 2,
            is_pro: false,
            is_consummate_professional: false,
        });
        eng.apply(TeamSide::Home, Action::UseReRoll { use_reroll: false }).unwrap();
        assert!(eng.pending_reroll.is_none(), "Declining reroll must clear pending_reroll");
    }

    #[test]
    fn team_reroll_consumed_on_accept() {
        // When agent accepts the reroll offer, team rerolls must decrement by 1.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_data_home.rerolls = 2;
        eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING));
        eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        eng.player_activated_this_turn = true;
        eng.pending_reroll = Some(PendingReroll::GoForIt {
            player_id: "mover".to_owned(),
            home_moving: true,
            origin_coord: FieldCoordinate::new(10, 7),
            dest: FieldCoordinate::new(11, 7),
            path_remaining: vec![],
            min_roll: 2,
            is_pro: false,
            is_consummate_professional: false,
        });
        eng.apply(TeamSide::Home, Action::UseReRoll { use_reroll: true }).unwrap();
        assert_eq!(eng.game.turn_data_home.rerolls, 1, "Accepting reroll must consume 1 team reroll");
        assert!(eng.pending_reroll.is_none(), "After resolving reroll, pending_reroll must be None");
    }

    #[test]
    fn reroll_used_flag_prevents_second_team_reroll_in_same_turn() {
        // After using a team reroll, reroll_used=true and second reroll offer must not fire.
        for seed in 0u64..200 {
            let mut home = make_test_team("home");
            home.players.push(make_test_player("mover", 1));
            let mut e = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            e.game.home_playing = true;
            e.game.turn_data_home.rerolls = 2;
            e.game.turn_data_home.reroll_used = true; // already used this turn
            e.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
            e.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING));
            e.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            e.game.acting_player.current_move = 6; // past MA of 6 → GFI
            e.player_activated_this_turn = true;

            if let Ok(evs) = e.apply_move("mover", &[FieldCoordinate::new(11, 7)]) {
                if evs.iter().any(|ev| matches!(ev, GameEvent::GoForItRoll { success: false, .. })) {
                    assert!(e.pending_reroll.is_none(),
                        "No reroll must be offered after reroll_used=true (seed {})", seed);
                    return;
                }
            }
        }
    }

