    // ── Group 186: Ball scatter in rerolled-then-failed movement ─────────────

    #[test]
    fn ball_scatters_when_rerolled_gfi_fails() {
        // When a team reroll is accepted on a GFI but the rerolled die also fails,
        // the ball must scatter from the ball carrier's original square.
        // Seed chosen so the rerolled GFI roll = 1 (always fails).
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut carrier = make_test_player("carrier", 1);
            carrier.movement = 6;
            home.players.push(carrier);
            let mut e = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            e.game.home_playing = true;
            e.game.turn_data_home.rerolls = 1;
            e.game.acting_player.set_player("carrier".into(), PlayerAction::Move);
            e.player_activated_this_turn = true;

            let origin = FieldCoordinate::new(10, 7);
            let dest = FieldCoordinate::new(11, 7);
            e.game.field_model.set_player_coordinate("carrier", dest);
            e.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING));
            e.game.field_model.ball_coordinate = Some(origin);
            e.game.field_model.ball_in_play = true;

            // Inject a pending GFI reroll with origin_coord
            e.pending_reroll = Some(PendingReroll::GoForIt {
                player_id: "carrier".to_owned(),
                home_moving: true,
                origin_coord: origin,
                dest,
                path_remaining: vec![],
                min_roll: 2,
                is_pro: false,
                is_consummate_professional: false,
            });

            let evs = e.apply(TeamSide::Home, Action::UseReRoll { use_reroll: true }).unwrap();
            let gfi = evs.iter().find(|ev| matches!(ev, GameEvent::GoForItRoll { rerolled: true, .. }));
            if let Some(GameEvent::GoForItRoll { success: false, .. }) = gfi {
                // Reroll also failed — ball must scatter
                assert!(
                    evs.iter().any(|ev| matches!(ev, GameEvent::BallScattered { .. })),
                    "Ball must scatter when rerolled GFI also fails (seed {})", seed
                );
                return;
            }
        }
        // If rerolled GFI always succeeded in 500 seeds, vacuously pass
    }

