    // ── Group 183: Pass interception resolution ───────────────────────────────

    #[test]
    fn successful_interception_awards_interception_spp() {
        // If a defender intercepts the ball, they receive SPP for an interception.
        for seed in 0u64..1000 {
            let mut home = make_test_team("home");
            let mut thrower = make_test_player("thrower", 1);
            thrower.agility = 4;
            home.players.push(thrower);
            let mut away = make_test_team("away");
            let mut interceptor = make_test_player("interceptor", 2);
            interceptor.agility = 4; // Good AG for interception
            away.players.push(interceptor);
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);

            let thrower_coord = FieldCoordinate::new(8, 7);
            let target_coord = FieldCoordinate::new(14, 7);
            let intercept_coord = FieldCoordinate::new(11, 7); // in the pass lane
            eng.game.field_model.set_player_coordinate("thrower", thrower_coord);
            eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_coordinate("interceptor", intercept_coord);
            eng.game.field_model.set_player_state("interceptor", PlayerState::new(PS_STANDING));
            eng.game.field_model.ball_coordinate = Some(thrower_coord);
            eng.game.field_model.ball_in_play = true;
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("thrower".into(), PlayerAction::Pass);

            if let Ok(evs) = eng.apply(TeamSide::Home, Action::Pass { coord: target_coord }) {
                let intercepted = evs.iter().any(|e| matches!(e, GameEvent::InterceptionRoll { success: true, .. }));
                if intercepted {
                    let interceptor_spp = eng.game.team_away.player("interceptor").map(|p| p.current_spps).unwrap_or(0);
                    assert!(interceptor_spp > 0,
                        "Successful interception must award SPP to the interceptor (seed {})", seed);
                    return;
                }
            }
        }
        // If no interception found, vacuously pass
    }

