    #[test]
    fn setup_transitions_to_kickoff_after_both_teams_set_up() {
        // After both teams confirm setup, turn mode must advance to Kickoff.
        let mut home = make_test_team("home");
        let mut away = make_test_team("away");
        // Add minimum required players
        for i in 1..=11 {
            home.players.push(make_test_player(&format!("h{i}"), i));
            away.players.push(make_test_player(&format!("a{i}"), 100 + i));
        }
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.turn_mode = TurnMode::Setup;
        eng.game.home_playing = true;
        eng.game.status = ffb_model::enums::GameStatus::Active;
        eng.game.half = 1;
        eng.game.turn_data_home.turn_nr = 0;
        eng.game.home_first_offense = true;
        eng.game.setup_offense = true;

        // Place home players on pitch (offense half)
        for (i, id) in (1..=11).map(|i| (i, format!("h{i}"))) {
            let x = if i <= 7 { 10 + (i as i32) } else { 10 + (i as i32) % 5 };
            let y = i as i32;
            eng.game.field_model.set_player_coordinate(&id, FieldCoordinate::new(x, y));
            eng.game.field_model.set_player_state(&id, PlayerState::new(PS_RESERVE));
        }

        let _ = eng.apply(TeamSide::Home, Action::ConfirmSetup);

        // After home confirms, it's away's turn to set up
        // (We just verify it doesn't stay in StartGame forever)
        assert_ne!(eng.game.turn_mode, TurnMode::StartGame, "Setup must not revert to StartGame");
    }

