    // ── Group 204: Secret weapon ejection at half-time ────────────────────────

    fn make_engine_at_end_of_first_half() -> GameEngine {
        // Create a game positioned just before the end of the first half.
        let mut home = make_test_team("home");
        let sw_player = make_test_player_with_skill("sw_p", 1, SkillId::SecretWeapon);
        home.players.push(sw_player);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 1);
        eng.game.home_playing = false; // away team's last turn of the half
        eng.game.half = 1;
        eng.game.turn_data_away.turn_nr = 8; // EndTurn → 9, completing the half
        eng.game.turn_data_home.turn_nr = 9; // home has already done all 8 turns
        eng.game.turn_mode = TurnMode::Regular;
        // Place the sw_player on the pitch for home team
        eng.game.field_model.set_player_coordinate("sw_p", FieldCoordinate::new(7, 7));
        eng.game.field_model.set_player_state("sw_p", PlayerState::new(PS_STANDING));
        eng
    }

    #[test]
    fn secret_weapon_player_ejected_at_half_time() {
        // When the half ends, any SecretWeapon player on the pitch must be ejected.
        let mut eng = make_engine_at_end_of_first_half();
        let evs = eng.apply(TeamSide::Away, crate::action::Action::EndTurn).unwrap();
        // After EndTurn, half 1 ends and SecretWeaponBan must be emitted for sw_p
        assert!(
            evs.iter().any(|e| matches!(e, GameEvent::SecretWeaponBan { player_id } if player_id == "sw_p")),
            "SecretWeapon player must be ejected (SecretWeaponBan event) at half-time"
        );
    }

    #[test]
    fn non_secret_weapon_player_not_ejected_at_half_time() {
        // Regular players must NOT receive SecretWeaponBan at half-time.
        let mut home = make_test_team("home");
        let normal_p = make_test_player("norm_p", 1);
        home.players.push(normal_p);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 1);
        eng.game.home_playing = false;
        eng.game.half = 1;
        eng.game.turn_data_away.turn_nr = 7;
        eng.game.turn_data_home.turn_nr = 8;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.field_model.set_player_coordinate("norm_p", FieldCoordinate::new(7, 7));
        eng.game.field_model.set_player_state("norm_p", PlayerState::new(PS_STANDING));

        let evs = eng.apply(TeamSide::Away, crate::action::Action::EndTurn).unwrap();
        assert!(
            !evs.iter().any(|e| matches!(e, GameEvent::SecretWeaponBan { .. })),
            "Non-SecretWeapon player must NOT receive SecretWeaponBan at half-time"
        );
    }

    // ── Group 205: TTM failed landing causes armor roll ───────────────────────

    // ── Group 206: Stunned → Prone at EndTurn ─────────────────────────────────

    #[test]
    fn stunned_player_becomes_prone_at_end_of_turn() {
        // When a stunned player's owner ends their turn, the player state changes to prone.
        let mut home = make_test_team("home");
        let stunned_p = make_test_player("stun_p", 1);
        home.players.push(stunned_p);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 1);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        // Set the player to stunned state (use PS_STUNNED constant)
        eng.game.field_model.set_player_coordinate("stun_p", FieldCoordinate::new(7, 7));
        eng.game.field_model.set_player_state("stun_p", PlayerState::new(PS_STUNNED));
        let _ = eng.apply(TeamSide::Home, crate::action::Action::EndTurn).unwrap();
        // After home's EndTurn, stunned player should be prone
        let state = eng.game.field_model.player_state("stun_p").unwrap();
        assert!(state.is_prone(), "Stunned player must become prone after owner's EndTurn");
    }

    #[test]
    fn standing_player_state_preserved_at_end_of_turn() {
        // Standing players should not change state at EndTurn.
        let mut home = make_test_team("home");
        let standing_p = make_test_player("stand_p", 1);
        home.players.push(standing_p);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 1);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.field_model.set_player_coordinate("stand_p", FieldCoordinate::new(7, 7));
        eng.game.field_model.set_player_state("stand_p", PlayerState::new(PS_STANDING));
        let _ = eng.apply(TeamSide::Home, crate::action::Action::EndTurn).unwrap();
        let state = eng.game.field_model.player_state("stand_p").unwrap();
        assert!(!state.is_prone(), "Standing player must remain standing after EndTurn");
    }

    #[test]
    fn ttm_failed_landing_emits_injury_event() {
        // When RightStuff fails the thrown player must take an armor roll.
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let thrower = make_test_player_with_skill("thrower", 1, SkillId::ThrowTeamMate);
            let mut thrown = make_test_player_with_skill("thrown", 2, SkillId::RightStuff);
            thrown.armour = 8; // medium armour
            home.players.push(thrower);
            home.players.push(thrown);
            let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.acting_player.set_player("thrower".into(), PlayerAction::ThrowTeamMate);
            eng.player_activated_this_turn = true;
            eng.game.field_model.set_player_coordinate("thrower", FieldCoordinate::new(5, 7));
            eng.game.field_model.set_player_state("thrower", PlayerState::new(PS_STANDING));
            eng.game.field_model.set_player_coordinate("thrown", FieldCoordinate::new(6, 7));
            eng.game.field_model.set_player_state("thrown", PlayerState::new(PS_STANDING));
            let target = FieldCoordinate::new(10, 7);

            if let Ok(evs) = eng.apply(TeamSide::Home, crate::action::Action::ThrowTeamMate { player_id: "thrown".into(), coord: target }) {
                let right_stuff_ev = evs.iter().find(|e| matches!(e, GameEvent::RightStuffRoll { .. }));
                if let Some(GameEvent::RightStuffRoll { success, .. }) = right_stuff_ev {
                    if !success {
                        // Failed RightStuff → armor roll (Injury event) must follow
                        let has_injury = evs.iter().any(|e| matches!(e, GameEvent::Injury { player_id, .. } if player_id == "thrown"));
                        assert!(has_injury, "Failed RightStuff landing must emit Injury event for thrown player (seed {})", seed);
                        return;
                    }
                }
            }
        }
    }

