    // ── Group 211: Loner failure behavior ───────────────────────────────────

    #[test]
    fn loner_failure_reroll_is_consumed_but_action_not_retried() {
        // When a Loner player uses a team reroll but rolls < 4 on Loner check:
        // - Team reroll is consumed (rerolls decremented)
        // - The action is NOT retried (player still fell)
        // - LonerRoll event with success: false is emitted
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("loner_mover", 1);
            mover.agility = 6; // dodge always fails (target 7+ with any TZ)
            mover.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Loner)];
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.turn_data_home.reroll_used = false;
            eng.game.field_model.set_player_coordinate("loner_mover", FieldCoordinate::new(2, 7));
            eng.game.field_model.set_player_state("loner_mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(4, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("loner_mover".into(), PlayerAction::Move);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Move {
                path: vec![FieldCoordinate::new(3, 7)],
            }).unwrap();
            // Try to use reroll
            if eng.pending_reroll.is_some() {
                let evs2 = eng.apply(TeamSide::Home, crate::action::Action::UseReRoll { use_reroll: true }).unwrap();
                let loner_failed = evs2.iter().any(|e| matches!(e, GameEvent::LonerRoll { success: false, .. }));
                if loner_failed {
                    // Reroll was consumed but action was not retried → player fell
                    assert_eq!(eng.game.turn_data_home.rerolls, 1, "Reroll should be consumed (seed {})", seed);
                    let state = eng.game.field_model.player_state("loner_mover").unwrap();
                    assert!(state.base() == PS_PRONE, "Player should be prone after failed loner reroll (seed {})", seed);
                    return;
                }
            }
        }
        // If we couldn't find a Loner failure, just check the behavior is structurally sound
        // (Loner failure is probabilistic; 3/6 chance per attempt)
    }

    #[test]
    fn loner_success_allows_dodge_retry() {
        // When Loner player uses a team reroll and rolls 4+ on Loner check:
        // - The dodge is retried with a new roll
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("loner_mover", 1);
            mover.agility = 5; // dodge target = 5+ (some successes)
            mover.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Loner)];
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.turn_data_home.reroll_used = false;
            eng.game.field_model.set_player_coordinate("loner_mover", FieldCoordinate::new(2, 7));
            eng.game.field_model.set_player_state("loner_mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(4, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("loner_mover".into(), PlayerAction::Move);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Move {
                path: vec![FieldCoordinate::new(3, 7)],
            }).unwrap();
            if eng.pending_reroll.is_some() {
                let evs2 = eng.apply(TeamSide::Home, crate::action::Action::UseReRoll { use_reroll: true }).unwrap();
                let loner_succeeded = evs2.iter().any(|e| matches!(e, GameEvent::LonerRoll { success: true, .. }));
                if loner_succeeded {
                    // Should see a second DodgeRoll (the retry)
                    let dodge_count = evs2.iter().filter(|e| matches!(e, GameEvent::DodgeRoll { rerolled: true, .. })).count();
                    assert!(dodge_count >= 1, "Loner success should result in a dodge retry (seed {})", seed);
                    return;
                }
            }
        }
    }

    #[test]
    fn loner_roll_threshold_is_4_plus() {
        // Verify LonerRoll event: success = roll >= 4.
        for seed in 0u64..500 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("loner_mover", 1);
            mover.agility = 6;
            mover.starting_skills = vec![ffb_model::model::skill_def::SkillWithValue::new(SkillId::Loner)];
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.field_model.set_player_coordinate("loner_mover", FieldCoordinate::new(2, 7));
            eng.game.field_model.set_player_state("loner_mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(4, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("loner_mover".into(), PlayerAction::Move);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Move {
                path: vec![FieldCoordinate::new(3, 7)],
            }).unwrap();
            if eng.pending_reroll.is_some() {
                let evs2 = eng.apply(TeamSide::Home, crate::action::Action::UseReRoll { use_reroll: true }).unwrap();
                if let Some(GameEvent::LonerRoll { roll, success, .. }) = evs2.iter().find(|e| matches!(e, GameEvent::LonerRoll { .. })) {
                    let expected = *roll >= 4;
                    assert_eq!(*success, expected, "LonerRoll success should be roll >= 4, but roll={} success={} (seed {})", roll, success, seed);
                    return;
                }
            }
        }
    }

