    #[test]
    fn pouring_rain_increases_hand_off_catch_target_by_one() {
        // PouringRain: catch_min = max(2, rcvr_ag + 1) instead of max(2, rcvr_ag).
        // Verify by checking that with ag=2, target is 3 not 2.
        let mut home = make_test_team("home");
        let mut carrier = make_test_player("carrier", 1);
        let mut receiver = make_test_player("receiver", 2);
        receiver.agility = 2; // would have target 2 in nice weather, 3 in rain
        home.players.push(carrier.clone());
        home.players.push(receiver);
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        eng.game.weather = Weather::PouringRain;
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.turn_data_home.rerolls = 0;
        eng.game.field_model.set_player_coordinate("carrier", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("carrier", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.set_player_coordinate("receiver", FieldCoordinate::new(11, 7));
        eng.game.field_model.set_player_state("receiver", PlayerState::new(PS_STANDING));
        eng.game.field_model.ball_coordinate = Some(FieldCoordinate::new(10, 7));
        eng.game.field_model.ball_in_play = true;
        eng.game.acting_player.set_player("carrier".into(), PlayerAction::HandOver);
        let evs = eng.apply(TeamSide::Home, crate::action::Action::HandOff {
            receiver_id: "receiver".into(),
        }).unwrap();
        // CatchRoll target should be 3 (ag=2 + rain=1) not 2
        if let Some(GameEvent::CatchRoll { target, .. }) = evs.iter().find(|e| matches!(e, GameEvent::CatchRoll { .. })) {
            assert_eq!(*target, 3, "Catch target should be ag+1=3 in PouringRain weather");
        } else {
            panic!("Expected CatchRoll event");
        }
        let _ = carrier;
    }

