    // ── Group 214: Turn data bookkeeping ────────────────────────────────────

    #[test]
    fn reroll_used_flag_set_on_team_reroll() {
        // When a team reroll is used, reroll_used flag should be set.
        for seed in 0u64..200 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("mover", 1);
            mover.agility = 6; // always fails dodge
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.turn_data_home.reroll_used = false;
            eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(2, 7));
            eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(4, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Move {
                path: vec![FieldCoordinate::new(3, 7)],
            }).unwrap();
            if eng.pending_reroll.is_some() {
                let _ = eng.apply(TeamSide::Home, crate::action::Action::UseReRoll { use_reroll: true }).unwrap();
                assert!(eng.game.turn_data_home.reroll_used, "reroll_used should be true after using team reroll (seed {})", seed);
                assert_eq!(eng.game.turn_data_home.rerolls, 1, "rerolls should decrement (seed {})", seed);
                return;
            }
        }
    }

    #[test]
    fn reroll_used_flag_cleared_on_end_turn() {
        // After EndTurn, reroll_used should be reset so the next turn can use a reroll.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("player1", 1));
        let away = make_test_team("away");
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.turn_data_home.reroll_used = true;
        eng.game.turn_data_home.rerolls = 2;
        eng.game.field_model.set_player_coordinate("player1", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("player1", PlayerState::new(PS_STANDING));
        let _ = eng.apply(TeamSide::Home, crate::action::Action::EndTurn).unwrap();
        assert!(!eng.game.turn_data_away.reroll_used || !eng.game.turn_data_home.reroll_used,
            "reroll_used should be reset after EndTurn");
    }

    #[test]
    fn turn_nr_increments_on_end_turn() {
        // EndTurn increments the NEXT team's turn counter (Java semantics: turn_nr set at start of each turn).
        let mut home = make_test_team("home");
        home.players.push(make_test_player("player1", 1));
        let away = make_test_team("away");
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.turn_data_home.turn_nr = 2;
        eng.game.turn_data_away.turn_nr = 2;
        eng.game.field_model.set_player_coordinate("player1", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("player1", PlayerState::new(PS_STANDING));
        let _ = eng.apply(TeamSide::Home, crate::action::Action::EndTurn).unwrap();
        assert_eq!(eng.game.turn_data_away.turn_nr, 3, "away turn_nr must increment when home ends turn");
    }

    #[test]
    fn home_playing_toggles_after_end_turn() {
        // After EndTurn, home_playing should flip (away team's turn next).
        let mut home = make_test_team("home");
        home.players.push(make_test_player("player1", 1));
        let away = make_test_team("away");
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.turn_data_home.turn_nr = 2;
        eng.game.field_model.set_player_coordinate("player1", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("player1", PlayerState::new(PS_STANDING));
        let _ = eng.apply(TeamSide::Home, crate::action::Action::EndTurn).unwrap();
        assert!(!eng.game.home_playing, "After home EndTurn, home_playing should be false");
    }

