    // ── Group 217: Tackle zones and dodge mechanics ──────────────────────────

    #[test]
    fn prone_opponent_does_not_add_tackle_zone() {
        // A prone opponent does not impose a tackle zone penalty on dodge.
        let mut home = make_test_team("home");
        home.players.push(make_test_player("mover", 1));
        let mut away = make_test_team("away");
        let def = make_test_player("prone_def", 11);
        away.players.push(def);
        let mut eng = GameEngine::new(home, away, Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
        eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
        // Place prone opponent adjacent to the destination
        eng.game.field_model.set_player_coordinate("prone_def", FieldCoordinate::new(12, 7));
        eng.game.field_model.set_player_state("prone_def", PlayerState::new(PS_PRONE));
        eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
        let evs = eng.apply(TeamSide::Home, crate::action::Action::Move {
            path: vec![FieldCoordinate::new(11, 7)],
        }).unwrap();
        // Movement to (11,7) adjacent to a prone opponent should not require a dodge roll
        assert!(!evs.iter().any(|e| matches!(e, GameEvent::DodgeRoll { .. })),
            "Prone opponent should not impose tackle zone, no DodgeRoll expected");
    }

