        let far_coord = FieldCoordinate::new(1, 7); // away from player
        eng.game.field_model.set_player_coordinate("runner", FieldCoordinate::new(24, 7));
        eng.game.field_model.set_player_state("runner", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.ball_coordinate = Some(far_coord); // ball elsewhere
        eng.game.field_model.ball_in_play = true;
        eng.game.acting_player.set_player("runner".into(), PlayerAction::Move);
