    // ── Group 223: Reroll source types ──────────────────────────────────────

    #[test]
    fn reroll_event_source_is_team_reroll() {
        // When team reroll is used, ReRoll event should have TeamReRoll source.
        for seed in 0u64..200 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("mover", 1);
            mover.agility = 6; // always fails dodge
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(2, 7));
            eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(4, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            let _ = eng.apply(TeamSide::Home, crate::action::Action::Move {
                path: vec![FieldCoordinate::new(3, 7)],
            }).unwrap();
            if eng.pending_reroll.is_some() {
                let evs2 = eng.apply(TeamSide::Home, crate::action::Action::UseReRoll { use_reroll: true }).unwrap();
                if let Some(GameEvent::ReRoll { source, .. }) = evs2.iter().find(|e| matches!(e, GameEvent::ReRoll { .. })) {
                    assert_eq!(source.name, "TeamReRoll", "Reroll source should be TeamReRoll");
                    return;
                }
            }
        }
    }

