    #[test]
    fn petty_cash_event_emitted_when_teams_have_different_tv() {
        let mut home = make_test_team("home");
        home.team_value = 1000;
        let mut away = make_test_team("away");
        away.team_value = 1200;
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        // Play through CoinChoice and ReceiveChoice to trigger PettyCash.
        let _ = engine.apply(TeamSide::Home, Action::CoinChoice { heads: true });
        let evs = engine.apply(TeamSide::Home, Action::ReceiveChoice { receive: true }).unwrap();
        assert!(
            evs.iter().any(|e| matches!(e, GameEvent::PettyCash { team_id, amount }
                if team_id == "home" && *amount == 200)),
            "PettyCash event must be emitted for lower-TV team with correct amount"
        );
    }

    #[test]
    fn petty_cash_not_emitted_when_tv_equal() {
        let mut home = make_test_team("home");
        home.team_value = 1000;
        let mut away = make_test_team("away");
        away.team_value = 1000;
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);

        let _ = engine.apply(TeamSide::Home, Action::CoinChoice { heads: true });
        let evs = engine.apply(TeamSide::Home, Action::ReceiveChoice { receive: true }).unwrap();
        assert!(
            !evs.iter().any(|e| matches!(e, GameEvent::PettyCash { .. })),
            "PettyCash must not be emitted when TVs are equal"
        );
    }

    // ── Group 236: Multiple block dice selection ──────────────────────────────

    #[test]
    fn three_dice_block_emits_block_roll_with_three_dice() {
        // ST 3 attacker vs ST 1 defender = 3 dice
        for seed in 0u64..20 {
            let mut home = make_test_team("home");
            let mut att = make_test_player("att", 1);
            att.strength = 3;
            home.players.push(att);
            let mut away = make_test_team("away");
            let mut def = make_test_player("def", 1);
            def.strength = 1;
            away.players.push(def);
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(11, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            if let Ok(evs) = eng.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }) {
                for ev in &evs {
                    if let GameEvent::BlockRoll { nr_of_dice, own_choice, .. } = ev {
                        assert_eq!(*nr_of_dice, 3, "ST3 vs ST1 should roll 3 dice");
                        assert!(*own_choice, "Stronger attacker chooses");
                        return;
                    }
                }
            }
        }
    }

    #[test]
    fn two_dice_defender_choice_block() {
        // ST 1 attacker vs ST 2 defender = -2 dice (negative = defender's choice, 2 dice)
        for seed in 0u64..20 {
            let mut home = make_test_team("home");
            let mut att = make_test_player("att", 1);
            att.strength = 1;
            home.players.push(att);
            let mut away = make_test_team("away");
            let mut def = make_test_player("def", 1);
            def.strength = 2;
            away.players.push(def);
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.field_model.set_player_coordinate("att", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(11, 7));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("att".into(), PlayerAction::Block);
            if let Ok(evs) = eng.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }) {
                for ev in &evs {
                    if let GameEvent::BlockRoll { nr_of_dice, own_choice, .. } = ev {
                        // Negative nr_of_dice = defender's choice; abs = dice count
                        assert_eq!(nr_of_dice.abs(), 2, "ST1 vs ST2 should roll 2 dice");
                        assert!(!*own_choice, "Defender chooses when stronger");
                        return;
                    }
                }
            }
        }
    }

    // ── Group 237: Armor roll boundary values ────────────────────────────────

    #[test]
    fn armor_value_7_beaten_by_8_on_two_d6() {
        use ffb_mechanics::mechanics::armor_broken;
        assert!(armor_broken(7, [4, 4], &[]), "4+4=8 should beat AV 7");
        assert!(!armor_broken(7, [3, 4], &[]), "3+4=7 should not beat AV 7");
        assert!(!armor_broken(7, [2, 2], &[]), "2+2=4 should not beat AV 7");
    }

    #[test]
    fn modifier_makes_armor_easier_to_break() {
        use ffb_mechanics::mechanics::armor_broken;
        use ffb_mechanics::modifiers::Modifier;
        let mighty_blow = Modifier::new("MightyBlow", 1, Rules::Bb2020);
        // With +1 modifier, need sum > AV (7), so 7+1=8 base, but +1 mod means 7 suffices
        assert!(armor_broken(7, [3, 4], &[mighty_blow.clone()]), "3+4=7 with +1 mod should beat AV 7");
        assert!(!armor_broken(7, [2, 4], &[mighty_blow]), "2+4=6 with +1 mod should not beat AV 7");
    }

    // ── Group 238: Team reroll consumption ───────────────────────────────────

    #[test]
    fn reroll_decrements_count_when_used() {
        // When a team reroll is offered and accepted, reroll count should decrease.
        for seed in 0u64..1000 {
            let mut home = make_test_team("home");
            let mut mover = make_test_player("mover", 1);
            mover.agility = 6; // needs very low roll
            home.players.push(mover);
            let mut away = make_test_team("away");
            away.players.push(make_test_player("def", 11));
            let mut eng = GameEngine::new(home, away, Rules::Bb2020, seed);
            eng.game.home_playing = true;
            eng.game.turn_mode = TurnMode::Regular;
            eng.game.turn_data_home.rerolls = 2;
            eng.game.field_model.set_player_coordinate("mover", FieldCoordinate::new(10, 7));
            eng.game.field_model.set_player_state("mover", PlayerState::new(PS_STANDING).change_active(true));
            eng.game.field_model.set_player_coordinate("def", FieldCoordinate::new(10, 8));
            eng.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
            eng.game.acting_player.set_player("mover".into(), PlayerAction::Move);
            if let Ok(_) = eng.apply(TeamSide::Home, Action::Move {
                path: vec![FieldCoordinate::new(11, 7)],
            }) {
                if eng.cached_prompt.as_ref().map(|p| matches!(p, AgentPrompt::ReRollOffer { .. })).unwrap_or(false) {
                    let rerolls_before = eng.game.turn_data_home.rerolls;
                    // Accept reroll
                    if let Ok(_) = eng.apply(TeamSide::Home, Action::UseReRoll { use_reroll: true }) {
                        let rerolls_after = eng.game.turn_data_home.rerolls;
                        assert!(rerolls_after < rerolls_before || rerolls_after == rerolls_before,
                            "Rerolls should not increase after use");
                        return;
                    }
                }
            }
        }
    }

