    // ── Group 240: Touchdown SPP and score interaction ────────────────────────

    #[test]
    fn touchdown_spp_equals_three() {
        use ffb_mechanics::mechanics::touchdown_spp;
        assert_eq!(touchdown_spp(Rules::Bb2020, false), 3);
        assert_eq!(touchdown_spp(Rules::Bb2016, false), 3);
    }

    #[test]
    fn player_spp_increments_after_touchdown() {
        let mut home = make_test_team("home");
        home.players.push(make_test_player("scorer", 1));
        let mut eng = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, 42);
        eng.game.home_playing = true;
        eng.game.turn_mode = TurnMode::Regular;
        let start = FieldCoordinate::new(24, 7);
        eng.game.field_model.set_player_coordinate("scorer", start);
        eng.game.field_model.set_player_state("scorer", PlayerState::new(PS_STANDING).change_active(true));
        eng.game.field_model.ball_coordinate = Some(start);
        eng.game.field_model.ball_in_play = true;
        eng.game.acting_player.set_player("scorer".into(), PlayerAction::Move);
        eng.apply(TeamSide::Home, Action::Move {
            path: vec![FieldCoordinate::new(25, 7)],
        }).unwrap();
        let spp = eng.game.team_home.player("scorer")
            .map(|p| p.current_spps).unwrap_or(0);
        assert_eq!(spp, 3, "Scorer should gain 3 SPP for touchdown");
    }

