    // ── Group 244: Pass result categories ────────────────────────────────────

    #[test]
    fn pass_result_accurate_on_good_roll_bb2020() {
        use ffb_mechanics::mechanics::{evaluate_pass, PassResult as MechPR};
        use ffb_model::enums::PassingDistance;
        // In BB2020, PA 3, QuickPass (dist_mod=0): roll 3+ = Accurate (roll >= PA)
        let res = evaluate_pass(Rules::Bb2020, 3, 3, PassingDistance::QuickPass, &[], false);
        assert_eq!(res, MechPR::Accurate, "Roll at PA = accurate in BB2020");
        let res6 = evaluate_pass(Rules::Bb2020, 3, 6, PassingDistance::QuickPass, &[], false);
        assert_eq!(res6, MechPR::Accurate, "Roll 6 always accurate in BB2020");
    }

    #[test]
    fn pass_result_inaccurate_on_low_roll_bb2020() {
        use ffb_mechanics::mechanics::{evaluate_pass, PassResult as MechPR};
        use ffb_model::enums::PassingDistance;
        // In BB2020, PA 4, QuickPass: roll 2 = inaccurate (2 < 4, effective=2 > 1)
        let res = evaluate_pass(Rules::Bb2020, 4, 2, PassingDistance::QuickPass, &[], false);
        assert_eq!(res, MechPR::Inaccurate, "Roll below PA but > 1 = inaccurate");
    }

    #[test]
    fn pass_result_fumble_in_bb2016_on_natural_1() {
        use ffb_mechanics::mechanics::{evaluate_pass, PassResult as MechPR};
        use ffb_model::enums::PassingDistance;
        // In BB2016 with AG 3, short pass: natural 1 always fumbles
        let res = evaluate_pass(Rules::Bb2016, 3, 1, PassingDistance::ShortPass, &[], false);
        assert_eq!(res, MechPR::Fumble, "Natural 1 in BB2016 = fumble");
    }

