    // ── Group 247: Wizard inducement integration ──────────────────────────────

    #[test]
    fn wizard_buy_then_fireball_emits_buy_and_injury_events() {
        // Full integration: buy a wizard via BuyInducements, then cast Fireball.
        // Verifies the end-to-end flow: BuyInducement event emitted, WizardUse event
        // emitted, Injury event emitted for a player in the blast.
        let mut home = make_test_team("home");
        let mut away = make_test_team("away");
        let mut target = make_test_player("target", 1);
        target.armour = 1; // guaranteed armor break
        away.players.push(target);

        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 1);
        // Set away player on the pitch
        engine.game.field_model.set_player_coordinate("target", FieldCoordinate::new(10, 7));
        engine.game.field_model.set_player_state("target", PlayerState::new(PS_STANDING));

        // Buy a wizard for the home team
        let buy_events = engine.apply(TeamSide::Home, Action::BuyInducements {
            purchases: vec![crate::action::InducementPurchase { id: "wizard".into(), count: 1 }],
        }).unwrap();
        assert!(buy_events.iter().any(|e| matches!(e, GameEvent::BuyInducement { inducement_id, .. } if inducement_id == "wizard")),
            "BuyInducements must emit BuyInducement event for wizard");

        // Cast Fireball at the target's square
        let spell_events = engine.apply(TeamSide::Home, Action::WizardSpell {
            spell: crate::action::WizardSpellChoice::Fireball,
            coord: FieldCoordinate::new(10, 7),
        }).unwrap();
        assert!(spell_events.iter().any(|e| matches!(e, GameEvent::WizardUse { .. })),
            "WizardSpell must emit WizardUse event");
        assert!(spell_events.iter().any(|e| matches!(e, GameEvent::Injury { player_id, .. } if player_id == "target")),
            "Fireball must injure the player in the blast");
    }

