    #[test]
    fn timmmber_absent_stand_up_roll_unmodified() {
        // Without Timmmber adjacent teammates must NOT lower the stand-up threshold.
        // MA=2 player needs 4+ to stand. Roll of 2 must FAIL without Timmmber.
        let mut home = make_test_team("home");
        let mut prone_player = make_test_player("prone", 1); // no Timmmber
        prone_player.movement = 2;
        let teammate = make_test_player("tm1", 2);
        home.players.push(prone_player);
        home.players.push(teammate);
        let away = make_test_team("away");
        let prone_coord = FieldCoordinate::new(10, 7);
        let tm1_coord = FieldCoordinate::new(9, 7);
        let mut found_low_roll_failure = false;
        for seed in 0u64..500 {
            let mut engine = GameEngine::new(home.clone(), away.clone(), Rules::Bb2020, seed);
            engine.game.home_playing = true;
            engine.game.turn_mode = TurnMode::Regular;
            engine.game.field_model.set_player_coordinate("prone", prone_coord);
            engine.game.field_model.set_player_state("prone", PlayerState::new(PS_PRONE));
            engine.game.field_model.set_player_coordinate("tm1", tm1_coord);
            engine.game.field_model.set_player_state("tm1", PlayerState::new(PS_STANDING));
            engine.game.acting_player.set_player("prone".into(), PlayerAction::Move);
            let evs = engine.apply(TeamSide::Home, Action::Move { path: vec![FieldCoordinate::new(11, 7)] });
            if let Ok(ref evs) = evs {
                if let Some(GameEvent::StandUpRoll { roll, success, .. }) = evs.iter().find(|e| matches!(e, GameEvent::StandUpRoll { .. })) {
                    if *roll < 4 && !success {
                        // Low roll correctly failed without Timmmber — no teammate bonus applied
                        found_low_roll_failure = true;
                        break;
                    }
                }
            }
        }
        assert!(found_low_roll_failure,
            "Without Timmmber a stand-up roll < 4 must fail even with adjacent teammates (checked 500 seeds)");
    }

    #[test]
    fn cannoneer_absent_long_bomb_uses_full_distance_penalty() {
        // Without Cannoneer the Long Bomb modifier is NOT reduced.
        // Verify pass can fail on rolls that Cannoneer would improve.
        use ffb_model::enums::PassingDistance;
        let mut found_fail = false;
        for seed in 0..500u64 {
            let mut home = make_test_team("home");
            let mut thrower = make_test_player("thr", 1); // no Cannoneer
            thrower.passing = 5;
            home.players.push(thrower);
            let mut engine = GameEngine::new(home, make_test_team("away"), Rules::Bb2020, seed);
            engine.game.field_model.set_player_coordinate("thr", FieldCoordinate::new(1, 7));
            engine.game.field_model.set_player_state("thr", PlayerState::new(PS_STANDING).change_active(true));
            engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(1, 7));
            engine.game.home_playing = true;
            engine.game.acting_player.set_player("thr".into(), PlayerAction::Pass);
            let evs = engine.apply(TeamSide::Home, Action::Pass { coord: FieldCoordinate::new(20, 7) }).unwrap();
            let failed = evs.iter().any(|e| matches!(e,
                GameEvent::PassRoll { result, distance, .. }
                if matches!(distance, PassingDistance::LongBomb) && *result != ffb_model::enums::PassResult::Complete
            ));
            if failed {
                found_fail = true;
                break;
            }
        }
        assert!(found_fail, "Without Cannoneer Long Bomb must be able to fail (checked 500 seeds)");
    }

