    // ── Group 197: BlindRage — free Dauntless reroll ──────────────────────────
    fn setup_dauntless_engine(has_blind_rage: bool) -> GameEngine {
        let mut home = make_test_team("home");
        let mut att = make_test_player("att", 1);
        att.strength = 2;
        if has_blind_rage { att.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::BlindRage)); }
        att.starting_skills.push(ffb_model::model::skill_def::SkillWithValue::new(SkillId::Dauntless));
        home.players.push(att);
        let mut away = make_test_team("away");
        let mut def = make_test_player_with_st("def", 2, 4);
        away.players.push(def);
        // seed 1 → d6 chain: first Dauntless fails (1), BlindRage reroll (2), still low
        // we only check events
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 1);
        engine.game.field_model.set_player_coordinate("att", FieldCoordinate::new(12, 7));
        engine.game.field_model.set_player_state("att", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("def", FieldCoordinate::new(13, 7));
        engine.game.field_model.set_player_state("def", PlayerState::new(PS_STANDING));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.acting_player.set_player("att".into(), PlayerAction::Block);
        engine
    }
    #[test]
    fn blind_rage_rerolls_failed_dauntless() {
        let mut engine = setup_dauntless_engine(true);
        let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
        let used = evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::BlindRage as u16));
        let daunt_count = evs.iter().filter(|e| matches!(e, GameEvent::DauntlessRoll { .. })).count();
        assert!(used, "BlindRage must emit SkillUse when Dauntless fails");
        assert!(daunt_count >= 2, "BlindRage must cause a second DauntlessRoll");
    }
    #[test]
    fn without_blind_rage_only_one_dauntless_roll() {
        let mut engine = setup_dauntless_engine(false);
        let evs = engine.apply(TeamSide::Home, Action::Block { defender_id: "def".into() }).unwrap_or_default();
        let daunt_count = evs.iter().filter(|e| matches!(e, GameEvent::DauntlessRoll { .. })).count();
        assert_eq!(daunt_count, 1, "Without BlindRage only one DauntlessRoll must occur");
    }

