    // ── Group 217: QuickBite — injure adjacent opponent after catch ───────────
    #[test]
    fn quick_bite_emits_skill_use_after_catch() {
        let mut home = make_test_team("home");
        let p = make_test_player_with_skill("catcher", 1, SkillId::QuickBite);
        home.players.push(p);
        let mut away = make_test_team("away");
        let mut opp = make_test_player_with_av("opp", 2, 1); // AV=1 always breaks
        away.players.push(opp);
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        let catch_coord = FieldCoordinate::new(10, 7);
        engine.game.field_model.set_player_coordinate("catcher", catch_coord);
        engine.game.field_model.set_player_state("catcher", PlayerState::new(PS_STANDING));
        engine.game.field_model.set_player_coordinate("opp", FieldCoordinate::new(11, 7));
        engine.game.field_model.set_player_state("opp", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_in_play = true;
        engine.game.home_playing = true;
        // Simulate ball landing on catcher's square — use test hook
        let mut evs = Vec::new();
        engine.resolve_ball_landing_test_hook(catch_coord, &mut evs);
        let skill_used = evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::QuickBite as u16));
        // QuickBite fires if catch succeeds (depends on seed/roll); verify it fires if catch succeeds
        let catch_ev = evs.iter().any(|e| matches!(e, GameEvent::BallPickedUp { .. }));
        if catch_ev {
            assert!(skill_used, "QuickBite must emit SkillUse after successful catch when opponent adjacent");
        }
        // Even if catch fails, verify skill is present
        assert!(engine.game.team_home.player("catcher").map(|p| p.has_skill(SkillId::QuickBite)).unwrap_or(false));
    }
    #[test]
    fn quick_bite_class_name() {
        use ffb_mechanics::skills::skill_def;
        assert_eq!(skill_def(SkillId::QuickBite).unwrap().class_name, "QuickBite");
    }

    // ── Group 218: RaidingParty — move adjacent open teammate ────────────────
    #[test]
    fn raiding_party_emits_skill_use_and_moves_teammate() {
        let mut home = make_test_team("home");
        let p = make_test_player_with_skill("rp", 1, SkillId::RaidingParty);
        let mut tm = make_test_player("tm", 2);
        home.players.push(p);
        home.players.push(tm);
        let away = make_test_team("away");
        let mut engine = GameEngine::new(home, away, Rules::Bb2020, 42);
        engine.game.field_model.set_player_coordinate("rp", FieldCoordinate::new(5, 7));
        engine.game.field_model.set_player_state("rp", PlayerState::new(PS_STANDING).change_active(true));
        engine.game.field_model.set_player_coordinate("tm", FieldCoordinate::new(6, 7));
        engine.game.field_model.set_player_state("tm", PlayerState::new(PS_STANDING));
        engine.game.field_model.ball_coordinate = Some(FieldCoordinate::new(15, 7));
        engine.game.home_playing = true;
        engine.game.turn_mode = TurnMode::Regular;
        engine.game.acting_player.set_player("rp".into(), PlayerAction::Move);
        let evs = engine.apply(TeamSide::Home, Action::UseSkill { skill_id: SkillId::RaidingParty, use_skill: true }).unwrap_or_default();
        let skill_used = evs.iter().any(|e| matches!(e, GameEvent::SkillUse { skill_id, used: true, .. } if *skill_id == SkillId::RaidingParty as u16));
        assert!(skill_used, "RaidingParty must emit SkillUse when used");
        let moved = evs.iter().any(|e| matches!(e, GameEvent::PlayerMoved { player_id, .. } if player_id == "tm"));
        assert!(moved, "RaidingParty must move the adjacent open teammate");
    }
