    #[test]
    fn kickoff_get_the_ref_gives_both_teams_reroll() {
        use ffb_model::enums::KickoffResult;
        let mut engine = make_kickoff_engine(Rules::Bb2020, 42);
        let home_before = engine.game.turn_data_home.rerolls;
        let away_before = engine.game.turn_data_away.rerolls;
        // GetTheRef fires on BB2020 roll=2
        let (evs, _) = engine.apply_kickoff_event(2, false);
        assert!(evs.iter().any(|e| matches!(e, GameEvent::KickoffResultEvent { result } if *result == KickoffResult::GetTheRef)));
        assert_eq!(engine.game.turn_data_home.rerolls, home_before + 1, "GetTheRef: home gains 1 reroll");
        assert_eq!(engine.game.turn_data_away.rerolls, away_before + 1, "GetTheRef: away gains 1 reroll");
    }

